    async function deleteGlossaryLibraryEntry() {
        if (!datasetManagerElements.glossaryLibrarySelect) {
            return;
        }
        const name = datasetManagerElements.glossaryLibrarySelect.value || "";
        if (!name) {
            setGlossaryMessage(datasetManagerElements.glossaryLibraryMessage, "Select a glossary to delete.", "warn");
            return;
        }
        if (datasetManagerState.glossaryLibraryDeleteInFlight) {
            return;
        }
        const ok = window.confirm(`Delete glossary "${name}"?`);
        if (!ok) return;
        datasetManagerState.glossaryLibraryDeleteInFlight = true;
        updateGlossaryActionButtons();
        try {
            const resp = await fetch(`${API_ROOT}/glossaries/${encodeURIComponent(name)}`, { method: "DELETE" });
            if (!resp.ok) {
                throw new Error(await resp.text());
            }
            datasetManagerElements.glossaryLibrarySelect.value = "";
            if (datasetManagerElements.glossaryLibraryName) datasetManagerElements.glossaryLibraryName.value = "";
            if (datasetManagerElements.glossaryLibraryEditor) datasetManagerElements.glossaryLibraryEditor.value = "";
            await refreshGlossaryLibrary({ silent: true });
            setGlossaryMessage(datasetManagerElements.glossaryLibraryMessage, "Deleted glossary.", "success");
        } catch (err) {
            console.error("Failed to delete glossary entry", err);
            setGlossaryMessage(datasetManagerElements.glossaryLibraryMessage, err.message || "Delete failed", "error");
        } finally {
            datasetManagerState.glossaryLibraryDeleteInFlight = false;
            updateGlossaryActionButtons();
        }
    }

    function downloadGlossaryLibraryEntry() {
        if (!datasetManagerElements.glossaryLibrarySelect || !datasetManagerElements.glossaryLibraryEditor) {
            return;
        }
        const name = datasetManagerElements.glossaryLibrarySelect.value || "";
        if (!name) {
            setGlossaryMessage(datasetManagerElements.glossaryLibraryMessage, "Select a glossary to download.", "warn");
            return;
        }
        const payload = {
            name,
            glossary: datasetManagerElements.glossaryLibraryEditor.value || "",
        };
        const blob = new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" });
        saveBlobToDisk(blob, `${sanitizeFilename(name, "glossary")}.json`);
    }

    async function handleGlossaryLibraryUpload() {
        if (!datasetManagerElements.glossaryLibraryUpload || !datasetManagerElements.glossaryLibraryUpload.files?.length) {
            return;
        }
        const file = datasetManagerElements.glossaryLibraryUpload.files[0];
        try {
            const text = await file.text();
            let payload;
            try {
                payload = JSON.parse(text);
            } catch {
                payload = null;
            }
            if (payload && typeof payload === "object") {
                const name = payload.name || payload.id || "";
                const glossary = payload.glossary || payload.body || "";
                if (name) {
                    datasetManagerElements.glossaryLibraryName.value = name;
                }
                if (glossary) {
                    datasetManagerElements.glossaryLibraryEditor.value = glossary;
                } else if (typeof payload === "object") {
                    datasetManagerElements.glossaryLibraryEditor.value = JSON.stringify(payload, null, 2);
                }
            } else {
                datasetManagerElements.glossaryLibraryEditor.value = text;
            }
            setGlossaryMessage(datasetManagerElements.glossaryLibraryMessage, "Loaded glossary file. Save to apply.", "info");
        } catch (err) {
            console.error("Failed to upload glossary file", err);
            setGlossaryMessage(datasetManagerElements.glossaryLibraryMessage, err.message || "Upload failed", "error");
        } finally {
            datasetManagerElements.glossaryLibraryUpload.value = "";
            updateGlossaryActionButtons();
        }
    }

    async function handleDatasetUploadSessionCancel(entry) {
        const sessionId = String(entry?.session_id || "").trim();
        if (!sessionId) return;
        const label = entry.run_name || sessionId;
        const ok = window.confirm(
            `Cancel unfinished dataset upload "${label}"? This removes only temporary staged chunks, not registered datasets.`
        );
        if (!ok) return;
        const actionKey = datasetActionKey(sessionId, "upload_session_cancel");
        if (datasetManagerState.actionInFlight.has(actionKey)) {
            return;
        }
        datasetManagerState.actionInFlight.add(actionKey);
        renderDatasetUploadSessions(datasetManagerState.uploadSessions);
        setDatasetUploadMessage(`Cancelling staged upload ${label}…`, "info");
        try {
            const resp = await fetch(`${API_ROOT}/datasets/upload_session/${encodeURIComponent(sessionId)}/cancel`, {
                method: "POST",
            });
            if (!resp.ok) {
                const detail = await resp.text();
                throw new Error(detail || `HTTP ${resp.status}`);
            }
            const payload = await resp.json().catch(() => ({}));
            setDatasetUploadMessage(`Cancelled staged upload ${payload.session_id || label}.`, "success");
            await refreshDatasetUploadSessions();
        } catch (err) {
            console.error("Failed to cancel dataset upload session", err);
            setDatasetUploadMessage(err.message || "Failed to cancel staged upload", "error");
        } finally {
            datasetManagerState.actionInFlight.delete(actionKey);
            renderDatasetUploadSessions(datasetManagerState.uploadSessions);
        }
    }

    async function handleDatasetTrashRestore(entry) {
        if (!entry || !entry.trash_id) return;
        const label = entry.label || entry.original_id || entry.trash_id;
        const ok = window.confirm(
            `Restore deleted dataset "${label}"? If the original id is already in use, the backend will choose a unique id.`
        );
        if (!ok) return;
        const actionKey = datasetActionKey(entry.trash_id, "trash_restore");
        if (datasetManagerState.actionInFlight.has(actionKey)) {
            return;
        }
        datasetManagerState.actionInFlight.add(actionKey);
        renderDatasetTrashList(datasetManagerState.trash);
        setDatasetUploadMessage(`Restoring ${label}…`, "info");
        try {
            const resp = await fetch(`${API_ROOT}/datasets/trash/${encodeURIComponent(entry.trash_id)}/restore`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({}),
            });
            if (!resp.ok) {
                const detail = await resp.text();
                throw new Error(detail || `HTTP ${resp.status}`);
            }
            const payload = await resp.json().catch(() => ({}));
            setDatasetUploadMessage(`Restored ${payload.id || label}.`, "success");
            await Promise.all([
                refreshDatasetList(),
                refreshDatasetTrashList(),
            ]);
        } catch (err) {
            console.error("Failed to restore dataset", err);
            setDatasetUploadMessage(err.message || "Failed to restore dataset", "error");
        } finally {
            datasetManagerState.actionInFlight.delete(actionKey);
            renderDatasetTrashList(datasetManagerState.trash);
        }
    }

	    async function handleDatasetDelete(entry) {
	        if (!entry || !entry.id) return;
            const isLinked = String(entry.storage_mode || "").toLowerCase() === "linked";
            const confirmText = isLinked
                ? `Delete linked dataset record "${entry.label || entry.id}"? This removes library metadata/overlays only; source files stay on disk.`
                : `Move managed dataset "${entry.label || entry.id}" to deleted datasets? You can restore it from Dataset Management.`;
	        const ok = window.confirm(confirmText);
	        if (!ok) return;
        const actionKey = datasetActionKey(entry.id, "delete");
        if (datasetManagerState.actionInFlight.has(actionKey)) {
            return;
        }
        datasetManagerState.actionInFlight.add(actionKey);
        // Re-render to disable duplicate destructive clicks while request is active.
        renderDatasetList(datasetManagerState.datasets);
        setDatasetUploadMessage(`Deleting ${entry.label || entry.id}…`, "info");
        try {
            const resp = await fetch(`${API_ROOT}/datasets/${encodeURIComponent(entry.id)}`, { method: "DELETE" });
            if (!resp.ok) {
                const detail = await resp.text();
                throw new Error(detail || `HTTP ${resp.status}`);
            }
            const payload = await resp.json().catch(() => ({}));
            if (payload && payload.status === "trashed") {
                setDatasetUploadMessage(`Moved ${entry.label || entry.id} to deleted datasets.`, "success");
            } else {
                setDatasetUploadMessage(`Deleted ${entry.label || entry.id}.`, "success");
            }
            await Promise.all([
                refreshDatasetList(),
                refreshDatasetTrashList(),
            ]);
        } catch (err) {
            console.error("Failed to delete dataset", err);
            setDatasetUploadMessage(err.message || "Failed to delete dataset", "error");
	        } finally {
                datasetManagerState.actionInFlight.delete(actionKey);
                renderDatasetList(datasetManagerState.datasets);
	        }
	    }

