    const sam3PromptElements = {
        select: null,
        refresh: null,
        summary: null,
        activeLabel: null,
        message: null,
        activate: null,
    };

    const sam3PromptState = {
        models: [],
        selected: null,
        refreshRequestId: 0,
        refreshInFlight: false,
        refreshNeedsRefresh: false,
        activateInFlight: false,
    };

    function initSam3PromptModelsUi() {
        if (sam3PromptUiInitialized) {
            refreshSam3PromptModels().catch((err) => {
                console.error("Failed to refresh SAM3 prompt models", err);
            });
            return;
        }
        sam3PromptUiInitialized = true;
        sam3PromptElements.select = document.getElementById("sam3PromptModelSelect");
        sam3PromptElements.refresh = document.getElementById("sam3PromptRefresh");
        sam3PromptElements.summary = document.getElementById("sam3PromptModelSummary");
        sam3PromptElements.activeLabel = document.getElementById("sam3PromptActiveLabel");
        sam3PromptElements.message = document.getElementById("sam3PromptMessage");
        sam3PromptElements.activate = document.getElementById("sam3PromptActivate");
        if (sam3PromptElements.select) {
            sam3PromptElements.select.addEventListener("change", () => updateSam3PromptSummary());
        }
        if (sam3PromptElements.refresh) {
            sam3PromptElements.refresh.addEventListener("click", () => {
                refreshSam3PromptModels().catch((error) => {
                    console.error("SAM3 prompt model refresh failed", error);
                });
            });
        }
        if (sam3PromptElements.activate) {
            sam3PromptElements.activate.addEventListener("click", () => {
                activateSam3PromptModel().catch((error) => {
                    console.error("SAM3 prompt model activation failed", error);
                });
            });
        }
        updateSam3PromptButtons();
        refreshSam3PromptModels().catch((error) => {
            console.error("Failed to load SAM3 prompt models", error);
        });
    }

    async function refreshSam3PromptModels() {
        if (!sam3PromptElements.select) return;
        if (sam3PromptState.refreshInFlight) {
            // Coalesce repeated refresh clicks while one request is active.
            sam3PromptState.refreshNeedsRefresh = true;
            return;
        }
        sam3PromptState.refreshInFlight = true;
        // Prevent duplicate refresh/activate submissions while model list request is active.
        updateSam3PromptButtons();
        const requestId = sam3PromptState.refreshRequestId + 1;
        sam3PromptState.refreshRequestId = requestId;
        try {
            const resp = await fetch(`${API_ROOT}/sam3/models/available?variant=all&promoted_only=true`);
            if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
            const data = await resp.json();
            // Ignore stale responses when a newer prompt-model refresh exists.
            if (requestId !== sam3PromptState.refreshRequestId) {
                return;
            }
            sam3PromptState.models = Array.isArray(data) ? data : [];
            sam3PromptState.models.sort((a, b) => {
                const pa = a.promoted ? 0 : 1;
                const pb = b.promoted ? 0 : 1;
                if (pa !== pb) return pa - pb;
                const va = a.variant || "";
                const vb = b.variant || "";
                if (va !== vb) return va.localeCompare(vb);
                return (a.id || "").localeCompare(b.id || "");
            });
            sam3PromptElements.select.innerHTML = "";
            sam3PromptState.models.forEach((m, idx) => {
                const opt = document.createElement("option");
                opt.value = m.key || m.path || m.id || `model-${idx}`;
            const sizeText = Number.isFinite(m.size_bytes) ? ` – ${formatBytes(m.size_bytes)}` : "";
            const activeText = m.active ? " (active)" : "";
            opt.textContent = `${m.id || `run ${idx + 1}`} [${m.variant || "sam3"}]${m.promoted ? " (promoted)" : ""}${activeText}${sizeText}`;
            sam3PromptElements.select.appendChild(opt);
        });
            if (sam3PromptState.models.length) {
                const first = sam3PromptState.models[0];
                sam3PromptElements.select.value = first.key || first.path || first.id || sam3PromptElements.select.options[0].value;
                updateSam3PromptSummary();
            } else {
                updateSam3PromptSummary();
            }
        } catch (err) {
            if (requestId !== sam3PromptState.refreshRequestId) {
                return;
            }
            console.error("Failed to load SAM3 prompt models", err);
            setSam3PromptMessage(`Load failed: ${err.message || err}`, "error");
        } finally {
            if (requestId === sam3PromptState.refreshRequestId) {
                sam3PromptState.refreshInFlight = false;
                updateSam3PromptButtons();
                if (sam3PromptState.refreshNeedsRefresh) {
                    sam3PromptState.refreshNeedsRefresh = false;
                    refreshSam3PromptModels().catch((err) => {
                        console.error("Queued SAM3 prompt model refresh failed", err);
                    });
                }
            }
        }
    }

    function updateSam3PromptSummary() {
        if (!sam3PromptElements.summary) return;
        const path = sam3PromptElements.select ? sam3PromptElements.select.value : null;
        const entry = sam3PromptState.models.find((m) => (m.key || m.path || m.id) === path);
        const activeEntry = sam3PromptState.models.find((m) => m.active);
        if (sam3PromptElements.activeLabel) {
            sam3PromptElements.activeLabel.textContent = activeEntry
                ? `Active model: ${activeEntry.id || "unknown"} [${activeEntry.variant || "sam3"}]`
                : "Active model: none";
        }
        if (!entry) {
            sam3PromptElements.summary.textContent = "No model selected.";
            updateSam3PromptButtons();
            return;
        }
        const parts = [];
        if (entry.promoted) parts.push("promoted");
        if (entry.active) parts.push("active");
        if (Number.isFinite(entry.size_bytes)) parts.push(formatBytes(entry.size_bytes));
        if (entry.run_path) parts.push(`run: ${entry.run_path}`);
        sam3PromptElements.summary.textContent = parts.length ? parts.join(" • ") : "";
        updateSam3PromptButtons();
    }

    function setSam3PromptMessage(text, tone = "info") {
        if (!sam3PromptElements.message) return;
        sam3PromptElements.message.textContent = text || "";
        sam3PromptElements.message.className = `training-message ${tone}`;
    }

    function updateSam3PromptButtons() {
        const hasModels = Array.isArray(sam3PromptState.models) && sam3PromptState.models.length > 0;
        const busy = sam3PromptState.refreshInFlight || sam3PromptState.activateInFlight;
        if (sam3PromptElements.refresh) {
            sam3PromptElements.refresh.disabled = busy;
        }
        if (sam3PromptElements.select) {
            sam3PromptElements.select.disabled = busy || !hasModels;
        }
        if (sam3PromptElements.activate) {
            sam3PromptElements.activate.disabled = busy || !hasModels;
        }
    }

    async function activateSam3PromptModel() {
        if (!sam3PromptElements.select) return;
        if (sam3PromptState.activateInFlight) {
            return;
        }
        const path = sam3PromptElements.select.value;
        const entry = sam3PromptState.models.find((m) => (m.key || m.path || m.id) === path);
        if (!entry) {
            setSam3PromptMessage("Select a model first.", "warn");
            return;
        }
        sam3PromptState.activateInFlight = true;
        updateSam3PromptButtons();
        const payload = {
            checkpoint_path: entry.path || null,
            enable_segmentation: false,
            label: `prompt:${(entry.id || entry.path || "sam3").toString().split("/").pop()}`,
        };
        try {
            const resp = await fetch(`${API_ROOT}/sam3/models/activate`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload),
            });
            if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
            await refreshSam3PromptModels();
            setSam3PromptMessage("SAM3 prompt model activated.", "success");
        } catch (err) {
            console.error("Activate SAM3 prompt model failed", err);
            setSam3PromptMessage(`Activate failed: ${err.message || err}`, "error");
        } finally {
            sam3PromptState.activateInFlight = false;
            updateSam3PromptButtons();
        }
    }

    function escapeHtml(value) {
        return String(value ?? "")
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;")
            .replace(/'/g, "&#39;");
    }

    function sanitizeFilename(value, fallback = "download") {
        const normalized = String(value ?? "").trim();
        const safe = normalized
            .replace(/[<>:"/\\|?*\x00-\x1F]/g, "_")
            .replace(/\s+/g, " ")
            .trim();
        return safe || fallback;
    }

    function splitFilenameParts(filename) {
        const safeName = sanitizeFilename(filename, "download.bin");
        const dotIndex = safeName.lastIndexOf(".");
        if (dotIndex <= 0 || dotIndex === safeName.length - 1) {
            return { basename: safeName, extension: "" };
        }
        return {
            basename: safeName.slice(0, dotIndex),
            extension: safeName.slice(dotIndex),
        };
    }

    function normalizeCounterText(value, fallback = "0") {
        const text = String(value ?? "").trim();
        if (!/^\d+$/.test(text)) {
            return fallback;
        }
        return text.replace(/^0+(?=\d)/, "") || "0";
    }

    function incrementCounterText(value) {
        const digits = normalizeCounterText(value).split("");
        let carry = 1;
        for (let i = digits.length - 1; i >= 0 && carry; i--) {
            const nextDigit = digits[i].charCodeAt(0) - 48 + carry;
            if (nextDigit >= 10) {
                digits[i] = "0";
            } else {
                digits[i] = String(nextDigit);
                carry = 0;
            }
        }
        if (carry) {
            digits.unshift("1");
        }
        return digits.join("");
    }

    function compareCounterText(left, right) {
        const a = normalizeCounterText(left);
        const b = normalizeCounterText(right);
        if (a.length !== b.length) {
            return a.length > b.length ? 1 : -1;
        }
        if (a === b) {
            return 0;
        }
        return a > b ? 1 : -1;
    }

    function formatNumberedFilename(filename, counterText) {
        const counter = normalizeCounterText(counterText);
        const safeName = sanitizeFilename(filename, "download.bin");
        if (counter === "0") {
            return safeName;
        }
        const { basename, extension } = splitFilenameParts(safeName);
        return `${basename} (${counter})${extension}`;
    }

    function escapeRegExp(value) {
        return String(value).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    }

    function getNumberedFilenameCounter(candidateFilename, baseFilename) {
        const candidate = sanitizeFilename(candidateFilename, "");
        const safeBase = sanitizeFilename(baseFilename, "download.bin");
        if (!candidate) {
            return null;
        }
        if (candidate === safeBase) {
            return "0";
        }
        const { basename, extension } = splitFilenameParts(safeBase);
        const pattern = new RegExp(`^${escapeRegExp(basename)} \\((\\d+)\\)${escapeRegExp(extension)}$`);
        const match = candidate.match(pattern);
        return match ? normalizeCounterText(match[1]) : null;
    }

    function readYoloExportDownloadCounter() {
        try {
            const stored = window.localStorage?.getItem(YOLO_CAPTIONS_EXPORT_DOWNLOAD_COUNTER_KEY);
            const counter = normalizeCounterText(stored, YOLO_CAPTIONS_EXPORT_DOWNLOAD_COUNTER_START);
            return compareCounterText(counter, YOLO_CAPTIONS_EXPORT_DOWNLOAD_COUNTER_START) < 0
                ? YOLO_CAPTIONS_EXPORT_DOWNLOAD_COUNTER_START
                : counter;
        } catch (error) {
            console.debug("Unable to read YOLO export download counter", error);
            return YOLO_CAPTIONS_EXPORT_DOWNLOAD_COUNTER_START;
        }
    }

    function writeYoloExportDownloadCounter(counterText) {
        const nextCounter = normalizeCounterText(counterText, YOLO_CAPTIONS_EXPORT_DOWNLOAD_COUNTER_START);
        try {
            window.localStorage?.setItem(YOLO_CAPTIONS_EXPORT_DOWNLOAD_COUNTER_KEY, nextCounter);
        } catch (error) {
            console.debug("Unable to persist YOLO export download counter", error);
        }
    }

    function writeYoloExportDownloadCounterAtLeast(counterText) {
        const current = readYoloExportDownloadCounter();
        if (compareCounterText(counterText, current) > 0) {
            writeYoloExportDownloadCounter(counterText);
        }
    }

    function nextYoloExportDownloadFilename(filename = YOLO_CAPTIONS_EXPORT_FILENAME) {
        const counter = readYoloExportDownloadCounter();
        writeYoloExportDownloadCounter(incrementCounterText(counter));
        return formatNumberedFilename(filename, counter);
    }

    function saveBlobToDisk(blob, filename) {
        const safeName = sanitizeFilename(filename, "download.bin");
        if (typeof saveAs === "function") {
            try {
                saveAs(blob, safeName);
                return safeName;
            } catch (error) {
                // Keep a robust fallback path if FileSaver throws at runtime.
                console.warn("saveAs failed; falling back to anchor download", error);
            }
        }
        // Fallback path if FileSaver did not load; keep download actions working.
        const objectUrl = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.href = objectUrl;
        link.download = safeName;
        if (document.body) {
            document.body.appendChild(link);
        }
        link.click();
        if (link.parentNode) {
            link.parentNode.removeChild(link);
        }
        // Revoke asynchronously so slow browsers don't lose the download.
        window.setTimeout(() => URL.revokeObjectURL(objectUrl), 0);
        return safeName;
    }

    function supportsLocalFolderExport() {
        return typeof window.showDirectoryPicker === "function";
    }

    function supportsExportHandleStorage() {
        return typeof window.indexedDB !== "undefined";
    }

    function openYoloExportHandleDb() {
        return new Promise((resolve, reject) => {
            if (!supportsExportHandleStorage()) {
                reject(new Error("indexeddb_unavailable"));
                return;
            }
            const request = window.indexedDB.open(YOLO_EXPORT_HANDLE_DB_NAME, 1);
            request.onupgradeneeded = () => {
                const db = request.result;
                if (!db.objectStoreNames.contains(YOLO_EXPORT_HANDLE_STORE)) {
                    db.createObjectStore(YOLO_EXPORT_HANDLE_STORE);
                }
            };
            request.onsuccess = () => resolve(request.result);
            request.onerror = () => reject(request.error || new Error("indexeddb_open_failed"));
            request.onblocked = () => reject(new Error("indexeddb_blocked"));
        });
    }

    async function readStoredYoloExportDirectoryHandle() {
        let db = null;
        try {
            db = await openYoloExportHandleDb();
            return await new Promise((resolve, reject) => {
                let settled = false;
                const finish = (fn, value) => {
                    if (settled) return;
                    settled = true;
                    try {
                        db.close();
                    } catch (error) {
                        console.debug("Failed to close export handle DB", error);
                    }
                    fn(value);
                };
                const tx = db.transaction(YOLO_EXPORT_HANDLE_STORE, "readonly");
                const request = tx.objectStore(YOLO_EXPORT_HANDLE_STORE).get(YOLO_EXPORT_DIRECTORY_HANDLE_KEY);
                request.onsuccess = () => finish(resolve, request.result || null);
                request.onerror = () => finish(reject, request.error || tx.error || new Error("indexeddb_read_failed"));
                tx.onerror = () => finish(reject, tx.error || new Error("indexeddb_read_failed"));
                tx.onabort = () => finish(reject, tx.error || new Error("indexeddb_read_aborted"));
            });
        } catch (error) {
            if (db) {
                try {
                    db.close();
                } catch (closeError) {
                    console.debug("Failed to close export handle DB", closeError);
                }
            }
            throw error;
        }
    }

    async function saveStoredYoloExportDirectoryHandle(handle) {
        if (!handle || !supportsExportHandleStorage()) {
            return false;
        }
        let db = null;
        try {
            db = await openYoloExportHandleDb();
            await new Promise((resolve, reject) => {
                let settled = false;
                const finish = (fn, value) => {
                    if (settled) return;
                    settled = true;
                    try {
                        db.close();
                    } catch (error) {
                        console.debug("Failed to close export handle DB", error);
                    }
                    fn(value);
                };
                const tx = db.transaction(YOLO_EXPORT_HANDLE_STORE, "readwrite");
                tx.objectStore(YOLO_EXPORT_HANDLE_STORE).put(handle, YOLO_EXPORT_DIRECTORY_HANDLE_KEY);
                tx.oncomplete = () => finish(resolve, true);
                tx.onerror = () => finish(reject, tx.error || new Error("indexeddb_write_failed"));
                tx.onabort = () => finish(reject, tx.error || new Error("indexeddb_write_aborted"));
            });
            return true;
        } catch (error) {
            if (db) {
                try {
                    db.close();
                } catch (closeError) {
                    console.debug("Failed to close export handle DB", closeError);
                }
            }
            console.debug("Unable to persist local export folder handle", error);
            return false;
        }
    }

    async function clearStoredYoloExportDirectoryHandle() {
        yoloExportDirectoryHandle = null;
        if (!supportsExportHandleStorage()) {
            return;
        }
        let db = null;
        try {
            db = await openYoloExportHandleDb();
            await new Promise((resolve, reject) => {
                let settled = false;
                const finish = (fn, value) => {
                    if (settled) return;
                    settled = true;
                    try {
                        db.close();
                    } catch (error) {
                        console.debug("Failed to close export handle DB", error);
                    }
                    fn(value);
                };
                const tx = db.transaction(YOLO_EXPORT_HANDLE_STORE, "readwrite");
                tx.objectStore(YOLO_EXPORT_HANDLE_STORE).delete(YOLO_EXPORT_DIRECTORY_HANDLE_KEY);
                tx.oncomplete = () => finish(resolve, true);
                tx.onerror = () => finish(reject, tx.error || new Error("indexeddb_delete_failed"));
                tx.onabort = () => finish(reject, tx.error || new Error("indexeddb_delete_aborted"));
            });
        } catch (error) {
            if (db) {
                try {
                    db.close();
                } catch (closeError) {
                    console.debug("Failed to close export handle DB", closeError);
                }
            }
            console.debug("Unable to clear local export folder handle", error);
        }
    }

    async function ensureYoloExportDirectoryPermission(handle, shouldRequest = false) {
        if (!handle) {
            return false;
        }
        const permissionOptions = { mode: "readwrite" };
        try {
            if (typeof handle.queryPermission === "function") {
                const current = await handle.queryPermission(permissionOptions);
                if (current === "granted") {
                    return true;
                }
                if (!shouldRequest) {
                    return false;
                }
            }
            if (shouldRequest && typeof handle.requestPermission === "function") {
                const next = await handle.requestPermission(permissionOptions);
                return next === "granted";
            }
            return typeof handle.queryPermission !== "function";
        } catch (error) {
            console.debug("Local export folder permission check failed", error);
            return false;
        }
    }

    function preloadYoloExportDirectoryHandle() {
        if (!supportsLocalFolderExport() || yoloExportDirectoryHandleLoadPromise) {
            return yoloExportDirectoryHandleLoadPromise;
        }
        yoloExportDirectoryHandleLoadPromise = readStoredYoloExportDirectoryHandle()
            .then((handle) => {
                if (yoloExportDirectoryHandle) {
                    yoloExportDirectoryHandleLoaded = true;
                    return yoloExportDirectoryHandle;
                }
                yoloExportDirectoryHandle = handle && handle.kind === "directory" ? handle : null;
                yoloExportDirectoryHandleLoaded = true;
                return yoloExportDirectoryHandle;
            })
            .catch((error) => {
                yoloExportDirectoryHandleLoaded = true;
                console.debug("No stored local export folder available", error);
                return null;
            });
        return yoloExportDirectoryHandleLoadPromise;
    }

    async function getYoloExportDirectoryHandle({ prompt = false } = {}) {
        if (!supportsLocalFolderExport()) {
            return null;
        }
        let handle = yoloExportDirectoryHandle;
        if (!handle && !prompt && !yoloExportDirectoryHandleLoaded) {
            handle = await preloadYoloExportDirectoryHandle();
        }
        if (handle) {
            const permitted = await ensureYoloExportDirectoryPermission(handle, prompt);
            if (permitted) {
                yoloExportDirectoryHandle = handle;
                return handle;
            }
            const clearPromise = clearStoredYoloExportDirectoryHandle();
            if (!prompt) {
                await clearPromise;
            } else {
                clearPromise.catch((error) => {
                    console.debug("Failed to clear stale local export folder handle", error);
                });
            }
        }
        if (!prompt) {
            return null;
        }
        try {
            const picked = await window.showDirectoryPicker({ mode: "readwrite" });
            yoloExportDirectoryHandle = picked;
            yoloExportDirectoryHandleLoaded = true;
            await saveStoredYoloExportDirectoryHandle(picked);
            return picked;
        } catch (error) {
            if (error?.name !== "AbortError") {
                console.warn("Unable to choose local export folder", error);
            }
            return null;
        }
    }

    async function getDirectoryFilenames(directoryHandle) {
        if (!directoryHandle) {
            return null;
        }
        try {
            const names = new Set();
            if (typeof directoryHandle.keys === "function") {
                for await (const name of directoryHandle.keys()) {
                    names.add(String(name));
                }
                return names;
            }
            if (typeof directoryHandle.entries === "function") {
                for await (const [name] of directoryHandle.entries()) {
                    names.add(String(name));
                }
                return names;
            }
        } catch (error) {
            console.debug("Unable to enumerate local export folder names", error);
        }
        return null;
    }

    function nextAvailableNumberedFilename(filename, existingNames) {
        const safeName = sanitizeFilename(filename, "download.bin");
        if (!(existingNames instanceof Set)) {
            return safeName;
        }
        let highestCounter = null;
        existingNames.forEach((name) => {
            const counter = getNumberedFilenameCounter(name, safeName);
            if (counter === null) {
                return;
            }
            if (highestCounter === null || compareCounterText(counter, highestCounter) > 0) {
                highestCounter = counter;
            }
        });
        if (highestCounter === null) {
            return safeName;
        }
        let counter = incrementCounterText(highestCounter);
        let candidate = formatNumberedFilename(safeName, counter);
        while (existingNames.has(candidate)) {
            counter = incrementCounterText(counter);
            candidate = formatNumberedFilename(safeName, counter);
        }
        return candidate;
    }

    async function resolveDirectoryExportFilename(filename, directoryHandle) {
        const existingNames = await getDirectoryFilenames(directoryHandle);
        if (existingNames) {
            const safeName = nextAvailableNumberedFilename(filename, existingNames);
            const counter = getNumberedFilenameCounter(safeName, filename);
            if (counter !== null) {
                writeYoloExportDownloadCounterAtLeast(incrementCounterText(counter));
            }
            return safeName;
        }
        return nextYoloExportDownloadFilename(filename);
    }

    async function saveBlobToDirectory(blob, filename, directoryHandle) {
        const safeName = await resolveDirectoryExportFilename(filename, directoryHandle);
        const fileHandle = await directoryHandle.getFileHandle(safeName, { create: true });
        const writable = await fileHandle.createWritable();
        try {
            await writable.write(blob);
        } finally {
            await writable.close();
        }
        return safeName;
    }

    function ensureJsZipAvailable(featureLabel = "zip operation") {
        if (typeof JSZip === "undefined") {
            throw new Error(`JSZip is not available for ${featureLabel}. Reload the page and try again.`);
        }
        return JSZip;
    }

    function formatTimestamp(seconds) {
        if (typeof seconds !== "number" || Number.isNaN(seconds)) {
            return "";
        }
        const date = new Date(seconds * 1000);
        if (Number.isNaN(date.getTime())) {
            return "";
        }
        return date.toLocaleTimeString([], { hour12: false });
    }

    function formatNumber(value, digits = 4) {
        if (value === null || value === undefined || Number.isNaN(value)) {
            return "—";
        }
        return Number(value).toFixed(digits);
    }

    function updateBalanceParamVisibility(strategy) {
        const chosen = strategy || (sam3TrainElements.balanceStrategy && sam3TrainElements.balanceStrategy.value) || "none";
        const rows = document.querySelectorAll(".sam3-balance-param");
        rows.forEach((row) => {
            const param = row.dataset ? row.dataset.param : null;
            let show = false;
            if (param === "power") {
                show = ["inv_sqrt", "clipped_inv"].includes(chosen);
            } else if (param === "clip") {
                show = chosen === "clipped_inv";
            } else if (param === "beta") {
                show = chosen === "effective_num";
            } else if (param === "gamma") {
                show = chosen === "focal";
            }
            row.style.display = show ? "" : "none";
        });
        if (sam3TrainElements.balanceDescription) {
            let desc = "";
            if (chosen === "inv_sqrt") {
                desc = "Weights = sum(1 / freq^power). Power < 1 gives mild up-weighting of rare classes (default power 0.5).";
            } else if (chosen === "clipped_inv") {
                desc = "Inverse-frequency with a cap: weight ∝ 1/freq^power, then clipped so max/min ≤ clip ratio.";
            } else if (chosen === "effective_num") {
                desc = "Effective number of samples: weight ∝ (1-β)/(1-β^n). Higher β (e.g., 0.99–0.999) boosts rare classes smoothly.";
            } else if (chosen === "focal") {
                desc = "Focal-style sampling: weight ∝ (freq / max_freq)^(-γ). Higher γ boosts rare/low-freq classes.";
            } else {
                desc = "Uniform sampling (no class rebalance).";
            }
            sam3TrainElements.balanceDescription.textContent = desc;
        }
    }

