	    async function handleSam3CascadeFile(event) {
	        if (sam3CascadeState.cascadePresetImportInFlight) {
	            return;
	        }
	        const inputEl = event?.target || sam3RecipeElements.cascadeFileInput;
	        const file = inputEl?.files?.[0];
	        if (!file) {
	            return;
	        }
	        sam3CascadeState.cascadePresetImportInFlight = true;
	        refreshSam3CascadeControls();
	        try {
	            if (!file.name.toLowerCase().endsWith(".zip")) {
	                throw new Error("zip_only");
	            }
	            const formData = new FormData();
	            formData.append("file", file);
	            const resp = await fetch(`${API_ROOT}/agent_mining/cascades/import`, {
	                method: "POST",
	                body: formData,
	            });
	            if (!resp.ok) {
	                const detail = await resp.text();
	                throw new Error(detail || `HTTP ${resp.status}`);
	            }
	            const data = await resp.json();
	            await loadSam3RecipePresets();
	            await loadSam3CascadePresets({ preserveSelection: false });
	            if (sam3RecipeElements.cascadePresetSelect && data?.id) {
	                sam3RecipeElements.cascadePresetSelect.value = data.id;
	            }
	            applyCascadePayloadToUi(data);
	            setSam3RecipeStatus(`Imported cascade ${data?.label || data?.id || ""}.`, "success");
	        } catch (err) {
	            console.error("Cascade import failed", err);
	            const msg = err?.message === "zip_only"
	                ? "Cascades must be loaded from a .zip file."
	                : (err?.message || "Cascade import failed.");
	            setSam3RecipeStatus(msg, "error");
	        } finally {
	            if (sam3RecipeElements.cascadeFileInput) sam3RecipeElements.cascadeFileInput.value = "";
	            sam3CascadeState.cascadePresetImportInFlight = false;
	            refreshSam3CascadeControls();
		        }
		    }

		    async function runSam3CascadeOnImage() {
	        if (sam3RecipeElements.status) {
	            sam3RecipeElements.status.removeAttribute("title");
	        } else if (sam3TextElements.status) {
	            sam3TextElements.status.removeAttribute("title");
	        }
	        if (sam3AgentApplyActive || sam3TextRequestActive || sam3SimilarityRequestActive || sam3TextBatchActive || sam3TextCascadeActive) {
	            setSam3RecipeStatus("SAM3 is busy; wait for the current job to finish.", "warn");
	            return;
	        }
		        if (!ensureAutomationAvailable("SAM3 cascade")) {
		            return;
		        }
		        if (!currentImage) {
		            setSam3RecipeStatus("Open an image first.", "warn");
		            return;
		        }
	        const classNames = orderedClassNames();
	        const enabledSteps = (Array.isArray(sam3CascadeState.steps) ? sam3CascadeState.steps : []).filter((s) => s && s.enabled);
	        const missingIndex = (Array.isArray(sam3CascadeState.steps) ? sam3CascadeState.steps : []).findIndex(
	            (s) => s && s.enabled && !s.recipe_id,
	        );
	        if (missingIndex >= 0) {
	            setSam3RecipeStatus(`Select a recipe for step ${missingIndex + 1} (or disable it) before applying.`, "warn");
	            return;
	        }
	        const stepsPayload = [];
	        for (const step of enabledSteps) {
	            let overrideName = null;
	            let overrideId = null;
	            if (step.override_enabled) {
	                overrideName = step.override_class_name || null;
	                if (!overrideName || !classNames.includes(overrideName)) {
	                    setSam3RecipeStatus("Select a valid output class override for each enabled step.", "warn");
	                    return;
	                }
	                overrideId = typeof classes[overrideName] !== "undefined" ? classes[overrideName] : null;
	            }
		            stepsPayload.push({
		                enabled: true,
		                recipe_id: step.recipe_id,
		                override_class_id: overrideId,
		                override_class_name: overrideName,
		                dedupe_group: step.dedupe_group || "",
		                participate_cross_class_dedupe: step.participate_cross_class_dedupe !== false,
		                clip_head_min_prob_override:
		                    typeof step.clip_head_min_prob_override === "number" && Number.isFinite(step.clip_head_min_prob_override)
		                        ? step.clip_head_min_prob_override
		                        : null,
		                clip_head_margin_override:
		                    typeof step.clip_head_margin_override === "number" && Number.isFinite(step.clip_head_margin_override)
		                        ? step.clip_head_margin_override
		                        : null,
		                extra_clip_classifier_path: step.extra_clip_classifier_path || null,
		                extra_clip_min_prob:
		                    typeof step.extra_clip_min_prob === "number" && Number.isFinite(step.extra_clip_min_prob)
		                        ? step.extra_clip_min_prob
		                        : null,
		                extra_clip_margin:
		                    typeof step.extra_clip_margin === "number" && Number.isFinite(step.extra_clip_margin)
		                        ? step.extra_clip_margin
		                        : null,
		            });
		        }
		        if (!stepsPayload.length) {
		            setSam3RecipeStatus("Add at least one enabled step with a recipe before applying.", "warn");
		            return;
		        }
		        const dedupe = getSam3CascadeDedupeConfig();
		        const cascadeTaskId = enqueueTask({
		            kind: "recipe-cascade",
		            imageName: currentImage.name,
		            detail: { steps: stepsPayload.length },
		        });
	        sam3AgentApplyActive = true;
	        refreshSam3CascadeControls();
		        setSam3RecipeStatus(`Running cascade on ${currentImage.name}…`, "info");
		        try {
		            let maskThreshold = parseFloat(sam3TextElements.maskThresholdInput?.value || "0.5");
	            if (Number.isNaN(maskThreshold)) {
	                maskThreshold = 0.5;
	            }
	            maskThreshold = Math.min(Math.max(maskThreshold, 0), 1);
	            const minSize = Math.max(0, getMinMaskArea());
	            const simplifyEps = Math.max(0, getSimplifyEpsilon());
	            let maxResults = parseInt(sam3TextElements.maxResultsInput?.value || "100", 10);
	            if (!Number.isFinite(maxResults) || maxResults <= 0) {
	                maxResults = 100;
	            }
	            maxResults = Math.min(Math.max(maxResults, 1), 5000);

	            const imageNameForRequest = currentImage.name;
	            const variantForRequest = "sam3";
	            const preloadToken = await waitForSamPreloadIfActive(imageNameForRequest, variantForRequest);
	            let imagePayload = await buildSamImagePayload({
	                variantOverride: variantForRequest,
	                preferredToken: preloadToken,
	                imageNameOverride: imageNameForRequest,
	            });
	            imagePayload.sam_variant = variantForRequest;
	            let resp = await fetch(`${API_ROOT}/agent_mining/apply_image_chain`, {
	                method: "POST",
	                headers: { "Content-Type": "application/json" },
	                body: JSON.stringify({
	                    ...imagePayload,
	                    steps: stepsPayload,
	                    dedupe,
	                    mask_threshold: maskThreshold,
	                    min_size: minSize,
	                    simplify_epsilon: simplifyEps,
	                    max_results: maxResults,
	                }),
	            });
	            if (resp.status === 428 || resp.status === 404) {
	                if (resp.status === 404 && imageNameForRequest) {
	                    forgetSamToken(imageNameForRequest, variantForRequest);
	                }
	                imagePayload = await buildSamImagePayload({
	                    forceBase64: true,
	                    variantOverride: variantForRequest,
	                    preferredToken: null,
	                    imageNameOverride: imageNameForRequest,
	                });
	                imagePayload.sam_variant = variantForRequest;
	                resp = await fetch(`${API_ROOT}/agent_mining/apply_image_chain`, {
	                    method: "POST",
	                    headers: { "Content-Type": "application/json" },
	                    body: JSON.stringify({
	                        ...imagePayload,
	                        steps: stepsPayload,
	                        dedupe,
	                        mask_threshold: maskThreshold,
	                        min_size: minSize,
	                        simplify_epsilon: simplifyEps,
	                        max_results: maxResults,
	                    }),
	                });
	            }
	            if (!resp.ok) {
	                const detail = await resp.text();
	                throw new Error(detail || resp.statusText || `HTTP ${resp.status}`);
	            }
	            const result = await resp.json();
	            if (imageNameForRequest && result?.image_token) {
	                rememberSamToken(imageNameForRequest, variantForRequest, result.image_token);
	            }
	            // Prevent applying detections to the wrong image if the user switched views.
	            if (!currentImage || currentImage.name !== imageNameForRequest) {
	                setSam3RecipeStatus(
	                    `Cascade finished for ${imageNameForRequest}, but view switched; skipped apply.`,
	                    "warn",
	                );
	                return;
		            }
		            const detections = Array.isArray(result?.detections) ? result.detections : [];
		            const warnList = Array.isArray(result?.warnings) ? result.warnings : [];
		            const warnDetails = formatAgentWarningsForUi(warnList);
		            const byClass = new Map();
		            const missingClasses = new Set();
		            detections.forEach((det) => {
		                const cls = det?.class_name || det?.qwen_label || "";
	                if (!cls) return;
	                if (!classNames.includes(cls)) {
	                    missingClasses.add(cls);
	                    return;
	                }
	                if (!byClass.has(cls)) byClass.set(cls, []);
	                byClass.get(cls).push(det);
	            });
		            let added = 0;
		            byClass.forEach((list, cls) => {
		                added += applySegAwareDetections(list, cls, "Recipe cascade");
		            });
		            const warnText = warnDetails.message ? ` Warnings: ${warnDetails.message}` : "";
		            const missingText = missingClasses.size ? ` Missing classes: ${Array.from(missingClasses).join(", ")}` : "";
		            if (sam3RecipeElements.status) {
		                sam3RecipeElements.status.title = warnDetails.codes.length ? warnDetails.codes.join("\n") : "";
		            } else if (sam3TextElements.status) {
		                sam3TextElements.status.title = warnDetails.codes.length ? warnDetails.codes.join("\n") : "";
		            }
		            if (added > 0) {
		                setSam3RecipeStatus(
		                    `Cascade applied: added ${added} ${datasetType === "seg" ? "polygons" : "boxes"}.${warnText}${missingText}`,
		                    warnList.length || missingClasses.size ? "warn" : "success",
	                );
	            } else {
	                setSam3RecipeStatus(`Cascade applied: no detections.${warnText}${missingText}`, "warn");
	            }
		        } catch (err) {
		            console.error("Cascade apply failed", err);
		            setSam3RecipeStatus(`Cascade failed: ${err.message || err}`, "error");
		        } finally {
	            sam3AgentApplyActive = false;
		            completeTask(cascadeTaskId);
		            refreshSam3CascadeControls();
		        }
		    }

    function normalizeAgentRecipePayload(data) {
        if (!data || typeof data !== "object") {
            return null;
        }
        const recipeBody =
            data.recipe && typeof data.recipe === "object" && !Array.isArray(data.recipe) ? data.recipe : data;
        const steps = Array.isArray(recipeBody.steps) ? recipeBody.steps : Array.isArray(data.steps) ? data.steps : [];
        const textPrompts = Array.isArray(recipeBody.text_prompts)
            ? recipeBody.text_prompts
            : Array.isArray(data.text_prompts)
                ? data.text_prompts
                : [];
        const positives = Array.isArray(recipeBody.positives)
            ? recipeBody.positives
            : Array.isArray(data.positives)
                ? data.positives
                : [];
        const negatives = Array.isArray(recipeBody.negatives)
            ? recipeBody.negatives
            : Array.isArray(data.negatives)
                ? data.negatives
                : [];
        const params =
            data.params && typeof data.params === "object"
                ? data.params
                : recipeBody?.params && typeof recipeBody.params === "object"
                    ? recipeBody.params
                    : {};
        const mode = recipeBody?.mode || data.mode || null;
        return {
            raw: data,
            id: data.id || null,
            label: data.label || data.id || "recipe",
            class_name: data.class_name || data?.recipe?.class_name || "",
            class_id: typeof data.class_id === "number" ? data.class_id : data?.recipe?.class_id,
            mode,
            params,
            steps: Array.isArray(steps) ? steps : [],
            text_prompts: Array.isArray(textPrompts) ? textPrompts : [],
            positives: Array.isArray(positives) ? positives : [],
            negatives: Array.isArray(negatives) ? negatives : [],
            summary: data?.recipe?.summary ?? data.summary ?? null,
            dataset_id: data.dataset_id ?? null,
            labelmap_hash: data.labelmap_hash ?? null,
            labelmap: data.labelmap ?? null,
            dataset_signature: data.dataset_signature ?? null,
            _zip: data._zip ?? null,
            _path: data._path ?? null,
        };
    }

	    async function handleSam3RecipeFile(event) {
	        const file = event.target?.files?.[0];
	        if (!file) {
	            return;
	        }
	        try {
	            if (!file.name.toLowerCase().endsWith(".zip")) {
	                throw new Error("zip_only");
	            }
	            const formData = new FormData();
	            formData.append("file", file);
	            const resp = await fetch(`${API_ROOT}/agent_mining/recipes/import`, {
	                method: "POST",
	                body: formData,
	            });
	            if (!resp.ok) throw new Error(await resp.text());
	            const data = await resp.json();
	            const recipe = normalizeAgentRecipePayload(data);
	            const hasContent =
	                recipe &&
	                ((Array.isArray(recipe.steps) && recipe.steps.length > 0) ||
	                    (Array.isArray(recipe.text_prompts) && recipe.text_prompts.length > 0) ||
	                    (Array.isArray(recipe.positives) && recipe.positives.length > 0));
	            if (!hasContent) {
	                throw new Error("no_steps");
	            }
	            const classNames = orderedClassNames();
	            const lowerToName = new Map(classNames.map((n) => [n.toLowerCase(), n]));
	            const targetName = (recipe.class_name || "").trim();
	            if (targetName) {
	                const found = lowerToName.get(targetName.toLowerCase());
	                if (found) {
	                    recipe.class_name = found;
	                } else {
	                    setSam3RecipeStatus(
	                        `Imported recipe ${recipe.label}. Note: class ${targetName} not in label map; use per-step output override.`,
	                        "warn",
	                    );
	                }
	            }
	            sam3RecipeState.recipe = recipe;
	            if (recipe.id) {
	                addSam3CascadeStep({ recipeId: recipe.id });
	            }
	            await loadSam3RecipePresets();
	            refreshSam3CascadeControls();
	            const parts = [];
	            if (recipe.mode) parts.push(recipe.mode);
	            const promptCount = Array.isArray(recipe.text_prompts) ? recipe.text_prompts.length : 0;
	            const posCount = Array.isArray(recipe.positives) ? recipe.positives.length : 0;
	            const stepCount = Array.isArray(recipe.steps) ? recipe.steps.length : 0;
	            parts.push(`${promptCount} prompts`);
	            parts.push(`${posCount} crops`);
	            if (stepCount) parts.push(`${stepCount} steps`);
	            const stepSuffix = recipe.id ? " Added as a cascade step." : "";
	            setSam3RecipeStatus(`Imported recipe ${recipe.label} (${parts.join(", ")}).${stepSuffix}`, "success");
	        } catch (err) {
	            console.error("Failed to load recipe", err);
	            const msg = err?.message === "zip_only" ? "Recipes must be loaded from a .zip file." : "Invalid recipe file (use zip).";
	            setSam3RecipeStatus(msg, "error");
	            sam3RecipeState.recipe = null;
	        } finally {
	            if (sam3RecipeElements.fileInput) sam3RecipeElements.fileInput.value = "";
	        }
	    }

    function refreshSam3SimilarityVisibility() {
        const row = sam3TextElements.similarityRow;
        const btn = sam3TextElements.similarityButton;
        const show = samVariant === "sam3" && samMode;
        if (row) {
            row.style.display = show ? "" : "none";
        }
        if (btn) {
            btn.style.display = show ? "" : "none";
        }
        if (sam3TextElements.similarityThresholdInput) {
            sam3TextElements.similarityThresholdInput.disabled = !show;
        }
    }

    function updateSam3TextButtons() {
        refreshSam3SimilarityVisibility();
        const locked = isGpuHeavyLockActive();
        const lockMessage = "GPU-heavy labeling is locked while prepass/calibration or training is active.";
        const busy = sam3TextRequestActive
            || sam3SimilarityRequestActive
            || sam3TextBatchActive
            || sam3TextCascadeActive
            || sam3AgentApplyActive;
        const blocked = busy || locked;
        setButtonDisabled(sam3TextElements.runButton, blocked);
        setButtonDisabled(sam3TextElements.similarityButton, blocked);
        setButtonDisabled(sam3TextElements.cascadeToggleButton, blocked);
        setButtonDisabled(sam3TextElements.cascadeAddButton, blocked);
        setButtonDisabled(sam3TextElements.cascadeRunButton, blocked);
        setButtonDisabled(sam3TextElements.cascadeClearButton, blocked);
        setButtonDisabled(sam3TextElements.cascadeDedupeToggle, blocked);
        setButtonDisabled(
            sam3TextElements.cascadeDedupeIouInput,
            blocked || !sam3TextElements.cascadeDedupeToggle?.checked,
        );
        // Disable repeated stop clicks once cancellation is already requested.
        setButtonDisabled(sam3TextElements.cascadeStopButton, !sam3TextCascadeActive || sam3TextCascadeCancel);
        setButtonDisabled(sam3TextElements.batchRunButton, blocked);
        setButtonDisabled(sam3TextElements.batchModeSingleRadio, blocked);
        setButtonDisabled(sam3TextElements.batchModeCascadeRadio, blocked);
        setButtonDisabled(sam3TextElements.batchCountInput, blocked);
        setButtonDisabled(sam3TextElements.batchIncludeCurrentToggle, blocked);
        // Disable repeated stop clicks once cancellation is already requested.
        setButtonDisabled(sam3TextElements.batchStopButton, !sam3TextBatchActive || sam3TextBatchCancel);
        if (sam3TextElements.runButton) {
            sam3TextElements.runButton.textContent = busy ? "Running…" : (locked ? "Run SAM3 (GPU locked)" : "Run SAM3");
        }
        if (sam3TextElements.similarityButton) {
            sam3TextElements.similarityButton.textContent = busy
                ? "Running…"
                : (locked ? "SAM3 similarity (GPU locked)" : "SAM3 similarity prompt (use selected box(es))");
        }
        if (sam3TextElements.batchRunButton) {
            const batchModeLabel = getSam3TextBatchMode() === "cascade" ? "cascade batch" : "single-prompt batch";
            sam3TextElements.batchRunButton.textContent = sam3TextBatchActive
                ? "Running batch…"
                : (locked ? `Run ${batchModeLabel} (GPU locked)` : `Run ${batchModeLabel}`);
        }
        if (sam3TextElements.cascadeRunButton) {
            sam3TextElements.cascadeRunButton.textContent = sam3TextCascadeActive ? "Running cascade…" : (locked ? "Run cascade (GPU locked)" : "Run cascade");
        }
        const statusText = sam3TextElements.status?.textContent || "";
        if (!busy && !locked && (!statusText || statusText === lockMessage)) {
            setSam3TextStatus("Enter a prompt to run SAM3 text segmentation.", "info");
        } else if (locked && !busy) {
            setSam3TextStatus(lockMessage, "warn");
        }
    }

    function orderedClassNames() {
        const entries = Object.entries(classes || {});
        if (!entries.length) {
            return [];
        }
        return entries
            .sort((a, b) => a[1] - b[1])
            .map(([name]) => name);
    }

    function getAnnotationDiversityApi() {
        if (typeof window === "undefined") {
            return null;
        }
        const api = window.TatorAnnotationDiversity;
        return api && typeof api.computeImageDiversityMetric === "function" ? api : null;
    }

    function getAnnotationDiversityClassNames() {
        const ordered = orderedClassNames();
        if (ordered.length) {
            return ordered;
        }
        if (Array.isArray(loadedClassList) && loadedClassList.length) {
            return loadedClassList.map((name) => String(name || "").trim()).filter(Boolean);
        }
        const manifestLabelmap = annotationSourceState.manifest?.labelmap;
        if (Array.isArray(manifestLabelmap)) {
            return manifestLabelmap.map((name) => String(name || "").trim()).filter(Boolean);
        }
        return [];
    }

    function getAnnotationDiversityRawLabelLines(imageKey) {
        if (!imageKey || !(annotationSourceState.rawLabelLinesByKey instanceof Map)) {
            return [];
        }
        const lines = annotationSourceState.rawLabelLinesByKey.get(imageKey);
        return Array.isArray(lines) ? lines : [];
    }

    function getAnnotationDiversityBucketCounts(api, imageKey) {
        if (!api || !imageKey || !bboxes || !Object.prototype.hasOwnProperty.call(bboxes, imageKey)) {
            return {};
        }
        return api.countBoxesByClassFromBuckets(bboxes[imageKey] || {});
    }

    function shouldUseAnnotationDiversityBuckets(api, imageKey, bucketCounts, rawLines) {
        if (!imageKey || !Object.prototype.hasOwnProperty.call(bboxes || {}, imageKey)) {
            return false;
        }
        if (api.sumCounts(bucketCounts) > 0) {
            return true;
        }
        if (isAnnotationDatasetModeActive() && annotationSourceState.hydratedKeys.has(imageKey)) {
            return true;
        }
        if (!rawLines.length) {
            return true;
        }
        return false;
    }

    function countAnnotationImageForDiversity(api, imageKey, classNames) {
        if (!api || !imageKey) {
            return {};
        }
        const rawLines = getAnnotationDiversityRawLabelLines(imageKey);
        const bucketCounts = getAnnotationDiversityBucketCounts(api, imageKey);
        if (shouldUseAnnotationDiversityBuckets(api, imageKey, bucketCounts, rawLines)) {
            return bucketCounts;
        }
        return api.countBoxesByClassFromYoloLines(rawLines, classNames);
    }

    function buildAnnotationDiversityCounts(api, classNames) {
        const currentName = currentImage?.name || "";
        const currentCounts = countAnnotationImageForDiversity(api, currentName, classNames);
        const datasetCounts = {};
        const imageKeys = new Set(Object.keys(images || {}));
        if (annotationSourceState.rawLabelLinesByKey instanceof Map) {
            annotationSourceState.rawLabelLinesByKey.forEach((_, key) => {
                if (key) {
                    imageKeys.add(key);
                }
            });
        }
        if (currentName) {
            imageKeys.add(currentName);
        }
        imageKeys.forEach((imageKey) => {
            const counts = imageKey === currentName
                ? currentCounts
                : countAnnotationImageForDiversity(api, imageKey, classNames);
            api.mergeCounts(datasetCounts, counts);
        });
        return { currentCounts, datasetCounts };
    }

    function isAnnotationDiversityMetricEnabled() {
        return Boolean(annotationDiversityToggle && annotationDiversityToggle.checked);
    }

    function setAnnotationDiversityMetricHidden(hidden) {
        if (!annotationDiversityMetricEl) {
            annotationDiversityMetricEl = document.getElementById("annotationDiversityMetric");
        }
        if (!annotationDiversityMetricEl) {
            return;
        }
        annotationDiversityMetricEl.hidden = Boolean(hidden);
        if (hidden) {
            annotationDiversityMetricEl.textContent = "";
            annotationDiversityMetricEl.removeAttribute("title");
            annotationDiversityMetricEl.classList.remove("is-low", "is-mid", "is-high");
        }
    }

    function getAnnotationDiversityTitle(metric) {
        if (!metric || metric.status === "empty") {
            return "Annotation class-balance score. Add or load bboxes to score this image. This does not use pixels, embeddings, Class Split, Data Ingestion, or a reference profile.";
        }
        const detail = (metric.classDetails || [])
            .slice(0, 6)
            .map((entry) => `${entry.className}: ${entry.currentCount} here, ${entry.existingCount} elsewhere`)
            .join(" | ");
        return `Annotation class-balance score. Higher means this image contains classes that are rare or missing elsewhere in the currently loaded labels. It is not visual diversity and does not use a reference profile. ${detail}`;
    }

    function renderAnnotationDiversityMetric(metric, message) {
        if (!annotationDiversityMetricEl) {
            annotationDiversityMetricEl = document.getElementById("annotationDiversityMetric");
        }
        if (!annotationDiversityMetricEl) {
            return;
        }
        annotationDiversityMetricEl.hidden = false;
        annotationDiversityMetricEl.textContent = message || "";
        annotationDiversityMetricEl.title = getAnnotationDiversityTitle(metric);
        annotationDiversityMetricEl.classList.remove("is-low", "is-mid", "is-high");
        const score = Number(metric?.score);
        if (!Number.isFinite(score)) {
            return;
        }
        annotationDiversityMetricEl.classList.add(score >= 75 ? "is-high" : (score >= 40 ? "is-mid" : "is-low"));
    }

    function refreshAnnotationDiversityMetric() {
        if (annotationDiversityRefreshTimer) {
            window.clearTimeout(annotationDiversityRefreshTimer);
            annotationDiversityRefreshTimer = 0;
        }
        if (!annotationDiversityToggle) {
            annotationDiversityToggle = document.getElementById("showAnnotationDiversityMetric");
        }
        if (!annotationDiversityMetricEl) {
            annotationDiversityMetricEl = document.getElementById("annotationDiversityMetric");
        }
        if (!isAnnotationDiversityMetricEnabled()) {
            setAnnotationDiversityMetricHidden(true);
            return;
        }
        if (!currentImage) {
            renderAnnotationDiversityMetric(null, "Image value pending - load an image.");
            return;
        }
        const api = getAnnotationDiversityApi();
        if (!api) {
            renderAnnotationDiversityMetric(null, "Image value unavailable.");
            return;
        }
        const classNames = getAnnotationDiversityClassNames();
        const { currentCounts, datasetCounts } = buildAnnotationDiversityCounts(api, classNames);
        const metric = api.computeImageDiversityMetric({
            currentCounts,
            datasetCounts,
            classNames,
        });
        renderAnnotationDiversityMetric(metric, api.formatImageDiversityMetric(metric));
    }

    function scheduleAnnotationDiversityMetricRefresh() {
        if (!isAnnotationDiversityMetricEnabled()) {
            setAnnotationDiversityMetricHidden(true);
            return;
        }
        if (annotationDiversityRefreshTimer) {
            return;
        }
        annotationDiversityRefreshTimer = window.setTimeout(() => {
            annotationDiversityRefreshTimer = 0;
            refreshAnnotationDiversityMetric();
        }, 40);
    }

    function initAnnotationDiversityControls() {
        annotationDiversityToggle = document.getElementById("showAnnotationDiversityMetric");
        annotationDiversityMetricEl = document.getElementById("annotationDiversityMetric");
        if (!annotationDiversityToggle || !annotationDiversityMetricEl) {
            return;
        }
        try {
            annotationDiversityToggle.checked = window.localStorage?.getItem(ANNOTATION_DIVERSITY_METRIC_STORAGE_KEY) === "1";
        } catch (error) {
            console.debug("Unable to restore annotation diversity metric preference", error);
        }
        annotationDiversityToggle.addEventListener("change", () => {
            try {
                window.localStorage?.setItem(
                    ANNOTATION_DIVERSITY_METRIC_STORAGE_KEY,
                    annotationDiversityToggle.checked ? "1" : "0",
                );
            } catch (error) {
                console.debug("Unable to store annotation diversity metric preference", error);
            }
            refreshAnnotationDiversityMetric();
        });
        refreshAnnotationDiversityMetric();
    }

    function updateQwenClassOptions({ resetOverride = false, preserveSelection = false } = {}) {
        if (!qwenElements.classSelect) {
            return;
        }
        const classNames = orderedClassNames();
        qwenElements.classSelect.innerHTML = "";
        if (!classNames.length) {
            const placeholder = document.createElement("option");
            placeholder.textContent = "Load classes first";
            placeholder.value = "";
            qwenElements.classSelect.appendChild(placeholder);
            qwenElements.classSelect.disabled = true;
            qwenClassOverride = false;
            return;
        }
        qwenElements.classSelect.disabled = false;
        const previousValue = preserveSelection ? qwenElements.classSelect.value : null;
        classNames.forEach((name) => {
            const option = document.createElement("option");
            option.value = name;
            option.textContent = name;
            qwenElements.classSelect.appendChild(option);
        });
        let targetValue = null;
        if (preserveSelection && previousValue && classNames.includes(previousValue)) {
            targetValue = previousValue;
        } else if (currentClass && classNames.includes(currentClass)) {
            targetValue = currentClass;
        } else {
            targetValue = classNames[0];
        }
        qwenElements.classSelect.value = targetValue;
        if (resetOverride) {
            qwenClassOverride = false;
        }
    }

    function syncQwenClassToCurrent() {
        if (!qwenElements.classSelect || qwenClassOverride) {
            return;
        }
        if (currentClass && qwenElements.classSelect.value !== currentClass) {
            let hasClass = false;
            for (const option of qwenElements.classSelect.options || []) {
                if (option.value === currentClass) {
                    hasClass = true;
                    break;
                }
            }
            if (hasClass) {
                qwenElements.classSelect.value = currentClass;
            }
        }
    }

    function getQwenTargetClass() {
        if (qwenElements.classSelect && qwenElements.classSelect.value) {
            return qwenElements.classSelect.value;
        }
        return currentClass;
    }

    function updateSam3ClassOptions({ resetOverride = false, preserveSelection = false } = {}) {
        if (!sam3TextElements.classSelect) {
            return;
        }
        const classNames = orderedClassNames();
        sam3TextElements.classSelect.innerHTML = "";
        if (!classNames.length) {
            const placeholder = document.createElement("option");
            placeholder.textContent = "Load classes first";
            placeholder.value = "";
            sam3TextElements.classSelect.appendChild(placeholder);
            sam3TextElements.classSelect.disabled = true;
            return;
        }
        sam3TextElements.classSelect.disabled = false;
        const previousValue = preserveSelection ? sam3TextElements.classSelect.value : null;
        classNames.forEach((name) => {
            const option = document.createElement("option");
            option.value = name;
            option.textContent = name;
            sam3TextElements.classSelect.appendChild(option);
        });
        let targetValue = null;
        if (preserveSelection && previousValue && classNames.includes(previousValue)) {
            targetValue = previousValue;
        } else if (currentClass && classNames.includes(currentClass)) {
            targetValue = currentClass;
        } else {
            targetValue = classNames[0];
        }
        sam3TextElements.classSelect.value = targetValue;
        if (resetOverride && classNames.length) {
            sam3TextElements.classSelect.value = targetValue;
        }
        refreshSam3TextCascadeClassOptions({ preserveSelection });
        renderSam3CascadeSteps();
        updateSam3TextWorkflow();
    }

    function isSam3TextPanelOpen() {
        return !!sam3TextElements.panel?.open;
    }

    function scheduleSam3TextWorkflowRefresh({ delay = 180 } = {}) {
        if (!isSam3TextPanelOpen() || !sam3TextElements.workflow) {
            return;
        }
        if (sam3TextWorkflowRefreshTimer) {
            window.clearTimeout(sam3TextWorkflowRefreshTimer);
        }
        sam3TextWorkflowRefreshTimer = window.setTimeout(() => {
            sam3TextWorkflowRefreshTimer = null;
            updateSam3TextWorkflow();
        }, Math.max(0, Number(delay) || 0));
    }

    function syncSam3ClassToCurrent({ refreshWorkflow = false } = {}) {
        if (!sam3TextElements.classSelect || !currentClass || sam3TextElements.classSelect.value === currentClass) {
            return;
        }
        let hasClass = false;
        for (const option of sam3TextElements.classSelect.options || []) {
            if (option.value === currentClass) {
                hasClass = true;
                break;
            }
        }
        if (!hasClass) {
            return;
        }
        sam3TextElements.classSelect.value = currentClass;
        if (refreshWorkflow) {
            updateSam3TextWorkflow();
        } else {
            scheduleSam3TextWorkflowRefresh();
        }
    }

    function setSam3LabelmapStatus(message, variant = "info") {
        if (!sam3TextElements.labelmapStatus) {
            return;
        }
        sam3TextElements.labelmapStatus.textContent = message || "";
        sam3TextElements.labelmapStatus.className = `training-help ${variant || ""}`;
    }

    function confirmSam3LabelmapExtension() {
        const classifierPath = String(activeElements.classifierPath?.value || "").trim();
        const classifierCount = Array.isArray(activeState.classifiers) ? activeState.classifiers.length : 0;
        const classifierNote = classifierPath || classifierCount
            ? "A trained class predictor appears to be available. "
            : "";
        return window.confirm(
            `${classifierNote}Adding a class changes the labelmap. Any trained auto-class classifier was trained on the old class list and must be retrained before auto-class can be trusted with this new labelmap. Continue?`
        );
    }

    function addSam3LabelmapClassFromUi() {
        const className = String(sam3TextElements.newClassInput?.value || "").trim();
        if (!className) {
            setSam3LabelmapStatus("Enter a class name first.", "warn");
            sam3TextElements.newClassInput?.focus();
            return;
        }
        if (/[\r\n]/.test(className)) {
            setSam3LabelmapStatus("Class names must be one line.", "warn");
            return;
        }
        if (isAnnotationDatasetModeActive() && isAnnotationMutationBlocked()) {
            setSam3LabelmapStatus(annotationMutationBlockedMessage("Extending labelmap"), "warn");
            return;
        }
        const existing = orderedClassNames();
        const duplicate = existing.find((name) => name.toLowerCase() === className.toLowerCase());
        if (duplicate) {
            if (sam3TextElements.classSelect) {
                sam3TextElements.classSelect.value = duplicate;
            }
            setSam3LabelmapStatus(`Class "${duplicate}" already exists.`, "warn");
            return;
        }
        if (!confirmSam3LabelmapExtension()) {
            setSam3LabelmapStatus("Class add cancelled.", "info");
            return;
        }
        const classList = document.getElementById("classList");
        if (!classList) {
            setSam3LabelmapStatus("Class list control is unavailable.", "error");
            return;
        }
        if (!Array.isArray(loadedClassList) || loadedClassList.length !== existing.length) {
            loadedClassList = existing.slice();
        }
        const nextIndex = loadedClassList.length;
        classes[className] = nextIndex;
        loadedClassList.push(className);
        const option = document.createElement("option");
        option.value = String(nextIndex);
        option.textContent = className;
        Array.from(classList.options || []).forEach((opt) => {
            opt.selected = false;
        });
        option.selected = true;
        classList.appendChild(option);
        classList.selectedIndex = nextIndex;
        classListIndex = nextIndex;
        currentClass = className;
        setCurrentClass();
        updateQwenClassOptions({ preserveSelection: true });
        updateSam3ClassOptions({ preserveSelection: true });
        if (sam3TextElements.classSelect) {
            sam3TextElements.classSelect.value = className;
        }
        if (qwenElements.classSelect && !qwenClassOverride) {
            qwenElements.classSelect.value = className;
        }
        if (sam3TextElements.newClassInput) {
            sam3TextElements.newClassInput.value = "";
        }
        if (annotationSourceState.manifest && Array.isArray(annotationSourceState.manifest.labelmap)) {
            annotationSourceState.manifest.labelmap = orderedClassNames();
        }
        refreshCaptionGlossaryForCurrentContext({ force: true, silent: true }).catch((error) => {
            console.warn("Failed to refresh caption glossary after labelmap extension", error);
        });
        setSam3LabelmapStatus(`Added "${className}". Save the new labelmap before retraining auto-class.`, "success");
        enqueueTaskNotice(`Labelmap class added: ${className}`, { durationMs: 3500 });
    }

    async function saveSam3LabelmapFromUi() {
        const labelmap = orderedClassNames();
        if (!labelmap.length) {
            setSam3LabelmapStatus("Load or create classes before saving.", "warn");
            return;
        }
        if (isAnnotationDatasetModeActive()) {
            if (isAnnotationMutationBlocked()) {
                setSam3LabelmapStatus(annotationMutationBlockedMessage("Saving labelmap"), "warn");
                return;
            }
            const base = getAnnotationBasePath();
            if (!base) {
                throw new Error("annotation API unavailable");
            }
            setSam3LabelmapStatus("Saving labelmap to dataset...", "info");
            const resp = await fetch(`${base}/meta`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(annotationSessionPayload({ labelmap })),
            });
            const detail = await resp.text();
            if (!resp.ok) {
                throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            }
            if (annotationSourceState.manifest) {
                annotationSourceState.manifest.labelmap = labelmap.slice();
            }
            setSam3LabelmapStatus(`Saved ${labelmap.length} classes to the dataset labelmap. Retrain auto-class before using the new class.`, "success");
            enqueueTaskNotice("Saved updated labelmap to dataset.", { durationMs: 4000 });
            return;
        }
        const blob = new Blob([`${labelmap.join("\n")}\n`], { type: "text/plain;charset=utf-8" });
        saveBlobToDisk(blob, "labelmap.txt");
        setSam3LabelmapStatus(`Downloaded labelmap.txt with ${labelmap.length} classes.`, "success");
    }

    function updateQwenRunButton() {
        if (!qwenElements.runButton) {
            return;
        }
        qwenElements.runButton.disabled = isGpuHeavyLockActive() || !qwenAvailable || qwenRequestActive;
        qwenElements.runButton.textContent = qwenRequestActive ? "Running…" : "Run detection engine";
    }

    function qwenCaptionArchiveMutationActive() {
        return !!(qwenCaptionActive || qwenCaptionBatchActive || qwenCaptionBatchBackendJobId);
    }

    function captionArchiveMutationBusyMessage(actionLabel) {
        if (!qwenCaptionArchiveMutationActive()) {
            return "";
        }
        return `Wait for the active caption or instruction job to finish before ${actionLabel}; the caption archive is changing.`;
    }

    function guardQwenCaptionArchiveIdle(actionLabel) {
        const message = captionArchiveMutationBusyMessage(actionLabel);
        if (!message) {
            return true;
        }
        setQwenCaptionStatus("Caption archive busy");
        setQwenCaptionBackendJobStatus(message);
        setSamStatus(message, { variant: "warn", duration: 5000 });
        updateQwenCaptionButton();
        return false;
    }

    function deferCaptionArchiveReadWhileBusy(actionLabel) {
        const message = captionArchiveMutationBusyMessage(actionLabel || "loading caption archive");
        if (!message) {
            return false;
        }
        setQwenCaptionStatus("Caption archive busy");
        setQwenCaptionBackendJobStatus(message);
        updateQwenCaptionButton();
        return true;
    }

    function captionOutputEditingBlocked() {
        const annotationReadOnly = isAnnotationDatasetModeActive() && isAnnotationMutationBlocked();
        return qwenCaptionArchiveMutationActive() || annotationReadOnly;
    }

    function rememberCaptionOutputStableText(text = null) {
        if (text === null && qwenElements.captionOutput) {
            qwenCaptionOutputStableText = String(qwenElements.captionOutput.value || "");
            return qwenCaptionOutputStableText;
        }
        qwenCaptionOutputStableText = String(text || "");
        return qwenCaptionOutputStableText;
    }

    function setCaptionOutputValue(text, options = {}) {
        if (!qwenElements.captionOutput) {
            return false;
        }
        const value = String(text || "");
        qwenElements.captionOutput.value = value;
        rememberCaptionOutputStableText(value);
        if (Object.prototype.hasOwnProperty.call(options, "generatedFor")) {
            qwenElements.captionOutput.dataset.generatedFor = String(options.generatedFor || "");
        }
        return true;
    }

    function restoreCaptionOutputStableText() {
        if (!qwenElements.captionOutput) {
            return;
        }
        qwenElements.captionOutput.value = qwenCaptionOutputStableText || "";
    }

    function updateCaptionOutputEditControl() {
        if (qwenElements.captionOutput) {
            qwenElements.captionOutput.disabled = captionOutputEditingBlocked();
        }
    }

