    async function downloadCaptionInstructionBundle() {
        const datasetId = getCaptionDatasetId();
        if (!datasetId) {
            setCaptionExportHealth("Select a caption dataset before exporting the training bundle.", "warn");
            return;
        }
        const busyMessage = captionInstructionArtifactBusyMessage("exporting the training bundle");
        if (busyMessage) {
            setCaptionExportHealth(busyMessage, "warn");
            setSamStatus(busyMessage, { variant: "warn", duration: 5000 });
            return;
        }
        const settings = getCaptionInstructionDatasetSettings(true);
        const query = captionInstructionExportQuery(settings, {
            requireReadyInstructionExport: settings.require_ready_instruction_export === true,
        });
        const resp = await fetch(`${API_ROOT}/datasets/${encodeURIComponent(datasetId)}/captions/instruction_bundle?${query}`);
        if (!resp.ok) {
            const detail = await resp.text();
            throw new Error(formatCaptionInstructionBundleApiError(parseApiError(detail, `HTTP ${resp.status}`)));
        }
        const blob = await resp.blob();
        if (!blob || !Number.isFinite(Number(blob.size)) || Number(blob.size) <= 0) {
            throw new Error("training bundle response was empty");
        }
        saveBlobToDisk(blob, "caption_instruction_training_bundle.zip");
        const readyText = settings.require_ready_instruction_export
            ? "Ready report gate passed."
            : "Ready report gate was disabled for this diagnostic bundle.";
        setCaptionExportHealth(`Training bundle exported with copied images, effective labels, instruction artifacts, and checksum manifest. ${readyText}`, "pass");
        setSamStatus("Training bundle download started.", { variant: "success", duration: 3500 });
    }

    async function downloadCaptionInstructionJsonl() {
        const datasetId = getCaptionDatasetId();
        if (!datasetId) {
            setCaptionExportHealth("Select a caption dataset before exporting instruction rows.", "warn");
            return;
        }
        const busyMessage = captionInstructionArtifactBusyMessage("exporting instruction trainer JSONL");
        if (busyMessage) {
            setCaptionExportHealth(busyMessage, "warn");
            setSamStatus(busyMessage, { variant: "warn", duration: 5000 });
            return;
        }
        const settings = getCaptionInstructionDatasetSettings(true);
        const payload = await loadCaptionExportPayload(datasetId, settings, {
            requireReadyInstructionExport: settings.require_ready_instruction_export === true,
        });
        const rows = payload?.instruction_training_rows;
        const validation = validateCaptionInstructionTrainingRows(rows);
        if (!validation.ok) {
            const message = describeCaptionInstructionValidation(validation);
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 5000 });
            return;
        }
        const rowList = Array.isArray(rows) ? rows : [];
        if (!rowList.length) {
            setCaptionExportHealth("No instruction rows are ready for export yet.", "warn");
            setSamStatus("No instruction rows are ready for export.", { variant: "warn", duration: 3000 });
            return;
        }
        const consistency = validateCaptionInstructionArtifactConsistency(payload, "training", validation);
        if (!consistency.ok) {
            const firstErrors = (consistency.errors || []).slice(0, 3).join("; ");
            const suffix = (consistency.errors || []).length > 3 ? `; +${consistency.errors.length - 3} more` : "";
            const message = `Instruction JSONL export blocked: ${firstErrors || "artifact consistency failed"}${suffix}.`;
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 5000 });
            return;
        }
        const readinessSummary = captionInstructionReadinessSummary(payload?.instruction_report);
        if (readinessSummary.blocked) {
            const message = `Instruction JSONL export blocked: ${readinessSummary.message}`;
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 5000 });
            return;
        }
        if (settings.require_ready_instruction_export && readinessSummary.status !== "ready") {
            const message = `Instruction JSONL export blocked: ${readinessSummary.message} Disable Require ready report only for deliberate review-pending diagnostics.`;
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 6000 });
            return;
        }
        setCaptionExportHealth(`${describeCaptionInstructionValidation(validation)} ${readinessSummary.message}`, readinessSummary.severity);
        const lines = rowList.map((row) => JSON.stringify(row));
        const blob = new Blob([lines.join("\n")], { type: "application/jsonl" });
        saveBlobToDisk(blob, "caption_instruction_training.jsonl");
    }

