    function parseCaptionInstructionReviewRowsText(text) {
        const raw = String(text || "").trim();
        if (!raw) {
            throw new Error("Review file is empty.");
        }
        const lines = raw.split(/\r?\n/).filter((line) => line.trim());
        if (raw.startsWith("[") || raw.startsWith("{")) {
            let parsed = null;
            let parsedJson = false;
            try {
                parsed = JSON.parse(raw);
                parsedJson = true;
            } catch (error) {
                if (raw.startsWith("[") || lines.length === 1) {
                    throw error;
                }
            }
            if (parsedJson) {
                if (Array.isArray(parsed)) {
                    return parsed;
                }
                if (parsed && typeof parsed === "object") {
                    const rowContainerFields = ["rows", "review_rows", "instruction_review_rows"];
                    for (const field of rowContainerFields) {
                        if (!Object.prototype.hasOwnProperty.call(parsed, field)) {
                            continue;
                        }
                        const rows = parsed[field];
                        if (!Array.isArray(rows)) {
                            throw new Error(`Review JSON ${field} must be an array.`);
                        }
                        return rows;
                    }
                    if (String(parsed.format || "").trim() === "tator_caption_instruction_review_rows_v1") {
                        return [parsed];
                    }
                }
                throw new Error("Review JSON must be an array, a review row, or an object with rows.");
            }
        }
        const rows = [];
        lines.forEach((line, index) => {
            const trimmed = line.trim();
            try {
                rows.push(JSON.parse(trimmed));
            } catch (error) {
                throw new Error(`Review JSONL parse failed at line ${index + 1}: ${error.message || error}`);
            }
        });
        return rows;
    }

    function captionInstructionReviewDatasetMismatches(rows, datasetId) {
        const expected = String(datasetId || "").trim();
        if (!expected) {
            return [];
        }
        const mismatches = new Set();
        (Array.isArray(rows) ? rows : []).forEach((row) => {
            const rowDatasetId = String(row?.dataset_id || "").trim();
            if (rowDatasetId && rowDatasetId !== expected) {
                mismatches.add(rowDatasetId);
            }
        });
        return Array.from(mismatches).sort();
    }

    function formatCaptionInstructionReviewImportApiError(message) {
        const raw = String(message || "").trim();
        if (!raw) {
            return "Instruction review import failed.";
        }
        const rowMatch = raw.match(/(?:^|:)row_(\d+)/);
        const rowText = rowMatch ? ` at row ${rowMatch[1]}` : "";
        const duplicateMatch = raw.match(/^review_rows_(conflicting_duplicate_target|duplicate_target|conflicting_duplicate_resolved_target|duplicate_resolved_target):row_(\d+):row_(\d+)$/);
        if (duplicateMatch) {
            const conflict = duplicateMatch[1].startsWith("conflicting_");
            const resolved = duplicateMatch[1].includes("_resolved_");
            const targetText = resolved
                ? "the same saved caption or generated-QA record"
                : "the same actionable review target";
            return `Instruction review import blocked: ${conflict ? "conflicting duplicate" : "duplicate"} decisions at rows ${duplicateMatch[2]} and ${duplicateMatch[3]} target ${targetText}. Keep one reviewed row per caption0 or generated-QA target.`;
        }
        const datasetMatch = raw.match(/^review_rows_dataset_id_mismatch:row_(\d+):(.+)!=(.+)$/);
        if (datasetMatch) {
            return `Instruction review import blocked at row ${datasetMatch[1]}: this review file is for dataset ${datasetMatch[2]}, not ${datasetMatch[3]}. Select the matching dataset or export a fresh review JSONL.`;
        }
        const fieldTooLongMatch = raw.match(/^review_rows_field_too_long:row_(\d+):([^:]+):(\d+)$/);
        if (fieldTooLongMatch) {
            return `Instruction review import blocked at row ${fieldTooLongMatch[1]}: ${fieldTooLongMatch[2]} exceeds ${fieldTooLongMatch[3]} characters. Shorten that field or export a fresh review JSONL.`;
        }
        const invalidTextFieldMatch = raw.match(/^review_rows_([^:]+)_invalid:row_(\d+)$/);
        const textReviewFields = new Set([
            "dataset_id",
            "image_path",
            "image_name",
            "image",
            "original_image_path",
            "bundle_image_path",
            "bundle_image_sha256",
            "qa_id",
            "row_origin",
            "split",
            "question",
            "candidate_answer",
            "training_answer",
            "validation_status",
            "review_decision",
            "review_notes",
        ]);
        if (invalidTextFieldMatch && textReviewFields.has(invalidTextFieldMatch[1])) {
            if (invalidTextFieldMatch[1] === "bundle_image_sha256") {
                return `Instruction review import blocked at row ${invalidTextFieldMatch[2]}: bundle_image_sha256 must be a 64-character SHA-256 digest from the exported bundle.`;
            }
            return `Instruction review import blocked at row ${invalidTextFieldMatch[2]}: ${invalidTextFieldMatch[1]} must be a text field from the exported review JSONL.`;
        }
        const unsupportedMatch = raw.match(/^review_rows_unsupported_row_origin:row_(\d+):(.+)$/);
        if (unsupportedMatch) {
            return `Instruction review import blocked at row ${unsupportedMatch[1]}: ${unsupportedMatch[2]} is not a persisted review row type. Only caption0 and generated-QA decisions can be imported.`;
        }
        const unsupportedDecisionMatch = raw.match(/^review_rows_unsupported_review_decision:row_(\d+):(.+)$/);
        if (unsupportedDecisionMatch) {
            return `Instruction review import blocked at row ${unsupportedDecisionMatch[1]}: ${unsupportedDecisionMatch[2]} is not a supported review decision. Use accepted, rejected, needs-revision, or leave the decision blank.`;
        }
        if (raw === "review_rows_list_required") {
            return "Instruction review import blocked: the file must contain a JSON array, JSONL rows, or an object with review rows.";
        }
        if (raw === "review_rows_too_many") {
            return "Instruction review import blocked: the file contains too many review rows. Split the review packet or export a smaller review JSONL.";
        }
        if (raw === "review_rows_no_actionable_decisions") {
            return "Instruction review import blocked: no accepted, rejected, or needs-revision caption0 or generated-QA decisions were found. Fill review_decision for persisted language rows before importing.";
        }
        const messageByCode = {
            review_rows_row_not_object: "the row is not a JSON object",
            review_rows_invalid_format: "the row is not an instruction review row from the current export format",
            review_rows_dataset_id_missing: "the row is missing the embedded dataset id needed to prove the review file belongs to the selected dataset",
            review_rows_qa_id_missing: "the row is missing the stable QA id needed to match the saved caption or generated-QA record",
            review_rows_missing_image_path: "the row is missing image identity, so it cannot be matched safely",
            review_rows_row_origin_missing: "the row is missing the review row origin needed to identify whether it targets caption0 or generated-QA",
            review_rows_question_missing: "the row is missing the reviewed question text",
            review_rows_candidate_answer_missing: "the row is missing the candidate answer text",
            review_rows_validation_status_missing: "the row is missing validation status from the exported review packet",
            review_rows_selected_for_training_invalid: "selected_for_training must be a boolean true or false value from the exported review packet",
            review_rows_requires_manual_review_invalid: "requires_manual_review must be a boolean true or false value from the exported review packet",
            review_rows_training_answer_missing: "the row is selected for training but is missing the training answer text",
            review_rows_source_summary_missing: "the row is missing source summary from the exported review packet",
            review_rows_rejection_reasons_invalid: "rejection_reasons must be an array from the exported review packet",
            review_rows_review_decision_missing: "the row is missing the review_decision column",
            review_rows_review_notes_missing: "the row is missing the review_notes column",
            review_rows_original_image_path_missing_for_bundle: "the row came from a copied bundle image but is missing the original image path needed to match the selected dataset safely",
            review_rows_bundle_image_not_found: "the reviewed bundle image cannot be resolved in the selected dataset through its original image path",
            review_rows_bundle_image_hash_failed: "the selected dataset image could not be hashed to verify it matches the reviewed bundle image",
            review_rows_bundle_image_sha256_mismatch: "the selected dataset image bytes no longer match the image bytes in the reviewed bundle",
            review_rows_generated_qa_text_missing: "the generated-QA row is missing the reviewed question or answer text needed to verify it still matches the saved record",
            review_rows_generated_qa_not_found: "the generated-QA row no longer matches a saved generated-QA record for that image, question, and answer",
            review_rows_generated_qa_training_answer_stale: "the generated-QA training answer no longer matches the current selected training answer; export a fresh review JSONL before importing decisions",
            review_rows_generated_qa_ambiguous: "the generated-QA row matches multiple saved records",
            review_rows_caption0_ambiguous: "the caption0 row matches multiple saved caption records",
            review_rows_caption0_not_found: "the caption0 row no longer matches the saved caption text for that image",
            review_rows_caption0_training_answer_stale: "the caption0 training answer no longer matches the current selected training answer; export a fresh review JSONL before importing decisions",
            review_rows_caption0_answer_missing: "the caption0 row is missing the reviewed caption text",
            review_rows_caption0_creation_not_allowed: "the caption0 row would create a new caption record but its synthetic id does not match the selected dataset, resolved image key, and current text-label caption",
            review_rows_caption0_image_not_found: "the caption0 row image could not be resolved in the selected dataset",
        };
        const code = raw.split(":")[0];
        if (Object.prototype.hasOwnProperty.call(messageByCode, code)) {
            const action = [
                "review_rows_generated_qa_not_found",
                "review_rows_caption0_not_found",
                "review_rows_bundle_image_not_found",
                "review_rows_bundle_image_sha256_mismatch",
            ].includes(code)
                ? " Export a fresh review JSONL after the latest generation/review changes, then reapply the decision."
                : "";
            return `Instruction review import blocked${rowText}: ${messageByCode[code]}.${action}`;
        }
        return `Instruction review import failed: ${raw}`;
    }

    async function importCaptionInstructionReviewFile(file) {
        const datasetId = getCaptionDatasetId();
        if (!datasetId) {
            setCaptionExportHealth("Select a caption dataset before importing reviewed instruction rows.", "warn");
            return;
        }
        const busyMessage = captionInstructionArtifactBusyMessage("importing reviewed instruction rows");
        if (busyMessage) {
            setCaptionExportHealth(busyMessage, "warn");
            setSamStatus(busyMessage, { variant: "warn", duration: 5000 });
            return;
        }
        const fileSize = Number(file?.size);
        if (Number.isFinite(fileSize) && fileSize > CAPTION_INSTRUCTION_REVIEW_IMPORT_MAX_BYTES) {
            const message = `Instruction review import blocked: selected file is ${formatBytesLabel(fileSize)}, above the ${formatBytesLabel(CAPTION_INSTRUCTION_REVIEW_IMPORT_MAX_BYTES)} browser import safety limit. Split the review packet or import a smaller review JSONL.`;
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 7000 });
            return;
        }
        const text = await file.text();
        const rows = parseCaptionInstructionReviewRowsText(text);
        const validation = validateCaptionInstructionReviewRows(rows);
        if (!validation.ok) {
            const message = describeCaptionInstructionReviewValidation(validation).replace("export blocked", "import blocked");
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 6000 });
            return;
        }
        const datasetMismatches = captionInstructionReviewDatasetMismatches(rows, datasetId);
        if (datasetMismatches.length) {
            const message = `Instruction review import blocked: file is for dataset ${datasetMismatches.slice(0, 3).join(", ")}, not ${datasetId}.`;
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 6000 });
            return;
        }
        const reviewedRows = rows.filter((row) => {
            const decision = normalizeCaptionInstructionReviewDecision(row?.review_decision);
            return ["accepted", "rejected", "needs_revision"].includes(decision);
        }).map((row) => {
            const decision = normalizeCaptionInstructionReviewDecision(row?.review_decision);
            return { ...row, review_decision: decision };
        });
        if (!reviewedRows.length) {
            const message = "Instruction review import found no accepted, rejected, or needs-revision decisions to apply.";
            setCaptionExportHealth(message, "warn");
            setSamStatus(message, { variant: "warn", duration: 4000 });
            return;
        }
        const persistableRows = reviewedRows.filter((row) => ["caption0", "generated_qa"].includes(String(row?.row_origin || "").trim()));
        if (!persistableRows.length) {
            const message = "Instruction review import found decisions only for deterministic rows; those rows are rebuilt from source labels and are not persisted.";
            setCaptionExportHealth(message, "warn");
            setSamStatus(message, { variant: "warn", duration: 5000 });
            return;
        }
        const resp = await fetch(`${API_ROOT}/datasets/${encodeURIComponent(datasetId)}/captions/instruction_review`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(captionMutationPayload({ rows: persistableRows })),
        });
        if (!resp.ok) {
            const detail = await resp.text();
            throw new Error(formatCaptionInstructionReviewImportApiError(parseApiError(detail, `HTTP ${resp.status}`)));
        }
        const result = await resp.json();
        const applied = Number.parseInt(result?.applied_count || "0", 10) || 0;
        const skipped = Number.parseInt(result?.skipped_count || "0", 10) || 0;
        const created = Number.parseInt(result?.created_caption_review_record_count || "0", 10) || 0;
        const severity = applied > 0 ? (skipped > 0 ? "warn" : "pass") : "warn";
        const message = `Instruction review import applied ${applied} decision${applied === 1 ? "" : "s"}`
            + `${created ? `, created ${created} caption review record${created === 1 ? "" : "s"}` : ""}`
            + `${skipped ? `, skipped ${skipped} row${skipped === 1 ? "" : "s"}` : ""}.`;
        setCaptionExportHealth(message, severity);
        setSamStatus(message, { variant: severity === "pass" ? "success" : "warn", duration: 5000 });
        if (currentImage?.name) {
            await loadCaptionForCurrentImage().catch((error) => {
                console.debug("Caption refresh after review import failed", error);
            });
        }
    }

    async function downloadCaptionInstructionReport() {
        const datasetId = getCaptionDatasetId();
        if (!datasetId) {
            setCaptionExportHealth("Select a caption dataset before exporting the instruction report.", "warn");
            return;
        }
        const busyMessage = captionInstructionArtifactBusyMessage("exporting the instruction report");
        if (busyMessage) {
            setCaptionExportHealth(busyMessage, "warn");
            setSamStatus(busyMessage, { variant: "warn", duration: 5000 });
            return;
        }
        const payload = await loadCaptionExportPayload(datasetId, getCaptionInstructionDatasetSettings(true));
        const report = payload?.instruction_report;
        if (!report || typeof report !== "object") {
            setCaptionExportHealth("No instruction report is ready for export yet.", "warn");
            setSamStatus("No instruction report is ready for export.", { variant: "warn", duration: 3000 });
            return;
        }
        const validation = validateCaptionInstructionReport(report);
        if (!validation.ok) {
            const firstErrors = (validation.errors || []).slice(0, 3).join("; ");
            const suffix = (validation.errors || []).length > 3 ? `; +${validation.errors.length - 3} more` : "";
            const message = `Instruction report export blocked: ${firstErrors || "invalid report"}${suffix}.`;
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 5000 });
            return;
        }
        const rowValidation = validateCaptionInstructionTrainingRows(payload?.instruction_training_rows);
        if (!rowValidation.ok) {
            const firstErrors = (rowValidation.errors || []).slice(0, 3).join("; ");
            const suffix = (rowValidation.errors || []).length > 3 ? `; +${rowValidation.errors.length - 3} more` : "";
            const message = `Instruction report export blocked: ${firstErrors || "invalid instruction rows"}${suffix}.`;
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 5000 });
            return;
        }
        const archiveValidation = validateCaptionInstructionArchiveRows(payload?.instruction_archive_rows);
        if (!archiveValidation.ok) {
            const firstErrors = (archiveValidation.errors || []).slice(0, 3).join("; ");
            const suffix = (archiveValidation.errors || []).length > 3 ? `; +${archiveValidation.errors.length - 3} more` : "";
            const message = `Instruction report export blocked: ${firstErrors || "invalid instruction archive rows"}${suffix}.`;
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 5000 });
            return;
        }
        const reviewValidation = validateCaptionInstructionReviewRows(payload?.instruction_review_rows);
        if (!reviewValidation.ok) {
            const firstErrors = (reviewValidation.errors || []).slice(0, 3).join("; ");
            const suffix = (reviewValidation.errors || []).length > 3 ? `; +${reviewValidation.errors.length - 3} more` : "";
            const message = `Instruction report export blocked: ${firstErrors || "invalid instruction review rows"}${suffix}.`;
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 5000 });
            return;
        }
        const consistencyChecks = [
            validateCaptionInstructionArtifactConsistency(payload, "training", rowValidation),
            validateCaptionInstructionArtifactConsistency(payload, "archive", archiveValidation),
            validateCaptionInstructionArtifactConsistency(payload, "review", reviewValidation),
        ];
        const consistency = consistencyChecks.find((check) => !check.ok);
        if (consistency) {
            const firstErrors = (consistency.errors || []).slice(0, 3).join("; ");
            const suffix = (consistency.errors || []).length > 3 ? `; +${consistency.errors.length - 3} more` : "";
            const message = `Instruction report export blocked: ${firstErrors || "artifact consistency failed"}${suffix}.`;
            setCaptionExportHealth(message, "fail");
            setSamStatus(message, { variant: "error", duration: 5000 });
            return;
        }
        const readinessSummary = captionInstructionReadinessSummary(report);
        setCaptionExportHealth(`Instruction report validated: corpus-quality metrics and readiness are present. ${readinessSummary.message}`, readinessSummary.severity);
        const blob = new Blob([JSON.stringify(report, null, 2)], { type: "application/json" });
        saveBlobToDisk(blob, "caption_instruction_report.json");
    }

    function buildSam3TextSnapshot() {
        const prompt = (sam3TextElements.promptInput?.value || "").trim();
        let threshold = parseFloat(sam3TextElements.thresholdInput?.value || "0.5");
        if (Number.isNaN(threshold)) {
            threshold = 0.5;
        }
        threshold = Math.min(Math.max(threshold, 0), 1);
        let maskThreshold = parseFloat(sam3TextElements.maskThresholdInput?.value || "0.5");
        if (Number.isNaN(maskThreshold)) {
            maskThreshold = 0.5;
        }
        maskThreshold = Math.min(Math.max(maskThreshold, 0), 1);
        let minSize = parseInt(sam3TextElements.minSizeInput?.value || "0", 10);
        if (Number.isNaN(minSize) || minSize < 0) {
            minSize = 0;
        }
        let maxResults = parseInt(sam3TextElements.maxResultsInput?.value || "20", 10);
        if (Number.isNaN(maxResults)) {
            maxResults = 20;
        }
        maxResults = Math.min(Math.max(maxResults, 1), 100);
        let maxPoints = parseInt(sam3TextElements.maxPointsInput?.value || "500", 10);
        if (!Number.isFinite(maxPoints) || maxPoints <= 3) {
            maxPoints = 500;
        }
        maxPoints = Math.min(Math.max(maxPoints, 10), 5000);
        let simplifyEps = parseFloat(sam3TextElements.epsilonInput?.value || "1.0");
        if (Number.isNaN(simplifyEps) || simplifyEps < 0) {
            simplifyEps = 1.0;
        }
        const targetClass = getSam3TargetClass();
        const windowSettings = readSam3TextWindowSettings();
        return {
            prompt,
            threshold,
            maskThreshold,
            minSize,
            maxResults,
            maxPoints,
            simplifyEps,
            targetClass,
            ...windowSettings,
        };
    }

    async function runSam3TextPromptSnapshot(snapshot, { requestImageName = null, statusLabel = "SAM3 text" } = {}) {
        const {
            prompt,
            threshold,
            maskThreshold,
            minSize,
            maxResults,
            maxPoints,
            simplifyEps,
            targetClass,
            windowed,
            windowSize,
            windowOverlap,
            mergeIou,
        } = snapshot;
        const targetImageName = requestImageName || currentImage?.name || null;
        if (!ensureAutomationAvailable("SAM3 text")) {
            return { added: 0, detections: 0, warnings: ["automation_locked"] };
        }
        stopSam3TextWindowOverlay({ clear: true });
        const plannedWindows = computeSam3TextWindowPlan(snapshot);
        let overlayState = { windows: plannedWindows };
        updateSam3TextWorkflow({ stepId: "prepare", snapshot });
        renderSam3TextLiveToast({
            title: statusLabel,
            meta: snapshot.windowed
                ? `Preparing ${plannedWindows.length} SAM3 window${plannedWindows.length === 1 ? "" : "s"}`
                : "Preparing full-image SAM3 text prompt",
            body: buildSam3TextToastBody(snapshot, null, {
                windows: plannedWindows,
                phase: "running",
            }),
        });
        if (snapshot.windowed) {
            overlayState = startSam3TextWindowOverlay(snapshot, { labelPrefix: statusLabel });
        } else {
            updateSam3TextWorkflow({ stepId: "full_scan", snapshot });
            renderSam3TextLiveToast({
                title: statusLabel,
                meta: "Full-image SAM3 text prompt",
                body: buildSam3TextToastBody(snapshot, null, {
                    windows: [],
                    phase: "running",
                }),
            });
        }
        let result = null;
        try {
            result = await invokeSam3TextPrompt({
                text_prompt: prompt,
                threshold,
                mask_threshold: maskThreshold,
                min_size: minSize,
                simplify_epsilon: simplifyEps,
                max_results: maxResults,
                windowed: !!windowed,
                window_size: windowSize,
                window_overlap: windowOverlap,
                merge_iou: mergeIou,
            });
        } catch (error) {
            stopSam3TextWindowOverlay({ clear: true });
            updateSam3TextWorkflow({ stepId: "complete", snapshot });
            renderSam3TextLiveToast({
                title: `${statusLabel} failed`,
                meta: "SAM3 text prompt error",
                body: `${buildSam3TextToastBody(snapshot, null, {
                    windows: overlayState.windows || plannedWindows,
                    phase: "running",
                })}\n\nError:\n${error.message || error}`,
                error: true,
                done: true,
            });
            throw error;
        }
        stopSam3TextWindowOverlay({ clear: false });
        updateSam3TextWorkflow({ stepId: windowed ? "fuse" : "apply", snapshot });
        if (targetImageName && result?.image_token) {
            rememberSamToken(targetImageName, samVariant, result.image_token);
        }
        // Prevent cross-image writes when user navigates during async SAM calls.
        if (targetImageName && (!currentImage || currentImage.name !== targetImageName)) {
            stopSam3TextWindowOverlay({ clear: true });
            updateSam3TextWorkflow({ stepId: "complete", snapshot });
            renderSam3TextLiveToast({
                title: `${statusLabel} skipped`,
                meta: "Image changed before SAM3 results could be applied",
                body: `${buildSam3TextToastBody(snapshot, result, {
                    windows: overlayState.windows || plannedWindows,
                    added: 0,
                    phase: "done",
                })}\n\nSkipped: active image changed before results were applied.`,
                done: true,
            });
            return {
                added: 0,
                detections: Array.isArray(result?.detections) ? result.detections.length : 0,
                warnings: [...(Array.isArray(result?.warnings) ? result.warnings : []), "stale_target_image"],
            };
        }
        if (Array.isArray(result?.masks) && Array.isArray(result?.detections)) {
            result.detections.forEach((det, idx) => {
                if (det && !det.mask && result.masks[idx]) {
                    det.mask = result.masks[idx];
                }
            });
        }
        const applied = applySegAwareDetections(result?.detections || [], targetClass, "SAM3", {
            simplifyEpsilon: simplifyEps,
            maxPointsPerPolygon: maxPoints,
            minArea: minSize,
        });
        if (applied) {
            const shapeLabel = datasetType === "seg" ? "polygon" : "bbox";
            setSam3TextStatus(`SAM3 added ${applied} ${shapeLabel}${applied === 1 ? "" : "es"} to ${targetClass}.`, "success");
            enqueueTaskNotice(`SAM3 text: added ${applied} ${shapeLabel}${applied === 1 ? "" : "es"} to ${targetClass}.`, { durationMs: 4500 });
        } else {
            const warning = Array.isArray(result?.warnings) && result.warnings.includes("no_results")
                ? "SAM3 found no matches for that prompt."
                : "SAM3 returned no usable detections.";
            setSam3TextStatus(warning, "warn");
            enqueueTaskNotice("SAM3 text: no detections added.", { durationMs: 3500 });
        }
        stopSam3TextWindowOverlay({ clear: true });
        updateSam3TextWorkflow({ stepId: "complete", snapshot });
        renderSam3TextLiveToast({
            title: applied ? `${statusLabel} complete` : `${statusLabel}: no usable detections`,
            meta: [
                windowed ? "Windowed SAM3" : "Full-image SAM3",
                `${Array.isArray(result?.detections) ? result.detections.length : 0} returned`,
                `${applied} applied`,
            ].join(" • "),
            body: buildSam3TextToastBody(snapshot, result, {
                windows: overlayState.windows || plannedWindows,
                added: applied,
                phase: "done",
            }),
            done: true,
        });
        return { added: applied, detections: Array.isArray(result?.detections) ? result.detections.length : 0, warnings: result?.warnings || [] };
    }

    function getSam3TextCascadeStepElements() {
        if (!sam3TextElements.cascadeSteps) {
            return [];
        }
        return Array.from(sam3TextElements.cascadeSteps.querySelectorAll(".sam3-text-cascade__step"));
    }

    function refreshSam3TextCascadeStepTitles() {
        const steps = getSam3TextCascadeStepElements();
        steps.forEach((step, idx) => {
            const title = step.querySelector(".sam3-text-cascade__step-title");
            if (title) {
                title.textContent = sam3TextCascadeEnabled ? `Step ${idx + 2}` : `Step ${idx + 1}`;
            }
        });
    }

    function refreshSam3TextCascadeClassOptions({ preserveSelection = true } = {}) {
        const classNames = orderedClassNames();
        const steps = getSam3TextCascadeStepElements();
        steps.forEach((step) => {
            const select = step.querySelector(".sam3-text-cascade__class");
            if (!select) {
                return;
            }
            const previous = preserveSelection ? select.value : null;
            select.innerHTML = "";
            if (!classNames.length) {
                const placeholder = document.createElement("option");
                placeholder.textContent = "Load classes first";
                placeholder.value = "";
                select.appendChild(placeholder);
                select.disabled = true;
                return;
            }
            classNames.forEach((name) => {
                const option = document.createElement("option");
                option.value = name;
                option.textContent = name;
                select.appendChild(option);
            });
            let targetValue = null;
            if (preserveSelection && previous && classNames.includes(previous)) {
                targetValue = previous;
            } else if (currentClass && classNames.includes(currentClass)) {
                targetValue = currentClass;
            } else {
                targetValue = classNames[0];
            }
            select.value = targetValue;
        });
    }

    function updateSam3TextCascadeStepWindowControls(step) {
        if (!step) {
            return;
        }
        const enabled = !!step.querySelector(".sam3-text-cascade__windowed")?.checked;
        [
            step.querySelector(".sam3-text-cascade__window-size"),
            step.querySelector(".sam3-text-cascade__window-overlap"),
        ].forEach((control) => {
            if (!control) {
                return;
            }
            control.disabled = !enabled;
            control.closest(".sam3-text-field")?.classList.toggle("is-disabled", !enabled);
        });
    }

    function createSam3TextCascadeStep({ useCurrentDefaults = false } = {}) {
        const promptDefault = useCurrentDefaults ? (sam3TextElements.promptInput?.value || "").trim() : "";
        const thresholdDefault = parseFloat(sam3TextElements.thresholdInput?.value || "0.5");
        const maskDefault = parseFloat(sam3TextElements.maskThresholdInput?.value || "0.5");
        const minSizeDefault = parseInt(sam3TextElements.minSizeInput?.value || "0", 10);
        const maxResultsDefault = parseInt(sam3TextElements.maxResultsInput?.value || "20", 10);
        const maxPointsDefault = parseInt(sam3TextElements.maxPointsInput?.value || "500", 10);
        const epsilonDefault = parseFloat(sam3TextElements.epsilonInput?.value || "1.0");
        const windowSettings = readSam3TextWindowSettings();
        const step = document.createElement("div");
        step.className = "sam3-text-cascade__step";
        step.innerHTML = `
            <div class="sam3-text-cascade__step-header">
                <span class="sam3-text-cascade__step-title">Step</span>
                <button type="button" class="training-button secondary sam3-text-cascade__remove" title="Remove this SAM3 text cascade step.">Remove</button>
            </div>
            <div class="sam3-text-field sam3-text-field--wide">
                <label>Prompt</label>
                <input type="text" class="sam3-text-cascade__prompt" placeholder="e.g., red helmet" />
            </div>
            <div class="sam3-text-cascade__step-grid">
                <div class="sam3-text-field">
                    <label>Assign class</label>
                    <select class="sam3-text-cascade__class"></select>
                </div>
                <div class="sam3-text-field">
                    <label>Score threshold</label>
                    <input type="number" class="sam3-text-cascade__threshold" step="0.05" min="0" max="1" />
                </div>
                <div class="sam3-text-field">
                    <label>Mask threshold</label>
                    <input type="number" class="sam3-text-cascade__mask" step="0.05" min="0" max="1" />
                </div>
                <div class="sam3-text-field">
                    <label>Max results</label>
                    <input type="number" class="sam3-text-cascade__max-results" min="1" max="100" />
                </div>
                <div class="sam3-text-field">
                    <label>Min size (px²)</label>
                    <input type="number" class="sam3-text-cascade__min-size" min="0" />
                </div>
                <div class="sam3-text-field">
                    <label>Max points/polygon</label>
                    <input type="number" class="sam3-text-cascade__max-points" min="10" max="5000" />
                </div>
                <div class="sam3-text-field">
                    <label>Simplify epsilon (px)</label>
                    <input type="number" class="sam3-text-cascade__epsilon" min="0" step="0.1" />
                </div>
                <div class="sam3-text-field sam3-text-field--checkbox">
                    <label>Windowed mode</label>
                    <input type="checkbox" class="sam3-text-cascade__windowed" />
                </div>
                <div class="sam3-text-field">
                    <label>Window size (px)</label>
                    <input type="number" class="sam3-text-cascade__window-size" min="64" step="32" />
                </div>
                <div class="sam3-text-field">
                    <label>Window overlap</label>
                    <input type="number" class="sam3-text-cascade__window-overlap" min="0" max="0.9" step="0.05" />
                </div>
            </div>
        `;
        const promptInput = step.querySelector(".sam3-text-cascade__prompt");
        const thresholdInput = step.querySelector(".sam3-text-cascade__threshold");
        const maskInput = step.querySelector(".sam3-text-cascade__mask");
        const maxResultsInput = step.querySelector(".sam3-text-cascade__max-results");
        const minSizeInput = step.querySelector(".sam3-text-cascade__min-size");
        const maxPointsInput = step.querySelector(".sam3-text-cascade__max-points");
        const epsilonInput = step.querySelector(".sam3-text-cascade__epsilon");
        const windowedInput = step.querySelector(".sam3-text-cascade__windowed");
        const windowSizeInput = step.querySelector(".sam3-text-cascade__window-size");
        const windowOverlapInput = step.querySelector(".sam3-text-cascade__window-overlap");
        if (promptInput) promptInput.value = promptDefault;
        if (thresholdInput) thresholdInput.value = Number.isFinite(thresholdDefault) ? thresholdDefault : 0.5;
        if (maskInput) maskInput.value = Number.isFinite(maskDefault) ? maskDefault : 0.5;
        if (maxResultsInput) maxResultsInput.value = Number.isFinite(maxResultsDefault) ? maxResultsDefault : 20;
        if (minSizeInput) minSizeInput.value = Number.isFinite(minSizeDefault) ? minSizeDefault : 0;
        if (maxPointsInput) maxPointsInput.value = Number.isFinite(maxPointsDefault) ? maxPointsDefault : 500;
        if (epsilonInput) epsilonInput.value = Number.isFinite(epsilonDefault) ? epsilonDefault : 1.0;
        if (windowedInput) windowedInput.checked = !!windowSettings.windowed;
        if (windowSizeInput) windowSizeInput.value = Number.isFinite(windowSettings.windowSize) ? windowSettings.windowSize : 672;
        if (windowOverlapInput) windowOverlapInput.value = Number.isFinite(windowSettings.windowOverlap) ? windowSettings.windowOverlap : 0.1;
        const removeButton = step.querySelector(".sam3-text-cascade__remove");
        step.querySelectorAll("input, select").forEach((el) => {
            const refreshStep = () => {
                updateSam3TextCascadeStepWindowControls(step);
                updateSam3TextWorkflow();
            };
            el.addEventListener("input", refreshStep);
            el.addEventListener("change", refreshStep);
        });
        updateSam3TextCascadeStepWindowControls(step);
        if (removeButton) {
            removeButton.addEventListener("click", () => {
                step.remove();
                refreshSam3TextCascadeStepTitles();
                updateSam3TextWorkflow();
            });
        }
        return step;
    }

    function addSam3TextCascadeStep(options = {}) {
        if (!sam3TextElements.cascadeSteps) {
            return;
        }
        const step = createSam3TextCascadeStep(options);
        sam3TextElements.cascadeSteps.appendChild(step);
        refreshSam3TextCascadeClassOptions();
        refreshSam3TextCascadeStepTitles();
        updateSam3TextWorkflow();
    }

    function setSam3TextCascadeEnabled(enabled) {
        sam3TextCascadeEnabled = !!enabled;
        setSam3TextBatchMode(sam3TextCascadeEnabled ? "cascade" : "single");
        if (sam3TextElements.cascadePanel) {
            sam3TextElements.cascadePanel.hidden = !sam3TextCascadeEnabled;
        }
        if (sam3TextElements.cascadeToggleButton) {
            sam3TextElements.cascadeToggleButton.textContent = sam3TextCascadeEnabled ? "Exit cascade" : "Start cascade";
        }
        if (sam3TextCascadeEnabled && sam3TextElements.cascadeSteps && !sam3TextElements.cascadeSteps.children.length) {
            addSam3TextCascadeStep({ useCurrentDefaults: true });
        }
        refreshSam3TextCascadeStepTitles();
        updateSam3TextWorkflow();
        updateSam3TextButtons();
    }

    function toggleSam3TextCascade() {
        setSam3TextCascadeEnabled(!sam3TextCascadeEnabled);
    }

    function clearSam3TextCascade() {
        if (!sam3TextElements.cascadeSteps) {
            return;
        }
        sam3TextElements.cascadeSteps.innerHTML = "";
        if (sam3TextCascadeEnabled) {
            addSam3TextCascadeStep({ useCurrentDefaults: true });
        }
        updateSam3TextWorkflow();
    }

    function readSam3TextCascadeStep(step) {
        const prompt = (step.querySelector(".sam3-text-cascade__prompt")?.value || "").trim();
        let threshold = parseFloat(step.querySelector(".sam3-text-cascade__threshold")?.value || "0.5");
        if (Number.isNaN(threshold)) threshold = 0.5;
        threshold = Math.min(Math.max(threshold, 0), 1);
        let maskThreshold = parseFloat(step.querySelector(".sam3-text-cascade__mask")?.value || "0.5");
        if (Number.isNaN(maskThreshold)) maskThreshold = 0.5;
        maskThreshold = Math.min(Math.max(maskThreshold, 0), 1);
        let maxResults = parseInt(step.querySelector(".sam3-text-cascade__max-results")?.value || "20", 10);
        if (Number.isNaN(maxResults)) maxResults = 20;
        maxResults = Math.min(Math.max(maxResults, 1), 100);
        let minSize = parseInt(step.querySelector(".sam3-text-cascade__min-size")?.value || "0", 10);
        if (Number.isNaN(minSize) || minSize < 0) minSize = 0;
        let maxPoints = parseInt(step.querySelector(".sam3-text-cascade__max-points")?.value || "500", 10);
        if (!Number.isFinite(maxPoints) || maxPoints <= 3) maxPoints = 500;
        maxPoints = Math.min(Math.max(maxPoints, 10), 5000);
        let simplifyEps = parseFloat(step.querySelector(".sam3-text-cascade__epsilon")?.value || "1.0");
        if (Number.isNaN(simplifyEps) || simplifyEps < 0) simplifyEps = 1.0;
        const targetClass = step.querySelector(".sam3-text-cascade__class")?.value || "";
        const windowed = !!step.querySelector(".sam3-text-cascade__windowed")?.checked;
        let windowSize = parseInt(step.querySelector(".sam3-text-cascade__window-size")?.value || "672", 10);
        if (Number.isNaN(windowSize) || windowSize <= 0) windowSize = 672;
        let windowOverlap = parseFloat(step.querySelector(".sam3-text-cascade__window-overlap")?.value || "0.1");
        if (!Number.isFinite(windowOverlap)) windowOverlap = 0.1;
        windowOverlap = Math.min(Math.max(windowOverlap, 0), 0.9);
        return {
            prompt,
            threshold,
            maskThreshold,
            minSize,
            maxResults,
            maxPoints,
            simplifyEps,
            targetClass,
            windowed,
            windowSize,
            windowOverlap,
            mergeIou: 0.5,
        };
    }

    function collectSam3TextCascadeSnapshots({ includeBase = false } = {}) {
        const steps = getSam3TextCascadeStepElements();
        const snapshots = [];
        let skipped = 0;
        if (includeBase) {
            const baseSnapshot = buildSam3TextSnapshot();
            if (baseSnapshot.prompt && baseSnapshot.targetClass) {
                snapshots.push(baseSnapshot);
            } else {
                skipped += 1;
            }
        }
        steps.forEach((step) => {
            const snapshot = readSam3TextCascadeStep(step);
            if (!snapshot.prompt || !snapshot.targetClass) {
                skipped += 1;
                return;
            }
            snapshots.push(snapshot);
        });
        return { snapshots, skipped, total: steps.length + (includeBase ? 1 : 0) };
    }

    async function runSam3TextCascadeSnapshots(
        snapshots,
        { shouldCancel = null, statusPrefix = "Cascade step", targetImageName = null } = {},
    ) {
        let totalAdded = 0;
        for (let idx = 0; idx < snapshots.length; idx += 1) {
            if (typeof shouldCancel === "function" && shouldCancel()) {
                break;
            }
            setSam3TextStatus(`${statusPrefix} ${idx + 1}/${snapshots.length}…`, "info");
            const result = await runSam3TextPromptSnapshot(snapshots[idx], {
                requestImageName: targetImageName,
                statusLabel: `${statusPrefix} ${idx + 1}/${snapshots.length}`,
            });
            totalAdded += Number(result?.added || 0);
        }
        return totalAdded;
    }

    async function runSam3TextCascade() {
        if (sam3TextCascadeActive || sam3TextBatchActive || sam3TextRequestActive || sam3SimilarityRequestActive) {
            setSam3TextStatus("SAM3 is busy; wait for the current job to finish.", "warn");
            return;
        }
        if (!ensureAutomationAvailable("SAM3 cascade")) {
            return;
        }
        if (!currentImage || !currentImage.name) {
            setSam3TextStatus("Load an image before running a cascade.", "warn");
            return;
        }
        const { snapshots, skipped, total } = collectSam3TextCascadeSnapshots({ includeBase: true });
        if (!snapshots.length) {
            setSam3TextStatus("Add at least one valid cascade step first.", "warn");
            return;
        }
        if (skipped) {
            setSam3TextStatus(`Skipping ${skipped} empty step${skipped === 1 ? "" : "s"} in cascade.`, "warn");
        }
        sam3TextCascadeActive = true;
        sam3TextCascadeCancel = false;
        updateSam3TextButtons();
        const taskId = enqueueTask({ kind: "sam3-cascade", imageName: currentImage.name, detail: { count: total } });
        let totalAdded = 0;
        let dedupeRemoved = 0;
        let cascadeFailed = false;
        const cascadeStartCreatedAt = bboxCreationCounter;
        const cascadeDedupe = getSam3TextCascadePostDedupeConfig();
        const assignedClasses = getSam3TextCascadeAssignedClasses(snapshots);
        try {
            totalAdded = await runSam3TextCascadeSnapshots(snapshots, {
                shouldCancel: () => sam3TextCascadeCancel,
                statusPrefix: "Cascade step",
                targetImageName: currentImage.name,
            });
            if (!sam3TextCascadeCancel && cascadeDedupe.enabled) {
                const dedupeResult = dedupeSam3AssignedClassesForCurrentImage(assignedClasses, {
                    iou: cascadeDedupe.iou,
                    minCreatedAtExclusive: cascadeStartCreatedAt,
                });
                dedupeRemoved = Number(dedupeResult.removed || 0);
            }
        } catch (error) {
            cascadeFailed = true;
            console.error("SAM3 cascade failed", error);
            setSam3TextStatus(`Cascade error: ${error.message || error}`, "error");
        } finally {
            sam3TextCascadeActive = false;
            updateSam3TextButtons();
            completeTask(taskId);
            let doneMessage = `Cascade complete: added ${totalAdded} ${datasetType === "seg" ? "polygons" : "boxes"}${dedupeRemoved ? `, deduped ${dedupeRemoved}` : ""}.`;
            if (sam3TextCascadeCancel) {
                doneMessage = "Cascade cancelled.";
            } else if (cascadeFailed) {
                doneMessage = `Cascade failed after adding ${totalAdded} ${datasetType === "seg" ? "polygons" : "boxes"}.`;
            }
            setSam3TextStatus(doneMessage, sam3TextCascadeCancel || cascadeFailed ? "warn" : "success");
            enqueueTaskNotice(doneMessage, { durationMs: 4500 });
        }
    }

    function stopSam3TextCascade() {
        if (!sam3TextCascadeActive) {
            return;
        }
        if (sam3TextCascadeCancel) {
            return;
        }
        sam3TextCascadeCancel = true;
        updateSam3TextButtons();
        setSam3TextStatus("Stopping cascade after current step…", "warn");
    }

    function getSam3TextCascadeBatchConfig() {
        const imageList = document.getElementById("imageList");
        if (!imageList || !imageList.options.length) {
            return null;
        }
        const includeCurrent = !!sam3TextElements.batchIncludeCurrentToggle?.checked;
        const countRaw = parseInt(sam3TextElements.batchCountInput?.value || "1", 10);
        const count = Number.isFinite(countRaw) ? Math.max(1, Math.min(999, countRaw)) : 1;
        const startIndex = Math.max(0, imageList.selectedIndex || 0);
        const names = [];
        for (let i = 0; i < count; i += 1) {
            const idx = includeCurrent ? startIndex + i : startIndex + i + 1;
            if (idx >= imageList.options.length) {
                break;
            }
            const name = getOptionImageName(imageList.options[idx]);
            if (name) {
                names.push(name);
            }
        }
        return names.length ? { names, includeCurrent } : null;
    }

    async function waitForCurrentImageReady(imageName, timeoutMs = 15000) {
        const start = Date.now();
        while (Date.now() - start < timeoutMs) {
            if (currentImage && currentImage.name === imageName && currentImage.object) {
                return true;
            }
            await yieldToDom(100);
        }
        return false;
    }

    async function startSam3TextBatch() {
        if (sam3TextBatchActive || sam3TextRequestActive || sam3SimilarityRequestActive || sam3TextCascadeActive) {
            setSam3TextStatus("SAM3 is busy; wait for the current job to finish.", "warn");
            return;
        }
        if (!ensureAutomationAvailable("SAM3 batch")) {
            return;
        }
        if (!currentImage || !currentImage.name) {
            setSam3TextStatus("Load an image before starting a batch run.", "warn");
            return;
        }
        const batchConfig = getSam3TextCascadeBatchConfig();
        if (!batchConfig) {
            setSam3TextStatus("No images found for the batch range.", "warn");
            return;
        }
        const { names } = batchConfig;
        const originalName = currentImage.name;
        const batchMode = getSam3TextBatchMode();
        const runCascadeBatch = batchMode === "cascade";
        if (runCascadeBatch && !getSam3TextCascadeStepElements().length) {
            setSam3TextStatus("Open the cascade editor and add at least one cascade step before running a cascade batch.", "warn");
            return;
        }
        const batchTaskId = enqueueTask({ kind: runCascadeBatch ? "sam3-cascade" : "sam3-batch", imageName: originalName, detail: { count: names.length } });
        sam3TextBatchActive = true;
        sam3TextBatchCancel = false;
        updateSam3TextButtons();
        let totalAdded = 0;
        let totalDedupeRemoved = 0;
        const cascadeConfig = runCascadeBatch ? collectSam3TextCascadeSnapshots({ includeBase: true }) : null;
        const cascadeDedupe = runCascadeBatch ? getSam3TextCascadePostDedupeConfig() : { enabled: false, iou: 0.65 };
        const cascadeAssignedClasses = runCascadeBatch
            ? getSam3TextCascadeAssignedClasses(cascadeConfig?.snapshots || [])
            : [];
        if (runCascadeBatch) {
            if (!cascadeConfig.snapshots.length) {
                setSam3TextStatus("Add at least one valid cascade step first.", "warn");
                sam3TextBatchActive = false;
                updateSam3TextButtons();
                completeTask(batchTaskId);
                return;
            }
            if (cascadeConfig.skipped) {
                setSam3TextStatus(`Skipping ${cascadeConfig.skipped} empty step${cascadeConfig.skipped === 1 ? "" : "s"} in cascade.`, "warn");
            }
        }
        const baseSnapshot = runCascadeBatch ? null : buildSam3TextSnapshot();
        if (!runCascadeBatch) {
            if (!baseSnapshot.prompt) {
                setSam3TextStatus("Enter a prompt before running a batch.", "warn");
                sam3TextElements.promptInput?.focus();
                sam3TextBatchActive = false;
                updateSam3TextButtons();
                completeTask(batchTaskId);
                return;
            }
            if (!baseSnapshot.targetClass) {
                setSam3TextStatus("Pick a class before running a batch.", "warn");
                sam3TextBatchActive = false;
                updateSam3TextButtons();
                completeTask(batchTaskId);
                return;
            }
        }
        try {
            for (let idx = 0; idx < names.length; idx += 1) {
                if (sam3TextBatchCancel) {
                    break;
                }
                const name = names[idx];
                setSam3TextStatus(`Batch ${idx + 1}/${names.length}: ${name}`, "info");
                setSamStatus(`SAM3 batch ${idx + 1}/${names.length}: ${name}`, { variant: "info", duration: 0 });
                const record = images[name];
                if (!record) {
                    continue;
                }
                await ensureImageRecordReady(record);
                if (!currentImage || currentImage.name !== name) {
                    setCurrentImage(record);
                }
                const ready = await waitForCurrentImageReady(name);
                if (!ready) {
                    setSam3TextStatus(`Batch ${idx + 1}/${names.length}: failed to load ${name}`, "warn");
                    continue;
                }
                try {
                    if (runCascadeBatch) {
                        const cascadeStartCreatedAt = bboxCreationCounter;
                        const added = await runSam3TextCascadeSnapshots(cascadeConfig.snapshots, {
                            shouldCancel: () => sam3TextBatchCancel,
                            statusPrefix: "Cascade step",
                            targetImageName: name,
                        });
                        totalAdded += Number(added || 0);
                        if (!sam3TextBatchCancel && cascadeDedupe.enabled) {
                            const dedupeResult = dedupeSam3AssignedClassesForCurrentImage(cascadeAssignedClasses, {
                                iou: cascadeDedupe.iou,
                                minCreatedAtExclusive: cascadeStartCreatedAt,
                            });
                            totalDedupeRemoved += Number(dedupeResult.removed || 0);
                        }
                    } else {
                        const result = await runSam3TextPromptSnapshot(baseSnapshot, {
                            requestImageName: name,
                            statusLabel: `Batch ${idx + 1}/${names.length}`,
                        });
                        totalAdded += Number(result?.added || 0);
                    }
                } catch (err) {
                    console.error("SAM3 batch step failed", err);
                    setSam3TextStatus(`Batch error on ${name}: ${err.message || err}`, "error");
                }
            }
        } finally {
            sam3TextBatchActive = false;
            updateSam3TextButtons();
            completeTask(batchTaskId);
            const doneMessage = sam3TextBatchCancel
                ? "Batch cancelled."
                : `Batch complete: added ${totalAdded} ${datasetType === "seg" ? "polygons" : "boxes"}${totalDedupeRemoved ? `, deduped ${totalDedupeRemoved}` : ""}.`;
            setSam3TextStatus(doneMessage, sam3TextBatchCancel ? "warn" : "success");
            enqueueTaskNotice(doneMessage, { durationMs: 5000 });
        }
    }

    function stopSam3TextBatch() {
        if (!sam3TextBatchActive) {
            return;
        }
        if (sam3TextBatchCancel) {
            return;
        }
        sam3TextBatchCancel = true;
        updateSam3TextButtons();
        setSam3TextStatus("Stopping batch after current image…", "warn");
    }

    async function handleSam3TextRequest() {
        if (sam3TextRequestActive) {
            return;
        }
        if (sam3TextBatchActive || sam3TextCascadeActive) {
            setSam3TextStatus("Batch or cascade is running; wait for it to finish.", "warn");
            return;
        }
        if (!currentImage || !currentImage.name) {
            setSam3TextStatus("Load an image before running SAM3.", "warn");
            return;
        }
        const snapshot = buildSam3TextSnapshot();
        if (!snapshot.prompt) {
            setSam3TextStatus("Enter a prompt describing what to segment.", "warn");
            sam3TextElements.promptInput?.focus();
            return;
        }
        if (!snapshot.targetClass) {
            setSam3TextStatus("Pick a class to assign boxes to before running SAM3.", "warn");
            return;
        }
        sam3TextRequestActive = true;
        updateSam3TextButtons();
        setSam3TextStatus("Running SAM3…", "info");
        setSamStatus("Running SAM3 text prompt…", { variant: "info", duration: 0 });
        try {
            const requestImageName = currentImage.name;
            await runSam3TextPromptSnapshot(snapshot, { requestImageName, statusLabel: "SAM3 text prompt" });
        } catch (error) {
            const detail = error?.message || error;
            setSam3TextStatus(`SAM3 error: ${detail}`, "error");
            console.error("SAM3 text prompt failed", error);
        } finally {
            sam3TextRequestActive = false;
            updateSam3TextButtons();
        }
    }

    async function handleSam3SimilarityPrompt() {
        if (sam3SimilarityRequestActive || sam3TextRequestActive || sam3TextBatchActive || sam3TextCascadeActive) {
            setSam3TextStatus("SAM3 is busy; wait for the current job to finish.", "warn");
            return;
        }
        if (!ensureAutomationAvailable("SAM3 similarity")) {
            return;
        }
        if (!currentImage || !currentImage.name) {
            setSam3TextStatus("Load an image and select a bbox to use as the exemplar.", "warn");
            return;
        }
        const requestImageName = currentImage.name;
        const requestImageWidth = currentImage.width;
        const requestImageHeight = currentImage.height;
        const selectedRecords = getSelectedBboxRecords({ negative: false });
        const negativeRecords = getSelectedBboxRecords({ negative: true });
        const currentUuid = currentBbox && currentBbox.bbox ? currentBbox.bbox.uuid : null;
        const isCurrentNegative = currentUuid ? negativeBboxes.has(currentUuid) : false;
        const primary = currentBbox && currentBbox.bbox && !isCurrentNegative
            ? currentBbox.bbox
            : (selectedRecords[0] || null);
        if (!primary) {
            setSam3TextStatus("Select or draw a bbox to use as the similarity prompt.", "warn");
            return;
        }
        const targetClass = primary.class || null;
        if (!targetClass || typeof classes[targetClass] === "undefined") {
            setSam3TextStatus("The selected bbox has no valid class; pick a labeled bbox first.", "warn");
            return;
        }
        const promptCandidates = selectedRecords.length ? selectedRecords : [primary];
        const promptRects = [];
        const promptLabels = [];
        const seenUuids = new Set();
        promptCandidates.forEach((bbox) => {
            if (!bbox || bbox.class !== targetClass) {
                return;
            }
            if (bbox.uuid && seenUuids.has(bbox.uuid)) {
                return;
            }
            const width = Math.abs(bbox.width);
            const height = Math.abs(bbox.height);
            if (width < minBBoxWidth || height < minBBoxHeight) {
                return;
            }
            const left = Math.min(bbox.x, bbox.x + bbox.width);
            const top = Math.min(bbox.y, bbox.y + bbox.height);
            promptRects.push({ x: left, y: top, width, height });
            promptLabels.push(true);
            if (bbox.uuid) {
                seenUuids.add(bbox.uuid);
            }
        });
        negativeRecords.forEach((bbox) => {
            if (!bbox) {
                return;
            }
            if (bbox.uuid && seenUuids.has(bbox.uuid)) {
                return;
            }
            const width = Math.abs(bbox.width);
            const height = Math.abs(bbox.height);
            if (width < minBBoxWidth || height < minBBoxHeight) {
                return;
            }
            const left = Math.min(bbox.x, bbox.x + bbox.width);
            const top = Math.min(bbox.y, bbox.y + bbox.height);
            promptRects.push({ x: left, y: top, width, height });
            promptLabels.push(false);
            if (bbox.uuid) {
                seenUuids.add(bbox.uuid);
            }
        });
        if (!promptRects.length) {
            setSam3TextStatus("Exemplar bbox is too small or missing for similarity.", "warn");
            return;
        }
        let threshold = parseFloat(sam3TextElements.similarityThresholdInput?.value ?? `${SAM3_SIMILARITY_DEFAULT_THRESHOLD}`);
        if (Number.isNaN(threshold)) threshold = SAM3_SIMILARITY_DEFAULT_THRESHOLD;
        threshold = Math.min(Math.max(threshold, 0), 1);
        let maskThreshold = parseFloat(sam3TextElements.maskThresholdInput?.value || `${SAM3_SIMILARITY_DEFAULT_MASK_THRESHOLD}`);
        if (Number.isNaN(maskThreshold)) maskThreshold = SAM3_SIMILARITY_DEFAULT_MASK_THRESHOLD;
        maskThreshold = Math.min(Math.max(maskThreshold, 0), 1);
        let minSize = parseInt(sam3TextElements.minSizeInput?.value || "0", 10);
        if (Number.isNaN(minSize) || minSize < 0) minSize = 0;
        let maxResults = parseInt(sam3TextElements.maxResultsInput?.value || "20", 10);
        if (Number.isNaN(maxResults)) maxResults = 20;
        maxResults = Math.min(Math.max(maxResults, 1), 100);
        let simplifyEps = parseFloat(sam3TextElements.epsilonInput?.value || "1.0");
        if (Number.isNaN(simplifyEps) || simplifyEps < 0) simplifyEps = 1.0;

        function yoloBoxToPixelRect(yoloBox) {
            if (!Array.isArray(yoloBox) || yoloBox.length < 4) return null;
            const [cx, cy, wNorm, hNorm] = yoloBox.map(Number);
            const wPx = wNorm * requestImageWidth;
            const hPx = hNorm * requestImageHeight;
            return {
                x: cx * requestImageWidth - wPx / 2,
                y: cy * requestImageHeight - hPx / 2,
                width: wPx,
                height: hPx,
            };
        }

        function rectIoU(a, b) {
            const ax2 = a.x + a.width;
            const ay2 = a.y + a.height;
            const bx2 = b.x + b.width;
            const by2 = b.y + b.height;
            const ix = Math.max(0, Math.min(ax2, bx2) - Math.max(a.x, b.x));
            const iy = Math.max(0, Math.min(ay2, by2) - Math.max(a.y, b.y));
            const inter = ix * iy;
            if (inter <= 0) return 0;
            const union = a.width * a.height + b.width * b.height - inter;
            if (union <= 0) return 0;
            return inter / union;
        }

        function rectArea(rect) {
            return Math.max(0, Number(rect?.width) || 0) * Math.max(0, Number(rect?.height) || 0);
        }

        function passesSimilarityShapeGate(rect, positiveInfos) {
            if (!rect || !positiveInfos.length) {
                return true;
            }
            const area = rectArea(rect);
            if (area <= 0) {
                return false;
            }
            const aspect = Math.max(rect.width, rect.height) / Math.max(1, Math.min(rect.width, rect.height));
            return positiveInfos.some((info) => {
                const exemplarArea = rectArea(info.rect);
                if (exemplarArea <= 0) {
                    return true;
                }
                const areaRatio = area / exemplarArea;
                if (areaRatio < 0.08 || areaRatio > 12) {
                    return false;
                }
                const exemplarAspect = Math.max(info.rect.width, info.rect.height)
                    / Math.max(1, Math.min(info.rect.width, info.rect.height));
                const aspectRatio = aspect >= exemplarAspect
                    ? aspect / Math.max(0.001, exemplarAspect)
                    : exemplarAspect / Math.max(0.001, aspect);
                return aspectRatio <= 3.5;
            });
        }

        function existingAnnotationRects() {
            const rects = [];
            const currentBboxes = bboxes[requestImageName];
            if (!currentBboxes) return rects;
            for (let className in currentBboxes) {
                const classBoxes = Array.isArray(currentBboxes[className]) ? currentBboxes[className] : [];
                classBoxes.forEach((bbox) => {
                    if (!bbox) return;
                    if (Array.isArray(bbox.points) && bbox.points.length >= 3) {
                        const xs = bbox.points.map((p) => p.x);
                        const ys = bbox.points.map((p) => p.y);
                        const minX = Math.min(...xs);
                        const maxX = Math.max(...xs);
                        const minY = Math.min(...ys);
                        const maxY = Math.max(...ys);
                        rects.push({ x: minX, y: minY, width: maxX - minX, height: maxY - minY });
                    } else {
                        rects.push({ x: bbox.x, y: bbox.y, width: bbox.width, height: bbox.height });
                    }
                });
            }
            return rects;
        }

        function countPhrase(count, singular, plural = `${singular}s`) {
            return `${count} ${count === 1 ? singular : plural}`;
        }

        function shapePhrase(count, shapeLabel) {
            const plural = shapeLabel === "bbox" ? "bboxes" : `${shapeLabel}s`;
            return countPhrase(count, shapeLabel, plural);
        }

        function buildFilterReasonText({
            exemplarFiltered,
            existingFiltered,
            invalidFiltered,
            shapeFiltered,
            filteredTotal,
        }) {
            const parts = [];
            if (exemplarFiltered) {
                parts.push(`${countPhrase(exemplarFiltered, "seed/exemplar duplicate")}`);
            }
            if (existingFiltered) {
                parts.push(`${countPhrase(existingFiltered, "existing annotation duplicate")}`);
            }
            if (invalidFiltered) {
                parts.push(`${countPhrase(invalidFiltered, "invalid candidate")}`);
            }
            if (shapeFiltered) {
                parts.push(`${countPhrase(shapeFiltered, "shape/scale mismatch")}`);
            }
            if (!parts.length && filteredTotal > 0) {
                parts.push(`${countPhrase(filteredTotal, "candidate")} filtered by duplicate checks`);
            }
            return parts.join(", ");
        }

        function buildSimilarityOutcomeMessages({
            added,
            shapeLabel,
            rawDetectionCount,
            usableDetectionCount,
            exemplarFiltered,
            existingFiltered,
            invalidFiltered,
            shapeFiltered,
        }) {
            const filteredTotal = Math.max(0, rawDetectionCount - usableDetectionCount);
            const filterReasons = buildFilterReasonText({
                exemplarFiltered,
                existingFiltered,
                invalidFiltered,
                shapeFiltered,
                filteredTotal,
            });
            const promptSummary = `${countPhrase(posCount, "positive")} / ${countPhrase(negCount, "negative")}`;
            const scoreSummary = `score >= ${threshold.toFixed(2)}`;
            if (added > 0) {
                const notApplied = Math.max(0, usableDetectionCount - added);
                const details = [];
                details.push(`${countPhrase(rawDetectionCount, "candidate")} from SAM3`);
                if (filteredTotal > 0) {
                    details.push(`${countPhrase(filteredTotal, "candidate")} filtered (${filterReasons})`);
                }
                if (notApplied > 0) {
                    details.push(`${countPhrase(notApplied, "candidate")} passed filters but could not be applied`);
                }
                return {
                    status: `Similarity added ${shapePhrase(added, shapeLabel)}.`,
                    notice: `SAM3 similarity: added ${shapePhrase(added, shapeLabel)} to ${targetClass}; ${details.join("; ")}.`,
                };
            }
            if (rawDetectionCount === 0) {
                return {
                    status: `SAM3 returned 0 candidates at ${scoreSummary}.`,
                    notice: `SAM3 similarity: 0 added. SAM3 returned no candidates before UI filtering (${promptSummary}, ${scoreSummary}). Try a larger/cleaner exemplar or lower Similarity score.`,
                };
            }
            if (usableDetectionCount === 0) {
                return {
                    status: `SAM3 returned ${rawDetectionCount}, all filtered.`,
                    notice: `SAM3 similarity: 0 added. SAM3 returned ${countPhrase(rawDetectionCount, "candidate")}, but all were filtered: ${filterReasons || "duplicate checks removed them"}.`,
                };
            }
            return {
                status: `SAM3 returned ${usableDetectionCount} usable candidates, but none could be added.`,
                notice: `SAM3 similarity: 0 added. SAM3 returned ${countPhrase(rawDetectionCount, "candidate")}; ${countPhrase(usableDetectionCount, "candidate")} passed filters but could not be converted/applied.`,
            };
        }

        sam3SimilarityRequestActive = true;
        updateSam3TextButtons();
        const posCount = promptLabels.filter(Boolean).length;
        const negCount = promptLabels.length - posCount;
        const promptCountLabel = promptLabels.length > 1 ? ` (${posCount} pos / ${negCount} neg)` : "";
        setSam3TextStatus(`Running SAM3 similarity prompt${promptCountLabel}…`, "info");
        const similarityTaskId = enqueueTask({ kind: "sam-similarity", imageName: requestImageName, detail: targetClass });
        const statusToken = beginSamActionStatus(`Running SAM3 similarity prompt${promptCountLabel}…`, { variant: "info" });
        try {
            const result = await invokeSam3VisualPrompt({
                bboxes: promptRects.map((rect) => [rect.x, rect.y, rect.width, rect.height]),
                bbox_labels: promptLabels,
                threshold,
                mask_threshold: maskThreshold,
                min_size: minSize,
                simplify_epsilon: simplifyEps,
                max_results: maxResults,
            });
            if (result?.image_token) {
                rememberSamToken(requestImageName, samVariant, result.image_token);
            }
            let detections = Array.isArray(result?.detections) ? result.detections.slice() : [];
            const rawDetectionCount = detections.length;
            let exemplarFilteredCount = 0;
            let existingFilteredCount = 0;
            let invalidFilteredCount = 0;
            let shapeFilteredCount = 0;
            if (detections.length) {
                const exemplarInfos = promptRects.map((rect) => ({
                    rect,
                    cx: rect.x + rect.width / 2,
                    cy: rect.y + rect.height / 2,
                    maxDim: Math.max(rect.width, rect.height),
                    positive: true,
                })).filter((info, idx) => !!promptLabels[idx]);
                const duplicateInfos = promptRects.map((rect) => ({
                    rect,
                    cx: rect.x + rect.width / 2,
                    cy: rect.y + rect.height / 2,
                    maxDim: Math.max(rect.width, rect.height),
                }));
                const existingRects = existingAnnotationRects();
                detections = detections.filter((det) => {
                    if (!det || !det.bbox) {
                        invalidFilteredCount += 1;
                        return false;
                    }
                    const rect = yoloBoxToPixelRect(det.bbox);
                    if (!rect) {
                        invalidFilteredCount += 1;
                        return false;
                    }
                    if (!passesSimilarityShapeGate(rect, exemplarInfos)) {
                        shapeFilteredCount += 1;
                        return false;
                    }
                    const rectCx = rect.x + rect.width / 2;
                    const rectCy = rect.y + rect.height / 2;
                    for (const info of duplicateInfos) {
                        const dist = Math.hypot(rectCx - info.cx, rectCy - info.cy);
                        const iou = rectIoU(rect, info.rect);
                        const nearCenter = dist <= info.maxDim * 0.1;
                        const highOverlap = iou >= 0.85;
                        if (nearCenter || highOverlap) {
                            exemplarFilteredCount += 1;
                            return false;
                        }
                    }
                    for (const existing of existingRects) {
                        const overlap = rectIoU(rect, existing);
                        if (overlap >= 0.75) {
                            existingFilteredCount += 1;
                            return false;
                        }
                        const exCx = existing.x + existing.width / 2;
                        const exCy = existing.y + existing.height / 2;
                        const exMax = Math.max(existing.width, existing.height);
                        const distEx = Math.hypot(rectCx - exCx, rectCy - exCy);
                        if (distEx <= exMax * 0.1 && overlap >= 0.2) {
                            existingFilteredCount += 1;
                            return false;
                        }
                    }
                    return true;
                });
            }
            // Never apply similarity detections to a different image than the request target.
            if (!currentImage || currentImage.name !== requestImageName) {
                const skippedMessage = `SAM3 similarity skipped: result was for ${requestImageName}, but the current image changed before apply.`;
                setSam3TextStatus(skippedMessage, "warn");
                enqueueTaskNotice(skippedMessage, { durationMs: 6500 });
                return;
            }
            const added = applySegAwareDetections(detections, targetClass, "SAM3 similarity");
            const shapeLabel = datasetType === "seg" ? "polygon" : "bbox";
            const outcome = buildSimilarityOutcomeMessages({
                added,
                shapeLabel,
                rawDetectionCount,
                usableDetectionCount: detections.length,
                exemplarFiltered: exemplarFilteredCount,
                existingFiltered: existingFilteredCount,
                invalidFiltered: invalidFilteredCount,
                shapeFiltered: shapeFilteredCount,
            });
            if (added) {
                setSam3TextStatus(outcome.status, "success");
                enqueueTaskNotice(outcome.notice, { durationMs: 6500 });
            } else {
                setSam3TextStatus(outcome.status, "warn");
                enqueueTaskNotice(outcome.notice, { durationMs: 8000 });
            }
        } catch (error) {
            const detail = error?.message || error;
            setSam3TextStatus(`SAM3 similarity error: ${detail}`, "error");
            console.error("SAM3 similarity prompt failed", error);
        } finally {
            sam3SimilarityRequestActive = false;
            updateSam3TextButtons();
            completeTask(similarityTaskId);
            endSamActionStatus(statusToken);
        }
    }

    async function triggerSam3SimilarityHotkey() {
        if (!ensureAutomationAvailable("SAM3 similarity")) {
            return;
        }
        if (!currentImage || !currentImage.name) {
            setSamStatus("Load an image before running SAM3 similarity.", { variant: "warn", duration: 2500 });
            return;
        }
        const selectedRecords = getSelectedBboxRecords({ negative: false });
        const currentUuid = currentBbox && currentBbox.bbox ? currentBbox.bbox.uuid : null;
        const isCurrentNegative = currentUuid ? negativeBboxes.has(currentUuid) : false;
        const exemplar = currentBbox && currentBbox.bbox && !isCurrentNegative
            ? currentBbox.bbox
            : (selectedRecords[0] || null);
        if (!exemplar) {
            setSamStatus("Select a bbox before running SAM3 similarity.", { variant: "warn", duration: 2500 });
            return;
        }
        const targetClass = exemplar.class;
        if (!targetClass || typeof classes[targetClass] === "undefined") {
            setSamStatus("Selected bbox has no valid class; pick a labeled bbox first.", { variant: "warn", duration: 2500 });
            return;
        }
        const slotEntry = findSlotStatusForImage(currentImage.name, "sam3");
        const sam3Loaded = !!(slotEntry && slotEntry.slot);
        if (!sam3Loaded) {
            if (samVariantSelect && samVariantSelect.value !== "sam3") {
                samVariantSelect.value = "sam3";
                samVariantSelect.dispatchEvent(new Event("change"));
            } else {
                samVariant = "sam3";
            }
            if (!samPreloadEnabled) {
                updateSamPreloadState(true);
            }
            prepareSamForCurrentImage({ messagePrefix: "Loading SAM3 predictor", immediate: true }).catch((err) => {
                console.debug("SAM3 preload for similarity failed", err);
            });
        }
        handleSam3SimilarityPrompt().catch((error) => {
            console.error("SAM3 similarity prompt run failed", error);
        });
    }

    async function invokeQwenInfer(requestFields) {
        if (!currentImage) {
            throw new Error("No active image");
        }
        const imageNameForRequest = currentImage.name;
        const variantForRequest = samVariant;
        const preloadToken = await waitForSamPreloadIfActive(imageNameForRequest, variantForRequest);
        let payload = await buildSamImagePayload({
            variantOverride: variantForRequest,
            preferredToken: preloadToken,
            imageNameOverride: imageNameForRequest,
        });
        if (imageNameForRequest && !payload.image_name) {
            payload.image_name = imageNameForRequest;
        }
        payload.sam_variant = variantForRequest;
        let resp = await fetch(`${API_ROOT}/qwen/infer`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ ...requestFields, ...payload }),
        });
        if (resp.status === 428 || resp.status === 404) {
            if (resp.status === 404 && imageNameForRequest) {
                forgetSamToken(imageNameForRequest, variantForRequest);
            }
            payload = await buildSamImagePayload({
                forceBase64: true,
                variantOverride: variantForRequest,
                preferredToken: null,
                imageNameOverride: imageNameForRequest,
            });
            if (imageNameForRequest && !payload.image_name) {
                payload.image_name = imageNameForRequest;
            }
            payload.sam_variant = variantForRequest;
            resp = await fetch(`${API_ROOT}/qwen/infer`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ ...requestFields, ...payload }),
            });
        }
        if (!resp.ok) {
            const detail = await resp.text();
            throw new Error(detail || resp.statusText || `HTTP ${resp.status}`);
        }
        return resp.json();
    }

