	    function prefillExtraPrompts() {
	        if (!agentElements.extraPrompts) return;
	        const datasetId = agentElements.datasetSelect?.value;
	        if (!datasetId) return;
	        const requestId = agentState.prefillRequestId + 1;
	        agentState.prefillRequestId = requestId;
	        fetch(`${API_ROOT}/sam3/datasets/${encodeURIComponent(datasetId)}/classes`)
            .then((resp) => {
                if (!resp.ok) throw new Error("Failed to load classes");
                return resp.json();
	            })
	            .then((data) => {
	                // Ignore stale responses once dataset selection changes.
	                if (requestId !== agentState.prefillRequestId) {
	                    return;
	                }
	                if ((agentElements.datasetSelect?.value || "") !== datasetId) {
	                    return;
	                }
	                const names = Array.isArray(data?.classes) ? data.classes : [];
	                const template = {};
	                template["__base__"] = ["object", "small object"];
	                if (names.length) {
	                    names.forEach((name) => {
                        template[String(name)] = [];
                    });
	                }
	                agentElements.extraPrompts.value = JSON.stringify(template, null, 2);
	                agentElements.extraPrompts.removeAttribute("readonly");
	            })
	            .catch((err) => {
	                if (requestId !== agentState.prefillRequestId) {
	                    return;
	                }
	                if ((agentElements.datasetSelect?.value || "") !== datasetId) {
	                    return;
	                }
	                console.warn("Failed to prefill extra prompts", err);
	                agentElements.extraPrompts.value = "{}";
	            });
	    }

    function getClassSplitScope() {
        return classSplitElements.scopeAll?.checked ? "all_classes" : "selected_class";
    }

    function getClassSplitImageKeys() {
        const listEl = document.getElementById("imageList");
        if (listEl && listEl.options?.length) {
            return Array.from(listEl.options)
                .map((option) => String(getOptionImageName(option) || "").trim())
                .filter((key) => key && images?.[key]);
        }
        return Object.keys(images || {}).filter((key) => !!images[key]);
    }

    function getClassSplitLabelmapEntries() {
        const ordered = [];
        Object.entries(classes || {}).forEach(([className, idx]) => {
            const classIndex = Number(idx);
            if (!Number.isFinite(classIndex) || classIndex < 0) {
                return;
            }
            ordered[classIndex] = String(className || "").trim();
        });
        if (!ordered.length && Array.isArray(loadedClassList)) {
            loadedClassList.forEach((className, idx) => {
                ordered[idx] = String(className || "").trim();
            });
        }
        return ordered.map((className) => String(className || "").trim()).filter(Boolean);
    }

    function getClassSplitActiveLabelLines(imageKey) {
        const key = String(imageKey || "");
        if (!key) {
            return [];
        }
        const row = annotationSourceState.imageRowsByKey?.get(key);
        if (row) {
            if (annotationSourceState.hydratedKeys.has(key)) {
                return serializeDatasetBboxesForImage(key);
            }
            const rawLines = annotationSourceState.rawLabelLinesByKey.get(key);
            return (Array.isArray(rawLines) ? rawLines : (Array.isArray(row.label_lines) ? row.label_lines : []))
                .map((line) => String(line || "").trim())
                .filter(Boolean);
        }
        return serializeDatasetBboxesForImage(key)
            .map((line) => String(line || "").trim())
            .filter(Boolean);
    }

    function getClassSplitLineClassName(line, labelmap = null) {
        const cols = String(line || "").trim().split(/\s+/).filter(Boolean);
        if (!cols.length) {
            return "";
        }
        const classIdx = parseInt(cols[0], 10);
        if (!Number.isFinite(classIdx)) {
            return "";
        }
        const names = Array.isArray(labelmap) && labelmap.length ? labelmap : getClassSplitLabelmapEntries();
        return String(names[classIdx] || getClassNameById(classIdx) || "").trim();
    }

    function classSplitLineMatchesScope(line, scope, className, labelmap = null) {
        if (String(scope || "") !== "selected_class") {
            return true;
        }
        return getClassSplitLineClassName(line, labelmap) === String(className || "").trim();
    }

    function getClassSplitActiveWorkspaceStats() {
        const labelmap = getClassSplitLabelmapEntries();
        const imageKeys = getClassSplitImageKeys();
        const counts = new Map(labelmap.map((className) => [className, 0]));
        let objectCount = 0;
        let labeledImageCount = 0;
        imageKeys.forEach((imageKey) => {
            const lines = getClassSplitActiveLabelLines(imageKey);
            if (lines.length) {
                labeledImageCount += 1;
            }
            lines.forEach((line) => {
                const className = getClassSplitLineClassName(line, labelmap);
                if (!className) {
                    return;
                }
                counts.set(className, (counts.get(className) || 0) + 1);
                objectCount += 1;
            });
        });
        return {
            imageCount: imageKeys.length,
            labeledImageCount,
            classCount: labelmap.length,
            objectCount,
            counts,
        };
    }

    function makeClassSplitUploadName(imageKey, usedNames) {
        const rawLeaf = String(imageKey || "image.jpg").split(/[\\/]/).pop() || "image.jpg";
        let cleaned = rawLeaf.replace(/[^A-Za-z0-9._-]+/g, "_").replace(/^[_ .-]+|[_ .-]+$/g, "");
        if (!cleaned) {
            cleaned = "image.jpg";
        }
        if (!/\.(jpe?g|png|bmp|gif|webp|tif|tiff)$/i.test(cleaned)) {
            cleaned = `${cleaned}.jpg`;
        }
        const dot = cleaned.lastIndexOf(".");
        const stem = dot > 0 ? cleaned.slice(0, dot) : cleaned;
        const ext = dot > 0 ? cleaned.slice(dot) : "";
        let candidate = cleaned;
        let idx = 1;
        while (usedNames.has(candidate)) {
            candidate = `${stem}_${idx}${ext}`;
            idx += 1;
        }
        usedNames.add(candidate);
        return candidate;
    }

    function classSplitDataUrlToBlob(dataUrl) {
        const raw = String(dataUrl || "");
        const match = raw.match(/^data:([^;,]+)?(;base64)?,(.*)$/);
        if (!match) {
            throw new Error("Image data URL is invalid.");
        }
        const mime = match[1] || "image/jpeg";
        const isBase64 = !!match[2];
        const body = isBase64 ? atob(match[3]) : decodeURIComponent(match[3]);
        const bytes = new Uint8Array(body.length);
        for (let idx = 0; idx < body.length; idx++) {
            bytes[idx] = body.charCodeAt(idx);
        }
        return new Blob([bytes], { type: mime });
    }

    async function classSplitImageObjectToBlob(imageRecord) {
        const imageObject = imageRecord?.object || (currentImage?.name === imageRecord?.name ? currentImage.object : null);
        if (!imageObject) {
            return null;
        }
        const width = imageObject.naturalWidth || imageObject.width || imageRecord.width || 0;
        const height = imageObject.naturalHeight || imageObject.height || imageRecord.height || 0;
        if (!width || !height) {
            return null;
        }
        const canvasEl = document.createElement("canvas");
        canvasEl.width = width;
        canvasEl.height = height;
        const ctx = canvasEl.getContext("2d");
        if (!ctx) {
            return null;
        }
        ctx.drawImage(imageObject, 0, 0, width, height);
        return new Promise((resolve, reject) => {
            canvasEl.toBlob((blob) => {
                if (blob) {
                    resolve(blob);
                } else {
                    reject(new Error("Failed to package image for Class Split Explorer."));
                }
            }, "image/jpeg", 0.95);
        });
    }

    async function getClassSplitImageBlob(imageKey, imageRecord) {
        if (imageRecord?.meta instanceof Blob) {
            return imageRecord.meta;
        }
        if (imageRecord?.dataUrl) {
            return classSplitDataUrlToBlob(imageRecord.dataUrl);
        }
        if (currentImage?.name === imageKey && currentImage?.dataUrl) {
            return classSplitDataUrlToBlob(currentImage.dataUrl);
        }
        const imageUrl = annotationImageUrlForRecord(imageRecord);
        if (imageUrl) {
            const resp = await fetch(imageUrl);
            const detail = resp.ok ? "" : await resp.text();
            if (!resp.ok) {
                throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            }
            return resp.blob();
        }
        const renderedBlob = await classSplitImageObjectToBlob(imageRecord);
        if (renderedBlob) {
            return renderedBlob;
        }
        throw new Error(`Image data is not available in the active workspace: ${imageKey}`);
    }

    function setDataIngestionStatus(message, variant = "") {
        if (!dataIngestionElements.status) {
            return;
        }
        dataIngestionElements.status.textContent = message || "";
        dataIngestionElements.status.classList.remove("warn", "error", "success", "info");
        if (variant) {
            dataIngestionElements.status.classList.add(variant);
        }
    }

    function renderDataIngestionProgress(job = null) {
        if (!dataIngestionElements.progress) {
            return;
        }
        const active = dataIngestionState.active || (job && !["completed", "failed", "cancelled"].includes(String(job.status || "")));
        dataIngestionElements.progress.hidden = !active && !job;
        const progress = Math.max(0, Math.min(1, Number(job?.progress) || 0));
        if (dataIngestionElements.progressFill) {
            dataIngestionElements.progressFill.style.width = `${Math.round(progress * 100)}%`;
        }
        if (dataIngestionElements.progressText) {
            const pct = `${Math.round(progress * 100)}%`;
            const message = String(job?.message || "").trim();
            const logTail = Array.isArray(job?.logs) && job.logs.length
                ? String(job.logs[job.logs.length - 1]?.message || "").trim()
                : "";
            dataIngestionElements.progressText.textContent = [pct, message || logTail].filter(Boolean).join(" • ");
        }
    }

    function getDataIngestionNumber(element, fallback, { min = null, max = null } = {}) {
        const parsed = parseFloat(element?.value || "");
        let value = Number.isFinite(parsed) ? parsed : fallback;
        if (min !== null) value = Math.max(min, value);
        if (max !== null) value = Math.min(max, value);
        return value;
    }

    function populateLocalSaladHeadSelect(selectEl, heads, previousValue = "", { emptyLabel = "" } = {}) {
        if (!selectEl) return;
        const previous = previousValue || selectEl.value;
        const availableHeads = Array.isArray(heads)
            ? heads.filter((head) => String(head.status || "available") === "available")
            : [];
        selectEl.innerHTML = "";
        const empty = document.createElement("option");
        empty.value = "";
        empty.textContent = availableHeads.length ? "Choose matching reference profile" : (emptyLabel || "No reference profiles built");
        selectEl.appendChild(empty);
        availableHeads.forEach((head) => {
            const option = document.createElement("option");
            option.value = String(head.id || "");
            const count = Number(head.train_image_count) || 0;
            const encoder = head.encoder_type ? `, ${String(head.encoder_type).toUpperCase()}` : "";
            const referenceLabel = String(head.reference_dataset_label || head.reference_label || "").trim();
            const referenceSuffix = referenceLabel ? `, ref: ${referenceLabel}` : "";
            option.textContent = `${head.label || head.id}${count ? ` (${count} imgs${encoder}${referenceSuffix})` : encoder ? ` (${encoder.slice(2)}${referenceSuffix})` : referenceSuffix ? ` (${referenceSuffix.slice(2)})` : ""}`;
            selectEl.appendChild(option);
        });
        const values = Array.from(selectEl.options || []).map((option) => option.value);
        if (values.includes(previous)) {
            selectEl.value = previous;
        } else if (availableHeads.length) {
            selectEl.value = String(availableHeads[0].id || "");
        }
    }

    function populateDataIngestionSaladHeads(preferredHeadId = "") {
        const heads = Array.isArray(dataIngestionState.capabilities?.local_salad_heads)
            ? dataIngestionState.capabilities.local_salad_heads
            : [];
        const matchingHeads = heads.filter((head) => dataIngestionHeadMatchesReference(head));
        const preferred = String(preferredHeadId || dataIngestionState.preferredSaladHeadId || "").trim();
        populateLocalSaladHeadSelect(
            dataIngestionElements.saladHead,
            matchingHeads,
            preferred,
            { emptyLabel: heads.length ? "No profiles for selected reference" : "No reference profiles built" },
        );
        if (preferred) {
            const values = Array.from(dataIngestionElements.saladHead?.options || []).map((option) => option.value);
            if (values.includes(preferred)) {
                dataIngestionState.preferredSaladHeadId = "";
            }
        }
    }

    function populateDataIngestionCradioModels() {
        const capsModels = Array.isArray(dataIngestionState.capabilities?.cradio_models)
            ? dataIngestionState.capabilities.cradio_models.map((model) => ({ value: model, label: model.split("/").pop() || model }))
            : CRADIO_BACKBONES;
        const defaultModel = dataIngestionState.capabilities?.default_cradio_model || "nvidia/C-RADIOv4-SO400M";
        fillSelectOptions(dataIngestionElements.trainCradioModel, capsModels, defaultModel);
    }

    function getDataIngestionReferenceSource() {
        return dataIngestionElements.referenceBackend?.checked ? "backend_dataset" : "active_label_images";
    }

    function dataIngestionActiveTransientReferenceId() {
        if (annotationSourceState.mode !== "transient") {
            return "";
        }
        return String(annotationSourceState.sessionId || "").trim();
    }

    function dataIngestionBackendDatasetExists(datasetId = "") {
        const safeId = String(datasetId || "").trim();
        if (!safeId) return false;
        return (Array.isArray(dataIngestionState.datasets) ? dataIngestionState.datasets : [])
            .some((entry) => String(entry?.id || "").trim() === safeId);
    }

    function getDataIngestionDatasetEntryImageCount(entry) {
        const rawCount = Number(entry?.image_count ?? entry?.train_count ?? entry?.annotation_progress?.images_total);
        return Number.isFinite(rawCount) && rawCount > 0 ? rawCount : null;
    }

    function getDataIngestionDatasetImageCount(datasetId = "") {
        return getDataIngestionDatasetEntryImageCount(getDataIngestionReferenceDatasetEntry(datasetId));
    }

    function getDataIngestionActiveBackendDatasetId() {
        const activeDatasetId = String(annotationSourceState.datasetId || "").trim();
        if (annotationSourceState.mode === "linked" && activeDatasetId) {
            const activeCount = getClassSplitImageKeys().length;
            const backendCount = getDataIngestionDatasetImageCount(activeDatasetId);
            if (activeCount > 0 && backendCount !== null && backendCount !== activeCount) {
                return "";
            }
            return activeDatasetId;
        }
        return "";
    }

    function getDataIngestionServerReferenceHandle(referenceSource = getDataIngestionReferenceSource()) {
        const source = String(referenceSource || "").trim();
        if (source === "backend_dataset") {
            const datasetId = getDataIngestionReferenceDatasetId();
            return datasetId
                ? { kind: "backend_dataset", datasetId, sessionId: "", id: datasetId }
                : null;
        }
        if (source !== "active_label_images") {
            return null;
        }
        const activeDatasetId = getDataIngestionActiveBackendDatasetId();
        if (activeDatasetId) {
            return { kind: "backend_dataset", datasetId: activeDatasetId, sessionId: "", id: activeDatasetId };
        }
        const sessionId = dataIngestionActiveTransientReferenceId();
        if (sessionId) {
            const openPath = String(annotationSourceState.transientOpenPath || datasetManagerState.transientOpenPath || "").trim();
            return {
                kind: "transient_session",
                datasetId: `transient:${sessionId}`,
                sessionId,
                openPath,
                id: `transient:${sessionId}`,
            };
        }
        return null;
    }

    function shouldDataIngestionUseBackendReferenceDataset(referenceSource = getDataIngestionReferenceSource()) {
        const handle = getDataIngestionServerReferenceHandle(referenceSource);
        return handle?.kind === "backend_dataset";
    }

    function shouldDataIngestionUseServerReferenceDataset(referenceSource = getDataIngestionReferenceSource()) {
        return !!getDataIngestionServerReferenceHandle(referenceSource);
    }

    function getDataIngestionReferenceDatasetId() {
        return String(dataIngestionElements.referenceDataset?.value || "").trim();
    }

    function getDataIngestionReferenceDatasetEntry(datasetId = "") {
        const safeId = String(datasetId || getDataIngestionReferenceDatasetId()).trim();
        if (!safeId) return null;
        return (Array.isArray(dataIngestionState.datasets) ? dataIngestionState.datasets : [])
            .find((entry) => String(entry?.id || "") === safeId) || null;
    }

    function getDataIngestionReferenceDatasetImageCount() {
        return getDataIngestionDatasetImageCount();
    }

    function getDataIngestionSelectedSaladHead() {
        const headId = String(dataIngestionElements.saladHead?.value || "").trim();
        if (!headId) return null;
        const heads = Array.isArray(dataIngestionState.capabilities?.local_salad_heads)
            ? dataIngestionState.capabilities.local_salad_heads
            : [];
        return heads.find((head) => String(head?.id || "") === headId) || null;
    }

    function dataIngestionHeadMatchesReference(head) {
        if (!head) return false;
        const headReferenceSource = String(head.reference_source || head.source_mode || "").trim();
        const headReferenceKind = String(head.reference_dataset_kind || "").trim();
        const headDatasetId = String(head.reference_dataset_id || "").trim();
        const headSessionId = String(head.reference_session_id || "").trim();
        const selectedSource = getDataIngestionReferenceSource();
        const selectedDatasetId = getDataIngestionReferenceDatasetId();
        if (!headReferenceSource && !headDatasetId && !headSessionId) {
            return false;
        }
        if (selectedSource === "backend_dataset") {
            return !!headDatasetId && !!selectedDatasetId && headDatasetId === selectedDatasetId;
        }
        const activeHandle = getDataIngestionServerReferenceHandle("active_label_images");
        if (activeHandle?.kind === "transient_session") {
            if (headSessionId && headSessionId === activeHandle.sessionId) {
                return true;
            }
            return headDatasetId === activeHandle.datasetId;
        }
        if (activeHandle?.kind === "backend_dataset") {
            return !!headDatasetId && headDatasetId === activeHandle.datasetId;
        }
        const uploadedActiveHandle = dataIngestionHandleFromSelectedHead(head);
        if (uploadedActiveHandle) {
            return true;
        }
        const activeDatasetId = String(annotationSourceState.datasetId || "").trim();
        if (headDatasetId || activeDatasetId) {
            if (!headDatasetId || !activeDatasetId) {
                return false;
            }
            return headDatasetId === activeDatasetId;
        }
        const headLabel = String(head.reference_label || head.reference_dataset_label || "").trim();
        const activeLabel = getDataIngestionReferenceLabel();
        if (headLabel && activeLabel && headLabel !== activeLabel) {
            return false;
        }
        return headReferenceSource === "active_label_images";
    }

    function handleDataIngestionReferenceChange() {
        populateDataIngestionSaladHeads();
        refreshDataIngestionControls();
    }

    function getDataIngestionReferenceLabel() {
        if (getDataIngestionReferenceSource() === "backend_dataset") {
            const entry = getDataIngestionReferenceDatasetEntry();
            return String(entry?.label || entry?.id || "backend dataset");
        }
        return String(
            annotationSourceState.datasetLabel ||
            annotationSourceState.datasetId ||
            annotationSourceState.sessionId ||
            "current Label Images dataset"
        );
    }

    function renderDataIngestionDatasetOptions() {
        const selectEl = dataIngestionElements.referenceDataset;
        if (!selectEl) return;
        const previous = selectEl.value;
        const datasets = Array.isArray(dataIngestionState.datasets) ? dataIngestionState.datasets : [];
        selectEl.innerHTML = "";
        if (!datasets.length) {
            const option = document.createElement("option");
            option.value = "";
            option.textContent = "No backend datasets found";
            selectEl.appendChild(option);
            return;
        }
        datasets.forEach((entry) => {
            const option = document.createElement("option");
            option.value = String(entry?.id || "");
            const count = Number(entry?.image_count ?? entry?.train_count ?? 0) || 0;
            option.textContent = `${entry?.label || entry?.id || "dataset"}${count ? ` (${count} imgs)` : ""}`;
            selectEl.appendChild(option);
        });
        const values = Array.from(selectEl.options || []).map((option) => option.value);
        if (values.includes(previous)) {
            selectEl.value = previous;
        }
    }

    function refreshDataIngestionControls() {
        const candidateCount = dataIngestionElements.files?.files?.length || 0;
        const source = getDataIngestionReferenceSource();
        const activeReferenceCount = getClassSplitImageKeys().length;
        const backendDatasetId = getDataIngestionReferenceDatasetId();
        const backendImageCount = getDataIngestionReferenceDatasetImageCount();
        const hasHead = !!String(dataIngestionElements.saladHead?.value || "").trim();
        const selectedHead = getDataIngestionSelectedSaladHead();
        const selectedHeadReferenceHandle = dataIngestionHandleFromSelectedHead(selectedHead);
        const hasBackendReference = source !== "backend_dataset" || !!backendDatasetId;
        const hasActiveReference = source !== "active_label_images" || activeReferenceCount > 0 || !!selectedHeadReferenceHandle;
        const hasBackendTrainingReference = source !== "backend_dataset"
            || (!!backendDatasetId && (backendImageCount === null || backendImageCount > 1));
        const hasTrainingReference = source === "backend_dataset" ? hasBackendTrainingReference : activeReferenceCount > 1;
        const trainingUsesCradio = String(dataIngestionElements.trainEncoder?.value || "dinov3") === "cradio";
        const headMatchesReference = hasHead && dataIngestionHeadMatchesReference(selectedHead);
        const acceptedCount = dataIngestionState.acceptedItemIds instanceof Set ? dataIngestionState.acceptedItemIds.size : 0;
        const hasAcceptedResult = !!(dataIngestionState.currentResult && Array.isArray(dataIngestionState.currentResult.items) && dataIngestionState.currentResult.items.length);
        const outputMode = String(dataIngestionElements.outputMode?.value || "tile");
        const needsTarget = outputMode !== "original";
        const canUseReference = hasBackendReference && hasActiveReference;
        setButtonDisabled(dataIngestionElements.analyzeButton, dataIngestionState.active || candidateCount <= 0 || !headMatchesReference || !canUseReference);
        setButtonDisabled(dataIngestionElements.buildProfileButton, dataIngestionState.active || !hasTrainingReference);
        setButtonDisabled(
            dataIngestionElements.cancelButton,
            !dataIngestionState.active
                || (!dataIngestionState.activeJobId && !dataIngestionState.activeUploadSessionId)
                || dataIngestionState.cancelInFlight,
        );
        setButtonDisabled(dataIngestionElements.profileDownloadButton, dataIngestionState.active || !hasHead);
        setButtonDisabled(dataIngestionElements.profileUploadButton, dataIngestionState.active || dataIngestionState.profileImportInFlight);
        setButtonDisabled(dataIngestionElements.previewAcceptedButton, dataIngestionState.active || !hasAcceptedResult || acceptedCount <= 0 || dataIngestionState.acceptedPreviewInFlight);
        setButtonDisabled(dataIngestionElements.downloadAcceptedButton, dataIngestionState.active || !hasAcceptedResult || acceptedCount <= 0 || dataIngestionState.acceptedDownloadInFlight);
        setButtonDisabled(dataIngestionElements.distributionButton, dataIngestionState.active || !hasAcceptedResult || !dataIngestionState.activeJobId || dataIngestionState.distributionInFlight);
        if (dataIngestionElements.distributionButton) {
            dataIngestionElements.distributionButton.textContent = dataIngestionState.distributionInFlight ? "Loading map ..." : "Show distribution map";
        }
        [
            dataIngestionElements.files,
            dataIngestionElements.referenceActive,
            dataIngestionElements.referenceBackend,
            dataIngestionElements.referenceDataset,
            dataIngestionElements.saladHead,
            dataIngestionElements.keepFraction,
            dataIngestionElements.localVendiEnabled,
            dataIngestionElements.localVendiWeight,
            dataIngestionElements.frameInterval,
            dataIngestionElements.maxFrames,
            dataIngestionElements.mediaWorkers,
            dataIngestionElements.headName,
            dataIngestionElements.trainEncoder,
            dataIngestionElements.trainCradioModel,
            dataIngestionElements.epochs,
            dataIngestionElements.batchSize,
            dataIngestionElements.maxTrainImages,
            dataIngestionElements.outputMode,
            dataIngestionElements.targetWidth,
            dataIngestionElements.targetHeight,
            dataIngestionElements.tileEdgePolicy,
            dataIngestionElements.tileOverlap,
            dataIngestionElements.jpegQuality,
        ].forEach((control) => {
            if (control) control.disabled = dataIngestionState.active;
        });
        if (dataIngestionElements.referenceDataset) {
            dataIngestionElements.referenceDataset.disabled = dataIngestionState.active || source !== "backend_dataset";
        }
        if (dataIngestionElements.activeUploadName) {
            dataIngestionElements.activeUploadName.disabled = dataIngestionState.active || source !== "active_label_images";
        }
        if (dataIngestionElements.trainCradioModel) {
            dataIngestionElements.trainCradioModel.disabled = dataIngestionState.active || !trainingUsesCradio;
        }
        if (dataIngestionElements.localVendiWeight) {
            dataIngestionElements.localVendiWeight.disabled = dataIngestionState.active || !dataIngestionElements.localVendiEnabled?.checked;
        }
        [
            dataIngestionElements.targetWidth,
            dataIngestionElements.targetHeight,
            dataIngestionElements.tileEdgePolicy,
            dataIngestionElements.tileOverlap,
            dataIngestionElements.jpegQuality,
        ].forEach((control) => {
            if (control) control.disabled = dataIngestionState.active || !needsTarget;
        });
        if (dataIngestionElements.tileEdgePolicy) {
            dataIngestionElements.tileEdgePolicy.disabled = dataIngestionState.active || outputMode !== "tile";
        }
        if (dataIngestionElements.tileOverlap) {
            dataIngestionElements.tileOverlap.disabled = dataIngestionState.active || outputMode !== "tile";
        }
    }

    async function refreshDataIngestionDatasets() {
        try {
            const resp = await fetch(`${API_ROOT}/datasets`);
            const detail = await resp.text();
            if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            const parsed = JSON.parse(detail || "[]");
            dataIngestionState.datasets = Array.isArray(parsed) ? parsed : [];
        } catch (error) {
            console.warn("Failed to refresh Data Ingestion datasets", error);
            dataIngestionState.datasets = [];
        }
        renderDataIngestionDatasetOptions();
    }

    async function refreshDataIngestionCapabilities() {
        const [capabilitiesResult] = await Promise.allSettled([
            fetch(`${API_ROOT}/data_ingestion/capabilities`).then(async (resp) => {
                const detail = await resp.text();
                if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
                return parseJsonObjectSafe(detail, {});
            }),
            refreshDataIngestionDatasets(),
        ]);
        if (capabilitiesResult.status === "fulfilled") {
            dataIngestionState.capabilities = capabilitiesResult.value;
        } else {
            console.warn("Failed to refresh Data Ingestion capabilities", capabilitiesResult.reason);
            dataIngestionState.capabilities = { local_salad_heads: [] };
        }
        if (!dataIngestionState.localVendiDefaultsApplied) {
            const localVendi = dataIngestionState.capabilities?.local_vendi || {};
            if (dataIngestionElements.localVendiEnabled && typeof localVendi.default_enabled === "boolean") {
                dataIngestionElements.localVendiEnabled.checked = localVendi.default_enabled;
            }
            if (dataIngestionElements.localVendiWeight && Number.isFinite(Number(localVendi.default_weight))) {
                const weightDefault = Number(localVendi.default_weight);
                dataIngestionElements.localVendiWeight.value = String(Math.max(0, Math.min(0.5, weightDefault)));
            }
            if (dataIngestionElements.mediaWorkers && Number.isFinite(Number(dataIngestionState.capabilities?.media_prepare_workers))) {
                const workerDefault = Math.max(1, Math.round(Number(dataIngestionState.capabilities.media_prepare_workers)));
                const workerMax = Math.max(workerDefault, Math.round(Number(dataIngestionState.capabilities?.media_prepare_workers_max || 16)));
                dataIngestionElements.mediaWorkers.max = String(workerMax);
                dataIngestionElements.mediaWorkers.value = String(Math.min(workerMax, workerDefault));
            }
            dataIngestionState.localVendiDefaultsApplied = true;
        }
        populateDataIngestionSaladHeads();
        populateDataIngestionCradioModels();
        refreshDataIngestionControls();
    }

    async function appendActiveWorkspaceReferenceFiles(formData, cap, fieldName = "reference_files") {
        const keys = getClassSplitImageKeys();
        const maxCount = Math.max(0, parseInt(String(cap || "0"), 10) || 0);
        const selectedKeys = maxCount > 0 ? keys.slice(0, maxCount) : keys;
        const usedNames = new Set();
        let appended = 0;
        for (const imageKey of selectedKeys) {
            const imageRecord = images?.[imageKey];
            if (!imageRecord) continue;
            const uploadName = makeClassSplitUploadName(imageKey, usedNames);
            const blob = await getClassSplitImageBlob(imageKey, imageRecord);
            formData.append(fieldName, blob, uploadName);
            appended += 1;
        }
        return appended;
    }

    function activeDatasetSaladHeadName(label = "") {
        const raw = String(
            label ||
            annotationSourceState.datasetLabel ||
            annotationSourceState.datasetId ||
            annotationSourceState.sessionId ||
            "active_dataset"
        );
        const cleaned = raw
            .toLowerCase()
            .replace(/[^a-z0-9._-]+/g, "_")
            .replace(/^[_ .-]+|[_ .-]+$/g, "")
            .slice(0, 80);
        return `${cleaned || "active_dataset"}_profile`;
    }

    function dataIngestionActiveWorkspaceSignature(keys = getClassSplitImageKeys()) {
        let hash = 2166136261;
        const append = (value) => {
            const text = String(value || "");
            for (let i = 0; i < text.length; i += 1) {
                hash ^= text.charCodeAt(i);
                hash = Math.imul(hash, 16777619) >>> 0;
            }
            hash ^= 0xff;
            hash = Math.imul(hash, 16777619) >>> 0;
        };
        append(annotationSourceState.mode);
        append(annotationSourceState.datasetId);
        append(annotationSourceState.sessionId);
        append(annotationSourceState.datasetLabel);
        append(datasetType);
        keys.forEach((key) => append(key));
        Object.keys(classes || {}).sort().forEach((className) => {
            append(`${className}:${classes[className]}`);
        });
        return `${keys.length}:${hash >>> 0}`;
    }

    function dataIngestionActiveReferenceUploadName(label = "") {
        const stem = activeDatasetSaladHeadName(label)
            .replace(/_profile$/, "")
            .replace(/^data_ingestion_reference_/, "")
            .slice(0, 72) || "active_dataset";
        return `data_ingestion_reference_${stem}_${getClassSplitImageKeys().length || 0}`;
    }

    function getDataIngestionActiveReferenceUploadName(label = "") {
        const explicit = String(dataIngestionElements.activeUploadName?.value || "").trim();
        return explicit || dataIngestionActiveReferenceUploadName(label);
    }

    function dataIngestionUploadedReferenceContext(label = "") {
        const safeLabel = String(label || getDataIngestionReferenceLabel() || "active Label Images dataset").trim();
        return `Data Ingestion active reference: ${safeLabel}`;
    }

    function getDataIngestionStoredActiveReferenceUploads() {
        try {
            const parsed = JSON.parse(window.localStorage?.getItem(DATA_INGESTION_ACTIVE_REFERENCE_UPLOADS_STORAGE_KEY) || "{}");
            return parsed && typeof parsed === "object" ? parsed : {};
        } catch (error) {
            return {};
        }
    }

    function setDataIngestionStoredActiveReferenceUpload(signature, datasetId, imageCount) {
        const safeSignature = String(signature || "").trim();
        const safeDatasetId = String(datasetId || "").trim();
        if (!safeSignature || !safeDatasetId) return;
        try {
            const uploads = getDataIngestionStoredActiveReferenceUploads();
            uploads[safeSignature] = {
                datasetId: safeDatasetId,
                imageCount: Number(imageCount) || 0,
                storedAt: Date.now(),
            };
            window.localStorage?.setItem(
                DATA_INGESTION_ACTIVE_REFERENCE_UPLOADS_STORAGE_KEY,
                JSON.stringify(uploads),
            );
        } catch (error) {
            console.warn("Failed to store Data Ingestion reference upload cache", error);
        }
    }

    function getDataIngestionStoredActiveReferenceUpload(signature) {
        const safeSignature = String(signature || "").trim();
        if (!safeSignature) return null;
        const entry = getDataIngestionStoredActiveReferenceUploads()[safeSignature];
        const datasetId = String(entry?.datasetId || "").trim();
        if (!datasetId || !dataIngestionBackendDatasetExists(datasetId)) return null;
        const cachedCount = Number(entry?.imageCount || 0) || 0;
        const backendCount = getDataIngestionDatasetImageCount(datasetId);
        if (cachedCount > 0 && backendCount !== null && backendCount !== cachedCount) return null;
        return {
            id: datasetId,
            dataset_id: datasetId,
            image_count: cachedCount || getClassSplitImageKeys().length,
        };
    }

    function dataIngestionActiveReferenceHandleFromDataset(entry, signature = "") {
        const datasetId = String(entry?.id || entry?.dataset_id || "").trim();
        if (!datasetId) return null;
        const imageCount = Number(entry?.image_count ?? entry?.train_count ?? getClassSplitImageKeys().length) || 0;
        const activeCount = getClassSplitImageKeys().length;
        if (activeCount > 0 && imageCount > 0 && imageCount !== activeCount) return null;
        return {
            kind: "backend_dataset",
            datasetId,
            sessionId: "",
            id: datasetId,
            uploadedActiveReference: true,
            imageCount,
            signature,
        };
    }

    async function ensureDataIngestionActiveReferenceDataset({ purpose = "reference" } = {}) {
        const existingHandle = getDataIngestionServerReferenceHandle("active_label_images");
        if (existingHandle) {
            return existingHandle;
        }
        const activeKeys = getClassSplitImageKeys();
        if (!activeKeys.length) {
            throw new Error("Open a reference dataset in Label Images first.");
        }
        const imageCount = activeKeys.length;
        const signature = dataIngestionActiveWorkspaceSignature(activeKeys);
        const referenceLabel = getDataIngestionReferenceLabel();
        const uploadName = getDataIngestionActiveReferenceUploadName(referenceLabel);
        const uploadCacheKey = `${signature}|name:${uploadName}`;
        const cached = dataIngestionState.activeReferenceDatasetUpload;
        if (cached?.signature === uploadCacheKey && cached?.datasetId && dataIngestionBackendDatasetExists(cached.datasetId)) {
            return {
                kind: "backend_dataset",
                datasetId: cached.datasetId,
                sessionId: "",
                id: cached.datasetId,
                uploadedActiveReference: true,
                imageCount,
                signature: uploadCacheKey,
            };
        }
        await initDatasetManagerTab();
        await refreshDataIngestionDatasets();
        const reusableEntry = getDataIngestionStoredActiveReferenceUpload(uploadCacheKey);
        const reusableHandle = dataIngestionActiveReferenceHandleFromDataset(reusableEntry, uploadCacheKey);
        if (reusableHandle) {
            dataIngestionState.activeReferenceDatasetUpload = {
                signature: uploadCacheKey,
                datasetId: reusableHandle.datasetId,
                imageCount,
            };
            return reusableHandle;
        }
        const purposeLabel = purpose === "analysis" ? "candidate analysis" : "reference profile";
        const uploadMessage = `Uploading active Label Images dataset (${imageCount} images) as backend reference for ${purposeLabel} ...`;
        setDataIngestionStatus(uploadMessage, "info");
        renderDataIngestionProgress({ progress: 0, message: uploadMessage });
        const result = await uploadCurrentDatasetToCache({
            runName: uploadName,
            context: dataIngestionUploadedReferenceContext(referenceLabel),
            split: false,
            transport: "chunked",
            throwOnError: true,
            imageKeys: activeKeys,
            statusPrefix: "active Label Images reference dataset",
            onSessionStart: ({ sessionId, abortController } = {}) => {
                dataIngestionState.activeUploadSessionId = String(sessionId || "");
                dataIngestionState.activeUploadAbortController = abortController || null;
                refreshDataIngestionControls();
            },
            onSessionEnd: ({ sessionId } = {}) => {
                if (!sessionId || dataIngestionState.activeUploadSessionId === sessionId) {
                    dataIngestionState.activeUploadSessionId = "";
                    dataIngestionState.activeUploadAbortController = null;
                    refreshDataIngestionControls();
                }
            },
            onProgress: ({ progress = 0, message = "" } = {}) => {
                const pct = Math.max(0, Math.min(0.98, Number(progress) || 0));
                renderDataIngestionProgress({ progress: pct, message: message || uploadMessage });
                if (message) {
                    setDataIngestionStatus(message, "info");
                }
            },
        });
        if (!result) {
            throw new Error("Active Label Images dataset upload did not return a backend dataset.");
        }
        const handle = dataIngestionActiveReferenceHandleFromDataset(result, uploadCacheKey);
        if (!handle) {
            throw new Error("Active Label Images dataset upload returned no dataset id.");
        }
        dataIngestionState.activeReferenceDatasetUpload = {
            signature: uploadCacheKey,
            datasetId: handle.datasetId,
            imageCount,
        };
        setDataIngestionStoredActiveReferenceUpload(uploadCacheKey, handle.datasetId, imageCount);
        await refreshDataIngestionDatasets();
        return handle;
    }

    function dataIngestionHandleFromSelectedHead(head) {
        if (!head || getDataIngestionReferenceSource() !== "active_label_images") return null;
        const activeHandle = getDataIngestionServerReferenceHandle("active_label_images");
        if (activeHandle) return activeHandle;
        const headDatasetId = String(head.reference_dataset_id || "").trim();
        if (!headDatasetId) return null;
        if (!dataIngestionBackendDatasetExists(headDatasetId)) return null;
        const headSource = String(head.reference_source || head.source_mode || "").trim();
        const headKind = String(head.reference_dataset_kind || "").trim();
        if (headSource && headSource !== "active_label_images") return null;
        if (headKind && headKind !== "backend_dataset") return null;
        const activeCount = getClassSplitImageKeys().length;
        const headActiveCount = Number(head.active_image_count || head.train_image_count || 0);
        if (Number.isFinite(headActiveCount) && headActiveCount > 0 && activeCount > 0 && headActiveCount !== activeCount) {
            return null;
        }
        const backendCount = getDataIngestionDatasetImageCount(headDatasetId);
        if (activeCount > 0 && backendCount !== null && backendCount !== activeCount) {
            return null;
        }
        return {
            kind: "backend_dataset",
            datasetId: headDatasetId,
            sessionId: "",
            id: headDatasetId,
            uploadedActiveReference: true,
            imageCount: activeCount || backendCount || headActiveCount || 0,
        };
    }

    async function appendActiveWorkspaceTrainingFiles(formData, cap) {
        return appendActiveWorkspaceReferenceFiles(formData, cap, "train_files");
    }

    async function startDataIngestionAnalysis() {
        if (dataIngestionState.active) return;
        const files = Array.from(dataIngestionElements.files?.files || []);
        if (!files.length) {
            setDataIngestionStatus("Choose candidate images or videos first.", "warn");
            return;
        }
        const saladHeadId = String(dataIngestionElements.saladHead?.value || "").trim();
        if (!saladHeadId) {
            setDataIngestionStatus("Build or select a reference profile before analyzing candidates.", "warn");
            return;
        }
        const selectedHead = getDataIngestionSelectedSaladHead();
        if (!dataIngestionHeadMatchesReference(selectedHead)) {
            setDataIngestionStatus("Selected reference profile does not match the chosen reference dataset. Build or choose the matching profile first.", "warn");
            return;
        }
        const referenceSource = getDataIngestionReferenceSource();
        let referenceHandle = getDataIngestionServerReferenceHandle(referenceSource) || dataIngestionHandleFromSelectedHead(selectedHead);
        if (referenceSource === "backend_dataset" && !getDataIngestionReferenceDatasetId()) {
            setDataIngestionStatus("Choose a backend reference dataset first.", "warn");
            return;
        }
        if (referenceSource === "active_label_images" && getClassSplitImageKeys().length < 1 && !referenceHandle) {
            setDataIngestionStatus("Open a reference dataset in Label Images first.", "warn");
            return;
        }
        try {
            dataIngestionState.active = true;
            dataIngestionState.activeJobId = "";
            dataIngestionState.currentResult = null;
            dataIngestionState.acceptedItemIds = new Set();
            dataIngestionState.lastPreview = null;
            dataIngestionState.visibleItemLimit = 120;
            clearDataIngestionDistribution();
            setDataIngestionStatus("Packaging media ...");
            renderDataIngestionProgress({ progress: 0, message: "Packaging candidate media ..." });
            refreshDataIngestionControls();
            const formData = new FormData();
            files.forEach((file) => formData.append("candidate_files", file, file.name));
            const maxReferenceImages = Math.round(getDataIngestionNumber(dataIngestionElements.maxTrainImages, 0, { min: 0 }));
            let referenceCount = 0;
            if (referenceSource === "active_label_images" && !referenceHandle) {
                referenceHandle = await ensureDataIngestionActiveReferenceDataset({ purpose: "analysis" });
            }
            const useBackendReferenceDataset = referenceHandle?.kind === "backend_dataset";
            const useServerReferenceDataset = !!referenceHandle;
            const referenceDatasetId = referenceHandle?.datasetId || (
                referenceSource === "backend_dataset" ? getDataIngestionReferenceDatasetId() : String(annotationSourceState.datasetId || "")
            );
            const referenceSessionId = referenceHandle?.sessionId || "";
            if (useServerReferenceDataset) {
                referenceCount = referenceHandle?.imageCount || getClassSplitImageKeys().length;
                setDataIngestionStatus(referenceHandle.kind === "transient_session"
                    ? "Queueing active transient dataset by backend session ..."
                    : "Queueing Label Images dataset by backend reference ...");
            } else if (referenceSource === "active_label_images") {
                referenceCount = await appendActiveWorkspaceReferenceFiles(formData, maxReferenceImages);
                if (referenceCount < 1) {
                    throw new Error("No usable reference images were available in Label Images.");
                }
            }
            const manifest = {
                encoder: "local_salad",
                salad_head_id: saladHeadId,
                reference_source: referenceSource,
                reference_dataset_kind: referenceHandle?.kind || (referenceSource === "backend_dataset" ? "backend_dataset" : "uploaded_workspace"),
                reference_dataset_id: referenceDatasetId,
                reference_session_id: referenceSessionId,
                reference_open_path: referenceHandle?.kind === "transient_session" ? (referenceHandle.openPath || "") : "",
                reference_dataset_label: referenceSource === "backend_dataset" ? getDataIngestionReferenceLabel() : "",
                reference_label: getDataIngestionReferenceLabel(),
                use_backend_reference_dataset: useBackendReferenceDataset,
                use_server_reference_dataset: useServerReferenceDataset,
                max_reference_images: maxReferenceImages,
                keep_fraction: getDataIngestionNumber(dataIngestionElements.keepFraction, 0.2, { min: 0.01, max: 1 }),
                local_vendi_enabled: !!dataIngestionElements.localVendiEnabled?.checked,
                local_vendi_weight: getDataIngestionNumber(dataIngestionElements.localVendiWeight, 0.2, { min: 0, max: 1 }),
                frame_interval: getDataIngestionNumber(dataIngestionElements.frameInterval, 1.0, { min: 0.1 }),
                max_frames_per_video: Math.round(getDataIngestionNumber(dataIngestionElements.maxFrames, 200, { min: 0 })),
                media_prepare_workers: Math.round(getDataIngestionNumber(dataIngestionElements.mediaWorkers, 4, { min: 1, max: 64 })),
                reference_count: referenceCount,
            };
            formData.append("manifest", JSON.stringify(manifest));
            const resp = await fetch(`${API_ROOT}/data_ingestion/jobs`, { method: "POST", body: formData });
            const detail = await resp.text();
            if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            const payload = parseJsonObjectSafe(detail, {});
            const jobId = String(payload.job_id || "").trim();
            if (!jobId) throw new Error("Data ingestion did not return a job id.");
            dataIngestionState.activeJobId = jobId;
            setDataIngestionStatus("Queued diversity analysis");
            pollDataIngestionJob(jobId);
        } catch (error) {
            console.error("Data Ingestion analysis failed to start", error);
            dataIngestionState.active = false;
            setDataIngestionStatus(`Failed: ${error.message || error}`, "error");
            renderDataIngestionProgress({ progress: 1, message: `Failed: ${error.message || error}` });
            refreshDataIngestionControls();
        }
    }

    async function startLocalSaladTraining() {
        if (dataIngestionState.active) return;
        const referenceSource = getDataIngestionReferenceSource();
        let referenceHandle = getDataIngestionServerReferenceHandle(referenceSource);
        const activeKeys = getClassSplitImageKeys();
        if (referenceSource === "active_label_images" && activeKeys.length < 2) {
            setDataIngestionStatus("Open at least two images in Label Images before building a reference profile from the active dataset.", "warn");
            return;
        }
        if (referenceSource === "backend_dataset" && !getDataIngestionReferenceDatasetId()) {
            setDataIngestionStatus("Choose a backend reference dataset before building a profile.", "warn");
            return;
        }
        try {
            dataIngestionState.active = true;
            dataIngestionState.activeJobId = "";
            dataIngestionState.currentResult = null;
            dataIngestionState.acceptedItemIds = new Set();
            dataIngestionState.lastPreview = null;
            dataIngestionState.visibleItemLimit = 120;
            clearDataIngestionDistribution();
            const initialMessage = referenceHandle
                ? (referenceHandle.kind === "transient_session" ? "Queueing active transient dataset reference profile ..." : "Queueing backend dataset reference profile ...")
                : "Preparing active Label Images dataset for reference profile ...";
            setDataIngestionStatus(initialMessage);
            renderDataIngestionProgress({ progress: 0, message: initialMessage });
            refreshDataIngestionControls();
            const formData = new FormData();
            const maxTrainImages = Math.round(getDataIngestionNumber(dataIngestionElements.maxTrainImages, 0, { min: 0 }));
            let packagedCount = 0;
            if (referenceSource === "active_label_images" && !referenceHandle) {
                referenceHandle = await ensureDataIngestionActiveReferenceDataset({ purpose: "profile" });
            }
            const useBackendReferenceDataset = referenceHandle?.kind === "backend_dataset";
            const useServerReferenceDataset = !!referenceHandle;
            const referenceDatasetId = referenceHandle?.datasetId || (
                referenceSource === "backend_dataset" ? getDataIngestionReferenceDatasetId() : String(annotationSourceState.datasetId || "")
            );
            const referenceSessionId = referenceHandle?.sessionId || "";
            if (useServerReferenceDataset) {
                packagedCount = referenceHandle?.imageCount || activeKeys.length;
            } else if (referenceSource === "active_label_images") {
                packagedCount = await appendActiveWorkspaceTrainingFiles(formData, maxTrainImages);
            }
            if (referenceSource === "active_label_images" && packagedCount < 2) {
                throw new Error("Reference profile build needs at least two usable images or frames.");
            }
            const requestedHeadName = String(dataIngestionElements.headName?.value || "").trim();
            const genericHeadName = !requestedHeadName || requestedHeadName === "reference_profile" || requestedHeadName === "reference_salad_profile" || requestedHeadName === "local_salad_head";
            const manifest = {
                head_name: genericHeadName
                    ? activeDatasetSaladHeadName(getDataIngestionReferenceLabel())
                    : requestedHeadName,
                encoder_type: String(dataIngestionElements.trainEncoder?.value || "dinov3"),
                encoder_model: String(dataIngestionElements.trainEncoder?.value || "dinov3") === "cradio"
                    ? String(dataIngestionElements.trainCradioModel?.value || "nvidia/C-RADIOv4-SO400M")
                    : "",
                source_mode: referenceSource,
                reference_source: referenceSource,
                reference_dataset_kind: referenceHandle?.kind || (referenceSource === "backend_dataset" ? "backend_dataset" : "uploaded_workspace"),
                reference_dataset_id: referenceDatasetId,
                reference_session_id: referenceSessionId,
                reference_open_path: referenceHandle?.kind === "transient_session" ? (referenceHandle.openPath || "") : "",
                reference_dataset_label: referenceSource === "backend_dataset" ? getDataIngestionReferenceLabel() : "",
                reference_label: getDataIngestionReferenceLabel(),
                active_image_count: referenceSource === "active_label_images" ? packagedCount : 0,
                use_backend_reference_dataset: useBackendReferenceDataset,
                use_server_reference_dataset: useServerReferenceDataset,
                epochs: Math.round(getDataIngestionNumber(dataIngestionElements.epochs, 8, { min: 1 })),
                batch_size: Math.round(getDataIngestionNumber(dataIngestionElements.batchSize, 8, { min: 2 })),
                max_train_images: maxTrainImages,
                frame_interval: getDataIngestionNumber(dataIngestionElements.frameInterval, 1.0, { min: 0.1 }),
                max_frames_per_video: Math.round(getDataIngestionNumber(dataIngestionElements.maxFrames, 200, { min: 0 })),
                media_prepare_workers: Math.round(getDataIngestionNumber(dataIngestionElements.mediaWorkers, 4, { min: 1, max: 64 })),
            };
            formData.append("manifest", JSON.stringify(manifest));
            const resp = await fetch(`${API_ROOT}/data_ingestion/salad_train_jobs`, { method: "POST", body: formData });
            const detail = await resp.text();
            if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            const payload = parseJsonObjectSafe(detail, {});
            const jobId = String(payload.job_id || "").trim();
            if (!jobId) throw new Error("Reference profile build did not return a job id.");
            dataIngestionState.activeJobId = jobId;
            setDataIngestionStatus("Queued reference profile build");
            pollDataIngestionJob(jobId);
        } catch (error) {
            console.error("Reference profile build failed to start", error);
            dataIngestionState.active = false;
            setDataIngestionStatus(`Failed: ${error.message || error}`, "error");
            renderDataIngestionProgress({ progress: 1, message: `Failed: ${error.message || error}` });
            refreshDataIngestionControls();
        }
    }

    function formatDataIngestionProfilePolicy(value) {
        const raw = String(value || "").trim();
        if (!raw || raw === "local_training_only") {
            return "reference profile only";
        }
        return raw.replace(/_/g, " ");
    }

    function stopDataIngestionPoll() {
        if (dataIngestionState.pollTimer) {
            clearTimeout(dataIngestionState.pollTimer);
            dataIngestionState.pollTimer = null;
        }
    }

    function pollDataIngestionJob(jobId) {
        stopDataIngestionPoll();
        const requestId = ++dataIngestionState.pollRequestId;
        const run = async () => {
            try {
                const resp = await fetch(`${API_ROOT}/data_ingestion/jobs/${encodeURIComponent(jobId)}`);
                const detail = await resp.text();
                if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
                const job = parseJsonObjectSafe(detail, {});
                if (requestId !== dataIngestionState.pollRequestId) return;
                renderDataIngestionProgress(job);
                const status = String(job.status || "");
                if (status === "completed") {
                    dataIngestionState.active = false;
                    const summary = job.summary || {};
                    const trainedHeadId = job.kind === "local_salad_train" ? String(summary.head_id || "").trim() : "";
                    if (trainedHeadId) {
                        dataIngestionState.preferredSaladHeadId = trainedHeadId;
                    }
                    setDataIngestionStatus(
                        job.kind === "local_salad_train"
                            ? (trainedHeadId ? `Reference profile completed; selected ${trainedHeadId}.` : "Reference profile completed.")
                            : "Diversity analysis completed.",
                        "success"
                    );
                    refreshDataIngestionControls();
                    await refreshDataIngestionCapabilities();
                    if (trainedHeadId) {
                        setSelectValueIfPresent(dataIngestionElements.saladHead, trainedHeadId);
                        refreshDataIngestionControls();
                    }
                    await loadDataIngestionResult(jobId);
                    return;
                }
                if (status === "failed" || status === "cancelled") {
                    dataIngestionState.active = false;
                    setDataIngestionStatus(`${status}: ${job.error || job.message || ""}`, status === "failed" ? "error" : "warn");
                    refreshDataIngestionControls();
                    return;
                }
                dataIngestionState.pollTimer = window.setTimeout(run, 1200);
            } catch (error) {
                console.error("Data Ingestion poll failed", error);
                dataIngestionState.pollTimer = window.setTimeout(run, 2000);
            }
        };
        run();
    }

    async function maybeResumeDataIngestionJob() {
        if (dataIngestionState.active || dataIngestionState.activeJobId || dataIngestionState.activeUploadSessionId) {
            return;
        }
        try {
            const resp = await fetch(`${API_ROOT}/data_ingestion/jobs`);
            const detail = await resp.text();
            if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            const jobs = parseJsonObjectSafe(detail, []);
            if (!Array.isArray(jobs)) return;
            const activeJob = jobs.find((job) => {
                const status = String(job?.status || "");
                return job?.job_id && !["completed", "failed", "cancelled"].includes(status);
            });
            if (!activeJob) return;
            const jobId = String(activeJob.job_id || "").trim();
            if (!jobId) return;
            dataIngestionState.active = true;
            dataIngestionState.activeJobId = jobId;
            renderDataIngestionProgress(activeJob);
            setDataIngestionStatus(`Recovered active Data Ingestion job: ${jobId}.`, "info");
            refreshDataIngestionControls();
            pollDataIngestionJob(jobId);
        } catch (error) {
            console.warn("No resumable Data Ingestion job found", error);
        }
    }

    async function cancelDataIngestionJob() {
        const jobId = dataIngestionState.activeJobId;
        const uploadSessionId = dataIngestionState.activeUploadSessionId;
        if ((!jobId && !uploadSessionId) || dataIngestionState.cancelInFlight) return;
        dataIngestionState.cancelInFlight = true;
        refreshDataIngestionControls();
        try {
            if (uploadSessionId) {
                if (dataIngestionState.activeUploadAbortController) {
                    dataIngestionState.activeUploadAbortController.abort();
                }
                const resp = await fetch(`${API_ROOT}/datasets/upload_session/${encodeURIComponent(uploadSessionId)}/cancel`, { method: "POST" });
                const detail = await resp.text();
                if (!resp.ok) {
                    throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
                }
                dataIngestionState.active = false;
                dataIngestionState.activeUploadSessionId = "";
                dataIngestionState.activeUploadAbortController = null;
                setDataIngestionStatus("Dataset upload cancelled.", "warn");
                renderDataIngestionProgress({ progress: 1, message: "Dataset upload cancelled." });
                return;
            }
            const resp = await fetch(`${API_ROOT}/data_ingestion/jobs/${encodeURIComponent(jobId)}/cancel`, { method: "POST" });
            const detail = await resp.text();
            if (!resp.ok) {
                throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            }
            setDataIngestionStatus("Cancellation requested ...", "warn");
        } catch (error) {
            setDataIngestionStatus(`Cancel failed: ${error.message || error}`, "error");
        } finally {
            dataIngestionState.cancelInFlight = false;
            refreshDataIngestionControls();
        }
    }

    function dataIngestionResultItemId(item) {
        const raw = String(item?.item_id || "").trim();
        if (raw) return raw;
        const idx = Number(item?.index);
        return `item_${String(Number.isFinite(idx) ? Math.max(0, Math.round(idx)) : 0).padStart(6, "0")}`;
    }

    function getDataIngestionResultItems() {
        return Array.isArray(dataIngestionState.currentResult?.items)
            ? dataIngestionState.currentResult.items
            : [];
    }

    function selectedDataIngestionItemIds() {
        return Array.from(dataIngestionState.acceptedItemIds || []);
    }

    function setDataIngestionItemAccepted(itemId, accepted) {
        const safeId = String(itemId || "").trim();
        if (!safeId) return;
        if (!(dataIngestionState.acceptedItemIds instanceof Set)) {
            dataIngestionState.acceptedItemIds = new Set();
        }
        if (accepted) {
            dataIngestionState.acceptedItemIds.add(safeId);
        } else {
            dataIngestionState.acceptedItemIds.delete(safeId);
        }
        dataIngestionState.lastPreview = null;
        renderDataIngestionResult(dataIngestionState.currentResult, {
            preserveSelection: true,
            preserveDistribution: true,
        });
        renderDataIngestionTilePreview([]);
        renderDataIngestionAcceptedSummary();
        refreshDataIngestionControls();
        if (dataIngestionState.distribution) {
            const selectedPoint = getDataIngestionDistributionPointById(dataIngestionState.selectedDistributionItemId);
            renderDataIngestionDistributionDetails(selectedPoint);
            renderDataIngestionDistributionGraph();
        }
    }

    function getDataIngestionAcceptedExportPayload({ offset = 0, limit = 80 } = {}) {
        const mode = String(dataIngestionElements.outputMode?.value || "tile");
        const payload = {
            transform_mode: mode,
            item_ids: selectedDataIngestionItemIds(),
            target_width: Math.round(getDataIngestionNumber(dataIngestionElements.targetWidth, 960, { min: 1 })),
            target_height: Math.round(getDataIngestionNumber(dataIngestionElements.targetHeight, 960, { min: 1 })),
            tile_edge_policy: String(dataIngestionElements.tileEdgePolicy?.value || "cover_no_padding"),
            tile_overlap: getDataIngestionNumber(dataIngestionElements.tileOverlap, 0, { min: 0, max: 0.9 }),
            jpeg_quality: Math.round(getDataIngestionNumber(dataIngestionElements.jpegQuality, 95, { min: 1, max: 100 })),
            offset,
            limit,
        };
        return payload;
    }

    function filenameFromResponse(resp, fallback) {
        const header = resp.headers.get("Content-Disposition") || "";
        const match = /filename="?([^";]+)"?/i.exec(header);
        return sanitizeFilename((match?.[1] || fallback || "download.zip").trim(), fallback || "download.zip");
    }

    function renderDataIngestionAcceptWarning() {
        if (!dataIngestionElements.acceptWarning) return;
        const mode = String(dataIngestionElements.outputMode?.value || "tile");
        const edge = String(dataIngestionElements.tileEdgePolicy?.value || "cover_no_padding");
        const lines = ["ZIP is unsplit so related tiles or frames cannot leak across train/val by accident."];
        if (mode === "tile") {
            if (edge === "cover_no_padding") {
                lines.push("Cover no padding preserves real pixels, but edge tiles may overlap neighboring tiles.");
            } else if (edge === "pad_edges") {
                lines.push("Pad edges keeps regular tile positions but adds border pixels.");
            } else if (edge === "drop_partials") {
                lines.push("Drop partials avoids edge overlaps but can discard border content.");
            }
            const overlap = Number(dataIngestionElements.tileOverlap?.value || 0);
            if (overlap > 0) lines.push("Tile overlap creates near-duplicates; split downstream by original source, not by tile.");
        }
        dataIngestionElements.acceptWarning.textContent = lines.join(" ");
    }

    function renderDataIngestionAcceptedSummary() {
        if (!dataIngestionElements.acceptedSummary) return;
        const itemCount = selectedDataIngestionItemIds().length;
        const previewTotal = Number(dataIngestionState.lastPreview?.total_outputs || 0);
        const parts = [`Selected candidates: ${itemCount}`];
        if (previewTotal) parts.push(`Download outputs: ${previewTotal}`);
        dataIngestionElements.acceptedSummary.textContent = parts.join(" • ");
    }

    function getDataIngestionHoverPreview() {
        let preview = document.getElementById("dataIngestionHoverPreview");
        if (!preview) {
            preview = document.createElement("div");
            preview.id = "dataIngestionHoverPreview";
            preview.className = "data-ingestion-hover-preview";
            preview.hidden = true;
            preview.innerHTML = `<img alt="Candidate preview"><span></span>`;
            document.body.appendChild(preview);
        }
        return preview;
    }

    function moveDataIngestionHoverPreview(event) {
        const preview = document.getElementById("dataIngestionHoverPreview");
        if (!preview || preview.hidden) return;
        const gap = 18;
        const rect = preview.getBoundingClientRect();
        let left = event.clientX + gap;
        let top = event.clientY + gap;
        if (left + rect.width > window.innerWidth - gap) {
            left = Math.max(gap, event.clientX - rect.width - gap);
        }
        if (top + rect.height > window.innerHeight - gap) {
            top = Math.max(gap, window.innerHeight - rect.height - gap);
        }
        preview.style.left = `${Math.round(left)}px`;
        preview.style.top = `${Math.round(top)}px`;
    }

    function showDataIngestionHoverPreview(event, previewUrl, label) {
        if (!previewUrl) return;
        const preview = getDataIngestionHoverPreview();
        const img = preview.querySelector("img");
        const caption = preview.querySelector("span");
        if (img && img.getAttribute("src") !== previewUrl) img.setAttribute("src", previewUrl);
        if (caption) caption.textContent = label || "";
        preview.hidden = false;
        moveDataIngestionHoverPreview(event);
    }

    function hideDataIngestionHoverPreview() {
        const preview = document.getElementById("dataIngestionHoverPreview");
        if (preview) preview.hidden = true;
    }

    function formatDataIngestionCoverageRank(item, selectedCount) {
        const rankValue = Number(item.rank);
        const scoreValue = Number(item.coverage_score ?? item.selection_score);
        const scoreLabel = Number.isFinite(scoreValue) ? `distance ${scoreValue.toFixed(3)}` : "";
        if (Number.isFinite(rankValue) && rankValue > 0) {
            const suffix = selectedCount > 0 ? `/${selectedCount}` : "";
            return [`Coverage #${Math.round(rankValue)}${suffix}`, scoreLabel].filter(Boolean).join(" · ");
        }
        return ["Coverage after cutoff", scoreLabel ? `distance to keep set ${scoreValue.toFixed(3)}` : ""].filter(Boolean).join(" · ");
    }

    function formatDataIngestionReferenceNovelty(item, totalItems) {
        const rawScore = item.reference_novelty_score ?? item.diversity_score ?? 0;
        const score = Number(rawScore) || 0;
        const percentileValue = Number(item.reference_novelty_percentile);
        const percentile = Number.isFinite(percentileValue) ? `Reference novelty p${Math.round(percentileValue)}` : "";
        const rankValue = Number(item.reference_novelty_rank);
        const rank = Number.isFinite(rankValue) && rankValue > 0 && totalItems > 0 ? `rank ${rankValue}/${totalItems}` : "";
        return [percentile, rank, `distance ${score.toFixed(3)}`].filter(Boolean).join(" · ");
    }

    function formatDataIngestionLocalVendi(item, totalItems) {
        const scoreValue = Number(item?.local_vendi_score);
        if (!Number.isFinite(scoreValue)) {
            return "";
        }
        const percentileValue = Number(item.local_vendi_percentile);
        const percentile = Number.isFinite(percentileValue) ? `Local Vendi p${Math.round(percentileValue)}` : "";
        const rankValue = Number(item.local_vendi_rank);
        const rank = Number.isFinite(rankValue) && rankValue > 0 && totalItems > 0 ? `rank ${rankValue}/${totalItems}` : "";
        const effective = Number(item.local_vendi_effective_patches);
        const effectiveText = Number.isFinite(effective) ? `eff patches ${effective.toFixed(1)}` : "";
        return [percentile, rank, `Vendi score ${scoreValue.toFixed(3)}`, effectiveText].filter(Boolean).join(" · ");
    }

    function dataIngestionSelectionScoreLabel(item = null) {
        const kind = String(
            item?.selection_score_kind ||
            dataIngestionState.currentResult?.summary?.selection_score_kind ||
            dataIngestionState.distribution?.summary?.selection_score_kind ||
            ""
        );
        if (kind === "coverage_percentile_plus_local_vendi") {
            return "priority score";
        }
        if (kind === "coverage_distance") {
            return "coverage distance";
        }
        return "selection score";
    }

    function formatDataIngestionSelectionPriority(item, totalItems, selectedCount = 0, fallbackRank = 0) {
        const rankValue = Number(item?.selection_priority_rank ?? fallbackRank);
        const totalValue = Number(item?.selection_priority_total ?? totalItems);
        const scoreValue = Number(item?.selection_score);
        const rankLabel = Number.isFinite(rankValue) && rankValue > 0
            ? `Selection priority #${Math.round(rankValue)}/${Number.isFinite(totalValue) && totalValue > 0 ? Math.round(totalValue) : totalItems}`
            : "Selection priority";
        const scoreLabel = Number.isFinite(scoreValue) ? `${dataIngestionSelectionScoreLabel(item)} ${scoreValue.toFixed(3)}` : "";
        const cutoffLabel = selectedCount > 0
            ? (Number.isFinite(rankValue) && rankValue > selectedCount ? `after top-${selectedCount} keep cutoff` : "inside keep cutoff")
            : (item?.keep ? "inside keep cutoff" : "after keep cutoff");
        return [rankLabel, scoreLabel, cutoffLabel].filter(Boolean).join(" · ");
    }

    function setDataIngestionDistributionStatus(message, variant = "") {
        if (!dataIngestionElements.distributionStatus) return;
        dataIngestionElements.distributionStatus.textContent = message || "";
        dataIngestionElements.distributionStatus.classList.remove("warn", "error", "success");
        if (variant) {
            dataIngestionElements.distributionStatus.classList.add(variant);
        }
    }

    function formatDataIngestionDistributionError(errorMessage) {
        const raw = String(errorMessage || "").trim();
        if (!raw || raw === "Not Found") {
            return "Map endpoint or job artifacts were not found. Restart the backend if it is still running old code, then rerun candidate analysis. Class Split Dataset Analysis is not required for this map.";
        }
        if (raw === "data_ingestion_embeddings_not_found") {
            return "This job has no saved map embeddings. Rerun candidate analysis to regenerate distribution artifacts. Class Split Dataset Analysis is not required.";
        }
        if (raw === "data_ingestion_reference_thumbnail_not_found") {
            return "Reference preview thumbnails are unavailable for this older job; rerun candidate analysis to regenerate them.";
        }
        return raw;
    }

    function openClassSplitDatasetAnalysisFromIngestion() {
        setActiveTab(TAB_CLASS_SPLIT);
        window.setTimeout(() => {
            initClassSplitExplorer();
            if (classSplitElements.scopeAll) {
                classSplitElements.scopeAll.checked = true;
            }
            if (classSplitElements.scopeSelected) {
                classSplitElements.scopeSelected.checked = false;
            }
            if (classSplitElements.recipePreset) {
                classSplitElements.recipePreset.value = "precise";
                applyEmbeddingRecipePresetToClassSplit("precise");
            }
            refreshClassSplitControls();
            renderClassSplitDatasetAnalysis();
            const panel = classSplitElements.datasetAnalysisPanel || document.getElementById("classSplitDatasetAnalysisPanel");
            if (panel) {
                panel.open = true;
                renderClassSplitDatasetAnalysisGraph(classSplitState.datasetAnalysis, { force: true });
            }
            const setupTarget = document.getElementById("classSplitTitle")?.closest(".class-split-panel") || classSplitElements.runButton || panel;
            if (setupTarget) {
                setupTarget.scrollIntoView({ behavior: "smooth", block: "start" });
            }
            if (classSplitElements.runButton) {
                classSplitElements.runButton.focus({ preventScroll: true });
            }
            setClassSplitJobStatus("Dataset Analysis needs an all-class Class Split result. Scope has been set to All classes; run analysis, then click Run dataset analysis.", "warn");
        }, 80);
    }

    function clearDataIngestionDistribution({ resetGraph = true } = {}) {
        dataIngestionState.distribution = null;
        dataIngestionState.selectedDistributionItemId = "";
        setDataIngestionDistributionStatus("");
        if (resetGraph && dataIngestionElements.distributionGraph) {
            dataIngestionElements.distributionGraph.innerHTML = `<div class="training-help">Map not loaded.</div>`;
        }
        if (resetGraph && dataIngestionElements.distributionDetails) {
            dataIngestionElements.distributionDetails.innerHTML = `<div class="training-help">Click a candidate point to inspect it.</div>`;
        }
    }

    function getDataIngestionDistributionPoints(kind = "") {
        const points = Array.isArray(dataIngestionState.distribution?.points) ? dataIngestionState.distribution.points : [];
        if (!kind) {
            return points;
        }
        return points.filter((point) => String(point?.kind || "") === kind);
    }

    function dataIngestionDistributionPointId(point) {
        return String(point?.item_id || point?.point_id || "");
    }

    function getDataIngestionDistributionPointById(pointId) {
        const target = String(pointId || "");
        if (!target) {
            return null;
        }
        return getDataIngestionDistributionPoints().find((point) => dataIngestionDistributionPointId(point) === target) || null;
    }

    function getDataIngestionDistributionPreviewUrl(point) {
        const thumbPath = String(point?.thumbnail_url || "");
        if (!thumbPath) {
            return "";
        }
        if (/^https?:\/\//i.test(thumbPath)) {
            return thumbPath;
        }
        return `${API_ROOT}${thumbPath}`;
    }

    function formatDataIngestionDistributionPointText(point, totalItems) {
        if (!point) {
            return "";
        }
        if (String(point.kind || "") === "reference") {
            const dims = point.width || point.height ? `${point.width || ""}x${point.height || ""}` : "";
            return [
                `<b>${escapeHtml(point.filename || point.label || "Reference image")}</b>`,
                "existing reference data",
                dims ? escapeHtml(dims) : "",
            ].filter(Boolean).join("<br>");
        }
        if (String(point.kind || "") !== "candidate") {
            return escapeHtml(point.label || point.filename || "point");
        }
        const accepted = dataIngestionState.acceptedItemIds?.has(dataIngestionDistributionPointId(point));
        const dims = point.width || point.height ? `${point.width || ""}x${point.height || ""}` : "";
        return [
            `<b>${escapeHtml(point.filename || "candidate")}</b>`,
            accepted ? "selected to keep" : "not selected",
            escapeHtml(formatDataIngestionSelectionPriority(point, totalItems, 0)),
            escapeHtml(formatDataIngestionCoverageRank(point, 0)),
            escapeHtml(formatDataIngestionReferenceNovelty(point, totalItems)),
            escapeHtml(formatDataIngestionLocalVendi(point, totalItems)),
            dims ? escapeHtml(dims) : "",
        ].filter(Boolean).join("<br>");
    }

    function renderDataIngestionDistributionDetails(point = null) {
        const details = dataIngestionElements.distributionDetails;
        if (!details) return;
        if (!point) {
            details.innerHTML = `<div class="training-help">Click a candidate point to inspect it.</div>`;
            return;
        }
        if (String(point.kind || "") === "reference") {
            const previewUrl = getDataIngestionDistributionPreviewUrl(point);
            const meta = [
                "existing reference data",
                `${point.source_type || "image"}${point.width || point.height ? ` • ${point.width || ""}x${point.height || ""}` : ""}`,
            ].filter(Boolean);
            details.innerHTML = [
                previewUrl ? `<img src="${escapeHtml(previewUrl)}" alt="Reference preview" loading="lazy">` : "",
                `<div class="data-ingestion-distribution-details__meta">`,
                `<strong>${escapeHtml(point.filename || point.label || "Reference image")}</strong>`,
                meta.map((entry) => `<span>${escapeHtml(entry)}</span>`).join(""),
                `</div>`,
            ].join("");
            return;
        }
        if (String(point.kind || "") !== "candidate") {
            details.innerHTML = `<div class="training-help">Click a candidate point to inspect it.</div>`;
            return;
        }
        const pointId = dataIngestionDistributionPointId(point);
        const previewUrl = getDataIngestionDistributionPreviewUrl(point);
        const accepted = dataIngestionState.acceptedItemIds?.has(pointId);
        const totalItems = getDataIngestionDistributionPoints("candidate").length;
        const meta = [
            accepted ? "selected to keep" : "not selected",
            formatDataIngestionSelectionPriority(point, totalItems, 0),
            formatDataIngestionCoverageRank(point, 0),
            formatDataIngestionReferenceNovelty(point, totalItems),
            formatDataIngestionLocalVendi(point, totalItems),
            `${point.source_type || "image"}${point.width || point.height ? ` • ${point.width || ""}x${point.height || ""}` : ""}`,
        ].filter(Boolean);
        details.innerHTML = [
            previewUrl ? `<img src="${escapeHtml(previewUrl)}" alt="Candidate preview" loading="lazy">` : "",
            `<div class="data-ingestion-distribution-details__meta">`,
            `<strong>${escapeHtml(point.filename || "candidate")}</strong>`,
            meta.map((entry) => `<span>${escapeHtml(entry)}</span>`).join(""),
            `</div>`,
            `<div class="data-ingestion-distribution-details__actions">`,
            `<button type="button" class="training-button secondary" data-data-ingestion-detail-toggle>${accepted ? "Discard candidate" : "Keep candidate"}</button>`,
            `</div>`,
        ].join("");
        const toggleButton = details.querySelector("[data-data-ingestion-detail-toggle]");
        if (toggleButton) {
            toggleButton.addEventListener("click", () => {
                setDataIngestionItemAccepted(pointId, !accepted);
            });
        }
    }

    function getDataIngestionDistributionRange(points, axisIndex) {
        const values = points
            .map((point) => Number(point?.projection?.[axisIndex]))
            .filter((value) => Number.isFinite(value));
        if (!values.length) {
            return [-1, 1];
        }
        let min = Math.min(...values);
        let max = Math.max(...values);
        if (min === max) {
            min -= 1;
            max += 1;
        }
        const pad = Math.max((max - min) * 0.08, 1e-6);
        return [min - pad, max + pad];
    }

    function buildDataIngestionDistributionTrace(points, name, marker) {
        const candidates = getDataIngestionDistributionPoints("candidate");
        return {
            type: "scattergl",
            mode: "markers",
            name,
            x: points.map((point) => Number(point?.projection?.[0]) || 0),
            y: points.map((point) => Number(point?.projection?.[1]) || 0),
            customdata: points.map((point) => dataIngestionDistributionPointId(point)),
            text: points.map((point) => formatDataIngestionDistributionPointText(point, candidates.length)),
            hovertemplate: "%{text}<extra></extra>",
            marker,
        };
    }

    function renderDataIngestionDistributionGraph() {
        const graphEl = dataIngestionElements.distributionGraph;
        if (!graphEl) {
            return Promise.resolve(false);
        }
        const points = getDataIngestionDistributionPoints();
        if (!points.length) {
            graphEl.innerHTML = `<div class="training-help">No distribution points returned.</div>`;
            return Promise.resolve(false);
        }
        if (!window.Plotly) {
            graphEl.innerHTML = `<div class="training-help">Plotly did not load; cannot render the distribution map.</div>`;
            return Promise.resolve(false);
        }
        const acceptedIds = dataIngestionState.acceptedItemIds instanceof Set ? dataIngestionState.acceptedItemIds : new Set();
        const referencePoints = points.filter((point) => String(point?.kind || "") === "reference");
        const candidatePoints = points.filter((point) => String(point?.kind || "") === "candidate");
        const acceptedPoints = candidatePoints.filter((point) => acceptedIds.has(dataIngestionDistributionPointId(point)));
        const skippedPoints = candidatePoints.filter((point) => !acceptedIds.has(dataIngestionDistributionPointId(point)));
        const selectedPoint = getDataIngestionDistributionPointById(dataIngestionState.selectedDistributionItemId);
        const traces = [];
        if (referencePoints.length) {
            traces.push(buildDataIngestionDistributionTrace(referencePoints, "Reference dataset", {
                size: 5,
                color: "rgba(148, 163, 184, 0.48)",
                line: { color: "rgba(71, 85, 105, 0.3)", width: 0.4 },
            }));
        }
        if (skippedPoints.length) {
            traces.push(buildDataIngestionDistributionTrace(skippedPoints, "Not selected", {
                size: 8,
                color: "rgba(245, 158, 11, 0.72)",
                line: { color: "rgba(146, 64, 14, 0.7)", width: 0.7 },
            }));
        }
        if (acceptedPoints.length) {
            traces.push(buildDataIngestionDistributionTrace(acceptedPoints, "Selected to keep", {
                size: 10,
                color: "rgba(37, 99, 235, 0.82)",
                line: { color: "rgba(191, 219, 254, 0.95)", width: 1.2 },
            }));
        }
        if (selectedPoint && String(selectedPoint.kind || "") === "candidate") {
            traces.push({
                type: "scatter",
                mode: "markers",
                name: "Current candidate",
                x: [Number(selectedPoint.projection?.[0]) || 0],
                y: [Number(selectedPoint.projection?.[1]) || 0],
                customdata: [dataIngestionDistributionPointId(selectedPoint)],
                text: [formatDataIngestionDistributionPointText(selectedPoint, candidatePoints.length)],
                hovertemplate: "%{text}<extra></extra>",
                marker: {
                    size: 22,
                    color: "rgba(250, 204, 21, 0.3)",
                    line: { color: "#facc15", width: 3 },
                    symbol: "circle-open",
                },
            });
        }
        const theme = getClassSplitPlotTheme();
        const layout = {
            paper_bgcolor: theme.paper,
            plot_bgcolor: theme.plot,
            font: { color: theme.text, family: "system-ui, -apple-system, BlinkMacSystemFont, sans-serif" },
            margin: { l: 42, r: 16, t: 20, b: 42 },
            xaxis: {
                title: "reference profile axis 1",
                range: getDataIngestionDistributionRange(points, 0),
                zeroline: false,
                gridcolor: theme.grid,
                linecolor: theme.grid,
            },
            yaxis: {
                title: "reference profile axis 2",
                range: getDataIngestionDistributionRange(points, 1),
                zeroline: false,
                gridcolor: theme.grid,
                linecolor: theme.grid,
            },
            legend: {
                orientation: "h",
                y: 1.08,
                x: 0,
                bgcolor: "rgba(0,0,0,0)",
            },
            dragmode: "pan",
            uirevision: [
                "data-ingestion-distribution",
                dataIngestionState.activeJobId || "live",
                points.length,
            ].join(":"),
        };
        return window.Plotly.react(graphEl, traces, layout, {
            responsive: true,
            displaylogo: false,
            scrollZoom: true,
            modeBarButtonsToRemove: ["toImage"],
        }).then(() => {
            if (typeof graphEl.removeAllListeners === "function") {
                ["plotly_click", "plotly_hover", "plotly_unhover"].forEach((eventName) => graphEl.removeAllListeners(eventName));
            }
            graphEl.on("plotly_click", (event) => {
                const pointId = String(event?.points?.[0]?.customdata || "");
                const point = getDataIngestionDistributionPointById(pointId);
                if (point) {
                    dataIngestionState.selectedDistributionItemId = dataIngestionDistributionPointId(point);
                    renderDataIngestionDistributionDetails(point);
                    renderDataIngestionDistributionGraph();
                }
            });
            graphEl.on("plotly_hover", (event) => {
                const pointId = String(event?.points?.[0]?.customdata || "");
                const point = getDataIngestionDistributionPointById(pointId);
                const previewUrl = getDataIngestionDistributionPreviewUrl(point);
                if (point && previewUrl && event?.event) {
                    showDataIngestionHoverPreview(event.event, previewUrl, point.filename || "candidate");
                } else {
                    hideDataIngestionHoverPreview();
                }
            });
            graphEl.on("plotly_unhover", hideDataIngestionHoverPreview);
            return true;
        }).catch((error) => {
            console.warn("Data Ingestion distribution graph render failed", error);
            graphEl.innerHTML = `<div class="training-help error">Distribution map failed: ${escapeHtml(error.message || error)}</div>`;
            return false;
        });
    }

    async function loadDataIngestionDistribution() {
        if (!dataIngestionState.currentResult || !dataIngestionState.activeJobId || dataIngestionState.distributionInFlight) {
            return;
        }
        dataIngestionState.distributionInFlight = true;
        setDataIngestionDistributionStatus("Loading map ...");
        refreshDataIngestionControls();
        try {
            const resp = await fetch(`${API_ROOT}/data_ingestion/jobs/${encodeURIComponent(dataIngestionState.activeJobId)}/distribution`);
            const detail = await resp.text();
            if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            const payload = parseJsonObjectSafe(detail, {});
            dataIngestionState.distribution = payload;
            dataIngestionState.selectedDistributionItemId = "";
            const summary = payload.summary || {};
            const candidateCount = Number(summary.candidate_point_count || 0);
            const referenceCount = Number(summary.reference_point_count || 0);
            setDataIngestionDistributionStatus(`${candidateCount} candidates projected onto ${referenceCount} reference images.`, "success");
            renderDataIngestionDistributionDetails();
            await renderDataIngestionDistributionGraph();
        } catch (error) {
            console.error("Data Ingestion distribution load failed", error);
            setDataIngestionDistributionStatus(`Map failed: ${formatDataIngestionDistributionError(error.message || error)}`, "error");
        } finally {
            dataIngestionState.distributionInFlight = false;
            refreshDataIngestionControls();
        }
    }

    async function downloadDataIngestionReferenceProfile() {
        const profileId = String(dataIngestionElements.saladHead?.value || "").trim();
        if (!profileId) {
            setDataIngestionStatus("Choose a reference profile to download.", "warn");
            return;
        }
        try {
            const resp = await fetch(`${API_ROOT}/data_ingestion/reference_profiles/${encodeURIComponent(profileId)}/export`);
            const detail = resp.ok ? "" : await resp.text();
            if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            const blob = await resp.blob();
            saveBlobToDisk(blob, filenameFromResponse(resp, `${profileId}.reference_profile.zip`));
            setDataIngestionStatus("Reference profile downloaded.", "success");
        } catch (error) {
            console.error("Reference profile download failed", error);
            setDataIngestionStatus(`Download failed: ${error.message || error}`, "error");
        }
    }

    async function uploadDataIngestionReferenceProfile(file) {
        if (!file || dataIngestionState.profileImportInFlight) return;
        dataIngestionState.profileImportInFlight = true;
        refreshDataIngestionControls();
        try {
            const formData = new FormData();
            formData.append("file", file, file.name || "reference_profile.zip");
            const resp = await fetch(`${API_ROOT}/data_ingestion/reference_profiles/import`, { method: "POST", body: formData });
            const detail = await resp.text();
            if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            const payload = parseJsonObjectSafe(detail, {});
            const importedId = String(payload.id || "").trim();
            if (importedId) {
                dataIngestionState.preferredSaladHeadId = importedId;
            }
            await refreshDataIngestionCapabilities();
            const importedHead = (Array.isArray(dataIngestionState.capabilities?.local_salad_heads) ? dataIngestionState.capabilities.local_salad_heads : [])
                .find((head) => String(head?.id || "") === importedId);
            if (importedHead && importedId && dataIngestionHeadMatchesReference(importedHead)) {
                setSelectValueIfPresent(dataIngestionElements.saladHead, importedId);
                setDataIngestionStatus(`Reference profile imported and selected: ${importedId}.`, "success");
            } else {
                setDataIngestionStatus("Reference profile imported but not selected because it belongs to a different reference dataset.", "warn");
            }
            refreshDataIngestionControls();
        } catch (error) {
            console.error("Reference profile import failed", error);
            setDataIngestionStatus(`Import failed: ${error.message || error}`, "error");
        } finally {
            dataIngestionState.profileImportInFlight = false;
            if (dataIngestionElements.profileUploadInput) dataIngestionElements.profileUploadInput.value = "";
            refreshDataIngestionControls();
        }
    }

    function renderDataIngestionTilePreview(outputs) {
        if (!dataIngestionElements.tilePreview) return;
        const rows = Array.isArray(outputs) ? outputs : [];
        if (!rows.length) {
            dataIngestionElements.tilePreview.innerHTML = `<div class="training-help">No preview outputs yet.</div>`;
            return;
        }
        dataIngestionElements.tilePreview.innerHTML = rows.map((output) => {
            const dims = `${escapeHtml(output.output_width || "")}x${escapeHtml(output.output_height || "")}`;
            const bounds = Array.isArray(output.source_bounds) ? output.source_bounds.join(",") : "";
            const thumbUrl = output.thumbnail_url ? `${API_ROOT}${output.thumbnail_url}` : "";
            return [
                `<label class="data-ingestion-tile-card">`,
                thumbUrl ? `<img src="${escapeHtml(thumbUrl)}" alt="Accepted output preview" loading="lazy">` : "",
                `<span>${escapeHtml(output.source_filename || output.output_filename || "output")}</span>`,
                `<span>${dims}${bounds ? ` • ${escapeHtml(bounds)}` : ""}</span>`,
                `</label>`,
            ].join("");
        }).join("");
    }

    async function previewDataIngestionAcceptedOutputs() {
        if (!dataIngestionState.currentResult || dataIngestionState.acceptedPreviewInFlight) return;
        dataIngestionState.acceptedPreviewInFlight = true;
        renderDataIngestionTilePreview([]);
        refreshDataIngestionControls();
        try {
            const resp = await fetch(`${API_ROOT}/data_ingestion/jobs/${encodeURIComponent(dataIngestionState.activeJobId)}/accepted_export/preview`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(getDataIngestionAcceptedExportPayload({ limit: 80 })),
            });
            const detail = await resp.text();
            if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            const payload = parseJsonObjectSafe(detail, {});
            const outputs = Array.isArray(payload.outputs) ? payload.outputs : [];
            dataIngestionState.lastPreview = payload;
            renderDataIngestionTilePreview(outputs);
            renderDataIngestionAcceptedSummary();
            setDataIngestionStatus(`Preview ready: ${payload.total_outputs || outputs.length} output(s).`, "success");
        } catch (error) {
            console.error("Accepted output preview failed", error);
            setDataIngestionStatus(`Preview failed: ${error.message || error}`, "error");
        } finally {
            dataIngestionState.acceptedPreviewInFlight = false;
            refreshDataIngestionControls();
        }
    }

    async function downloadDataIngestionAcceptedZip() {
        if (!dataIngestionState.currentResult || dataIngestionState.acceptedDownloadInFlight) return;
        dataIngestionState.acceptedDownloadInFlight = true;
        refreshDataIngestionControls();
        try {
            const resp = await fetch(`${API_ROOT}/data_ingestion/jobs/${encodeURIComponent(dataIngestionState.activeJobId)}/accepted_export/download`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(getDataIngestionAcceptedExportPayload()),
            });
            const detail = resp.ok ? "" : await resp.text();
            if (!resp.ok) throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            const blob = await resp.blob();
            saveBlobToDisk(blob, filenameFromResponse(resp, "accepted_data.zip"));
            setDataIngestionStatus("Accepted data ZIP downloaded.", "success");
        } catch (error) {
            console.error("Accepted data download failed", error);
            setDataIngestionStatus(`Download failed: ${error.message || error}`, "error");
        } finally {
            dataIngestionState.acceptedDownloadInFlight = false;
            refreshDataIngestionControls();
        }
    }

    async function loadDataIngestionResult(jobId) {
        const resp = await fetch(`${API_ROOT}/data_ingestion/jobs/${encodeURIComponent(jobId)}/result`);
        const detail = await resp.text();
        if (resp.ok) {
            renderDataIngestionResult(parseJsonObjectSafe(detail, {}));
        }
    }

    function showAllDataIngestionCandidates() {
        const items = getDataIngestionResultItems();
        dataIngestionState.visibleItemLimit = Math.max(items.length, 120);
        renderDataIngestionResult(dataIngestionState.currentResult, {
            preserveSelection: true,
            preserveDistribution: true,
        });
    }

    function renderDataIngestionResult(result, { preserveSelection = false, preserveDistribution = false } = {}) {
        hideDataIngestionHoverPreview();
        const summary = result?.summary || {};
        const items = Array.isArray(result?.items) ? result.items : [];
        const isProfileBuild = !!String(summary.head_id || "").trim() && !items.length;
        if (!preserveDistribution) {
            clearDataIngestionDistribution();
        }
        dataIngestionState.currentResult = isProfileBuild ? null : result;
        const previousAcceptedIds = dataIngestionState.acceptedItemIds instanceof Set
            ? new Set(dataIngestionState.acceptedItemIds)
            : new Set();
        dataIngestionState.acceptedItemIds = preserveSelection && !isProfileBuild
            ? previousAcceptedIds
            : new Set(isProfileBuild ? [] : items.filter((item) => !!item.keep).map(dataIngestionResultItemId));
        dataIngestionState.lastPreview = null;
        if (dataIngestionElements.results) dataIngestionElements.results.hidden = false;
        if (dataIngestionElements.acceptance) dataIngestionElements.acceptance.hidden = isProfileBuild || !items.length;
        if (dataIngestionElements.distribution) dataIngestionElements.distribution.hidden = isProfileBuild || !items.length;
        if (dataIngestionElements.reportTitle) {
            dataIngestionElements.reportTitle.textContent = isProfileBuild ? "Reference profile report" : "Ingestion report";
        }
        if (dataIngestionElements.listTitle) {
            dataIngestionElements.listTitle.textContent = isProfileBuild ? "Next step" : "Candidate priority ranking";
        }
        if (dataIngestionElements.report) {
            const rows = isProfileBuild
                ? [
                    ["Profile", summary.head_id || ""],
                    ["Reference", summary.reference_dataset_label || summary.reference_label || summary.source_mode || ""],
                    ["Source", summary.reference_source || summary.source_mode || ""],
                    ["Base encoder", summary.encoder_type || ""],
                    ["Reference images", summary.train_image_count ?? 0],
                    ["Epochs", summary.epochs ?? ""],
                    ["Batch size", summary.batch_size ?? ""],
                    ["Final loss", summary.loss_final == null ? "n/a" : Number(summary.loss_final || 0).toFixed(4)],
                ]
                : [
                    ["Profile", summary.head_id || summary.salad_head_id || ""],
                    ["Reference", summary.reference_dataset_label || summary.reference_label || summary.source_mode || ""],
                    ["Source", summary.reference_source || summary.source_mode || ""],
                    ["Encoder", summary.encoder_type || summary.encoder || "local_salad"],
                    ["Profile policy", formatDataIngestionProfilePolicy(summary.local_salad_policy || summary.policy)],
                    ["Candidates", summary.candidate_image_count ?? summary.train_image_count ?? summary.item_count ?? 0],
                    ["Reference images", summary.reference_count ?? 0],
                    ["Keep fraction", summary.keep_fraction ?? ""],
                    ["Selected", summary.selected_count ?? ""],
                    ["Selection", summary.selection_method || ""],
                    ["Local Vendi", summary.local_vendi_enabled ? `weight ${Number(summary.local_vendi_weight || 0).toFixed(2)} • mean ${Number(summary.local_vendi_mean || 0).toFixed(3)}` : "off"],
                    ["Mean NN distance", Number(summary.mean_nearest_neighbor_distance || 0).toFixed(3)],
                    ["Mean reference distance", summary.mean_reference_distance == null ? "n/a" : Number(summary.mean_reference_distance || 0).toFixed(3)],
                ];
            dataIngestionElements.report.innerHTML = `<div class="data-ingestion-report__grid">${
                rows.map(([label, value]) => `<div class="data-ingestion-report__item"><strong>${escapeHtml(label)}</strong><span>${escapeHtml(String(value))}</span></div>`).join("")
            }</div>`;
        }
        if (dataIngestionElements.list) {
            if (isProfileBuild) {
                dataIngestionElements.list.innerHTML = `<div class="training-help">Profile ready for candidate review. Choose candidate media and run analysis when ready.</div>`;
            } else if (!items.length) {
                dataIngestionElements.list.innerHTML = `<div class="training-help">No ranked candidates for this job.</div>`;
            } else {
                const selectedCount = Number(summary.selected_count ?? items.filter((entry) => !!entry.keep).length) || 0;
                const selectionDescription = String(summary.selection_score_description || "").trim();
                const scoreNote = [
                    `<div class="training-help data-ingestion-score-note">`,
                    `Ordered by selection priority across the whole pooled upload batch. The top ${selectedCount} are kept by the keep fraction; rejected frames continue below the cutoff by final ${dataIngestionSelectionScoreLabel()}.`,
                    selectionDescription ? ` Score basis: ${escapeHtml(selectionDescription)}.` : "",
                    `</div>`,
                ].join("");
                const visibleLimit = Math.max(1, Number(dataIngestionState.visibleItemLimit) || 120);
                const visibleItems = items.slice(0, visibleLimit);
                const listControls = items.length > visibleItems.length
                    ? [
                        `<div class="data-ingestion-list-controls">`,
                        `<span class="training-help">Showing ${visibleItems.length} of ${items.length} candidates.</span>`,
                        `<button type="button" class="training-button secondary" data-data-ingestion-show-all>Show all candidates</button>`,
                        `</div>`,
                    ].join("")
                    : "";
                dataIngestionElements.list.innerHTML = scoreNote + listControls + visibleItems.map((item, visibleIndex) => {
                    const itemId = dataIngestionResultItemId(item);
                    const accepted = dataIngestionState.acceptedItemIds.has(itemId);
                    const originalKeep = !!item.keep;
                    const checked = accepted ? " checked" : "";
                    const previewUrl = item.thumbnail_url ? `${API_ROOT}${item.thumbnail_url}` : "";
                    const sourceType = String(item.source_type || "image");
                    const dimensions = `${escapeHtml(item.width || "")}x${escapeHtml(item.height || "")}`;
                    const priority = formatDataIngestionSelectionPriority(item, items.length, selectedCount, visibleIndex + 1);
                    const coverage = formatDataIngestionCoverageRank(item, selectedCount);
                    const novelty = formatDataIngestionReferenceNovelty(item, items.length);
                    const vendi = formatDataIngestionLocalVendi(item, items.length);
                    const title = [
                        "Rows are ordered by selection priority.",
                        "Coverage distance measures upload-batch diversity.",
                        "Reference novelty is nearest-reference cosine distance.",
                        "Local Vendi is a Vendi-style local patch diversity bonus.",
                        selectionDescription ? `Score basis: ${selectionDescription}.` : "",
                    ].filter(Boolean).join(" ");
                    const stateLabel = accepted
                        ? (originalKeep ? `Keep #${escapeHtml(item.rank || "")}` : "Keep manual")
                        : (originalKeep ? `Discarded keep #${escapeHtml(item.rank || "")}` : "Reject");
                    const metricRows = [
                        ["Priority", priority],
                        ["Coverage", coverage],
                        ["Reference", novelty],
                        vendi ? ["Local Vendi", vendi] : null,
                        ["Source", `${sourceType} · ${dimensions}`],
                    ].filter(Boolean);
                    return [
                        `<div class="data-ingestion-list__item${accepted ? " is-keep" : ""}" data-data-ingestion-preview-url="${escapeHtml(previewUrl)}" data-data-ingestion-preview-label="${escapeHtml(item.filename || item.saved_name || "candidate")}" title="${escapeHtml(title)}">`,
                        `<label>`,
                        `<input type="checkbox" data-data-ingestion-item-id="${escapeHtml(itemId)}"${checked}>`,
                        `<span class="data-ingestion-list__content">`,
                        `<span class="data-ingestion-list__title"><strong>${stateLabel}</strong> ${escapeHtml(item.filename || item.saved_name || "candidate")}</span>`,
                        `<span class="data-ingestion-list__metrics">`,
                        metricRows.map(([label, value]) => `<span><b>${escapeHtml(label)}</b>${escapeHtml(value)}</span>`).join(""),
                        `</span>`,
                        `</span>`,
                        `</label>`,
                        `</div>`,
                    ].join("");
                }).join("");
                dataIngestionElements.list.querySelectorAll("[data-data-ingestion-preview-url]").forEach((card) => {
                    const previewUrl = String(card.getAttribute("data-data-ingestion-preview-url") || "");
                    const previewLabel = String(card.getAttribute("data-data-ingestion-preview-label") || "");
                    if (!previewUrl) return;
                    card.addEventListener("mouseenter", (event) => showDataIngestionHoverPreview(event, previewUrl, previewLabel));
                    card.addEventListener("mousemove", moveDataIngestionHoverPreview);
                    card.addEventListener("mouseleave", hideDataIngestionHoverPreview);
                });
                const showAllButton = dataIngestionElements.list.querySelector("[data-data-ingestion-show-all]");
                if (showAllButton) {
                    showAllButton.addEventListener("click", showAllDataIngestionCandidates);
                }
                dataIngestionElements.list.querySelectorAll("[data-data-ingestion-item-id]").forEach((checkbox) => {
                    checkbox.addEventListener("change", () => {
                        const itemId = String(checkbox.getAttribute("data-data-ingestion-item-id") || "");
                        if (!itemId) return;
                        setDataIngestionItemAccepted(itemId, checkbox.checked);
                    });
                });
            }
        }
        renderDataIngestionAcceptWarning();
        renderDataIngestionAcceptedSummary();
        renderDataIngestionTilePreview([]);
        refreshDataIngestionControls();
    }

