    function publicClassSplitActiveWorkspaceRows(rows) {
        return (Array.isArray(rows) ? rows : []).map((row) => ({
            split: row.split,
            upload_name: row.upload_name,
            image_relpath: row.image_relpath,
            image_name: row.image_name,
            frontend_image_key: row.frontend_image_key,
            label_lines: row.label_lines,
            text_label: row.text_label,
        }));
    }

    function buildClassSplitActiveWorkspaceSnapshot(request, { onProgress = null } = {}) {
        captureCurrentAnnotationDirtyState();
        const labelmap = getClassSplitLabelmapEntries();
        if (!labelmap.length) {
            throw new Error("Load a labelmap in Label Images before running Class Split Explorer.");
        }
        const scope = String(request.analysis_scope || "selected_class");
        const className = String(request.class_name || "").trim();
        const rows = [];
        const usedNames = new Set();
        let objectCount = 0;
        const imageKeys = getClassSplitImageKeys();
        const totalImages = imageKeys.length;
        const reportSnapshotProgress = (processed, message = "") => {
            if (typeof onProgress !== "function") {
                return;
            }
            const progress = totalImages > 0 ? Math.max(0, Math.min(1, processed / totalImages)) : 0;
            onProgress({
                progress,
                processed,
                total: totalImages,
                imageCount: rows.length,
                objectCount,
                message: message || `Snapshot-packaging ${processed}/${totalImages} active images (${objectCount} objects matched) ...`,
            });
        };
        reportSnapshotProgress(0, `Snapshot-packaging 0/${totalImages} active images ...`);
        let processedImages = 0;
        for (const imageKey of imageKeys) {
            processedImages += 1;
            const imageRecord = images?.[imageKey];
            if (!imageRecord) {
                reportSnapshotProgress(processedImages);
                continue;
            }
            const labelLines = getClassSplitActiveLabelLines(imageKey)
                .filter((line) => classSplitLineMatchesScope(line, scope, className, labelmap));
            if (!labelLines.length) {
                reportSnapshotProgress(processedImages);
                continue;
            }
            const uploadName = makeClassSplitUploadName(imageKey, usedNames);
            rows.push({
                _image_key: imageKey,
                split: "train",
                upload_name: uploadName,
                image_relpath: uploadName,
                image_name: String(imageRecord.displayName || imageRecord.meta?.name || imageKey),
                frontend_image_key: imageKey,
                label_lines: labelLines,
                text_label: String(textLabels?.[imageKey] || ""),
            });
            objectCount += labelLines.length;
            reportSnapshotProgress(processedImages);
        }
        if (!rows.length || objectCount <= 0) {
            throw new Error("No labeled objects in the active Label Images workspace match the selected scope.");
        }
        const manifest = {
            dataset_label: annotationSourceState.datasetLabel || "Active Label Images workspace",
            labelmap,
            images: rows,
            request,
            yolo_layout: "flat",
        };
        reportSnapshotProgress(totalImages, `Snapshot packaged ${rows.length}/${totalImages} images and ${objectCount} objects.`);
        return { manifest, rows, imageCount: rows.length, objectCount };
    }

    async function buildClassSplitActiveWorkspaceFormFromSnapshot(snapshot) {
        const formData = new FormData();
        for (const row of snapshot.rows) {
            const imageKey = row._image_key || row.frontend_image_key;
            const imageRecord = images?.[imageKey];
            if (!imageRecord) {
                throw new Error(`Image is not loaded in this session: ${imageKey}`);
            }
            const blob = await getClassSplitImageBlob(imageKey, imageRecord);
            formData.append("files", blob, row.upload_name);
        }
        formData.append("manifest", JSON.stringify({
            ...snapshot.manifest,
            images: publicClassSplitActiveWorkspaceRows(snapshot.rows),
        }));
        return { formData, imageCount: snapshot.imageCount, objectCount: snapshot.objectCount };
    }

    async function buildClassSplitActiveWorkspaceForm(request, { onProgress = null } = {}) {
        const snapshot = buildClassSplitActiveWorkspaceSnapshot(request, { onProgress });
        return buildClassSplitActiveWorkspaceFormFromSnapshot(snapshot);
    }

    function postClassSplitActiveWorkspaceForm(formData, { signal = null, onProgress = null } = {}) {
        return new Promise((resolve, reject) => {
            const xhr = new XMLHttpRequest();
            let settled = false;
            const cleanup = () => {
                if (signal) {
                    signal.removeEventListener("abort", handleAbort);
                }
            };
            const settleReject = (error) => {
                if (settled) {
                    return;
                }
                settled = true;
                cleanup();
                reject(error);
            };
            const handleAbort = () => {
                try {
                    xhr.abort();
                } catch (_) {
                    // Ignore abort races; the rejection below carries the useful state.
                }
                settleReject(new DOMException("Class Split upload cancelled.", "AbortError"));
            };
            if (signal?.aborted) {
                handleAbort();
                return;
            }
            if (signal) {
                signal.addEventListener("abort", handleAbort, { once: true });
            }
            xhr.open("POST", `${API_ROOT}/class_analysis/jobs/active_workspace`);
            xhr.upload.onprogress = (event) => {
                if (typeof onProgress !== "function") {
                    return;
                }
                if (event.lengthComputable && event.total > 0) {
                    onProgress({
                        progress: Math.max(0, Math.min(1, event.loaded / event.total)),
                        loaded: event.loaded,
                        total: event.total,
                        message: `Snapshot-uploading ${Math.round((event.loaded / event.total) * 100)}% ...`,
                    });
                } else {
                    onProgress({
                        progress: null,
                        loaded: event.loaded || 0,
                        total: 0,
                        message: "Snapshot-uploading active workspace ...",
                    });
                }
            };
            xhr.onload = () => {
                if (settled) {
                    return;
                }
                settled = true;
                cleanup();
                const text = String(xhr.responseText || "");
                resolve({
                    ok: xhr.status >= 200 && xhr.status < 300,
                    status: xhr.status,
                    text: async () => text,
                });
            };
            xhr.onerror = () => settleReject(new Error("Class Split active workspace upload failed."));
            xhr.onabort = () => settleReject(new DOMException("Class Split upload cancelled.", "AbortError"));
            xhr.send(formData);
        });
    }

    async function postClassSplitActiveWorkspaceChunked(snapshot, { signal = null, onProgress = null } = {}) {
        const total = Math.max(0, Array.isArray(snapshot?.rows) ? snapshot.rows.length : 0);
        if (!total) {
            throw new Error("No active workspace images to upload.");
        }
        const report = (completed, message) => {
            if (typeof onProgress !== "function") {
                return;
            }
            const progress = total > 0 ? Math.max(0, Math.min(1, completed / total)) : 0;
            onProgress({
                progress,
                completed,
                total,
                message: message || `Snapshot-uploading ${Math.round(progress * 100)}% (${completed}/${total} images) ...`,
            });
        };
        const startResp = await fetch(`${API_ROOT}/class_analysis/jobs/active_workspace/upload_session/start`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                ...snapshot.manifest,
                images: [],
                total_images: total,
            }),
            signal,
        });
        const startDetail = await startResp.text();
        if (!startResp.ok) {
            throw new Error(parseApiError(startDetail, `HTTP ${startResp.status}`));
        }
        const startData = parseJsonObjectSafe(startDetail, {});
        const sessionId = String(startData.session_id || startData.job_id || "").trim();
        if (!sessionId) {
            throw new Error("Class Split active workspace upload session did not return an id.");
        }
        classSplitState.activeUploadSessionId = sessionId;
        refreshClassSplitControls();
        let completed = 0;
        try {
            const batchSize = 32;
            for (let start = 0; start < snapshot.rows.length; start += batchSize) {
                const rows = snapshot.rows.slice(start, start + batchSize);
                const formData = new FormData();
                formData.append("manifest", JSON.stringify({ images: publicClassSplitActiveWorkspaceRows(rows) }));
                for (const row of rows) {
                    const imageKey = row._image_key || row.frontend_image_key;
                    const imageRecord = images?.[imageKey];
                    if (!imageRecord) {
                        throw new Error(`Image is not loaded in this session: ${imageKey}`);
                    }
                    const blob = await getClassSplitImageBlob(imageKey, imageRecord);
                    formData.append("files", blob, row.upload_name);
                }
                report(completed, `Snapshot-uploading ${Math.round((completed / total) * 100)}% (${completed}/${total} images) ...`);
                const batchResp = await fetch(`${API_ROOT}/class_analysis/jobs/active_workspace/upload_session/${encodeURIComponent(sessionId)}/batch`, {
                    method: "POST",
                    body: formData,
                    signal,
                });
                const batchDetail = await batchResp.text();
                if (!batchResp.ok) {
                    throw new Error(parseApiError(batchDetail, `HTTP ${batchResp.status}`));
                }
                completed += rows.length;
                report(completed);
            }
            const finalizeResp = await fetch(`${API_ROOT}/class_analysis/jobs/active_workspace/upload_session/${encodeURIComponent(sessionId)}/finalize`, {
                method: "POST",
                signal,
            });
            const finalizeDetail = await finalizeResp.text();
            if (!finalizeResp.ok) {
                throw new Error(parseApiError(finalizeDetail, `HTTP ${finalizeResp.status}`));
            }
            return {
                ok: true,
                status: finalizeResp.status,
                text: async () => finalizeDetail,
            };
        } catch (error) {
            try {
                await fetch(`${API_ROOT}/class_analysis/jobs/active_workspace/upload_session/${encodeURIComponent(sessionId)}/cancel`, { method: "POST" });
            } catch (cancelError) {
                console.warn("Class Split active workspace upload cleanup failed", cancelError);
            }
            throw error;
        } finally {
            if (classSplitState.activeUploadSessionId === sessionId) {
                classSplitState.activeUploadSessionId = "";
                refreshClassSplitControls();
            }
        }
    }

    function getClassSplitServerSourceHandle() {
        const mode = String(annotationSourceState.mode || "").trim().toLowerCase();
        const datasetId = String(annotationSourceState.datasetId || "").trim();
        if (mode === "linked" && datasetId) {
            const stats = getClassSplitActiveWorkspaceStats();
            return {
                sourceMode: "dataset",
                datasetId,
                sessionId: "",
                imageCount: stats.imageCount,
                objectCount: stats.objectCount,
                label: annotationSourceState.datasetLabel || datasetId,
            };
        }
        const sessionId = String(annotationSourceState.sessionId || "").trim();
        if (mode === "transient" && sessionId) {
            const stats = getClassSplitActiveWorkspaceStats();
            return {
                sourceMode: "transient",
                datasetId: "",
                sessionId,
                imageCount: stats.imageCount,
                objectCount: stats.objectCount,
                label: annotationSourceState.datasetLabel || sessionId,
            };
        }
        return null;
    }

    function classSplitHashValues(values = []) {
        let hash = 2166136261;
        const append = (value) => {
            const text = String(value || "");
            for (let i = 0; i < text.length; i += 1) {
                hash ^= text.charCodeAt(i);
                hash = Math.imul(hash, 16777619) >>> 0;
            }
            hash ^= 0xff;
            hash = Math.imul(hash, 16777619) >>> 0;
        };
        values.forEach(append);
        return hash >>> 0;
    }

    function invalidateClassSplitPointImageLookup() {
        classSplitState.pointImageLookup = null;
        classSplitState.pointImageLookupSignature = "";
    }

    async function getClassSplitServerAnalysisSourceHandle() {
        return getClassSplitServerSourceHandle();
    }

    function getClassSplitClassCounts() {
        return getClassSplitActiveWorkspaceStats().counts;
    }

    function getClassSplitSampleCap() {
        const raw = String(classSplitElements.sampleCap?.value || "").trim();
        if (!raw) {
            return 0;
        }
        const parsed = parseInt(raw, 10);
        if (!Number.isFinite(parsed) || parsed <= 0) {
            return 0;
        }
        return Math.min(50000, parsed);
    }

    function markClassSplitRecipeCustom() {
        if (classSplitElements.recipePreset && classSplitElements.recipePreset.value !== "custom") {
            classSplitElements.recipePreset.value = "custom";
        }
    }

    function applyEmbeddingRecipePresetToClassSplit(preset) {
        const key = String(preset || "balanced").toLowerCase();
        if (key === "custom") {
            updateClassSplitEmbeddingRecipeExplanation();
            return;
        }
        const values = embeddingRecipePresetValues(key);
        if (classSplitElements.canonicalSize) {
            classSplitElements.canonicalSize.value = values.canonicalSize;
        }
        if (classSplitElements.padding) {
            classSplitElements.padding.value = values.padding;
        }
        setSelectValueIfPresent(classSplitElements.preprocessMode, values.preprocessMode);
        setSelectValueIfPresent(classSplitElements.sizeBiasMode, values.adjustment);
        setSelectValueIfPresent(classSplitElements.dinov3Pooling, values.dinov3Pooling);
        setSelectValueIfPresent(classSplitElements.cradioPooling, values.cradioPooling || "summary");
        if (values.encoderType) {
            setSelectValueIfPresent(classSplitElements.encoderType, values.encoderType);
            updateClassSplitBackboneOptions();
        }
        setSelectValueIfPresent(classSplitElements.backgroundMode, values.backgroundMode);
        setSelectValueIfPresent(classSplitElements.viewMode, values.viewMode);
        updateClassSplitEmbeddingRecipeExplanation();
    }

    function populateClassSplitClasses({ preserveSelection = true } = {}) {
        const selectEl = classSplitElements.classSelect;
        if (!selectEl) {
            return;
        }
        const previous = preserveSelection ? selectEl.value : "";
        const classesAvailable = Array.isArray(loadedClassList)
            ? loadedClassList.map((name) => String(name || "").trim()).filter(Boolean)
            : [];
        const counts = getClassSplitClassCounts();
        selectEl.innerHTML = "";
        classesAvailable.forEach((className) => {
            const option = document.createElement("option");
            option.value = className;
            const count = counts.get(className) || 0;
            option.textContent = count > 0 ? `${className} (${count})` : className;
            selectEl.appendChild(option);
        });
        const desired = previous || currentClass || (classesAvailable.length ? classesAvailable[0] : "");
        if (desired && classesAvailable.includes(desired)) {
            selectEl.value = desired;
        }
        selectEl.disabled = !classesAvailable.length || getClassSplitScope() !== "selected_class";
    }

    function syncClassSplitCurrentClassSelection() {
        const selectEl = classSplitElements.classSelect;
        if (!selectEl || getClassSplitScope() !== "selected_class" || !currentClass) {
            return;
        }
        const values = Array.from(selectEl.options || []).map((option) => option.value);
        if (values.includes(currentClass)) {
            selectEl.value = currentClass;
        }
    }

    function isClassSplitTabActive() {
        return activeTab === TAB_CLASS_SPLIT;
    }

    function scheduleClassSplitControlsRefresh({ delay = 140, preferCurrentClass = false } = {}) {
        if (!classSplitState.initialized) {
            return;
        }
        if (!isClassSplitTabActive()) {
            return;
        }
        if (classSplitControlsRefreshTimer) {
            window.clearTimeout(classSplitControlsRefreshTimer);
        }
        classSplitControlsRefreshTimer = window.setTimeout(() => {
            classSplitControlsRefreshTimer = null;
            refreshClassSplitControls({ preferCurrentClass });
        }, Math.max(0, Number(delay) || 0));
    }

    async function loadClassSplitClipBackbones() {
        try {
            const resp = await fetch(`${API_ROOT}/clip/backbones`);
            if (!resp.ok) {
                throw new Error(`HTTP ${resp.status}`);
            }
            const data = await resp.json();
            classSplitState.clipBackbones = Array.isArray(data.available)
                ? data.available.map((entry) => String(entry || "").trim()).filter(Boolean)
                : [];
        } catch (error) {
            console.warn("Failed to load Class Split CLIP backbones", error);
            classSplitState.clipBackbones = [];
        }
    }

    async function loadClassSplitCapabilities() {
        try {
            const resp = await fetch(`${API_ROOT}/class_analysis/capabilities`);
            if (!resp.ok) {
                throw new Error(`HTTP ${resp.status}`);
            }
            classSplitState.capabilities = await resp.json();
        } catch (error) {
            console.warn("Failed to load Class Split capabilities", error);
            classSplitState.capabilities = {
                default_encoder_type: "dinov3",
                default_dinov3_model: "facebook/dinov3-vitb16-pretrain-lvd1689m",
                default_clip_model: "",
                projection_methods: ["pca"],
            };
        }
        updateClassSplitBackboneOptions();
        updateClassSplitProjectionOptions();
        applyClassSplitProjectionDefaultForScope();
        refreshClassSplitControls();
    }

    function updateClassSplitProjectionOptions() {
        const selects = [classSplitElements.projection, classSplitElements.graphProjection].filter(Boolean);
        if (!selects.length) {
            return;
        }
        const pcaModes = Array.isArray(classSplitState.capabilities?.pca_projection_modes)
            ? classSplitState.capabilities.pca_projection_modes
            : ["global_pca", "class_balanced_pca", "between_class_pca", "within_filter_pca"];
        const availableProjectionMethods = Array.isArray(classSplitState.capabilities?.projection_methods)
            ? classSplitState.capabilities.projection_methods
            : ["pca"];
        const options = [
            { value: "class_balanced_pca", label: "Class-balanced PCA" },
            { value: "global_pca", label: "Global PCA" },
            { value: "between_class_pca", label: "Between-class PCA" },
            { value: "within_filter_pca", label: "Within-filter PCA" },
            { value: "umap", label: availableProjectionMethods.includes("umap") ? "UMAP" : "UMAP if available" },
        ].filter((option) => option.value === "umap" || pcaModes.includes(option.value));
        const desired = normalizeClassSplitProjectionChoice(
            classSplitElements.graphProjection?.value
            || classSplitElements.projection?.value
            || defaultClassSplitProjectionForScope()
        );
        selects.forEach((select) => fillSelectOptions(select, options, desired));
        refreshClassSplitProjectionHint();
    }

    function normalizeClassSplitProjectionChoice(value) {
        const raw = String(value || "").trim().toLowerCase().replace(/-/g, "_");
        const aliases = {
            pca: "global_pca",
            global: "global_pca",
            global_pca: "global_pca",
            balanced: "class_balanced_pca",
            balanced_pca: "class_balanced_pca",
            class_balanced: "class_balanced_pca",
            class_balanced_pca: "class_balanced_pca",
            between: "between_class_pca",
            between_pca: "between_class_pca",
            between_class: "between_class_pca",
            between_class_pca: "between_class_pca",
            within: "within_filter_pca",
            within_pca: "within_filter_pca",
            within_class: "within_filter_pca",
            within_class_pca: "within_filter_pca",
            within_filter: "within_filter_pca",
            within_filter_pca: "within_filter_pca",
            umap: "umap",
        };
        return aliases[raw] || "class_balanced_pca";
    }

    function classSplitProjectionChoiceLabel(choice) {
        const labels = {
            global_pca: "Global PCA",
            class_balanced_pca: "Class-balanced PCA",
            between_class_pca: "Between-class PCA",
            within_filter_pca: "Within-filter PCA",
            umap: "UMAP",
        };
        return labels[normalizeClassSplitProjectionChoice(choice)] || labels.class_balanced_pca;
    }

    function classSplitUmapAvailable() {
        return Array.isArray(classSplitState.capabilities?.projection_methods)
            && classSplitState.capabilities.projection_methods.includes("umap");
    }

    function defaultClassSplitProjectionForScope(scope = getClassSplitScope()) {
        return String(scope || "") === "selected_class"
            ? (classSplitUmapAvailable() ? "umap" : "within_filter_pca")
            : "class_balanced_pca";
    }

    function classSplitProjectionIsAutoDefault(choice) {
        return ["class_balanced_pca", "within_filter_pca", "umap"].includes(normalizeClassSplitProjectionChoice(choice));
    }

    function applyClassSplitProjectionDefaultForScope({ force = false } = {}) {
        if (classSplitState.result && !force) {
            return;
        }
        const desired = defaultClassSplitProjectionForScope();
        const current = getClassSplitProjectionChoice();
        if (force || classSplitProjectionIsAutoDefault(current)) {
            setClassSplitProjectionChoice(desired);
        }
        refreshClassSplitProjectionHint();
    }

    function getClassSplitProjectionChoice() {
        return normalizeClassSplitProjectionChoice(
            classSplitElements.graphProjection?.value
            || classSplitElements.projection?.value
            || inferClassSplitResultSelectedProjection(classSplitState.result)
            || "class_balanced_pca"
        );
    }

    function inferClassSplitResultSelectedProjection(result) {
        if (!result || typeof result !== "object") {
            return "";
        }
        const projectionOptions = result.projection_options || {};
        const summary = result.summary || {};
        const explicit = projectionOptions.selected || summary.projection_mode;
        if (explicit) {
            return normalizeClassSplitProjectionChoice(explicit);
        }
        const projection = String(summary.projection || "").trim().toLowerCase();
        if (projection === "pca") {
            return "global_pca";
        }
        if (projection === "umap") {
            return "umap";
        }
        if (
            Array.isArray(result.points)
            && result.points.some((point) => Array.isArray(point?.projection) && point.projection.length >= 2)
        ) {
            return "global_pca";
        }
        return "";
    }

    function setClassSplitProjectionChoice(choice, source = null) {
        const normalized = normalizeClassSplitProjectionChoice(choice);
        [classSplitElements.projection, classSplitElements.graphProjection].forEach((select) => {
            if (select && select !== source) {
                select.value = normalized;
            }
        });
        return normalized;
    }

    function getClassSplitProjectionRequestParts() {
        const choice = getClassSplitProjectionChoice();
        if (choice === "umap") {
            return { projection: "umap", projectionMode: "global_pca" };
        }
        return { projection: "pca", projectionMode: choice };
    }

    function classSplitProjectionNeedsClassFilter(choice = getClassSplitProjectionChoice()) {
        return normalizeClassSplitProjectionChoice(choice) === "within_filter_pca"
            && getClassSplitResultScope() === "all_classes"
            && !String(classSplitElements.filterClass?.value || "").trim();
    }

    function getClassSplitPointProjection(point, axisIndex) {
        if (!point) {
            return 0;
        }
        const choice = getClassSplitProjectionChoice();
        if (classSplitProjectionNeedsClassFilter(choice)) {
            return 0;
        }
        const pointIndex = Number(point._projectionIndex);
        const loadedCoordinates = classSplitState.projectionCoordinates || {};
        const inlineCoordinates = classSplitState.result?.projection_options?.coordinates || {};
        const coordinates = loadedCoordinates[choice] || inlineCoordinates[choice];
        if (choice !== "umap" && Number.isInteger(pointIndex) && Array.isArray(coordinates)) {
            const pair = coordinates[pointIndex];
            const value = Number(Array.isArray(pair) ? pair[axisIndex] : NaN);
            if (Number.isFinite(value)) {
                return value;
            }
        }
        const fallback = Number(point.projection?.[axisIndex]);
        return Number.isFinite(fallback) ? fallback : 0;
    }

    function getClassSplitProjectionUnavailableMessage() {
        const choice = getClassSplitProjectionChoice();
        if (classSplitProjectionNeedsClassFilter(choice)) {
            return "Choose a class filter to use Within-filter PCA. Each class has its own local PCA axes, so all classes cannot be overlaid in that mode.";
        }
        if (choice === "umap" && String(classSplitState.result?.summary?.projection || "") !== "umap") {
            return "UMAP coordinates are only available after rerunning Class Split with UMAP selected.";
        }
        if (classSplitState.result && choice !== "umap") {
            const inlineCoordinates = classSplitState.result?.projection_options?.coordinates || {};
            const hasStoredCoordinates = Array.isArray(inlineCoordinates?.[choice])
                || Array.isArray(classSplitState.projectionCoordinates?.[choice]);
            const available = classSplitState.result?.projection_options?.coordinates_available;
            const canFetchCoordinates = Array.isArray(available) && available.includes(choice);
            const legacyGlobalPca = choice === "global_pca"
                && String(classSplitState.result?.summary?.projection || "").toLowerCase() === "pca";
            const selectedMode = inferClassSplitResultSelectedProjection(classSplitState.result);
            const selectedHasPointProjection = !!selectedMode && choice === selectedMode;
            if (!hasStoredCoordinates && !canFetchCoordinates && !legacyGlobalPca && !selectedHasPointProjection) {
                return `${classSplitProjectionChoiceLabel(choice)} coordinates are only available after rerunning Class Split.`;
            }
        }
        return "";
    }

    function refreshClassSplitProjectionHint() {
        const choice = getClassSplitProjectionChoice();
        const scope = getClassSplitScope();
        const unavailable = getClassSplitProjectionUnavailableMessage();
        const guidance = {
            umap: classSplitUmapAvailable()
                ? "UMAP preserves local neighborhoods and is the recommended selected-class view for spotting subclass islands. Axes and far-apart island distances are visual layout only."
                : "UMAP is not installed in this backend; rerunning with UMAP will fall back to Global PCA. Install umap-learn to enable neighborhood maps.",
            within_filter_pca: "Within-filter PCA is the conservative PCA fallback for one class or class filter. It recomputes linear axes inside that subset, but can still hide curved local islands.",
            class_balanced_pca: "Class-balanced PCA is the safest all-class overview. It reduces domination by huge classes, but it is not the best tool for finding subclasses inside one class.",
            between_class_pca: "Between-class PCA intentionally spreads labels apart for class overview. Use it to inspect class separation, not to prove subclass islands.",
            global_pca: "Global PCA is the most conservative linear overview. If a split is clear here it is strong, but smaller semantic islands are often compressed.",
        }[choice] || "Projection changes only the visible graph coordinates; wrong-class scoring stays in original embeddings.";
        const suffix = scope === "selected_class"
            ? " For subclass work: run Selected class + UMAP, then verify islands by crop previews before relabeling."
            : " For likely-wrong-class review: use All classes + Class-balanced PCA, then filter likely wrong objects.";
        const title = unavailable || `${guidance}${suffix}`;
        [classSplitElements.projection, classSplitElements.graphProjection].forEach((select) => {
            if (select) {
                select.title = title;
            }
        });
        if (classSplitElements.projectionHint) {
            classSplitElements.projectionHint.textContent = title;
            classSplitElements.projectionHint.classList.toggle("is-warning", !!unavailable || (choice === "umap" && !classSplitUmapAvailable()));
            classSplitElements.projectionHint.classList.toggle("is-recommended", !unavailable && scope === "selected_class" && choice === "umap");
        }
    }

    function classSplitProjectionCoordinatesLoaded(choice = getClassSplitProjectionChoice()) {
        const normalized = normalizeClassSplitProjectionChoice(choice);
        if (normalized === "umap") {
            return true;
        }
        if (Array.isArray(classSplitState.projectionCoordinates?.[normalized])) {
            return true;
        }
        if (Array.isArray(classSplitState.result?.projection_options?.coordinates?.[normalized])) {
            return true;
        }
        const selectedMode = inferClassSplitResultSelectedProjection(classSplitState.result);
        return !!selectedMode && normalized === selectedMode && Array.isArray(classSplitState.result?.points);
    }

    async function ensureClassSplitProjectionCoordinates(choice = getClassSplitProjectionChoice()) {
        const normalized = normalizeClassSplitProjectionChoice(choice);
        if (classSplitProjectionCoordinatesLoaded(normalized)) {
            return true;
        }
        const available = classSplitState.result?.projection_options?.coordinates_available;
        if (!Array.isArray(available) || !available.includes(normalized) || !classSplitState.currentJobId) {
            return false;
        }
        if (!classSplitState.projectionCoordinateLoads) {
            classSplitState.projectionCoordinateLoads = new Map();
        }
        if (!classSplitState.projectionCoordinateLoads.has(normalized)) {
            const loadPromise = fetch(`${API_ROOT}/class_analysis/jobs/${encodeURIComponent(classSplitState.currentJobId)}/projection/${encodeURIComponent(normalized)}`)
                .then(async (resp) => {
                    const detail = await resp.text();
                    if (!resp.ok) {
                        throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
                    }
                    const payload = parseJsonObjectSafe(detail, {});
                    const coords = Array.isArray(payload.coordinates) ? payload.coordinates : [];
                    classSplitState.projectionCoordinates = {
                        ...(classSplitState.projectionCoordinates || {}),
                        [normalized]: coords,
                    };
                    return true;
                })
                .finally(() => {
                    classSplitState.projectionCoordinateLoads?.delete(normalized);
                });
            classSplitState.projectionCoordinateLoads.set(normalized, loadPromise);
        }
        return classSplitState.projectionCoordinateLoads.get(normalized);
    }

    function updateClassSplitBackboneOptions() {
        const selectEl = classSplitElements.backbone;
        if (!selectEl) {
            return;
        }
        const encoder = String(classSplitElements.encoderType?.value || classSplitState.capabilities?.default_encoder_type || "dinov3").toLowerCase();
        if (encoder === "clip") {
            const clipOptions = classSplitState.clipBackbones.length
                ? classSplitState.clipBackbones
                : [classSplitState.capabilities?.default_clip_model || "ViT-B/32"];
            fillSelectOptions(selectEl, clipOptions, classSplitState.capabilities?.default_clip_model || "");
            return;
        }
        if (encoder === "cradio") {
            const models = Array.isArray(classSplitState.capabilities?.cradio_models)
                ? classSplitState.capabilities.cradio_models.map((model) => ({ value: model, label: model.split("/").pop() || model }))
                : CRADIO_BACKBONES;
            fillSelectOptions(selectEl, models, classSplitState.capabilities?.default_cradio_model || "nvidia/C-RADIOv4-SO400M");
            return;
        }
        fillSelectOptions(
            selectEl,
            DINOV3_BACKBONES,
            classSplitState.capabilities?.default_dinov3_model || "facebook/dinov3-vitb16-pretrain-lvd1689m"
        );
    }

    function setClassSplitJobStatus(message, variant = "") {
        if (!classSplitElements.jobStatus) {
            return;
        }
        classSplitElements.jobStatus.textContent = message || "";
        classSplitElements.jobStatus.classList.remove("warn", "error", "success", "info");
        if (variant) {
            classSplitElements.jobStatus.classList.add(variant);
        }
    }

    function renderClassSplitProgress(job = null) {
        if (!classSplitElements.progress) {
            return;
        }
        const active = classSplitState.active || (job && !["completed", "failed", "cancelled"].includes(String(job.status || "")));
        classSplitElements.progress.hidden = !active && !job;
        const progress = Math.max(0, Math.min(1, Number(job?.progress) || 0));
        if (classSplitElements.progressFill) {
            classSplitElements.progressFill.style.width = `${Math.round(progress * 100)}%`;
        }
        if (classSplitElements.progressText) {
            const pct = `${Math.round(progress * 100)}%`;
            const message = String(job?.message || "").trim();
            const logTail = Array.isArray(job?.logs) && job.logs.length
                ? String(job.logs[job.logs.length - 1]?.message || "").trim()
                : "";
            classSplitElements.progressText.textContent = [pct, message || logTail].filter(Boolean).join(" • ");
        }
    }

    function refreshClassSplitControls({ preferCurrentClass = false } = {}) {
        const stats = getClassSplitActiveWorkspaceStats();
        const available = stats.imageCount > 0 && stats.classCount > 0 && stats.objectCount > 0;
        populateClassSplitClasses({ preserveSelection: !preferCurrentClass });
        if (preferCurrentClass) {
            syncClassSplitCurrentClassSelection();
        }
        const scope = getClassSplitScope();
        const classSelected = !!String(classSplitElements.classSelect?.value || "").trim();
        const selectedClassCount = stats.counts.get(String(classSplitElements.classSelect?.value || "").trim()) || 0;
        const classSplitEncoderType = String(classSplitElements.encoderType?.value || "dinov3").trim().toLowerCase();
        const projectionChoice = getClassSplitProjectionChoice();
        if (classSplitElements.datasetStatus) {
            if (!stats.imageCount) {
                classSplitElements.datasetStatus.textContent = "Open images in Label Images to run analysis.";
            } else if (!stats.classCount) {
                classSplitElements.datasetStatus.textContent = "Load a labelmap in Label Images to run analysis.";
            } else if (!stats.objectCount) {
                classSplitElements.datasetStatus.textContent = "Draw or load labels in Label Images to run analysis.";
            } else {
                classSplitElements.datasetStatus.textContent =
                    `Active Label Images workspace • ${stats.imageCount} images • ${stats.labeledImageCount} labeled • ${stats.objectCount} objects`;
            }
        }
        if (classSplitElements.classSelect) {
            classSplitElements.classSelect.disabled = !available || scope !== "selected_class" || classSplitState.active;
        }
        [
            classSplitElements.scopeSelected,
            classSplitElements.scopeAll,
            classSplitElements.recipePreset,
            classSplitElements.encoderType,
            classSplitElements.backbone,
            classSplitElements.projection,
            classSplitElements.projectionNeighborK,
            classSplitElements.projectionMinDist,
            classSplitElements.sampleCap,
            classSplitElements.padding,
            classSplitElements.canonicalSize,
            classSplitElements.preprocessMode,
            classSplitElements.sizeBiasMode,
            classSplitElements.dinov3Pooling,
            classSplitElements.cradioPooling,
            classSplitElements.backgroundMode,
            classSplitElements.viewMode,
            classSplitElements.neighborK,
        ].forEach((control) => {
            if (control) {
                control.disabled = !available || classSplitState.active;
            }
        });
        const canRun = available
            && !classSplitState.active
            && (scope !== "selected_class" || (classSelected && selectedClassCount > 0));
        if (classSplitElements.dinov3Pooling) {
            classSplitElements.dinov3Pooling.disabled = !available || classSplitState.active || classSplitEncoderType !== "dinov3";
        }
        if (classSplitElements.cradioPooling) {
            classSplitElements.cradioPooling.disabled = !available || classSplitState.active || classSplitEncoderType !== "cradio";
        }
        if (classSplitElements.projectionNeighborK) {
            classSplitElements.projectionNeighborK.disabled = !available || classSplitState.active || projectionChoice !== "umap";
        }
        if (classSplitElements.projectionMinDist) {
            classSplitElements.projectionMinDist.disabled = !available || classSplitState.active || projectionChoice !== "umap";
        }
        refreshClassSplitProjectionHint();
        setButtonDisabled(classSplitElements.qwenReviewGlossaryReset, classSplitState.qwenReviewGlossaryLoadInFlight);
        setButtonDisabled(
            classSplitElements.qwenReviewGlossarySave,
            classSplitState.qwenReviewGlossarySaveInFlight || !getClassSplitQwenReviewDatasetId()
        );
        if (classSplitElements.qwenReviewGlossary && !classSplitState.qwenReviewGlossaryDirty) {
            const reviewContextKey = getClassSplitQwenReviewDatasetId()
                || `workspace:${classSplitHashValues(loadedClassList || [])}`;
            if (
                reviewContextKey
                && classSplitState.qwenReviewGlossaryLoadedFor !== reviewContextKey
                && !classSplitState.qwenReviewGlossaryLoadInFlight
            ) {
                loadClassSplitQwenReviewGlossary().catch((error) => {
                    console.warn("Class Split review glossary refresh failed", error);
                });
            }
        }
        setButtonDisabled(classSplitElements.runButton, !canRun);
        setButtonDisabled(
            classSplitElements.cancelButton,
            !classSplitState.active
                || (!classSplitState.currentJobId && !classSplitState.activeUploadSessionId && !classSplitState.activeUploadAbortController)
        );
        setButtonDisabled(classSplitElements.rerunButton, classSplitState.active || !classSplitState.lastRequest);
        setButtonDisabled(classSplitElements.mobilePush, classSplitState.active || !classSplitState.result);
        setButtonDisabled(
            classSplitElements.mobileSync,
            classSplitState.active
                || !classSplitState.result
                || !classSplitState.mobileReviewSessionId
                || classSplitState.mobileReviewTargetMode !== "desktop_workspace"
        );
        refreshClassSplitClusterControls();
        refreshClassSplitDatasetAnalysisControls();
    }

    function buildClassSplitRequest() {
        const stats = getClassSplitActiveWorkspaceStats();
        if (!stats.imageCount) {
            throw new Error("Open images in Label Images before running Class Split Explorer.");
        }
        if (!stats.classCount) {
            throw new Error("Load a labelmap in Label Images before running Class Split Explorer.");
        }
        if (!stats.objectCount) {
            throw new Error("Draw or load labels in Label Images before running Class Split Explorer.");
        }
        const scope = getClassSplitScope();
        const className = String(classSplitElements.classSelect?.value || currentClass || "").trim();
        if (scope === "selected_class" && !className) {
            throw new Error("Choose a class to analyze.");
        }
        if (scope === "selected_class" && !(stats.counts.get(className) > 0)) {
            throw new Error(`No active labels are assigned to ${className}.`);
        }
        const encoderType = String(classSplitElements.encoderType?.value || "dinov3").toLowerCase();
        const sampleCap = getClassSplitSampleCap();
        const padding = Math.max(0, Math.min(1, parseFloat(classSplitElements.padding?.value || "0.08") || 0));
        const canonicalSizeRaw = parseInt(classSplitElements.canonicalSize?.value || "336", 10);
        const canonicalSize = Number.isFinite(canonicalSizeRaw)
            ? Math.max(64, Math.min(1024, canonicalSizeRaw))
            : 336;
        const projectionNeighborRaw = parseInt(classSplitElements.projectionNeighborK?.value || "50", 10);
        const projectionNeighborK = Number.isFinite(projectionNeighborRaw)
            ? Math.max(0, Math.min(5000, projectionNeighborRaw))
            : 50;
        const projectionMinDistRaw = parseFloat(classSplitElements.projectionMinDist?.value || "0.08");
        const projectionMinDist = Number.isFinite(projectionMinDistRaw)
            ? Math.max(0, Math.min(0.99, projectionMinDistRaw))
            : 0.08;
        const neighborK = Math.max(3, Math.min(100, parseInt(classSplitElements.neighborK?.value || "15", 10) || 15));
        const projectionParts = getClassSplitProjectionRequestParts();
        const request = {
            analysis_scope: scope,
            class_name: scope === "selected_class" ? className : "",
            encoder_type: encoderType,
            encoder_model: String(classSplitElements.backbone?.value || "").trim(),
            projection: projectionParts.projection,
            projection_mode: projectionParts.projectionMode,
            projection_neighbor_k: projectionNeighborK,
            projection_min_dist: projectionMinDist,
            crop_mode: "padded_square",
            padding_ratio: padding,
            preprocess_mode: String(classSplitElements.preprocessMode?.value || "canonical").trim().toLowerCase() || "canonical",
            canonical_size: canonicalSize,
            embedding_adjustment: String(classSplitElements.sizeBiasMode?.value || "remove_size_bias").trim().toLowerCase() || "remove_size_bias",
            dinov3_pooling: String(classSplitElements.dinov3Pooling?.value || "pooler").trim().toLowerCase() || "pooler",
            cradio_pooling: String(classSplitElements.cradioPooling?.value || "summary").trim().toLowerCase() || "summary",
            background_mode: String(classSplitElements.backgroundMode?.value || "full_crop").trim().toLowerCase() || "full_crop",
            embedding_view_mode: String(classSplitElements.viewMode?.value || "single").trim().toLowerCase() || "single",
            neighbor_k: neighborK,
            batch_size: 64,
            seed: 42,
        };
        if (sampleCap > 0) {
            request.sample_cap = sampleCap;
        }
        return request;
    }

    async function ensureClassSplitSnapshotClean(actionLabel = "Class analysis") {
        if (!isAnnotationDatasetModeActive()) {
            return;
        }
        captureCurrentAnnotationDirtyState();
        if (!annotationSourceState.dirtyRecordsByKey.size) {
            return;
        }
        await flushAnnotationSnapshot({ manual: false });
        if (annotationSourceState.dirtyRecordsByKey.size) {
            throw new Error(`${actionLabel} needs the current annotation edits saved first.`);
        }
    }

    function snapshotClassSplitReviewState() {
        if (!classSplitState.result) {
            return null;
        }
        return {
            currentJobId: classSplitState.currentJobId,
            result: classSplitState.result,
            pointsById: new Map(classSplitState.pointsById || []),
            projectionCoordinates: { ...(classSplitState.projectionCoordinates || {}) },
            selectedPointId: classSplitState.selectedPointId,
            selectedClusterId: classSplitState.selectedClusterId,
            clusterSearchResult: classSplitState.clusterSearchResult,
            clusterSearchJobId: classSplitState.clusterSearchJobId,
            lassoPointIds: new Set(classSplitState.lassoPointIds || []),
            dismissedWrongIds: new Set(classSplitState.dismissedWrongIds || []),
            wrongQueueIds: Array.from(classSplitState.wrongQueueIds || []),
            wrongQueueSignature: classSplitState.wrongQueueSignature || "",
            currentSourceHandle: classSplitState.currentSourceHandle ? { ...classSplitState.currentSourceHandle } : null,
            mobileReviewSessionId: classSplitState.mobileReviewSessionId || "",
            mobileReviewTargetMode: classSplitState.mobileReviewTargetMode || "",
            mobileReviewSyncedActions: new Set(classSplitState.mobileReviewSyncedActions || []),
            lastRequest: classSplitState.lastRequest ? { ...classSplitState.lastRequest } : null,
            datasetAnalysis: classSplitState.datasetAnalysis,
        };
    }

    function restoreClassSplitReviewState(snapshot) {
        if (!snapshot || !snapshot.result) {
            return false;
        }
        classSplitState.active = false;
        classSplitState.currentJobId = snapshot.currentJobId;
        classSplitState.result = snapshot.result;
        classSplitState.pointsById = new Map(snapshot.pointsById || []);
        classSplitState.projectionCoordinates = { ...(snapshot.projectionCoordinates || {}) };
        classSplitState.projectionCoordinateLoads = new Map();
        classSplitState.selectedPointId = snapshot.selectedPointId || "";
        classSplitState.selectedClusterId = snapshot.selectedClusterId || "";
        classSplitState.clusterSearchActive = false;
        classSplitState.clusterSearchResult = snapshot.clusterSearchResult || null;
        classSplitState.clusterSearchJobId = snapshot.clusterSearchJobId || "";
        classSplitState.lassoPointIds = new Set(snapshot.lassoPointIds || []);
        classSplitState.dismissedWrongIds = new Set(snapshot.dismissedWrongIds || []);
        classSplitState.wrongQueueIds = Array.isArray(snapshot.wrongQueueIds) ? [...snapshot.wrongQueueIds] : [];
        classSplitState.wrongQueueSignature = snapshot.wrongQueueSignature || "";
        classSplitState.currentSourceHandle = snapshot.currentSourceHandle ? { ...snapshot.currentSourceHandle } : null;
        classSplitState.mobileReviewSessionId = snapshot.mobileReviewSessionId || "";
        classSplitState.mobileReviewTargetMode = snapshot.mobileReviewTargetMode || "";
        classSplitState.mobileReviewSyncedActions = new Set(snapshot.mobileReviewSyncedActions || []);
        classSplitState.lastRequest = snapshot.lastRequest ? { ...snapshot.lastRequest } : null;
        classSplitState.datasetAnalysis = snapshot.datasetAnalysis || null;
        invalidateClassSplitPointImageLookup();
        renderClassSplitResult();
        return true;
    }

    async function startClassSplitAnalysis({ reuseLast = false } = {}) {
        if (classSplitState.active) {
            return;
        }
        let previousReviewState = null;
        try {
            const request = reuseLast && classSplitState.lastRequest
                ? { ...classSplitState.lastRequest }
                : buildClassSplitRequest();
            await ensureClassSplitSnapshotClean("Class Split analysis");
            previousReviewState = snapshotClassSplitReviewState();
            stopClassSplitClusterPoll();
            classSplitState.pollRequestId += 1;
            classSplitState.clusterSearchRequestId += 1;
            classSplitState.active = true;
            classSplitState.currentJobId = "";
            classSplitState.result = null;
            classSplitState.pointsById = new Map();
            classSplitState.selectedPointId = "";
            classSplitState.selectedClusterId = "";
            classSplitState.clusterSearchActive = false;
            classSplitState.clusterSearchJobId = "";
            classSplitState.clusterSearchResult = null;
            classSplitState.lassoPointIds = new Set();
            classSplitState.selectionRevision += 1;
            classSplitState.dismissedWrongIds = new Set();
            classSplitState.wrongQueueIds = [];
            classSplitState.wrongQueueSignature = "";
            classSplitState.currentSourceHandle = null;
            classSplitState.mobileReviewSessionId = "";
            classSplitState.mobileReviewTargetMode = "";
            classSplitState.mobileReviewSyncedActions = new Set();
            invalidateClassSplitPointImageLookup();
            clearClassSplitDatasetAnalysis({ render: true });
            stopClassSplitPlotFlash();
            renderClassSplitResult();
            setClassSplitJobStatus("Starting analysis ...", "");
            renderClassSplitProgress({ progress: 0, message: "Preparing Class Split analysis ..." });
            refreshClassSplitControls();
            classSplitState.lastRequest = { ...request };
            const sourceHandle = await getClassSplitServerAnalysisSourceHandle(request, {
                onProgress: ({ progress = 0, message = "" } = {}) => {
                    const pct = Math.max(0, Math.min(1, Number(progress) || 0));
                    renderClassSplitProgress({
                        progress: 0.01 + (0.94 * pct),
                        message: message || "Uploading active workspace for Class Split analysis ...",
                    });
                },
            });
            classSplitState.currentSourceHandle = sourceHandle ? { ...sourceHandle } : null;
            let resp;
            if (sourceHandle) {
                const payload = {
                    ...request,
                    source_mode: sourceHandle.sourceMode,
                };
                if (sourceHandle.datasetId) {
                    payload.dataset_id = sourceHandle.datasetId;
                }
                if (sourceHandle.sessionId) {
                    payload.session_id = sourceHandle.sessionId;
                }
                renderClassSplitProgress({
                    progress: Math.max(0.01, sourceHandle.uploadedActiveWorkspace ? 0.96 : 0.01),
                    message: `Starting backend ${sourceHandle.sourceMode} analysis for ${sourceHandle.objectCount} objects from ${sourceHandle.imageCount} images ...`,
                });
                resp = await fetch(`${API_ROOT}/class_analysis/jobs`, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify(payload),
                });
            } else {
                renderClassSplitProgress({ progress: 0, message: "Packaging active labels and images ..." });
                const workspace = buildClassSplitActiveWorkspaceSnapshot(request, {
                    onProgress: ({ progress = 0, message = "" } = {}) => {
                        const snapshotProgress = Math.max(0, Math.min(1, Number(progress) || 0));
                        renderClassSplitProgress({
                            progress: 0.01 + (0.24 * snapshotProgress),
                            message: message || "Snapshot-packaging active workspace ...",
                        });
                    },
                });
                renderClassSplitProgress({
                    progress: 0.25,
                    message: `Snapshot-uploading ${workspace.objectCount} objects from ${workspace.imageCount} active images ...`,
                });
                const uploadAbortController = new AbortController();
                classSplitState.activeUploadAbortController = uploadAbortController;
                refreshClassSplitControls();
                try {
                    const renderUploadProgress = ({ progress = null, message = "" } = {}) => {
                        const uploadProgress = Number.isFinite(Number(progress))
                            ? Math.max(0, Math.min(1, Number(progress)))
                            : 0;
                        renderClassSplitProgress({
                            progress: Number.isFinite(Number(progress))
                                ? 0.25 + (0.70 * uploadProgress)
                                : 0.25,
                            message: message || `Snapshot-uploading ${workspace.objectCount} objects from ${workspace.imageCount} active images ...`,
                        });
                    };
                    try {
                        resp = await postClassSplitActiveWorkspaceChunked(workspace, {
                            signal: uploadAbortController.signal,
                            onProgress: renderUploadProgress,
                        });
                    } catch (chunkError) {
                        const message = String(chunkError?.message || chunkError || "");
                        if (chunkError?.name === "AbortError" || !/(HTTP 404|not found)/i.test(message)) {
                            throw chunkError;
                        }
                        console.warn("Class Split chunked active workspace upload unavailable; falling back to one-shot upload.", chunkError);
                        const fallback = await buildClassSplitActiveWorkspaceFormFromSnapshot(workspace);
                        resp = await postClassSplitActiveWorkspaceForm(fallback.formData, {
                            signal: uploadAbortController.signal,
                            onProgress: renderUploadProgress,
                        });
                    }
                } finally {
                    if (classSplitState.activeUploadAbortController === uploadAbortController) {
                        classSplitState.activeUploadAbortController = null;
                        refreshClassSplitControls();
                    }
                }
            }
            const detail = await resp.text();
            if (!resp.ok) {
                throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            }
            const payload = parseJsonObjectSafe(detail, {});
            const jobId = String(payload.job_id || "").trim();
            if (!jobId) {
                throw new Error("Class analysis did not return a job id.");
            }
            classSplitState.currentJobId = jobId;
            setClassSplitJobStatus(sourceHandle ? "Queued backend dataset" : "Queued active workspace", "");
            pollClassSplitJob(jobId);
        } catch (error) {
            console.error("Class Split analysis failed to start", error);
            const restoredPreviousResult = restoreClassSplitReviewState(previousReviewState);
            classSplitState.active = false;
            setClassSplitJobStatus(`Failed: ${error.message || error}`, "error");
            renderClassSplitProgress({ progress: 1, message: `Failed: ${error.message || error}` });
            if (restoredPreviousResult) {
                renderClassSplitPlot();
            }
            refreshClassSplitControls();
        }
    }

    function stopClassSplitPoll() {
        if (classSplitState.pollTimer) {
            clearTimeout(classSplitState.pollTimer);
            classSplitState.pollTimer = null;
        }
    }

    function pollClassSplitJob(jobId) {
        stopClassSplitPoll();
        const requestId = ++classSplitState.pollRequestId;
        const run = async () => {
            try {
                const resp = await fetch(`${API_ROOT}/class_analysis/jobs/${encodeURIComponent(jobId)}`);
                const detail = await resp.text();
                if (!resp.ok) {
                    throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
                }
                if (requestId !== classSplitState.pollRequestId) {
                    return;
                }
                const job = parseJsonObjectSafe(detail, {});
                renderClassSplitProgress(job);
                const status = String(job.status || "").toLowerCase();
                if (status === "completed") {
                    classSplitState.active = false;
                    setClassSplitJobStatus("Completed", "success");
                    await loadClassSplitResult(jobId);
                    refreshClassSplitControls();
                    return;
                }
                if (status === "failed") {
                    classSplitState.active = false;
                    setClassSplitJobStatus(`Failed: ${job.error || job.message || "unknown error"}`, "error");
                    refreshClassSplitControls();
                    return;
                }
                if (status === "cancelled") {
                    classSplitState.active = false;
                    setClassSplitJobStatus("Cancelled", "warn");
                    refreshClassSplitControls();
                    return;
                }
                setClassSplitJobStatus(status || "Running", "");
                classSplitState.pollTimer = window.setTimeout(run, 1200);
            } catch (error) {
                console.error("Class Split poll failed", error);
                if (requestId !== classSplitState.pollRequestId) {
                    return;
                }
                classSplitState.active = false;
                setClassSplitJobStatus(`Poll failed: ${error.message || error}`, "error");
                refreshClassSplitControls();
            }
        };
        run();
    }

    async function cancelClassSplitJob() {
        const uploadSessionId = String(classSplitState.activeUploadSessionId || "").trim();
        const uploadAbortController = classSplitState.activeUploadAbortController;
        if (uploadAbortController || uploadSessionId) {
            try {
                if (uploadAbortController && typeof uploadAbortController.abort === "function") {
                    uploadAbortController.abort();
                }
                if (uploadSessionId) {
                    await fetch(`${API_ROOT}/class_analysis/jobs/active_workspace/upload_session/${encodeURIComponent(uploadSessionId)}/cancel`, {
                        method: "POST",
                    }).catch(() => fetch(`${API_ROOT}/datasets/upload_session/${encodeURIComponent(uploadSessionId)}/cancel`, {
                        method: "POST",
                    }));
                }
                setClassSplitJobStatus("Cancelling active workspace upload ...", "warn");
            } catch (error) {
                console.error("Class Split upload cancel failed", error);
                setClassSplitJobStatus(`Upload cancel failed: ${error.message || error}`, "error");
            } finally {
                classSplitState.activeUploadSessionId = "";
                classSplitState.activeUploadAbortController = null;
                refreshClassSplitControls();
            }
            return;
        }
        const jobId = classSplitState.currentJobId;
        if (!jobId) {
            return;
        }
        try {
            const resp = await fetch(`${API_ROOT}/class_analysis/jobs/${encodeURIComponent(jobId)}/cancel`, {
                method: "POST",
            });
            const detail = await resp.text();
            if (!resp.ok) {
                throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            }
            setClassSplitJobStatus("Cancelling ...", "warn");
        } catch (error) {
            console.error("Class Split cancel failed", error);
            setClassSplitJobStatus(`Cancel failed: ${error.message || error}`, "error");
        }
    }

    function syncClassSplitSetupControlsFromResult(result) {
        const summary = result?.summary || {};
        const scope = String(summary.analysis_scope || "").trim();
        if (scope === "all_classes") {
            if (classSplitElements.scopeAll) {
                classSplitElements.scopeAll.checked = true;
            }
            if (classSplitElements.scopeSelected) {
                classSplitElements.scopeSelected.checked = false;
            }
            return;
        }
        if (scope === "selected_class") {
            if (classSplitElements.scopeSelected) {
                classSplitElements.scopeSelected.checked = true;
            }
            if (classSplitElements.scopeAll) {
                classSplitElements.scopeAll.checked = false;
            }
            const className = String(
                summary.class_name
                || summary.selected_class
                || classSplitState.lastRequest?.class_name
                || ""
            ).trim();
            if (
                className
                && classSplitElements.classSelect
                && Array.from(classSplitElements.classSelect.options || []).some((option) => option.value === className)
            ) {
                classSplitElements.classSelect.value = className;
            }
        }
    }

    function applyClassSplitResultPayload(resultPayload, jobId = "") {
        const result = resultPayload && typeof resultPayload === "object" ? resultPayload : {};
        stopClassSplitClusterPoll();
        classSplitState.clusterSearchRequestId += 1;
        if (jobId) {
            classSplitState.currentJobId = String(jobId || "").trim();
        }
        classSplitState.active = false;
        classSplitState.result = result;
        syncClassSplitSetupControlsFromResult(result);
        classSplitState.pointsById = new Map();
        classSplitState.projectionCoordinates = {};
        classSplitState.projectionCoordinateLoads = new Map();
        const inlineCoordinates = result?.projection_options?.coordinates;
        if (inlineCoordinates && typeof inlineCoordinates === "object") {
            classSplitState.projectionCoordinates = { ...inlineCoordinates };
            delete result.projection_options.coordinates;
            result.projection_options.coordinates_available = Object.keys(classSplitState.projectionCoordinates);
        }
        setClassSplitProjectionChoice(
            inferClassSplitResultSelectedProjection(result)
            || classSplitState.lastRequest?.projection_mode
            || classSplitState.capabilities?.default_pca_projection_mode
            || "class_balanced_pca"
        );
        if (classSplitElements.colorMode) {
            classSplitElements.colorMode.value = "class";
        }
        if (classSplitElements.displayMode) {
            classSplitElements.displayMode.value = "all";
        }
        if (classSplitElements.filterClass) {
            classSplitElements.filterClass.value = "";
        }
        invalidateClassSplitPointImageLookup();
        (Array.isArray(result.points) ? result.points : []).forEach((point, index) => {
            if (point) {
                point._projectionIndex = index;
            }
            if (point?.point_id) {
                classSplitState.pointsById.set(String(point.point_id), point);
            }
        });
        classSplitState.selectedPointId = "";
        classSplitState.selectedClusterId = "";
        classSplitState.clusterSearchActive = false;
        classSplitState.clusterSearchJobId = "";
        classSplitState.clusterSearchResult = null;
        classSplitState.lassoPointIds = new Set();
        classSplitState.selectionRevision += 1;
        classSplitState.dismissedWrongIds = new Set();
        classSplitState.wrongQueueIds = [];
        classSplitState.wrongQueueSignature = "";
        clearClassSplitDatasetAnalysis();
        stopClassSplitPlotFlash();
        renderClassSplitResult();
    }

    async function loadClassSplitResult(jobId) {
        const resp = await fetch(`${API_ROOT}/class_analysis/jobs/${encodeURIComponent(jobId)}/result`);
        const detail = await resp.text();
        if (!resp.ok) {
            throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
        }
        applyClassSplitResultPayload(parseJsonObjectSafe(detail, {}), jobId);
    }

    function getClassSplitFilteredPoints() {
        const result = classSplitState.result;
        const points = Array.isArray(result?.points) ? result.points : [];
        const filter = String(classSplitElements.filterClass?.value || "").trim();
        if (!filter) {
            return points;
        }
        return points.filter((point) => String(point.class_name || "") === filter);
    }

    function getClassSplitGraphPoints() {
        const points = getClassSplitFilteredPoints();
        const displayMode = String(classSplitElements.displayMode?.value || "all");
        if (displayMode === "wrong_only") {
            return points.filter((point) => !!point.is_wrong_class_candidate);
        }
        if (displayMode === "overlap_only") {
            return points.filter((point) => !!point.is_close_overlap_candidate && classSplitPointMatchesOverlapPairFilter(point));
        }
        if (displayMode === "review_only") {
            return points.filter((point) => Array.isArray(point.review_signals) && point.review_signals.length && classSplitPointMatchesOverlapPairFilter(point));
        }
        return points;
    }

    function classSplitPointMustStayPlotted(point) {
        const pointId = String(point?.point_id || "");
        if (!pointId) {
            return false;
        }
        if (
            pointId === classSplitState.selectedPointId
            || pointId === classSplitState.flashPointId
            || classSplitState.lassoPointIds?.has(pointId)
        ) {
            return true;
        }
        return !!point?.is_wrong_class_candidate;
    }

    function sampleClassSplitGraphPoints(points) {
        const source = Array.isArray(points) ? points : [];
        const cap = CLASS_SPLIT_MAX_PLOT_POINTS;
        if (source.length <= cap) {
            return { points: source, capped: false, requestedCount: source.length, cap };
        }
        const forcedIds = new Set();
        const forcedObjects = new Set();
        const groups = new Map();
        source.forEach((point) => {
            const pointId = String(point?.point_id || "");
            if (classSplitPointMustStayPlotted(point)) {
                if (pointId) {
                    forcedIds.add(pointId);
                } else {
                    forcedObjects.add(point);
                }
                return;
            }
            const className = String(point?.class_name || "").trim() || "unknown";
            if (!groups.has(className)) {
                groups.set(className, []);
            }
            groups.get(className).push(point);
        });
        const remainingSlots = Math.max(0, cap - forcedIds.size - forcedObjects.size);
        const keepIds = new Set(forcedIds);
        const keepObjects = new Set(forcedObjects);
        const groupEntries = Array.from(groups.entries()).filter(([, group]) => group.length > 0);
        const nonForcedCount = groupEntries.reduce((sum, [, group]) => sum + group.length, 0);
        if (remainingSlots > 0 && nonForcedCount > 0 && groupEntries.length > 0) {
            const quotas = groupEntries.map(([className, group]) => {
                const ideal = (group.length / nonForcedCount) * remainingSlots;
                const minimumQuota = remainingSlots >= groupEntries.length ? 1 : 0;
                return {
                    className,
                    group,
                    quota: Math.min(group.length, Math.max(minimumQuota, Math.floor(ideal))),
                    remainder: ideal - Math.floor(ideal),
                };
            });
            let quotaTotal = quotas.reduce((sum, entry) => sum + entry.quota, 0);
            quotas
                .slice()
                .sort((a, b) => b.remainder - a.remainder || b.group.length - a.group.length)
                .forEach((entry) => {
                    if (quotaTotal >= remainingSlots || entry.quota >= entry.group.length) {
                        return;
                    }
                    entry.quota += 1;
                    quotaTotal += 1;
                });
            quotas
                .slice()
                .sort((a, b) => b.quota - a.quota || a.group.length - b.group.length)
                .forEach((entry) => {
                    while (quotaTotal > remainingSlots && entry.quota > 0) {
                        entry.quota -= 1;
                        quotaTotal -= 1;
                    }
                });
            quotas.forEach((entry) => {
                const group = entry.group;
                const quota = Math.min(group.length, Math.max(0, entry.quota));
                if (quota <= 0) {
                    return;
                }
                if (quota >= group.length) {
                    group.forEach((point) => {
                        const pointId = String(point?.point_id || "");
                        if (pointId) {
                            keepIds.add(pointId);
                        } else {
                            keepObjects.add(point);
                        }
                    });
                    return;
                }
                const stride = group.length / quota;
                for (let index = 0; index < quota; index += 1) {
                    const sampled = group[Math.min(group.length - 1, Math.floor((index + 0.5) * stride))];
                    const pointId = String(sampled?.point_id || "");
                    if (pointId) {
                        keepIds.add(pointId);
                    } else {
                        keepObjects.add(sampled);
                    }
                }
            });
        }
        return {
            points: source.filter((point) => {
                const pointId = String(point?.point_id || "");
                return (pointId && keepIds.has(pointId)) || keepObjects.has(point);
            }),
            capped: true,
            requestedCount: source.length,
            cap,
        };
    }

    function classSplitPointMatchesActiveGraphView(point) {
        if (!point) {
            return false;
        }
        const filter = String(classSplitElements.filterClass?.value || "").trim();
        if (filter && String(point.class_name || "") !== filter) {
            return false;
        }
        const displayMode = String(classSplitElements.displayMode?.value || "all");
        if (displayMode === "wrong_only") {
            return !!point.is_wrong_class_candidate;
        }
        if (displayMode === "overlap_only") {
            return !!point.is_close_overlap_candidate && classSplitPointMatchesOverlapPairFilter(point);
        }
        if (displayMode === "review_only") {
            return Array.isArray(point.review_signals) && point.review_signals.length && classSplitPointMatchesOverlapPairFilter(point);
        }
        return true;
    }

    function pruneClassSplitSelectionsForActiveGraphView() {
        const selectedPoint = getClassSplitPointById(classSplitState.selectedPointId);
        if (classSplitState.selectedPointId && !classSplitPointMatchesActiveGraphView(selectedPoint)) {
            classSplitState.selectedPointId = "";
            stopClassSplitPlotFlash();
        }
        const previousSelectionSize = classSplitState.lassoPointIds?.size || 0;
        const visibleSelection = Array.from(classSplitState.lassoPointIds || [])
            .filter((pointId) => classSplitPointMatchesActiveGraphView(getClassSplitPointById(pointId)));
        if (visibleSelection.length !== previousSelectionSize) {
            classSplitState.selectionRevision += 1;
        }
        classSplitState.lassoPointIds = new Set(visibleSelection);
        if (
            classSplitState.selectedClusterId
            && !getClassSplitVisibleClusterSummaries().some((summary) => summary.clusterKey === classSplitState.selectedClusterId)
        ) {
            classSplitState.selectedClusterId = "";
        }
    }

    function refreshClassSplitFilteredReviewUi({ renderPlot = true } = {}) {
        pruneClassSplitSelectionsForActiveGraphView();
        refreshClassSplitProjectionHint();
        refreshClassSplitOverlapControls();
        refreshClassSplitClusterControls();
        renderClassSplitClusterList();
        renderClassSplitWrongList();
        renderClassSplitInspector();
        renderClassSplitBulkPanel();
        if (renderPlot) {
            renderClassSplitPlot();
        }
    }

    function classSplitScoreColor(score, low = "#dbeafe", high = "#ef4444") {
        const safeScore = Math.max(0, Math.min(1, Number(score) || 0));
        return mixHexColors(high, low, 1 - safeScore);
    }

    function classSplitClusterColor(clusterId) {
        const palette = [
            "#2563eb", "#dc2626", "#16a34a", "#f59e0b", "#9333ea", "#0891b2",
            "#db2777", "#65a30d", "#7c3aed", "#ea580c", "#0f766e", "#4f46e5",
        ];
        const idx = Math.abs(parseInt(clusterId, 10) || 0) % palette.length;
        return palette[idx];
    }

    function getClassSplitPointColor(point) {
        const mode = String(classSplitElements.colorMode?.value || "class");
        if (mode === "cluster") {
            const clusterKey = classSplitPointClusterKey(point);
            return clusterKey ? classSplitClusterColor(clusterKey) : (getClassSplitClassColorTokens(point.class_name || "").stroke || "#2563eb");
        }
        if (mode === "wrong") {
            return classSplitScoreColor(point.wrong_class_suspicion, "#e0f2fe", "#ef4444");
        }
        if (mode === "outlier") {
            return classSplitScoreColor(point.outlier_score, "#dcfce7", "#f97316");
        }
        if (mode === "area") {
            const area = Math.max(0, (Number(point.width) || 0) * (Number(point.height) || 0));
            const score = Math.min(1, Math.log10(area + 1) / 6);
            return classSplitScoreColor(score, "#f1f5f9", "#7c3aed");
        }
        if (mode === "image_value") {
            const score = Number(point.dataset_image_value_score);
            return Number.isFinite(score) ? classSplitScoreColor(score, "#dcfce7", "#be123c") : "#94a3b8";
        }
        return getClassSplitClassColorTokens(point.class_name || "").stroke || "#2563eb";
    }

    function getClassSplitPlotTheme() {
        const mode = typeof getActiveThemeMode === "function" ? getActiveThemeMode() : THEME_LIGHT;
        if (mode === THEME_PIPBOY) {
            return {
                paper: "rgba(2, 14, 5, 0.96)",
                plot: "rgba(1, 8, 3, 0.84)",
                grid: "rgba(118, 255, 92, 0.22)",
                text: "rgb(170, 255, 140)",
            };
        }
        if (mode === THEME_DARK) {
            return {
                paper: "#0f172a",
                plot: "#111827",
                grid: "rgba(148, 163, 184, 0.28)",
                text: "#dbeafe",
            };
        }
        return {
            paper: "#ffffff",
            plot: "#ffffff",
            grid: "rgba(148, 163, 184, 0.35)",
            text: "#0f172a",
        };
    }

    function getClassSplitResultClassNames(points = null) {
        const ordered = [];
        const seen = new Set();
        const add = (value) => {
            const className = String(value || "").trim();
            if (!className || seen.has(className)) {
                return;
            }
            seen.add(className);
            ordered.push(className);
        };
        (Array.isArray(loadedClassList) ? loadedClassList : []).forEach(add);
        const counts = classSplitState.result?.summary?.class_counts || {};
        Object.keys(counts).sort((a, b) => a.localeCompare(b, undefined, { numeric: true })).forEach(add);
        (Array.isArray(points) ? points : (Array.isArray(classSplitState.result?.points) ? classSplitState.result.points : []))
            .forEach((point) => add(point?.class_name));
        return ordered;
    }

    function getClassSplitVisibleClassNames(points) {
        const ordered = [];
        const seen = new Set();
        (Array.isArray(points) ? points : []).forEach((point) => {
            const className = String(point?.class_name || "").trim();
            if (!className || seen.has(className)) {
                return;
            }
            seen.add(className);
            ordered.push(className);
        });
        return ordered;
    }

    function getClassSplitClassColorTokens(className, points = null) {
        const label = String(className || "").trim() || "unknown";
        const mapped = classes && Object.prototype.hasOwnProperty.call(classes, label)
            ? Number(classes[label])
            : NaN;
        const order = getClassSplitResultClassNames(points);
        const orderIndex = order.indexOf(label);
        const index = Number.isFinite(mapped) && mapped >= 0
            ? Math.floor(mapped)
            : (orderIndex >= 0 ? orderIndex : hashStringForColor(label) % 4096);
        const cacheKey = `class-split:${label}::${index}`;
        const cached = classColorCache.get(cacheKey);
        if (cached) {
            return cached;
        }
        const stroke = index < curatedClassColors.length
            ? (normalizeHexColor(curatedClassColors[index]) || generatedClassColor(index))
            : generatedClassColor(index);
        const strokeLuminance = relativeLuminance(stroke);
        const strongBg = strokeLuminance > 0.42
            ? mixHexColors(stroke, "#0f172a", 0.34)
            : mixHexColors(stroke, "#ffffff", 0.1);
        const tokens = {
            stroke,
            fill: colorWithAlpha(stroke, 0.2),
            handleFill: colorWithAlpha(stroke, 0.35),
            strongBg: colorWithAlpha(strongBg, 0.96),
            textOnStrongBg: getTextColorForClassToastBackground(strongBg),
        };
        classColorCache.set(cacheKey, tokens);
        return tokens;
    }

    function getClassSplitThumbnailUrl(point) {
        if (!point) {
            return "";
        }
        const thumbPath = point.thumbnail_url || `/class_analysis/jobs/${encodeURIComponent(classSplitState.currentJobId)}/thumbnail/${encodeURIComponent(point.point_id)}`;
        if (/^https?:\/\//i.test(String(thumbPath))) {
            return thumbPath;
        }
        return `${API_ROOT}${thumbPath}`;
    }

    function getClassSplitPointBboxXyxy(point) {
        const raw = Array.isArray(point?.bbox_xyxy) ? point.bbox_xyxy.map((value) => Number(value)) : [];
        if (raw.length >= 4 && raw.every(Number.isFinite) && raw[2] > raw[0] && raw[3] > raw[1]) {
            return raw.slice(0, 4);
        }
        return null;
    }

    async function getClassSplitSourceImageObject(point) {
        const imageKey = getClassSplitPointImageKey(point);
        const imageRecord = images?.[imageKey];
        if (!imageRecord) {
            throw new Error(`Image is not loaded in this session: ${imageKey}`);
        }
        if (!imageRecord.object) {
            await loadImageObject(imageRecord);
        }
        if (!imageRecord.object) {
            throw new Error(`Source image could not be loaded: ${imageKey}`);
        }
        return imageRecord.object;
    }

    async function getClassSplitContextCropUrl(point) {
        if (!point) {
            return "";
        }
        const cacheKey = [
            getClassSplitPointImageKey(point),
            (Array.isArray(point.bbox_xyxy) ? point.bbox_xyxy.join(",") : ""),
        ].join("|");
        if (point._context_crop_key === cacheKey && point._context_crop_url) {
            return point._context_crop_url;
        }
        const bbox = getClassSplitPointBboxXyxy(point);
        if (!bbox) {
            return getClassSplitThumbnailUrl(point);
        }
        const imageObject = await getClassSplitSourceImageObject(point);
        const imageWidth = Number(imageObject.naturalWidth || imageObject.width) || 0;
        const imageHeight = Number(imageObject.naturalHeight || imageObject.height) || 0;
        if (!imageWidth || !imageHeight) {
            return getClassSplitThumbnailUrl(point);
        }
        const boxLeft = bbox[0];
        const boxTop = bbox[1];
        const boxWidth = Math.max(1, bbox[2] - bbox[0]);
        const boxHeight = Math.max(1, bbox[3] - bbox[1]);
        const padX = Math.min(boxWidth * 0.5, 50);
        const padY = Math.min(boxHeight * 0.5, 50);
        const cropLeft = boxLeft - padX;
        const cropTop = boxTop - padY;
        const cropWidth = Math.max(1, Math.round(boxWidth + padX * 2));
        const cropHeight = Math.max(1, Math.round(boxHeight + padY * 2));
        const sourceLeft = Math.max(0, cropLeft);
        const sourceTop = Math.max(0, cropTop);
        const sourceRight = Math.min(imageWidth, cropLeft + cropWidth);
        const sourceBottom = Math.min(imageHeight, cropTop + cropHeight);
        const sourceWidth = Math.max(0, sourceRight - sourceLeft);
        const sourceHeight = Math.max(0, sourceBottom - sourceTop);
        const maxPreviewDim = 1400;
        const outputScale = Math.min(1, maxPreviewDim / Math.max(cropWidth, cropHeight));
        const outputWidth = Math.max(1, Math.round(cropWidth * outputScale));
        const outputHeight = Math.max(1, Math.round(cropHeight * outputScale));
        const canvasEl = document.createElement("canvas");
        canvasEl.width = outputWidth;
        canvasEl.height = outputHeight;
        const ctx = canvasEl.getContext("2d");
        if (!ctx) {
            return getClassSplitThumbnailUrl(point);
        }
        ctx.fillStyle = "#000000";
        ctx.fillRect(0, 0, outputWidth, outputHeight);
        if (sourceWidth > 0 && sourceHeight > 0) {
            ctx.drawImage(
                imageObject,
                sourceLeft,
                sourceTop,
                sourceWidth,
                sourceHeight,
                (sourceLeft - cropLeft) * outputScale,
                (sourceTop - cropTop) * outputScale,
                sourceWidth * outputScale,
                sourceHeight * outputScale,
            );
        }
        const lineWidth = Math.max(2, Math.min(5, Math.round(Math.min(outputWidth, outputHeight) * 0.018)));
        ctx.lineWidth = lineWidth;
        ctx.strokeStyle = "#f97316";
        ctx.shadowColor = "rgba(0, 0, 0, 0.82)";
        ctx.shadowBlur = Math.max(2, lineWidth);
        ctx.strokeRect(
            (padX * outputScale) + lineWidth / 2,
            (padY * outputScale) + lineWidth / 2,
            Math.max(1, (boxWidth * outputScale) - lineWidth),
            Math.max(1, (boxHeight * outputScale) - lineWidth),
        );
        point._context_crop_key = cacheKey;
        point._context_crop_url = canvasEl.toDataURL("image/jpeg", 0.9);
        return point._context_crop_url;
    }

    function hydrateClassSplitContextPreviews(rootEl) {
        if (!rootEl) {
            return;
        }
        rootEl.querySelectorAll("[data-context-point-id]").forEach((img) => {
            if (!(img instanceof HTMLImageElement) || img.dataset.contextLoading === "true") {
                return;
            }
            const point = getClassSplitPointById(img.getAttribute("data-context-point-id") || "");
            if (!point) {
                return;
            }
            img.dataset.contextLoading = "true";
            getClassSplitContextCropUrl(point)
                .then((url) => {
                    if (url && img.isConnected) {
                        img.src = url;
                    }
                })
                .catch((error) => {
                    console.warn("Class Split context crop failed", error);
                    const fallback = getClassSplitThumbnailUrl(point);
                    if (fallback && img.isConnected) {
                        img.src = fallback;
                    }
                })
                .finally(() => {
                    if (img.isConnected) {
                        img.dataset.contextLoading = "false";
                    }
                });
        });
    }

    function getClassSplitPointById(pointId) {
        return classSplitState.pointsById.get(String(pointId || "")) || null;
    }

    function getClassSplitGraphHoverPreview() {
        let preview = document.getElementById("classSplitGraphHoverPreview");
        if (!preview) {
            preview = document.createElement("div");
            preview.id = "classSplitGraphHoverPreview";
            preview.className = "class-split-graph-hover-preview";
            preview.hidden = true;
            preview.innerHTML = `<img alt="Object crop preview"><span></span>`;
            document.body.appendChild(preview);
        }
        return preview;
    }

    function moveClassSplitGraphHoverPreview(event) {
        const preview = document.getElementById("classSplitGraphHoverPreview");
        if (!preview || preview.hidden) {
            return;
        }
        const gap = 18;
        const rect = preview.getBoundingClientRect();
        let left = event.clientX + gap;
        let top = event.clientY + gap;
        if (left + rect.width > window.innerWidth - gap) {
            left = Math.max(gap, event.clientX - rect.width - gap);
        }
        if (top + rect.height > window.innerHeight - gap) {
            top = Math.max(gap, window.innerHeight - rect.height - gap);
        }
        preview.style.left = `${Math.round(left)}px`;
        preview.style.top = `${Math.round(top)}px`;
    }

    function formatClassSplitGraphHoverLabel(point) {
        const className = String(point?.class_name || "object").trim();
        const imageName = classSplitShortHoverText(point?.image_relpath || "", 84);
        const suspicion = Number(point?.wrong_class_suspicion);
        const clusterLabel = formatClassSplitPointClusterLabel(point);
        const parts = [
            className,
            imageName,
            clusterLabel,
            Number.isFinite(suspicion) ? `suspicion ${suspicion.toFixed(2)}` : "",
        ].filter(Boolean);
        return parts.join(" • ");
    }

    function showClassSplitGraphHoverPreview(event, previewUrl, point) {
        if (!previewUrl) {
            return;
        }
        const preview = getClassSplitGraphHoverPreview();
        const img = preview.querySelector("img");
        const caption = preview.querySelector("span");
        if (img && img.getAttribute("src") !== previewUrl) {
            img.setAttribute("src", previewUrl);
        }
        if (caption) {
            caption.textContent = formatClassSplitGraphHoverLabel(point);
        }
        preview.hidden = false;
        moveClassSplitGraphHoverPreview(event);
    }

    function hideClassSplitGraphHoverPreview() {
        const preview = document.getElementById("classSplitGraphHoverPreview");
        if (preview) {
            preview.hidden = true;
        }
    }

    function classSplitClusterKey(clusterId) {
        if (clusterId === null || clusterId === undefined || clusterId === "") {
            return "";
        }
        return String(clusterId);
    }

    function classSplitPointClusterKey(point) {
        if (!point || getClassSplitResultScope() !== "selected_class") {
            return "";
        }
        const labels = classSplitState.clusterSearchResult?.labels_by_point_id || {};
        const pointId = String(point.point_id || "");
        if (!pointId || !Object.prototype.hasOwnProperty.call(labels, pointId)) {
            return "";
        }
        const clusterKey = classSplitClusterKey(labels[pointId]);
        return clusterKey && getClassSplitBackendClusterById(clusterKey) ? clusterKey : "";
    }

    function formatClassSplitPointClusterLabel(point) {
        const clusterKey = classSplitPointClusterKey(point);
        if (!clusterKey) {
            return "";
        }
        return `Subclass cluster ${clusterKey}`;
    }

    function getClassSplitResultScope() {
        return String(
            classSplitState.result?.summary?.analysis_scope
            || classSplitState.lastRequest?.analysis_scope
            || getClassSplitScope()
            || "selected_class"
        ).trim();
    }

    function classSplitClusterContextClass() {
        const scope = getClassSplitResultScope();
        if (scope === "selected_class") {
            return String(
                classSplitState.result?.summary?.class_name
                || classSplitState.result?.summary?.selected_class
                || classSplitState.lastRequest?.class_name
                || classSplitElements.classSelect?.value
                || ""
            ).trim();
        }
        return String(classSplitElements.filterClass?.value || "").trim();
    }

    function classSplitHasSelectedClassResult() {
        return !!classSplitState.result && getClassSplitResultScope() === "selected_class";
    }

    function classSplitClusterSearchReady() {
        return classSplitHasSelectedClassResult()
            && !!classSplitState.clusterSearchResult
            && Array.isArray(classSplitState.clusterSearchResult.clusters);
    }

    function classSplitClusterProposalsAllowed() {
        return classSplitClusterSearchReady()
            && (classSplitState.clusterSearchResult.clusters || []).length > 0;
    }

    function classSplitClusterHullsAllowed() {
        return false;
    }

    function setClassSplitClusterStatus(message, variant = "") {
        if (classSplitElements.clusterStatus) {
            classSplitElements.clusterStatus.textContent = message || "";
            classSplitElements.clusterStatus.classList.remove("warn", "error", "success", "info");
            if (variant) {
                classSplitElements.clusterStatus.classList.add(variant);
            }
        }
    }

    function renderClassSplitClusterProgress(job = null) {
        const active = !!classSplitState.clusterSearchActive
            || (job && !["completed", "failed", "cancelled"].includes(String(job.status || "")));
        if (classSplitElements.clusterProgress) {
            classSplitElements.clusterProgress.hidden = !active && !job;
        }
        const progress = Math.max(0, Math.min(1, Number(job?.progress) || 0));
        if (classSplitElements.clusterProgressFill) {
            classSplitElements.clusterProgressFill.style.width = `${Math.round(progress * 100)}%`;
        }
        if (classSplitElements.clusterStatus) {
            const pct = job ? `${Math.round(progress * 100)}%` : "";
            const message = String(job?.message || "").trim();
            const text = [pct, message].filter(Boolean).join(" • ");
            if (text) {
                setClassSplitClusterStatus(text);
            }
        }
    }

    function refreshClassSplitClusterControls() {
        const isSelectedClassResult = classSplitHasSelectedClassResult();
        const disabled = classSplitState.active || classSplitState.clusterSearchActive || !isSelectedClassResult || !classSplitState.currentJobId;
        [
            classSplitElements.clusterSource,
            classSplitElements.clusterSensitivity,
            classSplitElements.clusterMaxClusters,
            classSplitElements.clusterMinSize,
        ].forEach((control) => {
            if (control) {
                control.disabled = disabled;
            }
        });
        const source = String(classSplitElements.clusterSource?.value || "umap_islands").trim().toLowerCase();
        const umapIslandDisabled = disabled || source !== "umap_islands";
        [classSplitElements.clusterUmapNeighbors, classSplitElements.clusterUmapMinDist].forEach((control) => {
            if (control) {
                control.disabled = umapIslandDisabled;
            }
        });
        setButtonDisabled(classSplitElements.clusterRun, disabled);
    }

    function getClassSplitBackendClusterById(clusterKey) {
        const clusters = Array.isArray(classSplitState.clusterSearchResult?.clusters)
            ? classSplitState.clusterSearchResult.clusters
            : [];
        return clusters.find((cluster) => classSplitClusterKey(cluster?.cluster_id) === clusterKey) || null;
    }

    function getClassSplitVisibleClusterSummaries(points = getClassSplitFilteredPoints()) {
        const groups = new Map();
        points.forEach((point) => {
            const clusterKey = classSplitPointClusterKey(point);
            if (!clusterKey) {
                return;
            }
            if (!groups.has(clusterKey)) {
                const backendCluster = getClassSplitBackendClusterById(clusterKey);
                groups.set(clusterKey, {
                    clusterKey,
                    clusterId: clusterKey,
                    backendCluster,
                    points: [],
                    classCounts: new Map(),
                });
            }
            const group = groups.get(clusterKey);
            group.points.push(point);
            const className = String(point.class_name || "").trim() || "unknown";
            group.classCounts.set(className, (group.classCounts.get(className) || 0) + 1);
        });
        return Array.from(groups.values()).map((group) => {
            const sortedClassCounts = Array.from(group.classCounts.entries())
                .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]));
            const topClass = sortedClassCounts[0]?.[0] || "";
            const topClassCount = sortedClassCounts[0]?.[1] || 0;
            const size = group.points.length;
            const medoidId = String(group.backendCluster?.medoid_point_id || "");
            const medoidPoint = group.points.find((point) => String(point.point_id || "") === medoidId)
                || group.points
                    .slice()
                    .sort((a, b) => (Number(a.outlier_score) || 0) - (Number(b.outlier_score) || 0))[0]
                || null;
            return {
                ...group,
                size,
                totalSize: Number(group.backendCluster?.size) || size,
                medoidPoint,
                topClass,
                purity: size ? topClassCount / size : 0,
                classCount: sortedClassCounts.length,
                classCountsSorted: sortedClassCounts,
                meanOutlierScore: group.points.reduce((sum, point) => sum + (Number(point.outlier_score) || 0), 0) / Math.max(1, size),
            };
        }).sort((a, b) => {
            if (a.clusterKey === classSplitState.selectedClusterId) {
                return -1;
            }
            if (b.clusterKey === classSplitState.selectedClusterId) {
                return 1;
            }
            return b.size - a.size || String(a.clusterKey).localeCompare(String(b.clusterKey), undefined, { numeric: true });
        });
    }

    function formatClassSplitClusterMix(summary, limit = 3) {
        const entries = Array.isArray(summary?.classCountsSorted) ? summary.classCountsSorted : [];
        if (!entries.length) {
            return "no class mix";
        }
        return entries.slice(0, limit).map(([className, count]) => `${className} ${count}`).join(" / ");
    }

    function classSplitConvexHull(points) {
        const coords = [];
        const seen = new Set();
        points.forEach((point) => {
            const x = getClassSplitPointProjection(point, 0);
            const y = getClassSplitPointProjection(point, 1);
            if (!Number.isFinite(x) || !Number.isFinite(y)) {
                return;
            }
            const key = `${x.toFixed(7)}:${y.toFixed(7)}`;
            if (seen.has(key)) {
                return;
            }
            seen.add(key);
            coords.push({ x, y });
        });
        if (coords.length <= 2) {
            return coords;
        }
        coords.sort((a, b) => a.x - b.x || a.y - b.y);
        const cross = (o, a, b) => (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x);
        const lower = [];
        coords.forEach((point) => {
            while (lower.length >= 2 && cross(lower[lower.length - 2], lower[lower.length - 1], point) <= 0) {
                lower.pop();
            }
            lower.push(point);
        });
        const upper = [];
        coords.slice().reverse().forEach((point) => {
            while (upper.length >= 2 && cross(upper[upper.length - 2], upper[upper.length - 1], point) <= 0) {
                upper.pop();
            }
            upper.push(point);
        });
        return lower.slice(0, -1).concat(upper.slice(0, -1));
    }

    function buildClassSplitClusterHullTraces(points) {
        return [];
    }

    function focusClassSplitPlotOnCluster(clusterKey, { flash = true } = {}) {
        const graphEl = classSplitElements.graph;
        if (!graphEl || !window.Plotly) {
            return;
        }
        const summary = getClassSplitVisibleClusterSummaries()
            .find((item) => item.clusterKey === String(clusterKey || ""));
        if (!summary || !summary.points.length) {
            return;
        }
        const xs = summary.points.map((point) => getClassSplitPointProjection(point, 0)).filter(Number.isFinite);
        const ys = summary.points.map((point) => getClassSplitPointProjection(point, 1)).filter(Number.isFinite);
        if (!xs.length || !ys.length) {
            return;
        }
        const allXRange = getClassSplitPointRange(getClassSplitFilteredPoints(), 0);
        const allYRange = getClassSplitPointRange(getClassSplitFilteredPoints(), 1);
        const minX = Math.min(...xs);
        const maxX = Math.max(...xs);
        const minY = Math.min(...ys);
        const maxY = Math.max(...ys);
        const fullXSpan = Math.max(Math.abs(allXRange[1] - allXRange[0]), 1e-6);
        const fullYSpan = Math.max(Math.abs(allYRange[1] - allYRange[0]), 1e-6);
        const xSpan = Math.max(maxX - minX, fullXSpan * 0.14, 1e-6);
        const ySpan = Math.max(maxY - minY, fullYSpan * 0.14, 1e-6);
        const xMid = (minX + maxX) / 2;
        const yMid = (minY + maxY) / 2;
        window.Plotly.relayout(graphEl, {
            "xaxis.range": [xMid - xSpan * 0.7, xMid + xSpan * 0.7],
            "yaxis.range": [yMid - ySpan * 0.7, yMid + ySpan * 0.7],
        }).catch((error) => console.debug("Class Split cluster focus failed", error));
        if (flash && summary.medoidPoint?.point_id) {
            startClassSplitPlotFlash(summary.medoidPoint.point_id);
        }
    }

    function selectClassSplitCluster(clusterKey, { focusPlot = true } = {}) {
        const safeKey = String(clusterKey || "");
        const summary = getClassSplitVisibleClusterSummaries()
            .find((item) => item.clusterKey === safeKey);
        if (!summary || !summary.points.length) {
            return;
        }
        if (classSplitElements.displayMode && String(classSplitElements.displayMode.value || "all") !== "all") {
            classSplitElements.displayMode.value = "all";
        }
        classSplitState.selectedClusterId = safeKey;
        classSplitState.lassoPointIds = new Set(summary.points.map((point) => String(point.point_id || "")).filter(Boolean));
        classSplitState.selectionRevision += 1;
        classSplitState.selectedPointId = String(summary.medoidPoint?.point_id || summary.points[0]?.point_id || "");
        renderClassSplitInspector();
        renderClassSplitClusterList();
        renderClassSplitBulkPanel();
        const plotRender = renderClassSplitPlot();
        if (focusPlot) {
            Promise.resolve(plotRender).then(() => {
                if (classSplitState.selectedClusterId === safeKey) {
                    focusClassSplitPlotOnCluster(safeKey, { flash: true });
                }
            });
        }
    }

    function renderClassSplitClusterList() {
        const listEl = classSplitElements.clusterList;
        if (!listEl) {
            return;
        }
        if (!classSplitState.result) {
            listEl.innerHTML = `<div class="training-help">Run selected-class analysis before searching for subclass clusters.</div>`;
            renderClassSplitClusterProgress();
            refreshClassSplitClusterControls();
            return;
        }
        if (getClassSplitResultScope() !== "selected_class") {
            listEl.innerHTML = `<div class="training-help">Subclass clustering is disabled for all-class graphs. Rerun with Scope = Selected class to search for subclasses within one class.</div>`;
            setClassSplitClusterStatus("All-class cluster search disabled.", "warn");
            renderClassSplitClusterProgress();
            refreshClassSplitClusterControls();
            return;
        }
        if (classSplitState.clusterSearchActive) {
            listEl.innerHTML = `<div class="training-help">Searching ${escapeHtml(classSplitClusterContextClass() || "selected class")} for subclass candidates ...</div>`;
            refreshClassSplitClusterControls();
            return;
        }
        if (!classSplitState.clusterSearchResult) {
            listEl.innerHTML = `<div class="training-help">Click Find subclass clusters to propose review islands inside the selected class. UMAP island mode follows local visual density in a subclass-tuned UMAP map; strict embedding mode uses high-dimensional KMeans.</div>`;
            setClassSplitClusterStatus("Ready for selected-class cluster search.", "info");
            renderClassSplitClusterProgress();
            refreshClassSplitClusterControls();
            return;
        }
        const visiblePoints = getClassSplitFilteredPoints();
        const summaries = getClassSplitVisibleClusterSummaries(visiblePoints);
        if (!summaries.length) {
            const contextClass = classSplitClusterContextClass();
            const reason = String(classSplitState.clusterSearchResult.reason || "No clean subclass clusters were found.").trim();
            listEl.innerHTML = `<div class="training-help">${escapeHtml(contextClass ? `${reason} (${contextClass})` : reason)}</div>`;
            refreshClassSplitClusterControls();
            return;
        }
        const classNames = (Array.isArray(loadedClassList) ? loadedClassList : [])
            .map((className) => String(className || "").trim())
            .filter(Boolean);
        const selectOptions = [
            `<option value="">Choose target class</option>`,
            ...classNames.map((className) => `<option value="${escapeHtml(className)}">${escapeHtml(className)}</option>`),
        ].join("");
        const source = String(classSplitState.clusterSearchResult?.summary?.proposal_source || "").trim();
        const sourceText = source === "embedding_kmeans"
            ? "Strict embedding KMeans proposals"
            : "UMAP island proposals";
        listEl.innerHTML = [
            `<div class="training-help">Subclass clusters: ${escapeHtml(sourceText)} for ${escapeHtml(classSplitClusterContextClass() || "selected class")}. Review crop context and graph position before relabeling; proposals are not ground truth.</div>`,
            summaries.map((summary) => {
                const medoid = summary.medoidPoint;
                const thumbUrl = medoid ? getClassSplitThumbnailUrl(medoid) : "";
                const selectedClass = summary.clusterKey === classSplitState.selectedClusterId ? " class-split-cluster-item--selected" : "";
                const mix = formatClassSplitClusterMix(summary);
                const purityPct = Math.round(summary.purity * 100);
                const totalSuffix = summary.totalSize !== summary.size ? ` / ${summary.totalSize} total` : "";
                const clusterSource = String(summary.backendCluster?.proposal_source || source || "").trim();
                const score = Number(summary.backendCluster?.score ?? summary.backendCluster?.silhouette);
                const scoreLabel = clusterSource === "embedding_kmeans" ? "silhouette" : "island score";
                const scoreText = Number.isFinite(score) ? ` • ${scoreLabel} ${score.toFixed(2)}` : "";
                return [
                    `<div class="class-split-cluster-item${selectedClass}" data-cluster-id="${escapeHtml(summary.clusterKey)}">`,
                    thumbUrl
                        ? `<img class="class-split-cluster-item__thumb" src="${escapeHtml(thumbUrl)}" alt="Cluster representative crop">`
                        : `<div class="class-split-cluster-item__thumb" aria-hidden="true"></div>`,
                    `<div class="class-split-cluster-item__body">`,
                    `<strong>Subclass cluster ${escapeHtml(summary.clusterKey)} • ${escapeHtml(summary.size)} object${summary.size === 1 ? "" : "s"}${escapeHtml(totalSuffix)}</strong>`,
                    `<span>${escapeHtml(mix)} • purity ${purityPct}% • mean outlier ${summary.meanOutlierScore.toFixed(2)}${escapeHtml(scoreText)}</span>`,
                    `<div class="class-split-cluster-item__actions">`,
                    `<button type="button" class="training-button secondary" data-action="select-cluster" data-cluster-id="${escapeHtml(summary.clusterKey)}">Select cluster</button>`,
                    `<select data-action="target-cluster-class" data-cluster-id="${escapeHtml(summary.clusterKey)}">${selectOptions}</select>`,
                    `<button type="button" class="training-button" data-action="reassign-cluster" data-cluster-id="${escapeHtml(summary.clusterKey)}">Change cluster class</button>`,
                    `</div>`,
                    `</div>`,
                    `</div>`,
                ].join("");
            }).join(""),
        ].join("");
        listEl.querySelectorAll(".class-split-cluster-item").forEach((node) => {
            node.addEventListener("click", (event) => {
                if (event.target instanceof Element && event.target.closest("[data-action]")) {
                    return;
                }
                selectClassSplitCluster(node.getAttribute("data-cluster-id") || "");
            });
        });
        listEl.querySelectorAll('[data-action="select-cluster"]').forEach((button) => {
            button.addEventListener("click", (event) => {
                event.stopPropagation();
                selectClassSplitCluster(button.getAttribute("data-cluster-id") || "");
            });
        });
        listEl.querySelectorAll('[data-action="reassign-cluster"]').forEach((button) => {
            button.addEventListener("click", (event) => {
                event.stopPropagation();
                const clusterKey = button.getAttribute("data-cluster-id") || "";
                selectClassSplitCluster(clusterKey, { focusPlot: true });
                const row = button.closest(".class-split-cluster-item");
                const select = row?.querySelector('[data-action="target-cluster-class"]');
                const targetClass = select instanceof HTMLSelectElement ? select.value : "";
                changeClassSplitSelectedPointsClass(targetClass).catch((error) => {
                    console.error("Class Split cluster relabel failed", error);
                    setSamStatus(`Cluster class change failed: ${error.message || error}`, { variant: "error", duration: 5000 });
                });
            });
        });
        refreshClassSplitClusterControls();
    }

    function stopClassSplitClusterPoll() {
        if (classSplitState.clusterSearchPollTimer) {
            window.clearTimeout(classSplitState.clusterSearchPollTimer);
            classSplitState.clusterSearchPollTimer = null;
        }
    }

    function buildClassSplitClusterSearchRequest() {
        const source = String(classSplitElements.clusterSource?.value || "umap_islands").trim().toLowerCase();
        const sensitivity = String(classSplitElements.clusterSensitivity?.value || "balanced").trim().toLowerCase();
        const maxClustersRaw = parseInt(classSplitElements.clusterMaxClusters?.value || "8", 10);
        const minSizeRaw = parseInt(classSplitElements.clusterMinSize?.value || "0", 10);
        const umapNeighborsRaw = parseInt(classSplitElements.clusterUmapNeighbors?.value || "15", 10);
        const umapMinDistRaw = parseFloat(classSplitElements.clusterUmapMinDist?.value || "0.02");
        return {
            proposal_source: ["umap_islands", "embedding_kmeans"].includes(source) ? source : "umap_islands",
            sensitivity: ["conservative", "balanced", "sensitive"].includes(sensitivity) ? sensitivity : "balanced",
            max_clusters: Number.isFinite(maxClustersRaw) ? Math.max(2, Math.min(16, maxClustersRaw)) : 8,
            min_cluster_size: Number.isFinite(minSizeRaw) ? Math.max(0, Math.min(1000000, minSizeRaw)) : 0,
            umap_neighbors: Number.isFinite(umapNeighborsRaw) ? Math.max(0, Math.min(5000, umapNeighborsRaw)) : 15,
            umap_min_dist: Number.isFinite(umapMinDistRaw) ? Math.max(0, Math.min(0.99, umapMinDistRaw)) : 0.02,
        };
    }

    function applyClassSplitClusterSearchResult(resultPayload, clusterJobId = "") {
        const result = resultPayload && typeof resultPayload === "object" ? resultPayload : {};
        const labels = result.labels_by_point_id && typeof result.labels_by_point_id === "object"
            ? result.labels_by_point_id
            : {};
        (Array.isArray(classSplitState.result?.points) ? classSplitState.result.points : []).forEach((point) => {
            const pointId = String(point?.point_id || "");
            const clusterKey = pointId && Object.prototype.hasOwnProperty.call(labels, pointId)
                ? classSplitClusterKey(labels[pointId])
                : "";
            point._subclass_cluster_id = clusterKey;
        });
        classSplitState.clusterSearchResult = result;
        classSplitState.clusterSearchJobId = String(clusterJobId || result.cluster_job_id || "");
        classSplitState.selectedClusterId = "";
        if (classSplitState.lassoPointIds?.size) {
            classSplitState.selectionRevision += 1;
        }
        classSplitState.lassoPointIds = new Set();
        renderClassSplitClusterList();
        renderClassSplitReport();
        renderClassSplitBulkPanel();
        renderClassSplitPlot();
        const count = Array.isArray(result.clusters) ? result.clusters.length : 0;
        setClassSplitClusterStatus(
            count ? `Found ${count} subclass cluster${count === 1 ? "" : "s"}.` : (result.reason || "No clean subclass clusters were found."),
            count ? "success" : "warn",
        );
    }

    async function startClassSplitClusterSearch() {
        if (classSplitState.clusterSearchActive) {
            return;
        }
        if (!classSplitHasSelectedClassResult()) {
            setClassSplitClusterStatus("Run selected-class analysis before searching for subclass clusters.", "warn");
            return;
        }
        const parentJobId = String(classSplitState.currentJobId || "").trim();
        if (!parentJobId) {
            setClassSplitClusterStatus("Cluster search needs a completed backend analysis job.", "warn");
            return;
        }
        try {
            stopClassSplitClusterPoll();
            classSplitState.clusterSearchActive = true;
            classSplitState.clusterSearchJobId = "";
            classSplitState.clusterSearchResult = null;
            classSplitState.selectedClusterId = "";
            if (classSplitState.lassoPointIds?.size) {
                classSplitState.selectionRevision += 1;
            }
            classSplitState.lassoPointIds = new Set();
            const requestPayload = buildClassSplitClusterSearchRequest();
            const sourceLabel = requestPayload.proposal_source === "embedding_kmeans"
                ? "strict embedding cluster search"
                : "UMAP island search";
            renderClassSplitClusterProgress({ progress: 0, message: `Queueing ${sourceLabel} ...` });
            setClassSplitClusterStatus(`Queueing ${sourceLabel} ...`, "info");
            renderClassSplitClusterList();
            refreshClassSplitControls();
            const resp = await fetch(`${API_ROOT}/class_analysis/jobs/${encodeURIComponent(parentJobId)}/cluster_search`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(requestPayload),
            });
            const detail = await resp.text();
            if (!resp.ok) {
                throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            }
            const payload = parseJsonObjectSafe(detail, {});
            const clusterJobId = String(payload.cluster_job_id || payload.job_id || "").trim();
            if (!clusterJobId) {
                throw new Error("Cluster search did not return a job id.");
            }
            classSplitState.clusterSearchJobId = clusterJobId;
            pollClassSplitClusterSearch(clusterJobId);
        } catch (error) {
            console.error("Class Split subclass cluster search failed to start", error);
            classSplitState.clusterSearchActive = false;
            renderClassSplitClusterProgress({ progress: 1, message: `Failed: ${error.message || error}` });
            setClassSplitClusterStatus(`Failed: ${error.message || error}`, "error");
            renderClassSplitClusterList();
            refreshClassSplitControls();
        }
    }

    function pollClassSplitClusterSearch(clusterJobId) {
        stopClassSplitClusterPoll();
        const requestId = ++classSplitState.clusterSearchRequestId;
        const run = async () => {
            try {
                const resp = await fetch(`${API_ROOT}/class_analysis/cluster_search/${encodeURIComponent(clusterJobId)}`);
                const detail = await resp.text();
                if (!resp.ok) {
                    throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
                }
                if (requestId !== classSplitState.clusterSearchRequestId) {
                    return;
                }
                const job = parseJsonObjectSafe(detail, {});
                renderClassSplitClusterProgress(job);
                const status = String(job.status || "").toLowerCase();
                if (status === "completed") {
                    classSplitState.clusterSearchActive = false;
                    applyClassSplitClusterSearchResult(job.result || {}, clusterJobId);
                    refreshClassSplitControls();
                    return;
                }
                if (status === "failed") {
                    classSplitState.clusterSearchActive = false;
                    setClassSplitClusterStatus(`Failed: ${job.error || job.message || "unknown error"}`, "error");
                    renderClassSplitClusterList();
                    refreshClassSplitControls();
                    return;
                }
                if (status === "cancelled") {
                    classSplitState.clusterSearchActive = false;
                    setClassSplitClusterStatus("Cluster search cancelled.", "warn");
                    renderClassSplitClusterList();
                    refreshClassSplitControls();
                    return;
                }
                classSplitState.clusterSearchPollTimer = window.setTimeout(run, 900);
            } catch (error) {
                console.error("Class Split subclass cluster poll failed", error);
                if (requestId !== classSplitState.clusterSearchRequestId) {
                    return;
                }
                classSplitState.clusterSearchActive = false;
                setClassSplitClusterStatus(`Poll failed: ${error.message || error}`, "error");
                renderClassSplitClusterList();
                refreshClassSplitControls();
            }
        };
        run();
    }

    function classSplitShortHoverText(value, maxLength = 52) {
        const raw = String(value || "").trim();
        if (raw.length <= maxLength) {
            return raw;
        }
        const keep = Math.max(8, Math.floor((maxLength - 3) / 2));
        return `${raw.slice(0, keep)}...${raw.slice(-keep)}`;
    }

    function stopClassSplitPlotFlash({ render = false } = {}) {
        if (classSplitState.flashTimer) {
            window.clearInterval(classSplitState.flashTimer);
            classSplitState.flashTimer = null;
        }
        if (classSplitState.flashPointId) {
            classSplitState.flashPointId = "";
            classSplitState.flashStartedAt = 0;
            if (render) {
                renderClassSplitPlot();
            }
        }
    }

    function startClassSplitPlotFlash(pointId) {
        const safeId = String(pointId || "");
        if (!safeId || !classSplitState.pointsById.has(safeId)) {
            return;
        }
        stopClassSplitPlotFlash();
        classSplitState.flashPointId = safeId;
        classSplitState.flashStartedAt = Date.now();
        renderClassSplitPlot();
        classSplitState.flashTimer = window.setInterval(() => {
            if (!classSplitState.flashPointId || Date.now() - classSplitState.flashStartedAt > 1800) {
                stopClassSplitPlotFlash({ render: true });
                return;
            }
            renderClassSplitPlot();
        }, 180);
    }

    function buildClassSplitFlashTrace() {
        const point = getClassSplitPointById(classSplitState.flashPointId);
        if (!point) {
            return null;
        }
        const elapsed = Math.max(0, Date.now() - classSplitState.flashStartedAt);
        const wave = 0.5 + 0.5 * Math.sin(elapsed / 95);
        return {
            type: "scatter",
            mode: "markers",
            name: "Selected point",
            x: [getClassSplitPointProjection(point, 0)],
            y: [getClassSplitPointProjection(point, 1)],
            hoverinfo: "skip",
            showlegend: false,
            marker: {
                size: 24 + wave * 12,
                color: `rgba(250, 204, 21, ${0.28 + wave * 0.42})`,
                line: { color: "#f59e0b", width: 3 },
                symbol: "circle-open",
            },
        };
    }

    function getClassSplitPointRange(points, axisIndex) {
        const values = points
            .map((point) => getClassSplitPointProjection(point, axisIndex))
            .filter((value) => Number.isFinite(value));
        if (!values.length) {
            return [-1, 1];
        }
        let min = Math.min(...values);
        let max = Math.max(...values);
        if (min === max) {
            min -= 1;
            max += 1;
        }
        const pad = Math.max((max - min) * 0.08, 1e-6);
        return [min - pad, max + pad];
    }

    function getClassSplitAxisRange(graphEl, axisName, axisIndex) {
        const fullRange = graphEl?._fullLayout?.[axisName]?.range;
        if (Array.isArray(fullRange) && fullRange.length >= 2) {
            const a = Number(fullRange[0]);
            const b = Number(fullRange[1]);
            if (Number.isFinite(a) && Number.isFinite(b) && a !== b) {
                return [a, b];
            }
        }
        const layoutRange = graphEl?.layout?.[axisName]?.range;
        if (Array.isArray(layoutRange) && layoutRange.length >= 2) {
            const a = Number(layoutRange[0]);
            const b = Number(layoutRange[1]);
            if (Number.isFinite(a) && Number.isFinite(b) && a !== b) {
                return [a, b];
            }
        }
        return getClassSplitPointRange(getClassSplitFilteredPoints(), axisIndex);
    }

    function focusClassSplitPlotOnPoint(pointId, { flash = true } = {}) {
        const graphEl = classSplitElements.graph;
        const point = getClassSplitPointById(pointId);
        if (!graphEl || !window.Plotly || !point) {
            return;
        }
        const pointX = getClassSplitPointProjection(point, 0);
        const pointY = getClassSplitPointProjection(point, 1);
        const xRange = getClassSplitAxisRange(graphEl, "xaxis", 0);
        const yRange = getClassSplitAxisRange(graphEl, "yaxis", 1);
        const fullXRange = getClassSplitPointRange(getClassSplitFilteredPoints(), 0);
        const fullYRange = getClassSplitPointRange(getClassSplitFilteredPoints(), 1);
        const xSpan = Math.max(Math.abs(xRange[1] - xRange[0]), Math.abs(fullXRange[1] - fullXRange[0]) * 0.18, 1e-6);
        const ySpan = Math.max(Math.abs(yRange[1] - yRange[0]), Math.abs(fullYRange[1] - fullYRange[0]) * 0.18, 1e-6);
        const focusPromise = window.Plotly.relayout(graphEl, {
            "xaxis.range": [pointX - xSpan / 2, pointX + xSpan / 2],
            "yaxis.range": [pointY - ySpan / 2, pointY + ySpan / 2],
        });
        focusPromise
            .then(() => {
                if (flash) {
                    startClassSplitPlotFlash(pointId);
                }
            })
            .catch((error) => {
                console.debug("Class Split plot focus failed", error);
                if (flash) {
                    startClassSplitPlotFlash(pointId);
                }
            });
    }

    function formatClassSplitPointHoverText(point) {
        const neighbor = point.suggested_neighbor_class
            ? `Suggested by neighbors: ${escapeHtml(point.suggested_neighbor_class)}<br>`
            : "";
        const imageName = classSplitShortHoverText(point.image_relpath || "");
        const clusterLabel = formatClassSplitPointClusterLabel(point);
        return [
            `<b>${escapeHtml(point.class_name || "")}</b>`,
            `${escapeHtml(imageName)}`,
            clusterLabel ? escapeHtml(clusterLabel) : "",
            `${neighbor}Suspicion ${(Number(point.wrong_class_suspicion) || 0).toFixed(2)}`,
        ].filter(Boolean).join("<br>");
    }

    function getClassSplitPointMarkerSize(point, { suspiciousTrace = false } = {}) {
        const pointId = String(point?.point_id || "");
        if (pointId === classSplitState.selectedPointId) {
            return suspiciousTrace ? 17 : 15;
        }
        if (classSplitState.selectedClusterId && classSplitPointClusterKey(point) === classSplitState.selectedClusterId) {
            return suspiciousTrace ? 16 : 13;
        }
        if (classSplitState.lassoPointIds?.has(pointId)) {
            return suspiciousTrace ? 15 : 12;
        }
        return point?.is_wrong_class_candidate ? 10 : 8;
    }

    function getClassSplitPointMarkerLine(point, { suspiciousTrace = false } = {}) {
        const pointId = String(point?.point_id || "");
        if (pointId === classSplitState.selectedPointId) {
            return { color: "#facc15", width: 2.6 };
        }
        if (classSplitState.selectedClusterId && classSplitPointClusterKey(point) === classSplitState.selectedClusterId) {
            return { color: "#f59e0b", width: 2.1 };
        }
        if (classSplitState.lassoPointIds?.has(pointId)) {
            return { color: "#facc15", width: 1.8 };
        }
        if (point?.is_wrong_class_candidate || suspiciousTrace) {
            return { color: "#ef4444", width: 1.8 };
        }
        return { color: "rgba(15, 23, 42, 0.35)", width: 0.45 };
    }

    function buildClassSplitPointTrace(points, name, options = {}) {
        const filtered = Array.isArray(points) ? points : [];
        const suspiciousTrace = !!options.suspiciousTrace;
        const selectedPointIds = classSplitState.lassoPointIds || new Set();
        const hasAnySelection = selectedPointIds.size > 0;
        const selectedIndices = [];
        const pointIds = [];
        const xs = [];
        const ys = [];
        const hoverText = [];
        const markerSizes = [];
        const markerColors = [];
        const markerLineColors = [];
        const markerLineWidths = [];
        filtered.forEach((point, index) => {
            const pointId = String(point.point_id || "");
            if (selectedPointIds.has(pointId)) {
                selectedIndices.push(index);
            }
            const markerLine = getClassSplitPointMarkerLine(point, { suspiciousTrace });
            pointIds.push(pointId);
            xs.push(getClassSplitPointProjection(point, 0));
            ys.push(getClassSplitPointProjection(point, 1));
            hoverText.push(formatClassSplitPointHoverText(point));
            markerSizes.push(getClassSplitPointMarkerSize(point, { suspiciousTrace }));
            markerColors.push(options.color || getClassSplitPointColor(point));
            markerLineColors.push(markerLine.color);
            markerLineWidths.push(markerLine.width);
        });
        return {
            type: "scattergl",
            mode: "markers",
            name,
            legendgroup: options.legendgroup || name,
            showlegend: options.showlegend !== false,
            x: xs,
            y: ys,
            customdata: pointIds,
            selectedpoints: hasAnySelection ? selectedIndices : null,
            text: hoverText,
            hovertemplate: "%{text}<extra></extra>",
            marker: {
                size: markerSizes,
                color: markerColors,
                opacity: options.opacity ?? (suspiciousTrace ? 0.95 : 0.78),
                line: {
                    color: markerLineColors,
                    width: markerLineWidths,
                },
            },
            selected: {
                marker: {
                    opacity: 1,
                },
            },
            unselected: {
                marker: {
                    opacity: hasAnySelection ? 0.22 : (options.opacity ?? (suspiciousTrace ? 0.95 : 0.78)),
                },
            },
        };
    }

    function buildClassSplitTrace(points, name, suspiciousOnly = false) {
        const filtered = points.filter((point) => !!point.is_wrong_class_candidate === suspiciousOnly);
        return buildClassSplitPointTrace(filtered, name, { suspiciousTrace: suspiciousOnly });
    }

    function buildClassSplitClassTraces(points) {
        const order = getClassSplitResultClassNames(points);
        const groups = new Map();
        order.forEach((className) => groups.set(className, []));
        points.forEach((point) => {
            const className = String(point?.class_name || "").trim() || "unknown";
            if (!groups.has(className)) {
                groups.set(className, []);
            }
            groups.get(className).push(point);
        });
        return Array.from(groups.entries())
            .filter(([, classPoints]) => classPoints.length > 0)
            .map(([className, classPoints]) => buildClassSplitPointTrace(classPoints, className, {
                legendgroup: `class:${className}`,
                color: getClassSplitClassColorTokens(className, points).stroke,
                opacity: 0.82,
            }));
    }

    function buildClassSplitGraphTraces(points) {
        const colorMode = String(classSplitElements.colorMode?.value || "class");
        const pointTraces = colorMode === "class"
            ? buildClassSplitClassTraces(points)
            : [
                buildClassSplitTrace(points, "Objects", false),
                buildClassSplitTrace(points, "Likely wrong class", true),
            ];
        return [
            ...buildClassSplitClusterHullTraces(points),
            ...pointTraces,
        ].filter((trace) => trace && trace.x && trace.x.length > 0);
    }

    function updateClassSplitBulkClassOptions() {
        const select = classSplitElements.bulkClass;
        if (!select) {
            return;
        }
        const previous = select.value;
        select.innerHTML = "";
        (Array.isArray(loadedClassList) ? loadedClassList : [])
            .map((className) => String(className || "").trim())
            .filter(Boolean)
            .forEach((className) => {
                const option = document.createElement("option");
                option.value = className;
                option.textContent = className;
                select.appendChild(option);
            });
        if (Array.from(select.options).some((option) => option.value === previous)) {
            select.value = previous;
        }
    }

    function renderClassSplitBulkPanel() {
        const panel = classSplitElements.bulkPanel;
        if (!panel) {
            return;
        }
        const selectedIds = Array.from(classSplitState.lassoPointIds || []).filter((pointId) => classSplitState.pointsById.has(pointId));
        classSplitState.lassoPointIds = new Set(selectedIds);
        panel.hidden = selectedIds.length === 0;
        if (classSplitElements.bulkCount) {
            classSplitElements.bulkCount.textContent = `${selectedIds.length} selected`;
        }
        updateClassSplitBulkClassOptions();
    }

    function clearClassSplitBulkSelection({ render = false } = {}) {
        classSplitState.selectedClusterId = "";
        if (classSplitState.lassoPointIds?.size) {
            classSplitState.selectionRevision += 1;
        }
        classSplitState.lassoPointIds = new Set();
        renderClassSplitBulkPanel();
        renderClassSplitClusterList();
        renderClassSplitWrongList();
        refreshClassSplitClusterControls();
        if (render) {
            renderClassSplitPlot();
        }
    }

    function classSplitHasAllClassResult() {
        const scope = String(classSplitState.result?.summary?.analysis_scope || classSplitState.lastRequest?.analysis_scope || "");
        return scope === "all_classes";
    }

    function isClassSplitDatasetAnalysisPanelOpen() {
        return !!classSplitElements.datasetAnalysisPanel?.open;
    }

    function clearClassSplitDatasetAnalysis({ render = false } = {}) {
        classSplitState.datasetAnalysis = null;
        (Array.isArray(classSplitState.result?.points) ? classSplitState.result.points : []).forEach((point) => {
            delete point.dataset_image_value_score;
            delete point.dataset_image_value_rank;
        });
        if (render) {
            renderClassSplitDatasetAnalysis();
        }
    }

    function refreshClassSplitDatasetAnalysisControls() {
        const hasAllClassResult = classSplitHasAllClassResult();
        setButtonDisabled(classSplitElements.datasetAnalysisRun, classSplitState.active || !hasAllClassResult);
    }

    function applyClassSplitDatasetAnalysisToPoints(analysis) {
        (Array.isArray(classSplitState.result?.points) ? classSplitState.result.points : []).forEach((point) => {
            delete point.dataset_image_value_score;
            delete point.dataset_image_value_rank;
        });
        (Array.isArray(analysis?.items) ? analysis.items : []).forEach((item, index) => {
            const score = Number(item.image_value_score);
            (Array.isArray(item.point_ids) ? item.point_ids : []).forEach((pointId) => {
                const point = getClassSplitPointById(pointId);
                if (!point) {
                    return;
                }
                point.dataset_image_value_score = Number.isFinite(score) ? score : 0;
                point.dataset_image_value_rank = index + 1;
            });
        });
    }

    function getClassSplitDatasetHoverPreview() {
        let preview = document.getElementById("classSplitDatasetAnalysisHoverPreview");
        if (!preview) {
            preview = document.createElement("div");
            preview.id = "classSplitDatasetAnalysisHoverPreview";
            preview.className = "class-split-dataset-hover-preview";
            preview.hidden = true;
            preview.innerHTML = `<img alt="Representative crop preview"><span></span>`;
            document.body.appendChild(preview);
        }
        return preview;
    }

    function moveClassSplitDatasetHoverPreview(event) {
        const preview = document.getElementById("classSplitDatasetAnalysisHoverPreview");
        if (!preview || preview.hidden) {
            return;
        }
        const gap = 18;
        const rect = preview.getBoundingClientRect();
        let left = event.clientX + gap;
        let top = event.clientY + gap;
        if (left + rect.width > window.innerWidth - gap) {
            left = Math.max(gap, event.clientX - rect.width - gap);
        }
        if (top + rect.height > window.innerHeight - gap) {
            top = Math.max(gap, window.innerHeight - rect.height - gap);
        }
        preview.style.left = `${Math.round(left)}px`;
        preview.style.top = `${Math.round(top)}px`;
    }

    function showClassSplitDatasetHoverPreview(event, previewUrl, label) {
        if (!previewUrl) {
            return;
        }
        const preview = getClassSplitDatasetHoverPreview();
        const img = preview.querySelector("img");
        const caption = preview.querySelector("span");
        if (img && img.getAttribute("src") !== previewUrl) {
            img.setAttribute("src", previewUrl);
        }
        if (caption) {
            caption.textContent = label || "";
        }
        preview.hidden = false;
        moveClassSplitDatasetHoverPreview(event);
    }

    function hideClassSplitDatasetHoverPreview() {
        const preview = document.getElementById("classSplitDatasetAnalysisHoverPreview");
        if (preview) {
            preview.hidden = true;
        }
    }

    function renderClassSplitDatasetAnalysisGraph(analysis, { force = false } = {}) {
        const graphEl = classSplitElements.datasetAnalysisGraph;
        if (!graphEl) {
            return Promise.resolve(false);
        }
        const items = Array.isArray(analysis?.items) ? analysis.items : [];
        if (!items.length) {
            graphEl.innerHTML = `<div class="training-help">No image-value points yet.</div>`;
            return Promise.resolve(false);
        }
        if (!force && !isClassSplitDatasetAnalysisPanelOpen()) {
            return Promise.resolve(false);
        }
        if (!window.Plotly) {
            graphEl.innerHTML = `<div class="training-help">Plotly did not load; cannot render dataset value graph.</div>`;
            return Promise.resolve(false);
        }
        const theme = getClassSplitPlotTheme();
        const trace = {
            type: "scatter",
            mode: "markers",
            name: "Images",
            x: items.map((item) => Number(item.projection_rarity) || 0),
            y: items.map((item) => ((Number(item.bbox_rarity) || 0) + (Number(item.feature_rarity) || 0)) / 2),
            customdata: items.map((item) => String(item.preview_point_id || "")),
            text: items.map((item) => [
                item.image_relpath || item.image_name || "image",
                `value ${Number(item.image_value) || 0}/100`,
                `${Number(item.object_count) || 0} objects`,
            ].join("<br>")),
            hovertemplate: "%{text}<br>image edge %{x:.2f}<br>object rarity %{y:.2f}<extra></extra>",
            marker: {
                size: items.map((item) => Math.max(9, Math.min(28, 7 + Math.sqrt(Number(item.object_count) || 1) * 5))),
                color: items.map((item) => Number(item.image_value) || 0),
                cmin: 0,
                cmax: 100,
                colorscale: [
                    [0, "#22c55e"],
                    [0.55, "#f59e0b"],
                    [1, "#be123c"],
                ],
                colorbar: { title: "value" },
                opacity: 0.86,
                line: { color: "rgba(15, 23, 42, 0.38)", width: 0.75 },
            },
        };
        const layout = {
            paper_bgcolor: theme.paper,
            plot_bgcolor: theme.plot,
            font: { color: theme.text, family: "system-ui, -apple-system, BlinkMacSystemFont, sans-serif" },
            margin: { l: 46, r: 28, t: 16, b: 48 },
            xaxis: {
                title: "image edge",
                range: [-0.04, 1.04],
                zeroline: false,
                gridcolor: theme.grid,
                linecolor: theme.grid,
            },
            yaxis: {
                title: "bbox / feature rarity",
                range: [-0.04, 1.04],
                zeroline: false,
                gridcolor: theme.grid,
                linecolor: theme.grid,
            },
            showlegend: false,
            uirevision: `class-split-dataset:${classSplitState.currentJobId || "live"}`,
        };
        return window.Plotly.react(graphEl, [trace], layout, {
            responsive: true,
            displaylogo: false,
            modeBarButtonsToRemove: ["toImage"],
        }).then(() => {
            if (typeof graphEl.removeAllListeners === "function") {
                ["plotly_click", "plotly_hover", "plotly_unhover"].forEach((eventName) => graphEl.removeAllListeners(eventName));
            }
            graphEl.on("plotly_click", (event) => {
                const pointId = String(event?.points?.[0]?.customdata || "");
                if (pointId) {
                    selectClassSplitPoint(pointId, { jump: false, focusPlot: true, flash: true });
                }
            });
            graphEl.on("plotly_hover", (event) => {
                const pointId = String(event?.points?.[0]?.customdata || "");
                const point = getClassSplitPointById(pointId);
                const previewUrl = point ? getClassSplitThumbnailUrl(point) : "";
                if (previewUrl && event?.event) {
                    showClassSplitDatasetHoverPreview(event.event, previewUrl, point.image_relpath || point.class_name || "image");
                } else {
                    hideClassSplitDatasetHoverPreview();
                }
            });
            graphEl.on("plotly_unhover", hideClassSplitDatasetHoverPreview);
            return true;
        }).catch((error) => {
            console.warn("Class Split dataset graph render failed", error);
            graphEl.innerHTML = `<div class="training-help error">Dataset graph failed: ${escapeHtml(error.message || error)}</div>`;
            return false;
        });
    }

    function renderClassSplitDatasetAnalysisList(analysis) {
        const listEl = classSplitElements.datasetAnalysisList;
        if (!listEl) {
            return;
        }
        const items = Array.isArray(analysis?.items) ? analysis.items : [];
        if (!items.length) {
            listEl.innerHTML = `<div class="training-help">No image-value results yet.</div>`;
            return;
        }
        listEl.innerHTML = items.slice(0, 80).map((item, index) => {
            const point = getClassSplitPointById(item.preview_point_id);
            const previewUrl = point ? getClassSplitThumbnailUrl(point) : "";
            const classes = (Array.isArray(item.classes) ? item.classes : []).slice(0, 4).join(", ");
            const rarity = Math.round((((Number(item.bbox_rarity) || 0) + (Number(item.feature_rarity) || 0)) / 2) * 100);
            const edge = Math.round((Number(item.projection_rarity) || 0) * 100);
            return [
                `<div class="class-split-dataset-list__item" data-point-id="${escapeHtml(item.preview_point_id || "")}" data-preview-url="${escapeHtml(previewUrl)}" data-preview-label="${escapeHtml(item.image_relpath || item.image_name || "")}">`,
                `<strong>#${index + 1} • value ${escapeHtml(item.image_value ?? 0)}/100 • ${escapeHtml(item.image_name || "image")}</strong>`,
                `<span>${escapeHtml(item.object_count || 0)} objects • ${escapeHtml(item.class_count || 0)} classes${classes ? ` • ${escapeHtml(classes)}` : ""}</span><br>`,
                `<span>edge ${edge}% • bbox/feature rarity ${rarity}%</span>`,
                `</div>`,
            ].join("");
        }).join("");
        listEl.querySelectorAll(".class-split-dataset-list__item").forEach((node) => {
            const pointId = String(node.getAttribute("data-point-id") || "");
            const previewUrl = String(node.getAttribute("data-preview-url") || "");
            const previewLabel = String(node.getAttribute("data-preview-label") || "");
            node.addEventListener("click", () => {
                if (pointId) {
                    selectClassSplitPoint(pointId, { jump: false, focusPlot: true, flash: true });
                }
            });
            if (previewUrl) {
                node.addEventListener("mouseenter", (event) => showClassSplitDatasetHoverPreview(event, previewUrl, previewLabel));
                node.addEventListener("mousemove", moveClassSplitDatasetHoverPreview);
                node.addEventListener("mouseleave", hideClassSplitDatasetHoverPreview);
            }
        });
    }

    function renderClassSplitDatasetAnalysis() {
        refreshClassSplitDatasetAnalysisControls();
        const hasResult = !!classSplitState.result;
        const hasAllClassResult = classSplitHasAllClassResult();
        const points = Array.isArray(classSplitState.result?.points) ? classSplitState.result.points : [];
        const analysis = classSplitState.datasetAnalysis;
        const items = Array.isArray(analysis?.items) ? analysis.items : [];
        if (classSplitElements.datasetAnalysisStatus) {
            if (!hasResult) {
                classSplitElements.datasetAnalysisStatus.textContent = "Run Class Split with Scope = All classes first.";
            } else if (!hasAllClassResult) {
                classSplitElements.datasetAnalysisStatus.textContent = "This result is selected-class only. Switch Scope to All classes and rerun Class Split.";
            } else if (!items.length) {
                classSplitElements.datasetAnalysisStatus.textContent = `Ready for ${points.length} objects.`;
            } else {
                classSplitElements.datasetAnalysisStatus.textContent = `${items.length} images scored.`;
            }
        }
        if (classSplitElements.datasetAnalysisReport) {
            if (!items.length) {
                classSplitElements.datasetAnalysisReport.innerHTML = `<div class="training-help">${
                    hasAllClassResult
                        ? "Run dataset analysis to score central versus edge images."
                        : "Dataset Analysis is optional and separate from Data Ingestion. It needs an all-class Class Split result before it can score image value."
                }</div>`;
            } else {
                const summary = analysis.summary || {};
                const rows = [
                    ["Images", summary.image_count ?? items.length],
                    ["Objects", summary.object_count ?? points.length],
                    ["Mean value", `${summary.mean_image_value ?? 0}/100`],
                    ["Edge images", summary.high_value_count ?? 0],
                    ["Central images", summary.central_count ?? 0],
                ];
                classSplitElements.datasetAnalysisReport.innerHTML = `<div class="class-split-dataset-report__grid">${
                    rows.map(([label, value]) => `<div class="class-split-dataset-report__item"><strong>${escapeHtml(label)}</strong><span>${escapeHtml(String(value))}</span></div>`).join("")
                }</div>`;
            }
        }
        renderClassSplitDatasetAnalysisList(analysis);
        renderClassSplitDatasetAnalysisGraph(analysis);
    }

    function runClassSplitDatasetAnalysis() {
        const api = getAnnotationDiversityApi();
        const points = Array.isArray(classSplitState.result?.points) ? classSplitState.result.points : [];
        if (!classSplitHasAllClassResult()) {
            setClassSplitJobStatus("Run Class Split with Scope = All classes before Dataset Analysis.", "warn");
            renderClassSplitDatasetAnalysis();
            return;
        }
        if (!api?.computeDatasetImageValueAnalysis) {
            setClassSplitJobStatus("Dataset analysis helper is unavailable.", "error");
            return;
        }
        const analysis = api.computeDatasetImageValueAnalysis(points);
        classSplitState.datasetAnalysis = analysis;
        applyClassSplitDatasetAnalysisToPoints(analysis);
        renderClassSplitDatasetAnalysis();
        renderClassSplitPlot();
        setClassSplitJobStatus(`Dataset analysis scored ${analysis.summary?.image_count || 0} images.`, "success");
    }

    function rememberClassSplitSelectionFromPlot(event) {
        const ids = new Set();
        (Array.isArray(event?.points) ? event.points : []).forEach((plotPoint) => {
            const pointId = String(plotPoint?.customdata || "");
            if (pointId && classSplitState.pointsById.has(pointId)) {
                ids.add(pointId);
            }
        });
        classSplitState.selectedClusterId = "";
        classSplitState.lassoPointIds = ids;
        classSplitState.selectionRevision += 1;
        renderClassSplitBulkPanel();
        renderClassSplitClusterList();
        const firstId = ids.values().next().value;
        if (firstId) {
            selectClassSplitPoint(firstId, { jump: false });
        } else {
            renderClassSplitPlot();
        }
    }

    function suppressClassSplitShiftWheel(graphEl) {
        if (!graphEl || graphEl.__classSplitShiftWheelSuppressor) {
            return;
        }
        graphEl.__classSplitShiftWheelSuppressor = (event) => {
            if (!event.shiftKey) {
                return;
            }
            event.preventDefault();
            event.stopImmediatePropagation();
        };
        graphEl.addEventListener("wheel", graphEl.__classSplitShiftWheelSuppressor, { passive: false, capture: true });
    }

    function bindClassSplitGraphHoverPreviewMovement(graphEl) {
        if (!graphEl || graphEl.__classSplitGraphHoverPreviewBound) {
            return;
        }
        graphEl.__classSplitGraphHoverPreviewBound = true;
        graphEl.addEventListener("mousemove", moveClassSplitGraphHoverPreview, { passive: true });
        graphEl.addEventListener("mouseleave", hideClassSplitGraphHoverPreview);
    }

    function classSplitGraphHasLivePlot(graphEl = classSplitElements.graph) {
        return !!(graphEl && Array.isArray(graphEl.data) && graphEl.data.length > 0);
    }

    function clearClassSplitGraphPlaceholderText(graphEl) {
        if (!graphEl) {
            return;
        }
        Array.from(graphEl.children || []).forEach((child) => {
            if (child instanceof HTMLElement && child.classList.contains("training-help")) {
                child.remove();
            }
        });
    }

    function setClassSplitGraphPlaceholder(html, { purge = true } = {}) {
        const graphEl = classSplitElements.graph;
        if (!graphEl) {
            return;
        }
        if (purge) {
            try {
                if (window.Plotly && typeof window.Plotly.purge === "function" && Array.isArray(graphEl.data)) {
                    window.Plotly.purge(graphEl);
                }
            } catch (error) {
                console.warn("Class Split placeholder purge failed", error);
            }
            graphEl.data = [];
            graphEl.layout = null;
        }
        graphEl.innerHTML = html;
    }

    function getClassSplitGraphViewModel() {
        const allPoints = Array.isArray(classSplitState.result?.points) ? classSplitState.result.points : [];
        const filteredPoints = getClassSplitFilteredPoints();
        const requestedPoints = getClassSplitGraphPoints();
        const plotSample = sampleClassSplitGraphPoints(requestedPoints);
        const points = plotSample.points;
        const classNames = getClassSplitVisibleClassNames(points);
        const projectionChoice = getClassSplitProjectionChoice();
        const displayMode = String(classSplitElements.displayMode?.value || "all");
        const filterClass = String(classSplitElements.filterClass?.value || "").trim();
        const colorMode = String(classSplitElements.colorMode?.value || "class");
        return {
            allPoints,
            filteredPoints,
            requestedPoints,
            points,
            plotCapped: plotSample.capped,
            plotCap: plotSample.cap,
            classNames,
            projectionChoice,
            displayMode,
            filterClass,
            colorMode,
            projectionUnavailable: getClassSplitProjectionUnavailableMessage(),
        };
    }

    function classSplitColorModeLabel(value) {
        const labels = {
            class: "class",
            cluster: "cluster",
            wrong: "wrong-class suspicion",
            outlier: "outlier score",
            area: "box area",
            image_value: "image value",
        };
        return labels[String(value || "class")] || "class";
    }

    function updateClassSplitGraphStatus(view, message = "") {
        const statusEl = classSplitElements.graphStatus;
        if (!statusEl) {
            return;
        }
        if (!classSplitState.result) {
            statusEl.textContent = "";
            return;
        }
        const parts = [];
        if (view.plotCapped) {
            parts.push(`${view.points.length}/${view.requestedPoints.length} objects plotted`);
            parts.push(`plot thinned at ${view.plotCap} to keep the browser responsive`);
        } else {
            parts.push(`${view.points.length}/${view.allPoints.length} objects shown`);
        }
        parts.push(`${view.classNames.length} class${view.classNames.length === 1 ? "" : "es"}`);
        parts.push(classSplitProjectionChoiceLabel(view.projectionChoice));
        parts.push(`colored by ${classSplitColorModeLabel(view.colorMode)}`);
        if (view.filterClass) {
            parts.push(`filter: ${view.filterClass}`);
        }
        if (view.displayMode === "wrong_only") {
            parts.push("likely wrong only");
        }
        if (message) {
            parts.push(message);
        }
        statusEl.textContent = parts.join(" • ");
    }

    function renderClassSplitPlot() {
        const graphEl = classSplitElements.graph;
        hideClassSplitGraphHoverPreview();
        if (!graphEl) {
            return Promise.resolve(false);
        }
        if (!window.Plotly) {
            setClassSplitGraphPlaceholder(`<div class="training-help">Plotly did not load; cannot render the cluster graph.</div>`);
            return Promise.resolve(false);
        }
        const renderToken = ++classSplitState.plotRenderToken;
        const view = getClassSplitGraphViewModel();
        const points = view.points;
        refreshClassSplitProjectionHint();
        updateClassSplitGraphStatus(view);
        if (!points.length) {
            if (classSplitState.active && !classSplitState.result) {
                setClassSplitGraphPlaceholder(`<div class="training-help">Class Split analysis is running. The graph will appear when the backend finishes embedding and projection.</div>`);
                return Promise.resolve(false);
            }
            const wrongOnly = String(classSplitElements.displayMode?.value || "all") === "wrong_only";
            setClassSplitGraphPlaceholder(`<div class="training-help">${wrongOnly ? "No likely wrong-class points match the current class filter." : "No points match the current filter."}</div>`);
            return Promise.resolve(false);
        }
        const projectionUnavailable = view.projectionUnavailable;
        if (projectionUnavailable) {
            setClassSplitGraphPlaceholder(`<div class="training-help">${escapeHtml(projectionUnavailable)}</div>`);
            return Promise.resolve(false);
        }
        const projectionChoice = view.projectionChoice;
        if (!classSplitProjectionCoordinatesLoaded(projectionChoice)) {
            updateClassSplitGraphStatus(view, "loading coordinates");
            if (!classSplitGraphHasLivePlot(graphEl)) {
                setClassSplitGraphPlaceholder(
                    `<div class="training-help">Loading ${escapeHtml(classSplitProjectionChoiceLabel(projectionChoice))} coordinates ...</div>`,
                    { purge: false },
                );
            }
            return ensureClassSplitProjectionCoordinates(projectionChoice)
                .then((loaded) => {
                    if (renderToken !== classSplitState.plotRenderToken) {
                        return false;
                    }
                    if (!loaded) {
                        setClassSplitGraphPlaceholder(`<div class="training-help">${escapeHtml(classSplitProjectionChoiceLabel(projectionChoice))} coordinates are not available for this result. Rerun Class Split to use that projection.</div>`);
                        return false;
                    }
                    return renderClassSplitPlot();
                })
                .catch((error) => {
                    if (renderToken !== classSplitState.plotRenderToken) {
                        return false;
                    }
                    console.warn("Class Split projection coordinate load failed", error);
                    setClassSplitGraphPlaceholder(`<div class="training-help error">Projection load failed: ${escapeHtml(error.message || error)}</div>`);
                    return false;
                });
        }
        const theme = getClassSplitPlotTheme();
        const traces = buildClassSplitGraphTraces(points)
            .filter((trace) => trace.x.length > 0);
        const flashTrace = buildClassSplitFlashTrace();
        if (flashTrace) {
            traces.push(flashTrace);
        }
        const layout = {
            paper_bgcolor: theme.paper,
            plot_bgcolor: theme.plot,
            font: { color: theme.text, family: "system-ui, -apple-system, BlinkMacSystemFont, sans-serif" },
            margin: { l: 42, r: 16, t: 18, b: 42 },
            xaxis: {
                title: "embedding x",
                zeroline: false,
                gridcolor: theme.grid,
                linecolor: theme.grid,
            },
            yaxis: {
                title: "embedding y",
                zeroline: false,
                gridcolor: theme.grid,
                linecolor: theme.grid,
                scaleanchor: "x",
                scaleratio: 1,
            },
            legend: {
                orientation: "h",
                y: 1.08,
                x: 0,
                bgcolor: "rgba(0,0,0,0)",
            },
            dragmode: String(classSplitElements.dragMode?.value || "lasso"),
            uirevision: [
                "class-split",
                classSplitState.currentJobId || "live",
                classSplitElements.filterClass?.value || "all",
                classSplitElements.displayMode?.value || "all",
                getClassSplitProjectionChoice(),
                points.length,
            ].join(":"),
            selectionrevision: classSplitState.selectionRevision,
        };
        const config = {
            responsive: true,
            displaylogo: false,
            scrollZoom: true,
            modeBarButtonsToRemove: ["toImage"],
        };
        clearClassSplitGraphPlaceholderText(graphEl);
        suppressClassSplitShiftWheel(graphEl);
        bindClassSplitGraphHoverPreviewMovement(graphEl);
        return window.Plotly.react(graphEl, traces, layout, config).then(() => {
            if (renderToken !== classSplitState.plotRenderToken) {
                return false;
            }
            classSplitState.lastPlotViewKey = layout.uirevision;
            updateClassSplitGraphStatus(view);
            if (typeof graphEl.removeAllListeners === "function") {
                [
                    "plotly_click",
                    "plotly_hover",
                    "plotly_unhover",
                    "plotly_selected",
                    "plotly_deselect",
                ].forEach((eventName) => graphEl.removeAllListeners(eventName));
            }
            graphEl.on("plotly_click", (event) => {
                const point = event?.points?.[0];
                const pointId = String(point?.customdata || "");
                if (pointId) {
                    selectClassSplitPoint(pointId, { jump: false });
                }
            });
            graphEl.on("plotly_hover", (event) => {
                const pointId = String(event?.points?.[0]?.customdata || "");
                const point = getClassSplitPointById(pointId);
                const previewUrl = point ? getClassSplitThumbnailUrl(point) : "";
                if (point && previewUrl && event?.event) {
                    showClassSplitGraphHoverPreview(event.event, previewUrl, point);
                } else {
                    hideClassSplitGraphHoverPreview();
                }
            });
            graphEl.on("plotly_unhover", hideClassSplitGraphHoverPreview);
            graphEl.on("plotly_selected", rememberClassSplitSelectionFromPlot);
            graphEl.on("plotly_deselect", () => {
                clearClassSplitBulkSelection({ render: true });
            });
            return true;
        }).catch((error) => {
            if (renderToken !== classSplitState.plotRenderToken) {
                return false;
            }
            console.warn("Class Split plot render failed", error);
            setClassSplitGraphPlaceholder(`<div class="training-help error">Graph render failed: ${escapeHtml(error.message || error)}</div>`);
            return false;
        });
    }

    function getClassSplitSuspicionStatus() {
        const summary = classSplitState.result?.summary || {};
        const classCounts = summary.class_counts || {};
        const classCount = Object.keys(classCounts).filter((className) => Number(classCounts[className]) > 0).length;
        const scope = String(summary.analysis_scope || "");
        if (scope !== "all_classes") {
            return {
                enabled: false,
                text: "Wrong-class suspicion is expected to stay at 0 in selected-class runs. Run all classes to compare each object against neighboring classes.",
            };
        }
        if (classCount < 2) {
            return {
                enabled: false,
                text: "Wrong-class suspicion needs at least two represented classes. With one class in the graph, scores are expected to stay at 0.",
            };
        }
        return {
            enabled: true,
            text: "Wrong-class flags compare each point with its nearest embedded neighbors. A flag appears when nearby crops are mostly from another class.",
        };
    }

    function getClassSplitPerClassClusterStats(result = classSplitState.result) {
        return { clusterCount: 0, classCount: 0, topClasses: [] };
    }

    function formatClassSplitClusterReport(result = classSplitState.result, summary = result?.summary || {}) {
        const scope = String(summary.analysis_scope || classSplitState.lastRequest?.analysis_scope || getClassSplitResultScope());
        if (scope === "all_classes") {
            return "Subclass clustering disabled in all-class view";
        }
        const clusters = Array.isArray(classSplitState.clusterSearchResult?.clusters)
            ? classSplitState.clusterSearchResult.clusters
            : [];
        if (!clusters.length) {
            return classSplitState.clusterSearchResult ? "No subclass clusters" : "Cluster search not run";
        }
        const clusterShape = clusters
            .slice()
            .sort((a, b) => (Number(b.size) || 0) - (Number(a.size) || 0))
            .slice(0, 3)
            .map((cluster) => `#${cluster.cluster_id}: ${cluster.size}`)
            .join(", ");
        return `${clusters.length} subclass cluster${clusters.length === 1 ? "" : "s"} (${clusterShape})`;
    }

    function renderClassSplitReport() {
        const reportEl = classSplitElements.report;
        if (!reportEl) {
            return;
        }
        const result = classSplitState.result || {};
        const summary = result.summary || {};
        const classCounts = summary.class_counts || {};
        const classCount = Object.keys(classCounts).filter((className) => Number(classCounts[className]) > 0).length;
        const request = classSplitState.lastRequest || {};
        const sampleCap = Number(summary.sample_cap || request.sample_cap || 0) || 0;
        const suspicion = getClassSplitSuspicionStatus();
        const cache = summary.embedding_cache || {};
        const cropCache = summary.crop_cache || {};
        const diagnostics = classSplitState.result?.diagnostics || {};
        const strongest = diagnostics.strongest_size_axis || {};
        const projectionNeighbors = String(summary.projection || request.projection || "pca") === "umap"
            ? (summary.projection_neighbor_k_resolved || summary.projection_neighbor_k || request.projection_neighbor_k || 50)
            : "n/a for PCA";
        const projectionMinDist = String(summary.projection || request.projection || "pca") === "umap"
            ? (summary.projection_min_dist ?? request.projection_min_dist ?? 0.08)
            : "n/a for PCA";
        const projectionChoice = getClassSplitProjectionChoice();
        const projectionUnavailable = getClassSplitProjectionUnavailableMessage();
        const projectionLabel = projectionUnavailable
            ? `${classSplitProjectionChoiceLabel(projectionChoice)} (unavailable until filter/rerun)`
            : classSplitProjectionChoiceLabel(projectionChoice);
        const sizeCorr = strongest.metric
            ? `${strongest.axis || "axis"} vs ${strongest.metric}: ${Math.abs(Number(strongest.correlation) || 0).toFixed(2)}`
            : "n/a";
        const settings = [
            ["Objects", `${summary.object_count || 0}${summary.sampled ? ` sampled from ${summary.raw_object_count || 0}` : ""}`],
            ["Classes", `${classCount}`],
            ["Encoder", `${summary.encoder_type || request.encoder_type || "encoder"}`],
            ["Graph projection", projectionLabel],
            ["Projection neighbors", `${projectionNeighbors}`],
            ["Projection min distance", `${projectionMinDist}`],
            ["Clusters", formatClassSplitClusterReport(result, summary)],
            ["Scoring neighbors", `${summary.neighbor_k || request.neighbor_k || 15}`],
            ["Crop padding", `${summary.padding_ratio ?? request.padding_ratio ?? 0.08}`],
            ["Canonical size", `${summary.canonical_size || request.canonical_size || 336}`],
            ["Crop normalization", `${summary.preprocess_mode || request.preprocess_mode || "canonical"}`],
            ["Size-bias control", `${summary.embedding_adjustment || request.embedding_adjustment || "remove_size_bias"}`],
            ["DINOv3 pooling", `${summary.dinov3_pooling || request.dinov3_pooling || "pooler"}`],
            ["C-RADIOv4 pooling", `${summary.cradio_pooling || request.cradio_pooling || "summary"}`],
            ["Background", `${summary.background_mode || request.background_mode || "full_crop"}`],
            ["Embedding views", `${summary.embedding_view_mode || request.embedding_view_mode || "single"}`],
            ["Crop cache", `${cropCache.reused || 0} reused / ${cropCache.total || 0} objects`],
            ["Embedding cache", `${cache.hits || 0} hits / ${cache.misses || 0} misses`],
            ["Size-axis check", sizeCorr],
            ["Sample cap", sampleCap > 0 ? `${sampleCap}` : "All objects"],
            ["Close overlaps", `${summary.close_overlap_pair_count || 0} pairs / ${summary.close_overlap_candidate_count || 0} objects`],
        ];
        reportEl.innerHTML = [
            `<div class="class-split-report__grid">`,
            settings.map(([label, value]) => (
                `<div class="class-split-report__item"><strong>${escapeHtml(label)}</strong><span>${escapeHtml(String(value))}</span></div>`
            )).join(""),
            `</div>`,
            `<div class="class-split-report__note">${escapeHtml(suspicion.text)}</div>`,
        ].join("");
    }

    function renderClassSplitFilterOptions() {
        const filterEl = classSplitElements.filterClass;
        if (!filterEl) {
            return;
        }
        const result = classSplitState.result || {};
        const classCounts = result.summary?.class_counts || {};
        const previous = filterEl.value;
        filterEl.innerHTML = "";
        const allOption = document.createElement("option");
        allOption.value = "";
        allOption.textContent = "All classes";
        filterEl.appendChild(allOption);
        Object.keys(classCounts).sort().forEach((className) => {
            const option = document.createElement("option");
            option.value = className;
            option.textContent = `${className} (${classCounts[className]})`;
            filterEl.appendChild(option);
        });
        const values = Array.from(filterEl.options).map((option) => option.value);
        if (values.includes(previous)) {
            filterEl.value = previous;
        }
        updateClassSplitBulkClassOptions();
        renderClassSplitOverlapPairOptions();
        refreshClassSplitOverlapControls();
    }

    function renderClassSplitOverlapPairOptions() {
        const selects = [classSplitElements.overlapClassA, classSplitElements.overlapClassB].filter(Boolean);
        if (!selects.length) {
            return;
        }
        const classNames = getClassSplitResultClassNames();
        selects.forEach((selectEl) => {
            const previous = selectEl.value;
            selectEl.innerHTML = "";
            const anyOption = document.createElement("option");
            anyOption.value = "";
            anyOption.textContent = "Any class";
            selectEl.appendChild(anyOption);
            classNames.forEach((className) => {
                const option = document.createElement("option");
                option.value = className;
                option.textContent = className;
                selectEl.appendChild(option);
            });
            const values = Array.from(selectEl.options).map((option) => option.value);
            if (values.includes(previous)) {
                selectEl.value = previous;
            }
        });
    }

    function refreshClassSplitOverlapControls() {
        const displayMode = String(classSplitElements.displayMode?.value || "all");
        const overlapModeActive = displayMode === "overlap_only" || displayMode === "review_only";
        [classSplitElements.overlapPairMode, classSplitElements.overlapClassA, classSplitElements.overlapClassB].forEach((control) => {
            if (control) {
                control.disabled = !classSplitState.result || !overlapModeActive;
            }
        });
    }

    function classSplitPointMatchesOverlapPairFilter(point) {
        const mode = String(classSplitElements.overlapPairMode?.value || "any");
        if (mode === "any") {
            return true;
        }
        const classA = String(classSplitElements.overlapClassA?.value || "").trim();
        const classB = String(classSplitElements.overlapClassB?.value || "").trim();
        if (!classA || !classB) {
            return true;
        }
        const currentClass = String(point?.class_name || "").trim();
        const matches = Array.isArray(point?.close_overlap_matches) ? point.close_overlap_matches : [];
        const hasPair = matches.some((match) => {
            const otherClass = String(match?.class_name || "").trim();
            return (currentClass === classA && otherClass === classB) || (currentClass === classB && otherClass === classA);
        });
        return mode === "include" ? hasPair : !hasPair;
    }

    function getClassSplitVisibleWrongCandidates() {
        const candidates = Array.isArray(classSplitState.result?.wrong_class_candidates)
            ? classSplitState.result.wrong_class_candidates
            : [];
        const activeFilter = String(classSplitElements.filterClass?.value || "").trim();
        return candidates.filter((item) => {
            const pointId = String(item?.point_id || "");
            const point = getClassSplitPointById(pointId);
            if (activeFilter && String(point?.class_name || item?.class_name || "") !== activeFilter) {
                return false;
            }
            return pointId && !classSplitState.dismissedWrongIds.has(pointId) && (!point || !!point.is_wrong_class_candidate);
        });
    }

    function getClassSplitWrongQueueSignature(candidates) {
        const activeFilter = String(classSplitElements.filterClass?.value || "").trim();
        return [
            classSplitState.currentJobId || "live",
            activeFilter || "all",
            candidates.length,
            candidates.map((item) => String(item?.point_id || "")).join("|"),
        ].join("::");
    }

    function reconcileClassSplitWrongQueue(candidates, { shuffle = false } = {}) {
        const cap = 12;
        const ids = candidates.map((item) => String(item?.point_id || "")).filter(Boolean);
        const idSet = new Set(ids);
        const signature = getClassSplitWrongQueueSignature(candidates);
        const previousQueue = classSplitState.wrongQueueSignature === signature
            ? Array.from(classSplitState.wrongQueueIds || []).filter((id) => idSet.has(id))
            : [];
        let nextIds = [];
        if (shuffle) {
            const shuffled = [...ids];
            for (let index = shuffled.length - 1; index > 0; index -= 1) {
                const swapIndex = Math.floor(Math.random() * (index + 1));
                [shuffled[index], shuffled[swapIndex]] = [shuffled[swapIndex], shuffled[index]];
            }
            nextIds = shuffled.slice(0, cap);
        } else {
            nextIds = previousQueue.slice(0, cap);
            for (const id of ids) {
                if (nextIds.length >= cap) {
                    break;
                }
                if (!nextIds.includes(id)) {
                    nextIds.push(id);
                }
            }
        }
        classSplitState.wrongQueueIds = nextIds;
        classSplitState.wrongQueueSignature = signature;
        return nextIds;
    }

    function shuffleClassSplitWrongQueue() {
        const candidates = getClassSplitVisibleWrongCandidates();
        reconcileClassSplitWrongQueue(candidates, { shuffle: true });
        renderClassSplitWrongList();
    }

    function getClassSplitWrongReviewOrder(candidates) {
        const candidateById = new Map();
        (Array.isArray(candidates) ? candidates : []).forEach((item) => {
            const pointId = String(item?.point_id || "");
            if (pointId) {
                candidateById.set(pointId, item);
            }
        });
        const ordered = [];
        const seen = new Set();
        const queuedIds = Array.isArray(classSplitState.wrongQueueIds)
            ? classSplitState.wrongQueueIds
            : [];
        queuedIds.forEach((pointId) => {
            const safeId = String(pointId || "");
            if (safeId && candidateById.has(safeId) && !seen.has(safeId)) {
                seen.add(safeId);
                ordered.push(candidateById.get(safeId));
            }
        });
        (Array.isArray(candidates) ? candidates : []).forEach((item) => {
            const pointId = String(item?.point_id || "");
            if (pointId && !seen.has(pointId)) {
                seen.add(pointId);
                ordered.push(item);
            }
        });
        return ordered;
    }

    function getClassSplitWrongDiscardCount() {
        const rawValue = classSplitElements.wrongDiscardCount?.value;
        const parsed = Number.parseInt(String(rawValue || ""), 10);
        if (!Number.isFinite(parsed) || parsed <= 0) {
            return 20;
        }
        return Math.max(1, Math.min(1000, parsed));
    }

    function discardFirstClassSplitWrongCandidates() {
        const visibleCandidates = getClassSplitVisibleWrongCandidates();
        const queuedIds = reconcileClassSplitWrongQueue(visibleCandidates);
        if (!visibleCandidates.length || !queuedIds.length) {
            return;
        }
        const count = getClassSplitWrongDiscardCount();
        const reviewOrder = getClassSplitWrongReviewOrder(visibleCandidates);
        const discardedIds = reviewOrder
            .slice(0, count)
            .map((item) => String(item?.point_id || ""))
            .filter(Boolean);
        if (!discardedIds.length) {
            return;
        }
        discardedIds.forEach((pointId) => classSplitState.dismissedWrongIds.add(pointId));
        classSplitState.wrongQueueIds = [];
        classSplitState.wrongQueueSignature = "";
        syncClassSplitWrongCandidateSummaryCount();
        renderClassSplitWrongList();
        renderClassSplitReport();
        setClassSplitJobStatus(
            `Discarded ${discardedIds.length} likely-wrong vignette${discardedIds.length === 1 ? "" : "s"} for this review session.`,
            "success"
        );
    }

    function setClassSplitMobileStatus(html, variant = "") {
        const el = classSplitElements.mobileStatus;
        if (!el) {
            return;
        }
        el.classList.remove("warn", "error", "success", "info");
        if (variant) {
            el.classList.add(variant);
        }
        el.innerHTML = html || "";
    }

    function setClassSplitQwenReviewContextStatus(message, variant = "") {
        const el = classSplitElements.qwenReviewContextStatus;
        if (!el) {
            return;
        }
        el.textContent = message || "";
        el.classList.toggle("warn", variant === "warn");
        el.classList.toggle("error", variant === "error");
        el.classList.toggle("success", variant === "success");
        el.classList.toggle("info", variant === "info");
    }

    function getClassSplitQwenReviewDatasetId() {
        return annotationSourceState.mode === "linked"
            ? String(annotationSourceState.datasetId || "").trim()
            : "";
    }

    function buildClassSplitDefaultGlossaryText() {
        const classNames = (Array.isArray(loadedClassList) ? loadedClassList : [])
            .map((className) => String(className || "").trim())
            .filter(Boolean);
        return classNames.map((className) => `${className}: ${className}`).join("\n");
    }

    async function loadClassSplitQwenReviewGlossary({ force = false } = {}) {
        const textarea = classSplitElements.qwenReviewGlossary;
        if (!textarea) {
            return;
        }
        const datasetId = getClassSplitQwenReviewDatasetId();
        const contextKey = datasetId || `workspace:${classSplitHashValues(loadedClassList || [])}`;
        if (!force && classSplitState.qwenReviewGlossaryDirty) {
            setClassSplitQwenReviewContextStatus("Review glossary has local edits.", "info");
            return;
        }
        if (!force && classSplitState.qwenReviewGlossaryLoadedFor === contextKey && textarea.value.trim()) {
            return;
        }
        if (classSplitState.qwenReviewGlossaryLoadInFlight) {
            return;
        }
        classSplitState.qwenReviewGlossaryLoadInFlight = true;
        setButtonDisabled(classSplitElements.qwenReviewGlossaryReset, true);
        setButtonDisabled(classSplitElements.qwenReviewGlossarySave, true);
        try {
            if (datasetId) {
                const resp = await fetch(`${API_ROOT}/datasets/${encodeURIComponent(datasetId)}/glossary`);
                const detail = await resp.text();
                if (!resp.ok) {
                    throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
                }
                const data = parseJsonObjectSafe(detail, {});
                textarea.value = String(data.glossary || data.default_glossary || "").trim();
                classSplitState.qwenReviewGlossaryLoadedFor = contextKey;
                classSplitState.qwenReviewGlossaryDirty = false;
                setClassSplitQwenReviewContextStatus("Loaded dataset review glossary.", "success");
            } else {
                textarea.value = buildClassSplitDefaultGlossaryText();
                classSplitState.qwenReviewGlossaryLoadedFor = contextKey;
                classSplitState.qwenReviewGlossaryDirty = false;
                setClassSplitQwenReviewContextStatus("Using class-list review glossary for this session.", "info");
            }
        } catch (error) {
            console.error("Class Split Qwen glossary load failed", error);
            if (force || !textarea.value.trim()) {
                textarea.value = buildClassSplitDefaultGlossaryText();
                classSplitState.qwenReviewGlossaryLoadedFor = contextKey;
                classSplitState.qwenReviewGlossaryDirty = false;
            }
            setClassSplitQwenReviewContextStatus(`Glossary load failed: ${error.message || error}`, "error");
        } finally {
            classSplitState.qwenReviewGlossaryLoadInFlight = false;
            setButtonDisabled(classSplitElements.qwenReviewGlossaryReset, false);
            setButtonDisabled(classSplitElements.qwenReviewGlossarySave, !getClassSplitQwenReviewDatasetId());
        }
    }

    async function saveClassSplitQwenReviewGlossary() {
        const datasetId = getClassSplitQwenReviewDatasetId();
        const textarea = classSplitElements.qwenReviewGlossary;
        if (!datasetId || !textarea) {
            setClassSplitQwenReviewContextStatus("Open a linked backend dataset to save the glossary.", "warn");
            return;
        }
        if (classSplitState.qwenReviewGlossarySaveInFlight) {
            return;
        }
        classSplitState.qwenReviewGlossarySaveInFlight = true;
        setButtonDisabled(classSplitElements.qwenReviewGlossarySave, true);
        try {
            const resp = await fetch(`${API_ROOT}/datasets/${encodeURIComponent(datasetId)}/glossary`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ glossary: textarea.value || "" }),
            });
            const detail = await resp.text();
            if (!resp.ok) {
                throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            }
            classSplitState.qwenReviewGlossaryDirty = false;
            classSplitState.qwenReviewGlossaryLoadedFor = datasetId;
            setClassSplitQwenReviewContextStatus("Saved review glossary to dataset.", "success");
        } catch (error) {
            console.error("Class Split Qwen glossary save failed", error);
            setClassSplitQwenReviewContextStatus(`Glossary save failed: ${error.message || error}`, "error");
        } finally {
            classSplitState.qwenReviewGlossarySaveInFlight = false;
            setButtonDisabled(classSplitElements.qwenReviewGlossarySave, !getClassSplitQwenReviewDatasetId());
        }
    }

    async function pushClassSplitReviewToMobile() {
        const jobId = String(classSplitState.currentJobId || "").trim();
        const result = classSplitState.result || {};
        const summary = result.summary || {};
        if (!jobId || !result.points) {
            setClassSplitMobileStatus("Run Class Split first.", "warn");
            return;
        }
        const sourceMode = String(summary.source_mode || "").trim().toLowerCase();
        if (!["linked", "transient", "active_workspace"].includes(sourceMode)) {
            setClassSplitMobileStatus("Mobile review needs a live Class Split session from the currently open dataset. Rerun analysis from Label Images.", "warn");
            return;
        }
        const visibleCandidates = getClassSplitVisibleWrongCandidates();
        if (!visibleCandidates.length) {
            setClassSplitMobileStatus("No likely-wrong vignettes are queued.", "warn");
            return;
        }
        try {
            setButtonDisabled(classSplitElements.mobilePush, true);
            setClassSplitMobileStatus("Pushing mobile review session ...", "info");
            if (isAnnotationDatasetModeActive() && !isAnnotationMutationBlocked()) {
                captureCurrentAnnotationDirtyState();
                if (annotationSourceState.dirtyRecordsByKey.size) {
                    const saved = await flushAnnotationSnapshot({ manual: false });
                    if (!saved) {
                        throw new Error("Pending annotation edits could not be saved before mobile review.");
                    }
                }
            }
            const resp = await fetch(`${API_ROOT}/class_analysis/jobs/${encodeURIComponent(jobId)}/mobile_review`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    label: `${summary.dataset_label || "Class Split"} likely-wrong review`,
                    annotation_session_id: annotationSourceState.lockSessionId || "",
                    dismissed_point_ids: Array.from(classSplitState.dismissedWrongIds || []),
                }),
            });
            const detail = await resp.text();
            if (!resp.ok) {
                throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            }
            const payload = parseJsonObjectSafe(detail, {});
            const mobilePath = String(payload.mobile_url || "").trim();
            const sessionId = String(payload.session_id || "").trim();
            classSplitState.mobileReviewSessionId = sessionId;
            classSplitState.mobileReviewTargetMode = "desktop_workspace";
            classSplitState.mobileReviewSyncedActions = new Set();
            const url = mobilePath ? new URL(mobilePath, API_ROOT).toString() : "";
            const link = url
                ? `<a href="${escapeHtml(url)}" target="_blank" rel="noopener">Open mobile review</a>`
                : "";
            setClassSplitMobileStatus(
                [link, sessionId ? `session ${escapeHtml(sessionId)}` : "", "Sync mobile edits when you return."].filter(Boolean).join(" • "),
                payload.warning ? "warn" : "success"
            );
            refreshClassSplitControls();
        } catch (error) {
            console.error("Class Split mobile review push failed", error);
            setClassSplitMobileStatus(`Mobile push failed: ${escapeHtml(error.message || error)}`, "error");
        } finally {
            setButtonDisabled(classSplitElements.mobilePush, false);
        }
    }

    async function syncClassSplitMobileReviewEdits() {
        const sessionId = String(classSplitState.mobileReviewSessionId || "").trim();
        if (!sessionId) {
            setClassSplitMobileStatus("No mobile review session is linked to this graph.", "warn");
            return;
        }
        if (classSplitState.mobileReviewTargetMode && classSplitState.mobileReviewTargetMode !== "desktop_workspace") {
            setClassSplitMobileStatus("This mobile review session is from an older backend-save flow. Push a new mobile review session from the current graph.", "warn");
            return;
        }
        if (classSplitState.relabelInFlight) {
            return;
        }
        classSplitState.relabelInFlight = true;
        setButtonDisabled(classSplitElements.mobileSync, true);
        try {
            const resp = await fetch(`${API_ROOT}/class_analysis/mobile_review/${encodeURIComponent(sessionId)}`);
            const detail = await resp.text();
            if (!resp.ok) {
                throw new Error(parseApiError(detail, `HTTP ${resp.status}`));
            }
            const payload = parseJsonObjectSafe(detail, {});
            const actions = Array.isArray(payload.action_log) ? payload.action_log : [];
            let changed = 0;
            let confirmed = 0;
            let skipped = 0;
            let failed = 0;
            for (let index = 0; index < actions.length; index += 1) {
                const action = actions[index] || {};
                const actionKey = String(action.action_id || "").trim()
                    || `${action.timestamp || ""}:${action.name || ""}:${action.point_id || ""}:${action.target_class || ""}`;
                if (classSplitState.mobileReviewSyncedActions.has(actionKey)) {
                    continue;
                }
                const name = String(action.name || "").trim();
                const status = String(action.status || "").trim();
                try {
                    if (name === "change_class" && status === "changed") {
                        const pointId = String(action.point_id || "").trim();
                        const targetClass = String(action.target_class || "").trim();
                        const point = getClassSplitPointById(pointId);
                        if (!point || !targetClass) {
                            failed += 1;
                        } else if (applyClassSplitPointClassLocally(point, targetClass)) {
                            changed += 1;
                        }
                    } else if (name === "confirm" && status === "confirmed") {
                        const pointId = String(action.point_id || "").trim();
                        if (pointId) {
                            clearClassSplitWrongCandidate(pointId);
                            confirmed += 1;
                        }
                    } else if (name === "skip" && status === "skipped") {
                        const pointId = String(action.point_id || "").trim();
                        if (pointId) {
                            classSplitState.dismissedWrongIds.add(pointId);
                            skipped += 1;
                        }
                    } else if (name === "skip_next" && status === "skipped") {
                        (Array.isArray(action.point_ids) ? action.point_ids : []).forEach((pointId) => {
                            const safeId = String(pointId || "").trim();
                            if (safeId) {
                                classSplitState.dismissedWrongIds.add(safeId);
                                skipped += 1;
                            }
                        });
                    }
                    classSplitState.mobileReviewSyncedActions.add(actionKey);
                } catch (error) {
                    failed += 1;
                    console.warn("Class Split mobile action sync failed", action, error);
                }
            }
            syncClassSplitWrongCandidateSummaryCount();
            renderClassSplitFilterOptions();
            refreshClassSplitFilteredReviewUi({ renderPlot: false });
            renderClassSplitReport();
            renderClassSplitDatasetAnalysis();
            renderClassSplitPlot();
            let saveText = "";
            if (isAnnotationDatasetModeActive() && !isAnnotationMutationBlocked() && annotationSourceState.dirtyRecordsByKey.size) {
                const saved = await flushAnnotationSnapshot({ manual: false });
                saveText = saved && !annotationSourceState.dirtyRecordsByKey.size
                    ? " Saved."
                    : " Save pending.";
            } else if (!isAnnotationDatasetModeActive() && changed > 0) {
                saveText = " Export/save the open labels when ready.";
            }
            const parts = [
                changed ? `${changed} class change${changed === 1 ? "" : "s"}` : "",
                confirmed ? `${confirmed} confirmation${confirmed === 1 ? "" : "s"}` : "",
                skipped ? `${skipped} skip${skipped === 1 ? "" : "s"}` : "",
                failed ? `${failed} failed` : "",
            ].filter(Boolean);
            setClassSplitMobileStatus(
                parts.length ? `Synced mobile review: ${parts.join(", ")}.${saveText}` : "No new mobile edits to sync.",
                failed ? "warn" : "success"
            );
        } catch (error) {
            console.error("Class Split mobile sync failed", error);
            setClassSplitMobileStatus(`Mobile sync failed: ${escapeHtml(error.message || error)}`, "error");
        } finally {
            classSplitState.relabelInFlight = false;
            refreshClassSplitControls();
        }
    }

    function setClassSplitQwenReviewStatus(message, variant = "") {
        if (!classSplitElements.qwenReviewStatus) {
            return;
        }
        classSplitElements.qwenReviewStatus.textContent = message || "";
        classSplitElements.qwenReviewStatus.classList.toggle("warn", variant === "warn");
        classSplitElements.qwenReviewStatus.classList.toggle("error", variant === "error");
        classSplitElements.qwenReviewStatus.classList.toggle("success", variant === "success");
    }

    function formatClassSplitQwenTraceTimestamp(rawTimestamp) {
        const timestamp = Number(rawTimestamp);
        if (!Number.isFinite(timestamp) || timestamp <= 0) {
            return "";
        }
        try {
            return new Date(timestamp * 1000).toLocaleTimeString([], {
                hour: "2-digit",
                minute: "2-digit",
                second: "2-digit",
                hour12: false,
            });
        } catch (_) {
            return "";
        }
    }

    function getLatestClassSplitQwenReviewJob() {
        let latest = null;
        classSplitState.qwenReviewJobs.forEach((review) => {
            if (!review) {
                return;
            }
            if (!latest || Number(review.updated_at || 0) >= Number(latest.updated_at || 0)) {
                latest = review;
            }
        });
        return latest;
    }

    function classSplitQwenReviewEvidenceRole(item, citedIds = null) {
        const kind = String(item?.kind || "").trim();
        const metadata = item?.metadata && typeof item.metadata === "object" ? item.metadata : {};
        const cited = citedIds instanceof Set && citedIds.has(String(item?.evidence_id || ""));
        let role = "audit artifact";
        if (["target_detail", "source_clean", "zoom_region", "specificity_region_contrast"].includes(kind)) {
            role = "final VLM visual core";
        } else if (["class_context_pack", "local_consensus_context", "overlap_decomposition", "same_image_scale_report", "same_image_embedding_report"].includes(kind)) {
            role = "text/ledger context";
        } else if (kind === "source_overlay") {
            role = "geometry overlay context";
        } else if (kind === "target_context") {
            role = "target setup context";
        }
        if (metadata.bbox_overlay === true && role === "final VLM visual core") {
            role = "overlay context";
        }
        return cited ? `${role} • cited by final` : role;
    }

    function renderClassSplitQwenEvidenceThumb(item, citedIds = null) {
        const url = String(item?.artifact_url || "");
        if (!url) {
            return "";
        }
        const evidenceId = String(item?.evidence_id || "").trim();
        const title = String(item?.title || item?.kind || "Qwen evidence").trim();
        const role = classSplitQwenReviewEvidenceRole(item, citedIds);
        const citedClass = citedIds instanceof Set && citedIds.has(evidenceId) ? " is-cited" : "";
        return [
            `<a class="class-split-qwen-review__evidence-item${citedClass}" href="${escapeHtml(url)}" target="_blank" rel="noopener">`,
            `<img src="${escapeHtml(url)}" alt="${escapeHtml(title)}" loading="lazy">`,
            `<span>${escapeHtml(title)}</span>`,
            `<small>${escapeHtml(evidenceId)}${evidenceId ? " • " : ""}${escapeHtml(role)}</small>`,
            `</a>`,
        ].join("");
    }

    function formatClassSplitQwenTraceEventTitle(event) {
        const type = String(event?.type || "event");
        const phase = String(event?.phase || "").trim();
        const tool = String(event?.tool || "").trim();
        if (type === "controller_tool_call") {
            return `Tool call: ${tool || "evidence tool"}`;
        }
        if (type === "tool_result") {
            return `Tool output: ${tool || "evidence tool"}`;
        }
        if (type === "router_decision") {
            return `Route: ${String(event?.router?.action || "controller decision")}`;
        }
        if (type === "model_output") {
            return `VLM output${phase ? `: ${phase}` : ""}`;
        }
        if (type === "final_context_compacted") {
            return "Final VLM context selected";
        }
        if (type === "compact_final_expanded") {
            return "Final JSON expanded";
        }
        return phase ? `${type}: ${phase}` : type;
    }

    function renderClassSplitQwenTraceEvent(event) {
        const timestamp = formatClassSplitQwenTraceTimestamp(event?.timestamp ?? event?.ts);
        const type = String(event?.type || "event");
        const summary = String(event?.summary || event?.message || event?.reason || "").trim();
        const evidenceIds = Array.isArray(event?.evidence_ids) ? event.evidence_ids.map((id) => String(id || "").trim()).filter(Boolean) : [];
        const details = [];
        if (summary) {
            details.push(`<p>${escapeHtml(summary)}</p>`);
        }
        if (evidenceIds.length) {
            details.push(`<p><strong>Evidence:</strong> ${escapeHtml(evidenceIds.join(", "))}</p>`);
        }
        if (type === "final_context_compacted") {
            const imageTools = Array.isArray(event.image_observations) ? event.image_observations.join(", ") : "";
            const textTools = Array.isArray(event.text_only_observations) ? event.text_only_observations.join(", ") : "";
            details.push(`<p><strong>Images sent:</strong> ${escapeHtml(imageTools || "none")}</p>`);
            details.push(`<p><strong>Text/ledger only:</strong> ${escapeHtml(textTools || "none")}</p>`);
        }
        if (type === "router_decision" && event.router) {
            details.push(`<pre>${escapeHtml(JSON.stringify(event.router, null, 2))}</pre>`);
        }
        if (type === "model_output" && typeof event.text === "string") {
            details.push(`<details open><summary>Complete VLM text</summary><pre>${escapeHtml(event.text)}</pre></details>`);
        } else if (["final_validation_error", "final_degenerate_output", "compact_final_expanded", "thinking_scratchpad_result", "specificity_probe_result"].includes(type)) {
            details.push(`<details><summary>Raw event</summary><pre>${escapeHtml(JSON.stringify(event, null, 2))}</pre></details>`);
        }
        return [
            `<li class="class-split-qwen-trace-step class-split-qwen-trace-step--${escapeHtml(type.replace(/[^a-z0-9_-]/gi, "_"))}">`,
            `<div class="class-split-qwen-trace-step__head">`,
            `<strong>${escapeHtml(formatClassSplitQwenTraceEventTitle(event))}</strong>`,
            timestamp ? `<span>${escapeHtml(timestamp)}</span>` : "",
            `</div>`,
            details.join("") || `<p>${escapeHtml(type)}</p>`,
            `</li>`,
        ].join("");
    }

    function buildClassSplitQwenReviewTraceHtml(review) {
        if (!review) {
            return "Waiting for the next Qwen review.";
        }
        const pointId = String(review.point_id || "").trim();
        const point = pointId ? getClassSplitPointById(pointId) : null;
        const status = String(review.status || "queued").toLowerCase();
        const progress = Math.max(0, Math.min(1, Number(review.progress) || 0));
        const lines = [
            `<strong>review:</strong> ${escapeHtml(String(review.review_id || review.job_id || "pending"))}`,
            `<strong>status:</strong> ${escapeHtml(status)} (${Math.round(progress * 100)}%)`,
        ];
        if (point?.class_name || point?.image_relpath) {
            lines.push(`<strong>target:</strong> ${escapeHtml(String(point.class_name || "object"))} • ${escapeHtml(String(point.image_relpath || point.image_name || pointId))}`);
        } else if (pointId) {
            lines.push(`<strong>target:</strong> ${escapeHtml(pointId)}`);
        }
        if (review.message) {
            lines.push(`<strong>message:</strong> ${escapeHtml(String(review.message))}`);
        }
        if (review.error) {
            lines.push(`<strong>error:</strong> ${escapeHtml(String(review.error))}`);
        }
        const logs = Array.isArray(review.logs) ? review.logs : [];
        const logHtml = logs.length
            ? `<details class="class-split-qwen-trace-raw"><summary>Recent backend log</summary><pre>${escapeHtml(logs.slice(-14).map((entry) => {
                const timestamp = formatClassSplitQwenTraceTimestamp(entry?.timestamp ?? entry?.ts);
                const message = String(entry?.message ?? entry?.msg ?? entry?.summary ?? entry ?? "").trim();
                return message ? `${timestamp ? `${timestamp} ` : ""}${message}` : "";
            }).filter(Boolean).join("\n"))}</pre></details>`
            : "";
        const traceEvents = Array.isArray(review.trace_events) ? review.trace_events : [];
        const timelineEvents = traceEvents.filter((event) => {
            const type = String(event?.type || "");
            return type !== "model_input";
        });
        const timelineHtml = timelineEvents.length
            ? `<ol class="class-split-qwen-trace-timeline">${timelineEvents.map(renderClassSplitQwenTraceEvent).join("")}</ol>`
            : `<div class="training-help">Waiting for backend trace events. Current status is shown above.</div>`;
        const rawOutputEvents = traceEvents.filter((event) => String(event?.type || "") === "model_output");
        const rawOutputHtml = rawOutputEvents.length
            ? `<details class="class-split-qwen-trace-raw" open><summary>Complete raw VLM outputs</summary>${rawOutputEvents.map((event) => {
                const phase = String(event?.phase || "model_output");
                return `<h4>${escapeHtml(phase)}</h4><pre>${escapeHtml(String(event?.text || ""))}</pre>`;
            }).join("")}</details>`
            : "";
        const result = review.result && typeof review.result === "object" ? review.result : null;
        const resultHtml = result
            ? [
                `<div class="class-split-qwen-trace-decision">`,
                `<strong>${escapeHtml(formatClassSplitQwenDecision(result))}</strong>`,
                Number.isFinite(Number(result.confidence)) ? `<span>confidence ${Math.round(Number(result.confidence) * 100)}%</span>` : "",
                result.rationale_short ? `<p>${escapeHtml(String(result.rationale_short))}</p>` : "",
                `</div>`,
            ].join("")
            : "";
        return [
            `<div class="class-split-qwen-trace-summary">${lines.map((line) => `<div>${line}</div>`).join("")}</div>`,
            timelineHtml,
            resultHtml,
            rawOutputHtml,
            logHtml,
        ].join("");
    }

    function buildClassSplitQwenReviewTraceText(review) {
        if (!review) {
            return "Waiting for the next Qwen review.";
        }
        const pointId = String(review.point_id || "").trim();
        const point = pointId ? getClassSplitPointById(pointId) : null;
        const status = String(review.status || "queued").toLowerCase();
        const progress = Math.max(0, Math.min(1, Number(review.progress) || 0));
        const lines = [
            `review: ${String(review.review_id || review.job_id || "pending")}`,
            `status: ${status} (${Math.round(progress * 100)}%)`,
        ];
        if (point?.class_name || point?.image_relpath) {
            lines.push(`target: ${String(point.class_name || "object")} • ${String(point.image_relpath || point.image_name || pointId)}`);
        } else if (pointId) {
            lines.push(`target: ${pointId}`);
        }
        if (review.message) {
            lines.push(`message: ${String(review.message)}`);
        }
        if (review.error) {
            lines.push(`error: ${String(review.error)}`);
        }
        const logs = Array.isArray(review.logs) ? review.logs : [];
        if (logs.length) {
            lines.push("", "recent backend log:");
            logs.slice(-14).forEach((entry) => {
                const timestamp = formatClassSplitQwenTraceTimestamp(entry?.timestamp ?? entry?.ts);
                const message = String(entry?.message ?? entry?.msg ?? entry?.summary ?? entry ?? "").trim();
                if (message) {
                    lines.push(`${timestamp ? `${timestamp} ` : ""}${message}`);
                }
            });
        }
        const traceEvents = Array.isArray(review.trace_events) ? review.trace_events : [];
        const visibleEvents = traceEvents.filter((event) => {
            const type = String(event?.type || "");
            return type === "model_output"
                || type === "final_validation_error"
                || type === "final_degenerate_output"
                || type === "compact_final_expanded"
                || type === "thinking_scratchpad_result"
                || type === "specificity_probe_result";
        }).slice(-12);
        if (visibleEvents.length) {
            lines.push("", "raw VLM / controller output:");
            visibleEvents.forEach((event) => {
                const type = String(event?.type || "event");
                const phase = String(event?.phase || "").trim();
                const label = phase ? `${type} (${phase})` : type;
                if (typeof event?.text === "string") {
                    lines.push("", `${label}:`, event.text);
                } else {
                    lines.push("", `${label}:`, JSON.stringify(event, null, 2));
                }
            });
        }
        const result = review.result && typeof review.result === "object" ? review.result : null;
        if (result) {
            lines.push("", "decision:");
            lines.push(formatClassSplitQwenDecision(result));
            if (Number.isFinite(Number(result.confidence))) {
                lines.push(`confidence: ${Math.round(Number(result.confidence) * 100)}%`);
            }
            if (result.rationale_short) {
                lines.push(`rationale: ${String(result.rationale_short)}`);
            }
            const guarded = result.guarded_recommendation && typeof result.guarded_recommendation === "object"
                ? result.guarded_recommendation
                : null;
            if (guarded?.blocked) {
                const reasons = Array.isArray(guarded.guardrail_reasons)
                    ? guarded.guardrail_reasons.map((item) => String(item || "").trim()).filter(Boolean)
                    : [];
                lines.push(`guarded: held for human review${reasons.length ? ` • ${reasons[0]}` : ""}`);
            }
        }
        return lines.join("\n");
    }

    function renderClassSplitQwenReviewTraceToast(review = null) {
        if (!classSplitElements.qwenReviewTraceToast || !classSplitElements.qwenReviewTraceBody) {
            return;
        }
        if (!classSplitState.qwenReviewTraceEnabled) {
            classSplitElements.qwenReviewTraceToast.hidden = true;
            return;
        }
        const activeReview = review || getLatestClassSplitQwenReviewJob();
        classSplitElements.qwenReviewTraceToast.hidden = false;
        classSplitElements.qwenReviewTraceBody.innerHTML = buildClassSplitQwenReviewTraceHtml(activeReview);
        classSplitElements.qwenReviewTraceBody.scrollTop = classSplitElements.qwenReviewTraceBody.scrollHeight;
    }

    function setClassSplitQwenReviewTraceEnabled(enabled) {
        classSplitState.qwenReviewTraceEnabled = Boolean(enabled);
        if (classSplitElements.qwenReviewTraceToggle) {
            classSplitElements.qwenReviewTraceToggle.checked = classSplitState.qwenReviewTraceEnabled;
        }
        renderClassSplitQwenReviewTraceToast();
    }

    function renderClassSplitQwenReviewModelOptions() {
        const select = classSplitElements.qwenReviewModel;
        if (!select) {
            return;
        }
        const selected = select.value || classSplitState.qwenReviewActiveModelId || "";
        const models = Array.isArray(classSplitState.qwenReviewModels) ? classSplitState.qwenReviewModels : [];
        const options = [
            `<option value="">Active model${classSplitState.qwenReviewActiveModelId ? ` (${escapeHtml(classSplitState.qwenReviewActiveModelId)})` : ""}</option>`,
            ...models.map((entry) => {
                const id = String(entry?.id || "").trim();
                if (!id) {
                    return "";
                }
                const metadata = entry?.metadata || {};
                if (metadata.inference_supported === false || metadata.vision_inference_supported === false) {
                    return "";
                }
                const label = String(metadata.display_name || metadata.label || metadata.name || entry.label || entry.name || id);
                const activeSuffix = id === classSplitState.qwenReviewActiveModelId ? " (active)" : "";
                return `<option value="${escapeHtml(id)}"${id === selected ? " selected" : ""}>${escapeHtml(label + activeSuffix)}</option>`;
            }).filter(Boolean),
        ].join("");
        select.innerHTML = options;
        if (selected && models.some((entry) => String(entry?.id || "") === selected)) {
            select.value = selected;
        }
    }

    async function refreshClassSplitQwenReviewModels() {
        if (classSplitState.qwenReviewModelRefreshInFlight) {
            return;
        }
        classSplitState.qwenReviewModelRefreshInFlight = true;
        setButtonDisabled(classSplitElements.qwenReviewRefresh, true);
        setClassSplitQwenReviewStatus("Loading reviewer models ...", "info");
        try {
            const resp = await fetch(`${API_ROOT}/qwen/models`);
            if (!resp.ok) {
                const text = await resp.text();
                throw new Error(text || `HTTP ${resp.status}`);
            }
            const data = await resp.json();
            classSplitState.qwenReviewModels = Array.isArray(data.models) ? data.models : [];
            classSplitState.qwenReviewActiveModelId = String(data.active || "");
            renderClassSplitQwenReviewModelOptions();
            setClassSplitQwenReviewStatus("Reviewer models loaded.", "success");
        } catch (error) {
            console.error("Failed to load Class Split reviewer models", error);
            setClassSplitQwenReviewStatus(`Reviewer models failed: ${error.message || error}`, "error");
        } finally {
            classSplitState.qwenReviewModelRefreshInFlight = false;
            setButtonDisabled(classSplitElements.qwenReviewRefresh, false);
        }
    }

    function clearClassSplitQwenReviewPolls({ clearJobs = false } = {}) {
        classSplitState.qwenReviewPollTimers.forEach((timer) => clearTimeout(timer));
        classSplitState.qwenReviewPollTimers.clear();
        if (clearJobs) {
            classSplitState.qwenReviewJobs.clear();
            renderClassSplitQwenReviewTraceToast();
        }
    }

    function getClassSplitQwenReviewForPoint(pointId) {
        return classSplitState.qwenReviewJobs.get(String(pointId || "")) || null;
    }

    function isClassSplitQwenReviewActive(review) {
        return ["queued", "running", "cancelling"].includes(String(review?.status || "").toLowerCase());
    }

    function updateClassSplitQwenReviewJob(review) {
        const pointId = String(review?.point_id || "").trim();
        if (!pointId) {
            return;
        }
        classSplitState.qwenReviewJobs.set(pointId, review);
        renderClassSplitQwenReviewTraceToast(review);
    }

    function scheduleClassSplitQwenReviewPoll(pointId, reviewId) {
        const safePointId = String(pointId || "").trim();
        const safeReviewId = String(reviewId || "").trim();
        if (!safePointId || !safeReviewId) {
            return;
        }
        const existing = classSplitState.qwenReviewPollTimers.get(safePointId);
        if (existing) {
            clearTimeout(existing);
        }
        const timer = setTimeout(async () => {
            classSplitState.qwenReviewPollTimers.delete(safePointId);
            try {
                const resp = await fetch(`${API_ROOT}/class_analysis/qwen_review/${encodeURIComponent(safeReviewId)}`);
                if (!resp.ok) {
                    const text = await resp.text();
                    throw new Error(text || `HTTP ${resp.status}`);
                }
                const review = await resp.json();
                updateClassSplitQwenReviewJob(review);
                renderClassSplitWrongList();
                if (isClassSplitQwenReviewActive(review)) {
                    scheduleClassSplitQwenReviewPoll(safePointId, safeReviewId);
                }
            } catch (error) {
                console.error("Class Split Qwen review poll failed", error);
                const review = getClassSplitQwenReviewForPoint(safePointId) || { point_id: safePointId };
                updateClassSplitQwenReviewJob({
                    ...review,
                    status: "failed",
                    message: `Poll failed: ${error.message || error}`,
                    error: String(error.message || error),
                });
                renderClassSplitWrongList();
            }
        }, 1400);
        classSplitState.qwenReviewPollTimers.set(safePointId, timer);
    }

    async function startClassSplitQwenReview(pointId) {
        const safePointId = String(pointId || "").trim();
        if (!safePointId || !classSplitState.currentJobId) {
            setSamStatus("Run Class Split analysis before starting Qwen review.", { variant: "warn", duration: 5000 });
            return;
        }
        const existing = getClassSplitQwenReviewForPoint(safePointId);
        if (isClassSplitQwenReviewActive(existing)) {
            return;
        }
        updateClassSplitQwenReviewJob({
            point_id: safePointId,
            status: "queued",
            progress: 0,
            message: "Starting Qwen review ...",
            evidence: [],
            result: null,
        });
        renderClassSplitWrongList();
        try {
            const modelId = String(classSplitElements.qwenReviewModel?.value || "").trim();
            const labelmapGlossary = String(classSplitElements.qwenReviewGlossary?.value || "").trim();
            const reviewGuidance = String(classSplitElements.qwenReviewGuidance?.value || "").trim();
            const resp = await fetch(`${API_ROOT}/class_analysis/jobs/${encodeURIComponent(classSplitState.currentJobId)}/points/${encodeURIComponent(safePointId)}/qwen_review`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    model_id: modelId || null,
                    max_turns: 10,
                    labelmap_glossary: labelmapGlossary || null,
                    review_guidance: reviewGuidance || null,
                    enable_local_consensus_context: true,
                    enable_class_concept_briefs: true,
                    allow_limited_final_review: true,
                    enable_cue_verifier: true,
                }),
            });
            if (!resp.ok) {
                const text = await resp.text();
                throw new Error(text || `HTTP ${resp.status}`);
            }
            const review = await resp.json();
            updateClassSplitQwenReviewJob(review);
            renderClassSplitWrongList();
            if (isClassSplitQwenReviewActive(review)) {
                scheduleClassSplitQwenReviewPoll(safePointId, review.review_id || review.job_id);
            }
        } catch (error) {
            console.error("Class Split Qwen review failed to start", error);
            updateClassSplitQwenReviewJob({
                point_id: safePointId,
                status: "failed",
                progress: 1,
                message: `Qwen review failed: ${error.message || error}`,
                evidence: [],
                result: null,
                error: String(error.message || error),
            });
            renderClassSplitWrongList();
        }
    }

    async function cancelClassSplitQwenReview(pointId) {
        const safePointId = String(pointId || "").trim();
        const review = getClassSplitQwenReviewForPoint(safePointId);
        const reviewId = String(review?.review_id || review?.job_id || "").trim();
        if (!reviewId) {
            return;
        }
        try {
            const resp = await fetch(`${API_ROOT}/class_analysis/qwen_review/${encodeURIComponent(reviewId)}/cancel`, { method: "POST" });
            if (!resp.ok) {
                const text = await resp.text();
                throw new Error(text || `HTTP ${resp.status}`);
            }
            const updated = await resp.json();
            updateClassSplitQwenReviewJob(updated);
            renderClassSplitWrongList();
        } catch (error) {
            console.error("Class Split Qwen review cancel failed", error);
            setSamStatus(`Qwen review cancel failed: ${error.message || error}`, { variant: "error", duration: 5000 });
        }
    }

    function formatClassSplitQwenDecision(result) {
        const decision = String(result?.decision || "").trim();
        const targetClass = String(result?.target_class || "").trim();
        const dualConflict = result && typeof result.dual_bbox_conflict === "object" ? result.dual_bbox_conflict : null;
        const dualResolution = String(result?.dual_bbox_resolution || "not_applicable").trim();
        if (dualConflict && dualResolution === "overlap_box_class") {
            return targetClass ? `Resolve dual bbox: switch class to ${targetClass}` : "Resolve dual bbox: switch class";
        }
        if (dualConflict && dualResolution === "current_box_class") {
            return "Resolve dual bbox: confirm current class";
        }
        if (dualConflict && dualResolution === "both_valid_overlapping_objects") {
            return "Dual bbox: both classes may be valid";
        }
        if (dualConflict && dualResolution === "uncertain_or_neither") {
            return "Dual bbox: unresolved";
        }
        const guarded = result && typeof result.guarded_recommendation === "object"
            ? result.guarded_recommendation
            : null;
        if (guarded?.blocked) {
            const guardedDecision = String(guarded.decision || "").trim();
            const guardedTarget = String(guarded.target_class || "").trim();
            if (guardedDecision === "confirm_current") {
                return "Guarded suggestion: confirm current class";
            }
            return guardedTarget
                ? `Guarded suggestion: switch class to ${guardedTarget}`
                : "Guarded suggestion: review class change";
        }
        if (decision === "confirm_current") {
            return "Confirm current class";
        }
        if (decision === "accept_suggested" || decision === "change_to_other") {
            return targetClass ? `Switch class to ${targetClass}` : "Switch class";
        }
        if (decision === "skip_uncertain") {
            return "Skip / human review";
        }
        return "Waiting for decision";
    }

    function getClassSplitDualBBoxConflict(item, point, result = null) {
        const sources = [
            result?.dual_bbox_conflict,
            point?.dual_bbox_conflict,
            item?.dual_bbox_conflict,
        ];
        for (const source of sources) {
            if (source && typeof source === "object" && source.enabled !== false) {
                return source;
            }
        }
        return null;
    }

    function formatClassSplitDualBBoxConflict(conflict, currentClass = "") {
        if (!conflict || typeof conflict !== "object") {
            return "";
        }
        const otherClass = String(conflict.other_class_name || conflict.class_name || "").trim();
        const current = String(conflict.current_class || currentClass || "").trim();
        const iou = Number(conflict.iou);
        const cover = Number(conflict.target_area_covered);
        const parts = [];
        if (current || otherClass) {
            parts.push(`${current || "current"} vs ${otherClass || "overlap"}`);
        }
        if (Number.isFinite(iou)) {
            parts.push(`IoU ${iou.toFixed(2)}`);
        }
        if (Number.isFinite(cover)) {
            parts.push(`target cover ${Math.round(cover * 100)}%`);
        }
        return parts.join(" • ");
    }

    function renderClassSplitQwenReviewBlock(pointId) {
        const review = getClassSplitQwenReviewForPoint(pointId);
        if (!review) {
            return "";
        }
        const status = String(review.status || "queued").toLowerCase();
        const progress = Math.max(0, Math.min(1, Number(review.progress) || 0));
        const result = review.result || null;
        const evidence = Array.isArray(review.evidence) ? review.evidence : [];
        const resultEvidenceIds = new Set((Array.isArray(result?.evidence_ids) ? result.evidence_ids : []).map((id) => String(id || "")));
        const guarded = result && typeof result.guarded_recommendation === "object"
            ? result.guarded_recommendation
            : null;
        const guardedReasons = Array.isArray(guarded?.guardrail_reasons)
            ? guarded.guardrail_reasons.map((item) => String(item || "").trim()).filter(Boolean)
            : [];
        const guardedTarget = String(guarded?.target_class || "").trim();
        const guardedDecision = String(guarded?.decision || "").trim();
        const guardedConfidence = Number(guarded?.confidence);
        const guardedLabel = guardedDecision === "confirm_current"
            ? "confirm current class"
            : guardedTarget
                ? `switch class to ${guardedTarget}`
                : "class change";
        const disposition = result && typeof result.review_disposition === "object"
            ? result.review_disposition
            : null;
        const dispositionLabel = String(disposition?.label || "").trim();
        const dispositionPriority = String(disposition?.priority || "").trim();
        const dispositionSignal = String(disposition?.signal || "").trim();
        const dispositionHtml = dispositionLabel
            ? `<span>${escapeHtml(dispositionLabel)}${dispositionPriority ? ` • priority ${escapeHtml(dispositionPriority)}` : ""}${dispositionSignal ? ` • ${escapeHtml(dispositionSignal.replace(/_/g, " "))}` : ""}</span>`
            : "";
        const guardedUsefulNegative = dispositionSignal === "useful_negative" && dispositionLabel;
        const guardedHeader = guardedUsefulNegative
            ? dispositionLabel
            : `Guarded suggestion: ${guardedLabel}`;
        const guardedDetail = guardedUsefulNegative
            ? `Controller rejected model suggestion (${guardedLabel})${guardedReasons.length ? `: ${guardedReasons[0]}` : "."}`
            : `Model confidence ${Number.isFinite(guardedConfidence) ? `${Math.round(guardedConfidence * 100)}%` : "n/a"} • held for human review${guardedReasons.length ? `: ${guardedReasons[0]}` : "."}`;
        const guardedHtml = guarded?.blocked
            ? [
                `<div class="class-split-qwen-review__guarded">`,
                `<strong>${escapeHtml(guardedHeader)}</strong>`,
                `<span>${escapeHtml(guardedDetail)}</span>`,
                guarded.rationale_short ? `<p>${escapeHtml(guarded.rationale_short)}</p>` : "",
                `</div>`,
            ].join("")
            : "";
        const dualConflict = getClassSplitDualBBoxConflict(null, null, result);
        const dualResolution = String(result?.dual_bbox_resolution || "not_applicable").trim();
        const dualConflictLabel = formatClassSplitDualBBoxConflict(dualConflict, result?.current_class || "");
        const dualHtml = dualConflict
            ? `<span>dual-bbox ${escapeHtml(dualResolution.replace(/_/g, " "))}${dualConflictLabel ? ` • ${escapeHtml(dualConflictLabel)}` : ""}</span>`
            : "";
        const citedEvidence = resultEvidenceIds.size
            ? evidence.filter((item) => resultEvidenceIds.has(String(item?.evidence_id || "")))
            : [];
        const evidenceHtml = citedEvidence.length
            ? `<div class="class-split-qwen-review__evidence">${citedEvidence.slice(-6).map((item) => renderClassSplitQwenEvidenceThumb(item, resultEvidenceIds)).join("")}</div>`
            : "";
        const auditEvidenceHtml = evidence.length
            ? [
                `<details class="class-split-qwen-review__audit">`,
                `<summary>Audit trail intermediate outputs (${evidence.length})</summary>`,
                `<div class="class-split-qwen-review__audit-grid">`,
                evidence.map((item) => renderClassSplitQwenEvidenceThumb(item, resultEvidenceIds)).join(""),
                `</div>`,
                `</details>`,
            ].join("")
            : "";
        const resultHtml = result
            ? [
                `<strong>${escapeHtml(formatClassSplitQwenDecision(result))}</strong>`,
                `<span>confidence ${Math.round((Number(result.confidence) || 0) * 100)}% • ${escapeHtml(result.reviewed_by_model || "")}</span>`,
                dispositionHtml,
                dualHtml,
                `<span>overlap ${escapeHtml(result.overlap_assessment || "n/a")} • anchors current ${escapeHtml(result.anchor_evidence_current || "n/a")} / suggested ${escapeHtml(result.anchor_evidence_suggested || "n/a")}</span>`,
                result.rationale_short ? `<p>${escapeHtml(result.rationale_short)}</p>` : "",
                result.counter_evidence ? `<p><em>Counter-evidence:</em> ${escapeHtml(result.counter_evidence)}</p>` : "",
                guardedHtml,
            ].join("")
            : `<span>${escapeHtml(review.message || status)}</span>`;
        const cancelHtml = isClassSplitQwenReviewActive(review)
            ? `<button type="button" class="training-button secondary" data-action="qwen-cancel" data-point-id="${escapeHtml(pointId)}">Cancel Qwen</button>`
            : "";
        return [
            `<div class="class-split-qwen-review class-split-qwen-review--${escapeHtml(status)}">`,
            `<div class="class-split-qwen-review__bar"><span style="width:${Math.round(progress * 100)}%"></span></div>`,
            `<div class="class-split-qwen-review__body">${resultHtml}</div>`,
            evidenceHtml,
            auditEvidenceHtml,
            cancelHtml ? `<div class="class-split-qwen-review__actions">${cancelHtml}</div>` : "",
            `</div>`,
        ].join("");
    }

    function renderClassSplitWrongList() {
        const listEl = classSplitElements.wrongList;
        if (!listEl) {
            return;
        }
        const visibleCandidates = getClassSplitVisibleWrongCandidates();
        const queuedIds = reconcileClassSplitWrongQueue(visibleCandidates);
        const queuedIdSet = new Set(queuedIds);
        const queuedCandidates = visibleCandidates.filter((item) => queuedIdSet.has(String(item?.point_id || "")));
        if (classSplitElements.wrongQueueStatus) {
            classSplitElements.wrongQueueStatus.textContent = visibleCandidates.length
                ? `Showing ${queuedCandidates.length} of ${visibleCandidates.length} flagged objects.`
                : "No queued likely-wrong objects.";
        }
        setButtonDisabled(classSplitElements.wrongShuffle, visibleCandidates.length <= queuedCandidates.length);
        setButtonDisabled(classSplitElements.wrongDiscardFirst, !queuedCandidates.length);
        setButtonDisabled(classSplitElements.mobilePush, !visibleCandidates.length || !classSplitState.currentJobId);
        setButtonDisabled(
            classSplitElements.mobileSync,
            !classSplitState.mobileReviewSessionId || classSplitState.mobileReviewTargetMode !== "desktop_workspace"
        );
        if (!visibleCandidates.length) {
            const suspicion = getClassSplitSuspicionStatus();
            listEl.innerHTML = `<div class="training-help">${escapeHtml(suspicion.enabled ? "No likely wrong-class objects were flagged." : suspicion.text)}</div>`;
            return;
        }
        const classNames = (Array.isArray(loadedClassList) ? loadedClassList : [])
            .map((className) => String(className || "").trim())
            .filter(Boolean);
        listEl.innerHTML = queuedCandidates.map((item) => {
            const score = Number(item.wrong_class_suspicion) || 0;
            const point = getClassSplitPointById(item.point_id);
            const pointId = String(item.point_id || "");
            const currentClass = String(point?.class_name || item.class_name || "").trim();
            const suggestedClass = String(item.suggested_neighbor_class || "").trim();
            const dualConflict = getClassSplitDualBBoxConflict(item, point);
            const dualOtherClass = String(dualConflict?.other_class_name || dualConflict?.class_name || "").trim();
            const dualConflictLabel = formatClassSplitDualBBoxConflict(dualConflict, currentClass);
            const suggestedClassAvailable = suggestedClass && classNames.includes(suggestedClass);
            const dualOtherClassAvailable = dualOtherClass && classNames.includes(dualOtherClass);
            const qwenReview = getClassSplitQwenReviewForPoint(pointId);
            const qwenBusy = isClassSplitQwenReviewActive(qwenReview);
            const qwenResult = qwenReview?.result || null;
            const displayedTargetClass = dualOtherClass || suggestedClass;
            const qwenGuarded = qwenResult && typeof qwenResult.guarded_recommendation === "object"
                ? qwenResult.guarded_recommendation
                : null;
            const qwenDecision = String(qwenResult?.decision || "").trim();
            const qwenGuardedDecision = String(qwenGuarded?.decision || "").trim();
            const qwenGuardedTarget = String(qwenGuarded?.target_class || "").trim();
            const qwenActionTarget = String(qwenResult?.target_class || "").trim();
            const qwenPreferredTarget = qwenGuarded?.blocked && qwenGuardedDecision !== "confirm_current"
                ? qwenGuardedTarget
                : (qwenDecision === "accept_suggested" || qwenDecision === "change_to_other")
                    ? qwenActionTarget
                    : "";
            const preferredTargetClass = classNames.includes(qwenPreferredTarget)
                ? qwenPreferredTarget
                : dualOtherClassAvailable
                    ? dualOtherClass
                : suggestedClassAvailable
                    ? suggestedClass
                    : "";
            const options = [
                `<option value=""${preferredTargetClass ? "" : " selected"}>Choose class</option>`,
                ...classNames.map((className) => {
                    const selected = className === preferredTargetClass ? " selected" : "";
                    return `<option value="${escapeHtml(className)}"${selected}>${escapeHtml(className)}</option>`;
                }),
            ].join("");
            const thumbUrl = point ? getClassSplitThumbnailUrl(point) : "";
            return [
                `<div class="class-split-wrong-item" data-point-id="${escapeHtml(pointId)}">`,
                thumbUrl
                    ? `<img class="class-split-wrong-item__preview" src="${escapeHtml(thumbUrl)}" alt="Object context crop" loading="lazy" data-context-point-id="${escapeHtml(pointId)}">`
                    : `<div class="class-split-wrong-item__preview" aria-hidden="true"></div>`,
                `<div class="class-split-wrong-item__body">`,
                `<strong>${escapeHtml(currentClass || "current class")} → ${escapeHtml(displayedTargetClass || "review target")}</strong>`,
                dualConflict
                    ? `<span class="class-split-wrong-item__badge class-split-wrong-item__badge--dual">Dual-box conflict • ${escapeHtml(dualConflictLabel || "near-identical cross-class boxes")}</span>`
                    : "",
                dualConflict
                    ? `<span>Qwen question: choose ${escapeHtml(currentClass || "current class")} vs ${escapeHtml(dualOtherClass || "overlap class")} vs both-valid overlap vs unresolved.</span>`
                    : "",
                suggestedClass ? `<span>Suggested target: ${escapeHtml(suggestedClass)}</span>` : "",
                dualOtherClass && dualOtherClass !== suggestedClass ? `<span>Overlapping target: ${escapeHtml(dualOtherClass)}</span>` : "",
                `<span>${Math.round(score * 100)}% suspicion • ${escapeHtml(item.image_relpath || "")}</span>`,
                `<div class="class-split-wrong-item__actions">`,
                `<button type="button" class="training-button secondary" data-action="jump-instance" data-point-id="${escapeHtml(pointId)}">See instance</button>`,
                `<button type="button" class="training-button secondary" data-action="correct-class" data-point-id="${escapeHtml(pointId)}">Confirm current class</button>`,
                `<button type="button" class="training-button secondary" data-action="skip-wrong" data-point-id="${escapeHtml(pointId)}">Skip</button>`,
                `<button type="button" class="training-button secondary" data-action="qwen-review" data-point-id="${escapeHtml(pointId)}"${qwenBusy ? " disabled" : ""}>${qwenBusy ? "Qwen reviewing ..." : dualConflict ? "Review dual bbox with Qwen" : "Review with Qwen"}</button>`,
                `<select data-action="target-class" data-point-id="${escapeHtml(pointId)}">${options}</select>`,
                `<button type="button" class="training-button" data-action="reassign-class" data-point-id="${escapeHtml(pointId)}">${escapeHtml(preferredTargetClass ? `Switch class to ${preferredTargetClass}` : "Reassign")}</button>`,
                `</div>`,
                renderClassSplitQwenReviewBlock(pointId),
                `</div>`,
                `</div>`,
            ].join("");
        }).join("");
        hydrateClassSplitContextPreviews(listEl);
        listEl.querySelectorAll(".class-split-wrong-item").forEach((node) => {
            node.addEventListener("click", (event) => {
                if (event.target instanceof Element && event.target.closest("[data-action]")) {
                    return;
                }
                selectClassSplitPoint(node.getAttribute("data-point-id") || "", {
                    jump: false,
                    focusPlot: true,
                    flash: true,
                });
            });
        });
        listEl.querySelectorAll('[data-action="jump-instance"]').forEach((button) => {
            button.addEventListener("click", (event) => {
                event.stopPropagation();
                const pointId = button.getAttribute("data-point-id") || "";
                const point = getClassSplitPointById(pointId);
                if (!point) {
                    setSamStatus("Could not find the selected Class Split point.", { variant: "error", duration: 5000 });
                    return;
                }
                selectClassSplitPoint(pointId, {
                    jump: false,
                    focusPlot: true,
                    flash: true,
                });
                jumpToClassSplitPoint(point).catch((error) => {
                    console.error("Class Split vignette jump failed", error);
                    setSamStatus(`Jump failed: ${error.message || error}`, { variant: "error", duration: 5000 });
                });
            });
        });
        listEl.querySelectorAll('[data-action="correct-class"]').forEach((button) => {
            button.addEventListener("click", (event) => {
                event.stopPropagation();
                markClassSplitWrongCandidateCorrect(button.getAttribute("data-point-id") || "");
            });
        });
        listEl.querySelectorAll('[data-action="skip-wrong"]').forEach((button) => {
            button.addEventListener("click", (event) => {
                event.stopPropagation();
                skipClassSplitWrongCandidate(button.getAttribute("data-point-id") || "");
            });
        });
        listEl.querySelectorAll('[data-action="reassign-class"]').forEach((button) => {
            button.addEventListener("click", (event) => {
                event.stopPropagation();
                const pointId = button.getAttribute("data-point-id") || "";
                const point = getClassSplitPointById(pointId);
                const row = button.closest(".class-split-wrong-item");
                const select = row?.querySelector('[data-action="target-class"]');
                const targetClass = select instanceof HTMLSelectElement ? select.value : "";
                changeClassSplitPointClass(point, targetClass).catch((error) => {
                    console.error("Class Split vignette relabel failed", error);
                    setSamStatus(`Class change failed: ${error.message || error}`, { variant: "error", duration: 5000 });
                });
            });
        });
        listEl.querySelectorAll('[data-action="qwen-review"]').forEach((button) => {
            button.addEventListener("click", (event) => {
                event.stopPropagation();
                startClassSplitQwenReview(button.getAttribute("data-point-id") || "").catch((error) => {
                    console.error("Class Split Qwen review action failed", error);
                    setSamStatus(`Qwen review failed: ${error.message || error}`, { variant: "error", duration: 5000 });
                });
            });
        });
        listEl.querySelectorAll('[data-action="qwen-cancel"]').forEach((button) => {
            button.addEventListener("click", (event) => {
                event.stopPropagation();
                cancelClassSplitQwenReview(button.getAttribute("data-point-id") || "").catch((error) => {
                    console.error("Class Split Qwen review cancel action failed", error);
                });
            });
        });
        listEl.querySelectorAll('[data-action="target-class"]').forEach((select) => {
            select.addEventListener("change", () => {
                const row = select.closest(".class-split-wrong-item");
                const button = row?.querySelector('[data-action="reassign-class"]');
                if (button) {
                    button.textContent = select.value ? `Switch class to ${select.value}` : "Reassign";
                }
            });
        });
    }

    function renderClassSplitInspector() {
        const inspector = classSplitElements.inspector;
        if (!inspector) {
            return;
        }
        if (classSplitState.cropResizeObserver) {
            classSplitState.cropResizeObserver.disconnect();
            classSplitState.cropResizeObserver = null;
        }
        const point = classSplitState.pointsById.get(classSplitState.selectedPointId);
        if (!point) {
            inspector.innerHTML = `<div class="training-help">Select a point to inspect its crop.</div>`;
            return;
        }
        const thumbUrl = getClassSplitThumbnailUrl(point);
        const currentClass = String(point.class_name || "").trim();
        const suggestedClass = String(point.suggested_neighbor_class || "").trim();
        const classOptions = (Array.isArray(loadedClassList) ? loadedClassList : [])
            .map((className) => String(className || "").trim())
            .filter(Boolean)
            .map((className) => {
                const selected = suggestedClass ? className === suggestedClass : className === currentClass;
                return `<option value="${escapeHtml(className)}"${selected ? " selected" : ""}>${escapeHtml(className)}</option>`;
            })
            .join("");
        inspector.innerHTML = [
            `<div class="class-split-inspector__crop-shell">`,
            `<img class="class-split-inspector__crop" src="${escapeHtml(thumbUrl)}" alt="Object context crop" data-crop-preview data-context-point-id="${escapeHtml(point.point_id || "")}" />`,
            `<div class="class-split-inspector__crop-status" data-crop-status hidden>Crop preview unavailable.</div>`,
            `</div>`,
            `<div class="class-split-inspector__meta">`,
            `<strong>${escapeHtml(currentClass || "")}</strong><br>`,
            `${escapeHtml(point.split || "train")}/${escapeHtml(point.image_relpath || "")}<br>`,
            `Cluster ${escapeHtml(point.cluster_id ?? "")} • outlier ${(Number(point.outlier_score) || 0).toFixed(2)}<br>`,
            `Neighbor mix: same ${Math.round((Number(point.same_class_neighbor_ratio) || 0) * 100)}%`,
            point.suggested_neighbor_class
                ? ` • top other ${escapeHtml(point.suggested_neighbor_class)} ${Math.round((Number(point.top_other_neighbor_ratio) || 0) * 100)}%`
                : "",
            suggestedClass ? `<br>Suggested target: ${escapeHtml(suggestedClass)}` : "",
            `</div>`,
            `<div class="class-split-inspector__actions">`,
            `<button type="button" class="training-button secondary" data-action="jump">See instance</button>`,
            `<select data-action="class">${classOptions}</select>`,
            `<button type="button" class="training-button" data-action="change">${escapeHtml(suggestedClass ? `Switch class to ${suggestedClass}` : "Change class")}</button>`,
            `</div>`,
        ].join("");
        const jumpButton = inspector.querySelector('[data-action="jump"]');
        const changeButton = inspector.querySelector('[data-action="change"]');
        const classSelect = inspector.querySelector('[data-action="class"]');
        const cropShell = inspector.querySelector(".class-split-inspector__crop-shell");
        const cropPreview = inspector.querySelector("[data-crop-preview]");
        const cropStatus = inspector.querySelector("[data-crop-status]");
        if (cropShell && cropPreview) {
            let cropZoom = 1;
            const updateCropFitScale = () => {
                const naturalWidth = Number(cropPreview.naturalWidth) || 0;
                const naturalHeight = Number(cropPreview.naturalHeight) || 0;
                const shellWidth = Number(cropShell.clientWidth) || 0;
                const shellHeight = Number(cropShell.clientHeight) || 0;
                if (!naturalWidth || !naturalHeight || !shellWidth || !shellHeight) {
                    cropShell.style.setProperty("--class-split-crop-scale", cropZoom.toFixed(4));
                    cropPreview.style.width = "";
                    cropPreview.style.height = "";
                    return;
                }
                const fitScale = Math.min(shellWidth / naturalWidth, shellHeight / naturalHeight);
                const nextScale = Math.max(0.01, fitScale * cropZoom);
                cropShell.style.setProperty("--class-split-crop-scale", nextScale.toFixed(4));
                cropPreview.style.width = `${Math.max(1, Math.round(naturalWidth * nextScale))}px`;
                cropPreview.style.height = `${Math.max(1, Math.round(naturalHeight * nextScale))}px`;
                cropShell.classList.toggle("class-split-inspector__crop-shell--zoomed", Math.abs(cropZoom - 1) > 0.01);
            };
            updateCropFitScale();
            cropShell.addEventListener("wheel", (event) => {
                event.preventDefault();
                event.stopPropagation();
                const factor = Math.exp((-(Number(event.deltaY) || 0)) * 0.0014);
                cropZoom = Math.max(0.2, Math.min(16, cropZoom * factor));
                updateCropFitScale();
            }, { passive: false });
            cropShell.addEventListener("dblclick", () => {
                cropZoom = 1;
                updateCropFitScale();
            });
            cropShell.addEventListener("class-split-crop-fit", updateCropFitScale);
            if (typeof ResizeObserver === "function") {
                classSplitState.cropResizeObserver = new ResizeObserver(updateCropFitScale);
                classSplitState.cropResizeObserver.observe(cropShell);
            }
        }
        if (cropPreview && cropStatus) {
            cropPreview.addEventListener("error", () => {
                cropPreview.hidden = true;
                cropStatus.hidden = false;
                cropStatus.textContent = "Crop preview failed to load. Rerun analysis if this job was from an older backend session.";
            });
            cropPreview.addEventListener("load", () => {
                cropPreview.hidden = false;
                cropStatus.hidden = true;
                const cropShellForFit = cropPreview.closest(".class-split-inspector__crop-shell");
                if (cropShellForFit) {
                    cropShellForFit.dispatchEvent(new Event("class-split-crop-fit"));
                }
            });
            if (cropPreview.complete && Number(cropPreview.naturalWidth) > 0) {
                cropPreview.dispatchEvent(new Event("load"));
            }
        }
        hydrateClassSplitContextPreviews(inspector);
        if (jumpButton) {
            jumpButton.addEventListener("click", () => {
                jumpToClassSplitPoint(point).catch((error) => {
                    console.error("Class Split jump failed", error);
                    setSamStatus(`Jump failed: ${error.message || error}`, { variant: "error", duration: 5000 });
                });
            });
        }
        if (changeButton && classSelect) {
            classSelect.addEventListener("change", () => {
                changeButton.textContent = classSelect.value ? `Switch class to ${classSelect.value}` : "Change class";
            });
            changeButton.addEventListener("click", () => {
                changeClassSplitPointClass(point, classSelect.value).catch((error) => {
                    console.error("Class Split relabel failed", error);
                    setSamStatus(`Class change failed: ${error.message || error}`, { variant: "error", duration: 5000 });
                });
            });
        }
    }

    function hideClassSplitResultUiUntilReady() {
        classSplitState.plotRenderToken += 1;
        clearClassSplitQwenReviewPolls({ clearJobs: true });
        hideClassSplitGraphHoverPreview();
        if (classSplitElements.results) {
            classSplitElements.results.hidden = true;
        }
        if (classSplitElements.graphStatus) {
            classSplitElements.graphStatus.textContent = "";
        }
        if (classSplitElements.bulkPanel) {
            classSplitElements.bulkPanel.hidden = true;
        }
        const graphEl = classSplitElements.graph;
        if (!graphEl) {
            return;
        }
        try {
            if (window.Plotly && typeof window.Plotly.purge === "function" && Array.isArray(graphEl.data)) {
                window.Plotly.purge(graphEl);
            }
        } catch (error) {
            console.warn("Class Split plot purge failed", error);
        }
        graphEl.data = [];
        graphEl.layout = null;
        graphEl.innerHTML = "";
    }

    function renderClassSplitResult() {
        if (!classSplitState.result) {
            hideClassSplitResultUiUntilReady();
            return;
        }
        if (classSplitElements.results) {
            classSplitElements.results.hidden = false;
        }
        const summary = classSplitState.result?.summary || {};
        const warnings = Array.isArray(summary.warnings) && summary.warnings.length
            ? ` • ${summary.warnings[0]}`
            : "";
        setClassSplitJobStatus(
            `${summary.object_count || 0} objects • ${formatClassSplitClusterReport(classSplitState.result, summary)} • ${summary.wrong_class_candidate_count || 0} flags${warnings}`,
            summary.warnings?.length ? "warn" : "success"
        );
        renderClassSplitFilterOptions();
        renderClassSplitReport();
        renderClassSplitClusterList();
        renderClassSplitWrongList();
        renderClassSplitInspector();
        renderClassSplitBulkPanel();
        renderClassSplitDatasetAnalysis();
        refreshClassSplitClusterControls();
        renderClassSplitPlot();
    }

    function selectClassSplitPoint(pointId, { jump = false, focusPlot = false, flash = false } = {}) {
        const safeId = String(pointId || "");
        if (!safeId || !classSplitState.pointsById.has(safeId)) {
            return;
        }
        const point = classSplitState.pointsById.get(safeId);
        let filterChanged = false;
        const activeFilter = String(classSplitElements.filterClass?.value || "").trim();
        if (focusPlot && activeFilter && String(point?.class_name || "") !== activeFilter) {
            classSplitElements.filterClass.value = "";
            filterChanged = true;
        }
        if (
            focusPlot
            && classSplitElements.displayMode
            && String(classSplitElements.displayMode.value || "all") === "wrong_only"
            && !point.is_wrong_class_candidate
        ) {
            classSplitElements.displayMode.value = "all";
            filterChanged = true;
        }
        if (classSplitState.selectedClusterId && classSplitPointClusterKey(point) !== classSplitState.selectedClusterId) {
            classSplitState.selectedClusterId = "";
            renderClassSplitClusterList();
        }
        classSplitState.selectedPointId = safeId;
        renderClassSplitInspector();
        const plotRender = renderClassSplitPlot();
        if (filterChanged) {
            renderClassSplitBulkPanel();
            renderClassSplitClusterList();
            renderClassSplitWrongList();
            refreshClassSplitClusterControls();
        }
        if (focusPlot) {
            Promise.resolve(plotRender).then(() => {
                if (classSplitState.selectedPointId === safeId) {
                    focusClassSplitPlotOnPoint(safeId, { flash });
                }
            });
        } else if (flash) {
            startClassSplitPlotFlash(safeId);
        }
        if (jump) {
            jumpToClassSplitPoint(point).catch((error) => {
                console.error("Class Split jump failed", error);
            });
        }
    }

    function syncClassSplitWrongCandidateSummaryCount() {
        const summary = classSplitState.result?.summary;
        if (!summary) {
            return;
        }
        const candidates = Array.isArray(classSplitState.result?.wrong_class_candidates)
            ? classSplitState.result.wrong_class_candidates
            : [];
        summary.wrong_class_candidate_count = candidates.filter((item) => {
            const pointId = String(item?.point_id || "");
            const point = getClassSplitPointById(pointId);
            return pointId && !classSplitState.dismissedWrongIds.has(pointId) && (!point || !!point.is_wrong_class_candidate);
        }).length;
    }

    function skipClassSplitWrongCandidate(pointId) {
        const safeId = String(pointId || "");
        if (!safeId) {
            return;
        }
        classSplitState.dismissedWrongIds.add(safeId);
        syncClassSplitWrongCandidateSummaryCount();
        renderClassSplitWrongList();
        renderClassSplitReport();
        setClassSplitJobStatus("Skipped object for this review session.", "success");
    }

    function clearClassSplitWrongCandidate(pointId) {
        const safeId = String(pointId || "");
        if (!safeId) {
            return;
        }
        classSplitState.dismissedWrongIds.add(safeId);
        const point = getClassSplitPointById(safeId);
        if (point) {
            point.is_wrong_class_candidate = false;
            point.wrong_class_suspicion = 0;
        }
        if (Array.isArray(classSplitState.result?.wrong_class_candidates)) {
            classSplitState.result.wrong_class_candidates = classSplitState.result.wrong_class_candidates
                .filter((item) => String(item?.point_id || "") !== safeId);
        }
        syncClassSplitWrongCandidateSummaryCount();
    }

    function markClassSplitWrongCandidateCorrect(pointId) {
        const safeId = String(pointId || "");
        if (!safeId) {
            return;
        }
        clearClassSplitWrongCandidate(safeId);
        refreshClassSplitFilteredReviewUi({ renderPlot: false });
        renderClassSplitReport();
        renderClassSplitPlot();
        setClassSplitJobStatus("Marked object as correct for this review session.", "success");
    }

    function classSplitImageLookupAliases(rawValue) {
        const raw = String(rawValue || "").trim().replace(/\\/g, "/").replace(/^\/+/, "");
        if (!raw) {
            return [];
        }
        const aliases = new Set([raw]);
        const withoutImages = raw.replace(/(^|\/)images\//, "$1");
        aliases.add(withoutImages);
        const parts = withoutImages.split("/").filter(Boolean);
        if (parts.length) {
            aliases.add(parts[parts.length - 1]);
        }
        if (!/^(train|val|test)\//i.test(withoutImages)) {
            aliases.add(`train/${withoutImages}`);
        }
        return Array.from(aliases).filter(Boolean);
    }

    function classSplitImageExactLookupAliases(rawValue) {
        const raw = String(rawValue || "").trim().replace(/\\/g, "/").replace(/^\/+/, "");
        if (!raw) {
            return [];
        }
        const aliases = new Set([raw]);
        const withoutImages = raw.replace(/(^|\/)images\//, "$1");
        aliases.add(withoutImages);
        if (!/^(train|val|test)\//i.test(withoutImages)) {
            aliases.add(`train/${withoutImages}`);
        }
        return Array.from(aliases).filter(Boolean);
    }

    function addClassSplitImageLookupAlias(lookup, alias, imageKey) {
        const safeImageKey = String(imageKey || "").trim();
        if (!lookup || !safeImageKey) {
            return;
        }
        classSplitImageLookupAliases(alias).forEach((candidate) => {
            const previous = lookup.get(candidate);
            if (previous && previous !== safeImageKey) {
                lookup.set(candidate, null);
            } else if (!lookup.has(candidate)) {
                lookup.set(candidate, safeImageKey);
            }
        });
    }

    function addClassSplitExactImageLookupAlias(lookup, alias, imageKey) {
        const safeImageKey = String(imageKey || "").trim();
        if (!lookup || !safeImageKey) {
            return;
        }
        classSplitImageExactLookupAliases(alias).forEach((candidate) => {
            const previous = lookup.get(candidate);
            if (previous && previous !== safeImageKey) {
                lookup.set(candidate, null);
            } else if (!lookup.has(candidate)) {
                lookup.set(candidate, safeImageKey);
            }
        });
    }

    function classSplitPointImageLookupSignature() {
        const keys = getClassSplitImageKeys();
        const values = [
            annotationSourceState.mode,
            annotationSourceState.datasetId,
            annotationSourceState.sessionId,
            annotationSourceState.datasetLabel,
        ];
        keys.forEach((imageKey) => {
            const imageRecord = images?.[imageKey] || {};
            const row = annotationSourceState.imageRowsByKey?.get(imageKey) || {};
            values.push(
                imageKey,
                imageRecord.displayName,
                imageRecord.annotationSplit,
                imageRecord.annotationRelpath,
                imageRecord.meta?.name,
                row.split,
                row.image_relpath,
                row.image_name,
            );
        });
        return `${keys.length}:${classSplitHashValues(values)}`;
    }

    function buildClassSplitPointImageLookup() {
        const signature = classSplitPointImageLookupSignature();
        if (classSplitState.pointImageLookup && classSplitState.pointImageLookupSignature === signature) {
            return classSplitState.pointImageLookup;
        }
        const lookup = {
            exact: new Map(),
            fuzzy: new Map(),
        };
        const activeImageKeys = getClassSplitImageKeys();
        const chunkedUsedNames = new Map();
        const chunkedNamesByKey = new Map();
        activeImageKeys.forEach((imageKey) => {
            const imageRecord = images?.[imageKey] || {};
            const row = annotationSourceState.imageRowsByKey?.get(imageKey) || {};
            const baseName = imageRecord.meta?.name || imageRecord.displayName || row.image_relpath || imageKey;
            chunkedNamesByKey.set(imageKey, makeUniqueFilename(baseName, chunkedUsedNames));
        });
        const snapshotUsedNames = new Set();
        activeImageKeys.forEach((imageKey) => {
            const imageRecord = images?.[imageKey] || {};
            const row = annotationSourceState.imageRowsByKey?.get(imageKey) || {};
            const split = String(row.split || imageRecord.annotationSplit || "train").trim() || "train";
            const rel = String(row.image_relpath || imageRecord.annotationRelpath || "").trim();
            const chunkedSafeName = chunkedNamesByKey.get(imageKey) || "";
            const snapshotSafeName = makeClassSplitUploadName(imageKey, snapshotUsedNames);
            [
                imageKey,
                annotationImageKey(split, rel || imageKey),
                rel,
                chunkedSafeName,
                `${split}/${chunkedSafeName}`,
                `${split}/images/${chunkedSafeName}`,
                snapshotSafeName,
                `${split}/${snapshotSafeName}`,
                `${split}/images/${snapshotSafeName}`,
            ].forEach((alias) => addClassSplitExactImageLookupAlias(lookup.exact, alias, imageKey));
            [
                imageKey,
                annotationImageKey(split, rel || imageKey),
                rel,
                row.image_name,
                imageRecord.displayName,
                imageRecord.meta?.name,
                chunkedSafeName,
                `${split}/${chunkedSafeName}`,
                `${split}/images/${chunkedSafeName}`,
                snapshotSafeName,
                `${split}/${snapshotSafeName}`,
                `${split}/images/${snapshotSafeName}`,
            ].forEach((alias) => addClassSplitImageLookupAlias(lookup.fuzzy, alias, imageKey));
        });
        classSplitState.pointImageLookup = lookup;
        classSplitState.pointImageLookupSignature = signature;
        return lookup;
    }

    function resolveClassSplitPointImageKey(point) {
        if (!point) {
            return "";
        }
        const cached = String(point._resolved_frontend_image_key || "").trim();
        if (cached && images?.[cached]) {
            return cached;
        }
        const fallbackAnnotationKey = annotationImageKey(point.split || "train", point.image_relpath || "");
        const candidates = [
            point.frontend_image_key,
            point.image_key,
            fallbackAnnotationKey,
            point.image_relpath,
            point.image_name,
            point.filename,
            point.source_image_name,
            point.source_key,
        ].map((value) => String(value || "").trim()).filter(Boolean);
        const direct = candidates.find((candidate) => images?.[candidate]);
        if (direct) {
            point._resolved_frontend_image_key = direct;
            return direct;
        }
        const lookup = buildClassSplitPointImageLookup();
        for (const candidate of candidates) {
            for (const alias of classSplitImageExactLookupAliases(candidate)) {
                const resolved = lookup.exact.get(alias);
                if (resolved && images?.[resolved]) {
                    point._resolved_frontend_image_key = resolved;
                    return resolved;
                }
            }
        }
        for (const candidate of candidates) {
            for (const alias of classSplitImageLookupAliases(candidate)) {
                const resolved = lookup.fuzzy.get(alias);
                if (resolved && images?.[resolved]) {
                    point._resolved_frontend_image_key = resolved;
                    return resolved;
                }
            }
        }
        return String(point.frontend_image_key || fallbackAnnotationKey || "").trim();
    }

    function getClassSplitPointImageKey(point) {
        return resolveClassSplitPointImageKey(point);
    }

    function findClassSplitBboxMatch(point) {
        if (!point) {
            return null;
        }
        const imageKey = getClassSplitPointImageKey(point);
        const buckets = bboxes[imageKey];
        if (!buckets) {
            return null;
        }
        const target = Array.isArray(point.bbox_xyxy) ? point.bbox_xyxy.slice(0, 4).map((value) => Number(value)) : null;
        if (!target || target.length < 4 || !target.every(Number.isFinite) || target[2] <= target[0] || target[3] <= target[1]) {
            return null;
        }
        const targetClass = String(point.class_name || "");
        const searchClasses = [
            targetClass,
            ...Object.keys(buckets).filter((className) => className !== targetClass),
        ].filter(Boolean);
        let best = null;
        searchClasses.forEach((className) => {
            const list = Array.isArray(buckets[className]) ? buckets[className] : [];
            list.forEach((bboxRecord, index) => {
                if (!bboxRecord) {
                    return;
                }
                const bounds = getBboxBounds(bboxRecord);
                const diff =
                    Math.abs(bounds.left - target[0])
                    + Math.abs(bounds.top - target[1])
                    + Math.abs(bounds.right - target[2])
                    + Math.abs(bounds.bottom - target[3]);
                const scaleRef = Math.max(1, Math.abs(target[2] - target[0]) + Math.abs(target[3] - target[1]));
                const score = diff / scaleRef;
                if (!best || score < best.score) {
                    best = { bbox: bboxRecord, className, index, score };
                }
            });
        });
        return best && best.score <= 0.08 ? best : null;
    }

    function ensureClassSplitPointBboxMatch(point) {
        if (!point) {
            throw new Error("No point selected.");
        }
        const imageKey = getClassSplitPointImageKey(point);
        const imageRecord = images?.[imageKey];
        if (!imageRecord) {
            throw new Error(`Image is not loaded in this session: ${imageKey}`);
        }
        if (isDatasetBackedImageRecord(imageRecord) && !annotationSourceState.hydratedKeys.has(imageKey)) {
            const hydrated = hydrateDatasetBboxesForImage(imageRecord);
            if (!hydrated) {
                throw new Error(`Annotations are not ready for ${imageKey}`);
            }
        }
        const match = findClassSplitBboxMatch(point);
        if (!match) {
            throw new Error(`Could not find the matching bbox for ${imageKey}`);
        }
        return { imageKey, match };
    }

    function updateClassSplitSummaryClassCounts(previousClass, nextClass) {
        const counts = classSplitState.result?.summary?.class_counts;
        if (!counts || previousClass === nextClass) {
            return;
        }
        if (Object.prototype.hasOwnProperty.call(counts, previousClass)) {
            counts[previousClass] = Math.max(0, (Number(counts[previousClass]) || 0) - 1);
        }
        counts[nextClass] = (Number(counts[nextClass]) || 0) + 1;
    }

    function applyClassSplitPointClassLocally(point, targetClass) {
        const nextClass = String(targetClass || "").trim();
        if (!nextClass) {
            throw new Error("Choose a target class.");
        }
        if (!point) {
            throw new Error("No point selected.");
        }
        const graphClass = String(point.class_name || "").trim();
        const knownClasses = Array.isArray(loadedClassList)
            ? loadedClassList.map((className) => String(className || "").trim()).filter(Boolean)
            : [];
        if (knownClasses.length && !knownClasses.includes(nextClass)) {
            throw new Error(`Unknown class: ${nextClass}`);
        }
        const { imageKey, match } = ensureClassSplitPointBboxMatch(point);
        const previousClass = String(match.className || graphClass).trim();
        if (!previousClass) {
            throw new Error("Could not determine the current bbox class.");
        }
        if (nextClass === previousClass) {
            point.class_name = nextClass;
            point.cluster_id = null;
            point._subclass_cluster_id = "";
            clearClassSplitWrongCandidate(point.point_id);
            return false;
        }
        const buckets = bboxes[imageKey] || {};
        bboxes[imageKey] = buckets;
        const sourceBucket = Array.isArray(buckets[previousClass]) ? buckets[previousClass] : [];
        const sourceIndex = sourceBucket.indexOf(match.bbox);
        if (sourceIndex !== -1) {
            sourceBucket.splice(sourceIndex, 1);
        }
        if (!buckets[nextClass]) {
            buckets[nextClass] = [];
        }
        match.bbox.class = nextClass;
        buckets[nextClass].push(match.bbox);
        point.class_name = nextClass;
        point.cluster_id = null;
        point._subclass_cluster_id = "";
        classSplitState.selectedClusterId = "";
        clearClassSplitWrongCandidate(point.point_id);
        updateClassSplitSummaryClassCounts(previousClass, nextClass);
        if (currentImage?.name === imageKey && currentBbox?.bbox === match.bbox) {
            currentBbox = {
                bbox: match.bbox,
                index: buckets[nextClass].length - 1,
                originalX: match.bbox.x,
                originalY: match.bbox.y,
                originalWidth: match.bbox.width,
                originalHeight: match.bbox.height,
                moving: false,
                resizing: null,
            };
            currentClass = nextClass;
            selectClassListOptionByName(nextClass);
            syncQwenClassToCurrent();
            updateSam3ClassOptions({ preserveSelection: true });
            syncClassSplitCurrentClassSelection();
            markOnlyBboxRecord(match.bbox);
        }
        captureAnnotationDirtyStateForImage(imageKey);
        scheduleAnnotationDiversityMetricRefresh();
        clearClassSplitDatasetAnalysis();
        return true;
    }

    async function changeClassSplitSelectedPointsClass(newClass) {
        const targetClass = String(newClass || "").trim();
        if (!targetClass) {
            setSamStatus("Choose a target class for the selected objects.", { variant: "warn", duration: 3000 });
            return;
        }
        const selectedIds = Array.from(classSplitState.lassoPointIds || [])
            .filter((pointId) => classSplitState.pointsById.has(pointId));
        if (!selectedIds.length) {
            setSamStatus("Lasso-select objects in the plot before changing their class.", { variant: "warn", duration: 3000 });
            return;
        }
        if (!annotationEditableGuard("Changing selected classes")) {
            return;
        }
        if (classSplitState.relabelInFlight) {
            return;
        }
        classSplitState.relabelInFlight = true;
        let changed = 0;
        const failed = [];
        try {
            selectedIds.forEach((pointId) => {
                const point = getClassSplitPointById(pointId);
                try {
                    if (applyClassSplitPointClassLocally(point, targetClass)) {
                        changed += 1;
                    }
                } catch (error) {
                    failed.push({ pointId, message: error.message || String(error) });
                }
            });
            clearClassSplitBulkSelection();
            renderClassSplitFilterOptions();
            refreshClassSplitFilteredReviewUi({ renderPlot: false });
            renderClassSplitReport();
            renderClassSplitDatasetAnalysis();
            renderClassSplitPlot();
            const suffix = failed.length ? ` ${failed.length} failed.` : " Save labels when ready.";
            const variant = failed.length && !changed ? "error" : failed.length ? "warn" : "success";
            setSamStatus(`Changed ${changed} selected object${changed === 1 ? "" : "s"} to ${targetClass}.${suffix}`, {
                variant,
                duration: failed.length ? 6000 : 4200,
            });
            if (failed.length) {
                console.warn("Class Split bulk class change skipped some points", failed);
            }
        } finally {
            classSplitState.relabelInFlight = false;
        }
    }

    async function waitForClassSplitBbox(point, timeoutMs = 5000) {
        const imageKey = getClassSplitPointImageKey(point);
        const started = Date.now();
        while (Date.now() - started < timeoutMs) {
            const sourceReady = annotationSourceState.hydratedKeys.has(imageKey) || !isDatasetBackedImageRecord(images?.[imageKey]);
            if (currentImage?.name === imageKey && sourceReady) {
                const match = findClassSplitBboxMatch(point);
                if (match) {
                    return match;
                }
            }
            await new Promise((resolve) => window.setTimeout(resolve, 100));
        }
        return null;
    }

    function selectClassSplitSourceBbox(match) {
        if (!match || !match.bbox) {
            return;
        }
        currentBbox = {
            bbox: match.bbox,
            index: match.index,
            originalX: match.bbox.x,
            originalY: match.bbox.y,
            originalWidth: match.bbox.width,
            originalHeight: match.bbox.height,
            moving: false,
            resizing: null,
        };
        currentClass = match.className;
        selectClassListOptionByName(match.className);
        syncQwenClassToCurrent();
        updateSam3ClassOptions({ preserveSelection: true });
        syncClassSplitCurrentClassSelection();
        markOnlyBboxRecord(match.bbox);
        showAnnotationFocusHud({ durationMs: 2400 });
    }

    function selectClassListOptionByName(className) {
        const classList = document.getElementById("classList");
        if (!classList) {
            return;
        }
        Array.from(classList.options || []).forEach((option, index) => {
            if (option.text === className || option.textContent === className) {
                classList.selectedIndex = index;
                classListIndex = index;
            }
        });
    }

    async function jumpToClassSplitPoint(point) {
        if (!point) {
            throw new Error("No point selected.");
        }
        const imageKey = getClassSplitPointImageKey(point);
        const imageRecord = images[imageKey];
        if (!imageRecord) {
            throw new Error(`Image is not loaded in this session: ${imageKey}`);
        }
        if (activeTab !== TAB_LABELING) {
            setActiveTab(TAB_LABELING);
            await new Promise((resolve) => window.requestAnimationFrame(resolve));
        }
        if (!currentImage || currentImage.name !== imageKey) {
            setCurrentImage(imageRecord);
        }
        const match = await waitForClassSplitBbox(point);
        if (!match) {
            throw new Error("Could not find the matching bbox after opening the image.");
        }
        selectClassSplitSourceBbox(match);
        startClassSplitInstancePulse(match.bbox, { durationMs: 2800 });
        setSamStatus(`Selected ${match.className} from Class Split Explorer.`, { variant: "success", duration: 3000 });
        return match;
    }

    async function changeClassSplitPointClass(point, newClass, { jumpToSource = false } = {}) {
        const targetClass = String(newClass || "").trim();
        if (!targetClass) {
            throw new Error("Choose a target class.");
        }
        if (!point) {
            throw new Error("No point selected.");
        }
        if (targetClass === String(point?.class_name || "")) {
            if (point.is_wrong_class_candidate) {
                markClassSplitWrongCandidateCorrect(point.point_id);
            }
            return;
        }
        if (!annotationEditableGuard("Changing class")) {
            return;
        }
        if (classSplitState.relabelInFlight) {
            return;
        }
        classSplitState.relabelInFlight = true;
        try {
            if (jumpToSource) {
                await jumpToClassSplitPoint(point);
            }
            const changed = applyClassSplitPointClassLocally(point, targetClass);
            if (changed) {
                let saveStatus = "Save labels when ready.";
                if (isAnnotationDatasetModeActive() && !isAnnotationMutationBlocked() && annotationSourceState.dirtyRecordsByKey.size) {
                    const saved = await flushAnnotationSnapshot({ manual: false });
                    if (saved && !annotationSourceState.dirtyRecordsByKey.size) {
                        saveStatus = "Saved.";
                    } else if (annotationSourceState.dirtyRecordsByKey.size) {
                        saveStatus = "Save pending; use Save labels if it does not clear.";
                    }
                }
                renderClassSplitFilterOptions();
                refreshClassSplitFilteredReviewUi({ renderPlot: false });
                renderClassSplitReport();
                renderClassSplitDatasetAnalysis();
                renderClassSplitPlot();
                setSamStatus(`Changed class to ${targetClass}. ${saveStatus}`, { variant: "success", duration: 3500 });
            }
        } finally {
            classSplitState.relabelInFlight = false;
        }
    }

